﻿'use client';

import { Repeat2, Loader2, BookOpen, MessageSquare, ExternalLink } from 'lucide-react';
import Link from 'next/link';
import { useState } from 'react';
import useSWR from 'swr';

import { RepostButton } from '@/components/Repost/RepostButton';

const fetcher = (url: string) => fetch(url).then((r) => r.json());

const typeIcons: Record<string, typeof BookOpen> = {
  MANGA: BookOpen,
  CHAPTER: BookOpen,
  COMMENT: MessageSquare,
};

const typeLabels: Record<string, string> = {
  MANGA: 'Manga',
  CHAPTER: 'Capítulo',
  COMMENT: 'Comentario',
};

export default function RepostsPage() {
  const { data, error } = useSWR('/api/reposts', fetcher, { refreshInterval: 10000 });
  const [filter, setFilter] = useState<string | null>(null);

  if (error) return <div className="max-w-3xl mx-auto px-4 py-8 text-center text-muted">Error al cargar reposts</div>;
  if (!data) return <div className="max-w-3xl mx-auto px-4 py-8" role="status"><Loader2 size={24} className="animate-spin mx-auto text-muted" /></div>;

  const reposts = data.reposts || [];
  const filtered = filter ? reposts.filter((r: any) => r.originalType === filter) : reposts;
  const types = [...new Set(reposts.map((r: any) => r.originalType))] as string[];

  return (
    <div className="max-w-3xl mx-auto px-4 pt-20 pb-10">
      <div className="mb-8">
        <h1 className="text-3xl font-extrabold tracking-tight flex items-center gap-3">
          <Repeat2 className="text-[var(--primary)]" size={30} /> Reposts
        </h1>
        <p className="text-muted">Contenido que has compartido</p>
      </div>

      {reposts.length > 0 && (
        <div className="flex gap-2 mb-6">
          <button onClick={() => setFilter(null)} className={`px-4 py-2 rounded-xl text-sm font-semibold border transition-colors cursor-pointer ${!filter ? 'bg-accent-blue text-white border-accent-blue' : 'bg-secondary border-custom hover:bg-tertiary'}`}>
            Todos ({reposts.length})
          </button>
          {types.map((t) => {
            const count = reposts.filter((r: any) => r.originalType === t).length;
            return (
              <button key={t} onClick={() => setFilter(t)} className={`px-4 py-2 rounded-xl text-sm font-semibold border transition-colors cursor-pointer ${filter === t ? 'bg-accent-blue text-white border-accent-blue' : 'bg-secondary border-custom hover:bg-tertiary'}`}>
                {typeLabels[t] || t} ({count})
              </button>
            );
          })}
        </div>
      )}

      {filtered.length === 0 ? (
        <div className="text-center py-16">
          <Repeat2 size={48} className="mx-auto text-muted mb-4 opacity-50" />
          <h2 className="text-xl font-bold mb-2">Sin reposts aún</h2>
          <p className="text-muted mb-6">Compartí mangas y capítulos que te gusten</p>
          <Link href="/explore" className="inline-flex items-center gap-2 bg-tertiary hover:bg-custom border border-custom px-6 py-3 rounded-xl font-semibold transition-colors">
            Explorar mangas
          </Link>
        </div>
      ) : (
        <div className="space-y-3">
          {filtered.map((repost: any) => {
            const Icon = typeIcons[repost.originalType] || BookOpen;
            return (
              <div key={repost.id} className="bg-secondary border border-custom rounded-xl p-4 flex items-center justify-between gap-4">
                <div className="flex items-center gap-3 min-w-0">
                  <div className="w-10 h-10 rounded-full bg-tertiary flex items-center justify-center shrink-0">
                    <Icon size={18} className="text-muted" />
                  </div>
                  <div className="min-w-0">
                    <p className="text-xs text-muted">{typeLabels[repost.originalType] || repost.originalType}</p>
                    <p className="text-sm font-semibold truncate">ID: {repost.originalId.slice(0, 12)}...</p>
                    {repost.comment && <p className="text-xs text-muted italic truncate">&quot;{repost.comment}&quot;</p>}
                    <p className="text-xs text-muted">{new Date(repost.createdAt).toLocaleDateString()}</p>
                  </div>
                </div>
                <div className="flex items-center gap-2 shrink-0">
                  <RepostButton originalType={repost.originalType} originalId={repost.originalId} initialReposted={true} />
                  <Link href={`?id=${repost.originalId}`} className="p-2 rounded-lg bg-tertiary hover:bg-custom border border-custom transition-colors">
                    <ExternalLink size={14} className="text-muted" />
                  </Link>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

import { Gem } from 'lucide-react';
import type { Metadata } from 'next';
import { redirect } from 'next/navigation';

import { SponsorshipsList } from '@/components/Sponsorships/SponsorshipsList';
import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

export const metadata: Metadata = {
  title: 'Mis Patrocinios | Inkverse',
  description: 'Gestiona tus patrocinios y pujas en capítulos',
};

async function getSponsorships(userId: string) {
  const [activeBids, wonBids, history] = await Promise.all([
    prisma.sponsorshipBid.findMany({
      where: { userId, status: 'ACTIVE' },
      include: {
        chapter: { select: { id: true, chapterNumber: true, title: true, manga: { select: { id: true, title: true, slug: true } } } },
      },
      orderBy: { createdAt: 'desc' },
      take: 20,
    }),
    prisma.sponsorshipBid.findMany({
      where: { userId, isWinning: true, status: { not: 'ACTIVE' } },
      include: {
        chapter: { select: { id: true, chapterNumber: true, title: true, manga: { select: { id: true, title: true, slug: true } } } },
      },
      orderBy: { createdAt: 'desc' },
      take: 20,
    }),
    prisma.sponsorshipBid.findMany({
      where: { userId, status: 'LOST' },
      include: {
        chapter: { select: { id: true, chapterNumber: true, title: true, manga: { select: { id: true, title: true, slug: true } } } },
      },
      orderBy: { createdAt: 'desc' },
      take: 50,
    }),
  ]);

  return { activeBids, wonBids, history };
}

export default async function SponsorshipsPage() {
  const session = await auth();
  if (!session?.user?.id) redirect('/auth/login');

  const { activeBids, wonBids, history } = await getSponsorships(session.user.id);

  return (
    <div className="max-w-4xl mx-auto px-4 pt-20 pb-10">
      <div className="mb-8">
        <h1 className="text-3xl font-extrabold tracking-tight flex items-center gap-3">
          <Gem className="text-[var(--primary)]" size={30} /> Mis Patrocinios
        </h1>
        <p className="text-muted">Gestiona tus pujas y patrocinios en capítulos</p>
      </div>
      <SponsorshipsList activeBids={activeBids as any} wonBids={wonBids as any} history={history as any} />
    </div>
  );
}

import { Coins } from 'lucide-react';
import { Suspense } from 'react';

import { TipsClient } from './TipsClient';
import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

export const metadata = {
  title: 'Propinas | InkVerse',
  description: 'Historial de propinas enviadas y recibidas',
};

async function getTips(userId: string) {
  const [sent, received] = await Promise.all([
    prisma.tip.findMany({
      where: { fromUserId: userId },
      orderBy: { createdAt: 'desc' },
      take: 100,
      include: {
        toUser: { select: { id: true, username: true, avatarUrl: true } },
        chapter: { select: { chapterNumber: true, manga: { select: { title: true, slug: true } } } },
      },
    }),
    prisma.tip.findMany({
      where: { toUserId: userId },
      orderBy: { createdAt: 'desc' },
      take: 100,
      include: {
        fromUser: { select: { id: true, username: true, avatarUrl: true } },
        chapter: { select: { chapterNumber: true, manga: { select: { title: true, slug: true } } } },
      },
    }),
  ]);

  const totalSent = sent.reduce((sum, t) => sum + t.amount, 0);
  const totalReceived = received.reduce((sum, t) => sum + t.amount, 0);

  return { sent: sent as any, received: received as any, stats: { sent: sent.length, received: received.length, totalSent, totalReceived } };
}

export default async function TipsPage() {
  const session = await auth();
  if (!session?.user?.id) return <div className="max-w-4xl mx-auto px-4 py-8 text-center text-muted">Inicia sesión para ver tus propinas</div>;

  const { sent, received, stats } = await getTips(session.user.id);

  return (
    <div className="max-w-4xl mx-auto px-4 pt-20 pb-10">
      <div className="mb-8">
        <h1 className="text-3xl font-extrabold tracking-tight flex items-center gap-3">
          <Coins className="text-[var(--primary)]" size={30} /> Propinas
        </h1>
        <p className="text-muted">Historial de propinas enviadas y recibidas</p>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
        <div className="bg-secondary border border-custom rounded-xl p-4">
          <p className="text-2xl font-bold text-accent-blue">{stats.totalSent.toLocaleString()}</p>
          <p className="text-xs text-muted">IC enviados ({stats.sent} props)</p>
        </div>
        <div className="bg-secondary border border-custom rounded-xl p-4">
          <p className="text-2xl font-bold text-accent-green">{stats.totalReceived.toLocaleString()}</p>
          <p className="text-xs text-muted">IC recibidos ({stats.received} props)</p>
        </div>
      </div>

      <Suspense fallback={<div className="animate-pulse h-96 bg-tertiary rounded-xl" />}>
        <TipsClient sent={sent} received={received} />
      </Suspense>
    </div>
  );
}

'use client';

import { Mail, Send, HelpCircle, MessageSquare, AlertCircle, Loader2, CheckCircle2 } from 'lucide-react';
import React, { useState } from 'react';

import { Container } from '@/components/Layout/Container';
import { PageHeader } from '@/components/Layout/PageHeader';
import { useT } from '@/i18n';
import { cn } from '@/lib/utils';

export default function ContactPage() {
  const t = useT();
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    subject: '',
    message: '',
    category: 'general'
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [errors, setErrors] = useState<Partial<typeof formData>>({});

  const categories = [
    { value: 'general', label: t('contact.categories.general'), icon: <HelpCircle className="w-4 h-4" /> },
    { value: 'support', label: t('contact.categories.support'), icon: <MessageSquare className="w-4 h-4" /> },
    { value: 'dmca', label: t('contact.categories.dmca'), icon: <AlertCircle className="w-4 h-4" /> },
    { value: 'business', label: t('contact.categories.business'), icon: <Mail className="w-4 h-4" /> }
  ];

  const validateForm = () => {
    const newErrors: Partial<typeof formData> = {};
    if (!formData.name.trim()) newErrors.name = t('contact.form.nameRequired');
    if (!formData.email.trim()) {
      newErrors.email = t('contact.form.emailRequired');
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
      newErrors.email = t('contact.form.emailInvalid');
    }
    if (!formData.subject.trim()) newErrors.subject = t('contact.form.subjectRequired');
    if (!formData.message.trim()) newErrors.message = t('contact.form.messageRequired');
    if (formData.message.length < 20) newErrors.message = t('contact.form.messageMinLength');
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validateForm()) return;

    setIsSubmitting(true);
    try {
      const res = await fetch('/api/contact', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
      });
      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.error || t('contact.form.sendError'));
      }
      setIsSubmitted(true);
    } catch (err: any) {
      setErrors({ ...errors, message: err.message || t('contact.form.error') });
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isSubmitted) {
    return (
      <Container className="py-12">
        <div className="max-w-2xl mx-auto text-center">
          <div className="bg-secondary border border-custom rounded-2xl p-12 shadow-lg">
        <div className="w-20 h-20 bg-[var(--success)]/20 rounded-full flex items-center justify-center mx-auto mb-6">
          <CheckCircle2 className="w-10 h-10 text-[var(--success)]" aria-hidden="true" />
            </div>
            <h1 className="text-3xl font-bold mb-4">{t('contact.success.title')}</h1>
            <p className="text-muted mb-8">
              {t('contact.success.message')}
            </p>
            <button
              onClick={() => {
                setIsSubmitted(false);
                setFormData({ name: '', email: '', subject: '', message: '', category: 'general' });
              }}
              className="bg-accent-blue hover:bg-accent-blue-hover text-[var(--text-inverse)] font-medium px-8 py-3 rounded-xl transition-colors"
            >
              {t('contact.success.sendAnother')}
            </button>
          </div>
        </div>
      </Container>
    );
  }

  return (
    <Container className="py-12">
      <PageHeader
        title={t('contact.title')}
        description={t('contact.description')}
        icon={<Mail className="w-8 h-8" aria-hidden="true" />}
      />

      <div className="max-w-3xl mx-auto">
        <div className="grid md:grid-cols-3 gap-4 mb-8">
          {[
            { icon: <HelpCircle className="w-6 h-6" aria-hidden="true" />, title: t('contact.info.faq'), desc: t('contact.info.faqDesc') },
            { icon: <MessageSquare className="w-6 h-6" aria-hidden="true" />, title: t('contact.info.support'), desc: t('contact.info.supportDesc') },
            { icon: <Mail className="w-6 h-6" aria-hidden="true" />, title: t('contact.info.email'), desc: 'soporte@inkverse.app' }
          ].map((item, index) => (
            <div key={item.title || `contact-card-${index}`} className="bg-secondary border border-custom rounded-xl p-6 text-center">
              <div className="w-12 h-12 bg-accent-blue/10 rounded-full flex items-center justify-center mx-auto mb-3 text-accent-blue">
                {item.icon}
              </div>
              <h2 className="font-semibold">{item.title}</h2>
              <p className="text-sm text-muted">{item.desc}</p>
            </div>
          ))}
        </div>

        <div className="bg-secondary border border-custom rounded-2xl p-8 shadow-lg">
          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid md:grid-cols-2 gap-4">
              <div>
                <label htmlFor="contact-name" className="block text-sm font-semibold mb-2">{t('contact.form.name')}</label>
                <input
                  id="contact-name"
                  type="text"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  aria-invalid={!!errors.name}
                  aria-describedby={errors.name ? 'contact-name-error' : undefined}
                  aria-required
                  autoComplete="name"
                  className={cn(
                    'w-full px-4 py-3 bg-tertiary border rounded-xl outline-none transition-all',
                    errors.name ? 'border-[var(--error)]' : 'border-custom focus:border-accent-blue'
                  )}
                  placeholder={t('contact.form.namePlaceholder')}
                />
                {errors.name && <p id="contact-name-error" className="mt-1 text-sm text-[var(--error)]">{errors.name}</p>}
              </div>
              <div>
                <label htmlFor="contact-email" className="block text-sm font-semibold mb-2">{t('contact.form.email')}</label>
                <input
                  id="contact-email"
                  type="email"
                  value={formData.email}
                  onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                  aria-invalid={!!errors.email}
                  aria-describedby={errors.email ? 'contact-email-error' : undefined}
                  aria-required
                  autoComplete="email"
                  className={cn(
                    'w-full px-4 py-3 bg-tertiary border rounded-xl outline-none transition-all',
                    errors.email ? 'border-[var(--error)]' : 'border-custom focus:border-accent-blue'
                  )}
                  placeholder={t('contact.form.emailPlaceholder')}
                />
                {errors.email && <p id="contact-email-error" className="mt-1 text-sm text-[var(--error)]">{errors.email}</p>}
              </div>
            </div>

            <div>
              <label className="block text-sm font-semibold mb-2">{t('contact.form.category')}</label>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                {categories.map((cat) => (
                  <button
                    key={cat.value}
                    type="button"
                    onClick={() => setFormData({ ...formData, category: cat.value })}
                    aria-pressed={formData.category === cat.value}
                    aria-label={cat.label}
                    className={cn(
                      'flex items-center justify-center gap-2 px-4 py-3 rounded-xl border transition-all',
                      formData.category === cat.value
                        ? 'bg-accent-blue text-[var(--text-inverse)] border-accent-blue'
                        : 'bg-tertiary border-custom hover:border-accent-blue/50'
                    )}
                  >
                    <span aria-hidden="true">{cat.icon}</span>
                    <span className="text-sm font-medium">{cat.label}</span>
                  </button>
                ))}
              </div>
            </div>

            <div>
                <label htmlFor="contact-subject" className="block text-sm font-semibold mb-2">{t('contact.form.subject')}</label>
                <input
                  id="contact-subject"
                  type="text"
                  value={formData.subject}
                  onChange={(e) => setFormData({ ...formData, subject: e.target.value })}
                  aria-invalid={!!errors.subject}
                  aria-describedby={errors.subject ? 'contact-subject-error' : undefined}
                  aria-required
                  className={cn(
                    'w-full px-4 py-3 bg-tertiary border rounded-xl outline-none transition-all',
                    errors.subject ? 'border-[var(--error)]' : 'border-custom focus:border-accent-blue'
                  )}
                  placeholder={t('contact.form.subjectPlaceholder')}
                />
              {errors.subject && <p id="contact-subject-error" className="mt-1 text-sm text-[var(--error)]">{errors.subject}</p>}
            </div>

            <div>
                <label htmlFor="contact-message" className="block text-sm font-semibold mb-2">{t('contact.form.message')}</label>
                <textarea
                  id="contact-message"
                  value={formData.message}
                  onChange={(e) => setFormData({ ...formData, message: e.target.value })}
                  rows={5}
                  aria-invalid={!!errors.message}
                  aria-describedby={errors.message ? 'contact-message-error' : undefined}
                  aria-required
                  className={cn(
                  'w-full px-4 py-3 bg-tertiary border rounded-xl outline-none transition-all resize-none',
                  errors.message ? 'border-[var(--error)]' : 'border-custom focus:border-accent-blue'
                )}
                placeholder={t('contact.form.messagePlaceholder')}
              />
              {errors.message && <p id="contact-message-error" className="mt-1 text-sm text-[var(--error)]">{errors.message}</p>}
              <p className="mt-1 text-xs text-muted text-right">
                {formData.message.length} {t('contact.form.characters')}
              </p>
            </div>

            <button
              type="submit"
              disabled={isSubmitting}
              className="w-full bg-accent-blue hover:bg-accent-blue-hover text-[var(--text-inverse)] font-bold py-3 rounded-xl transition-all flex items-center justify-center gap-2 disabled:opacity-50"
            >
              {isSubmitting ? (
                <>
                  <Loader2 className="w-5 h-5 animate-spin" aria-hidden="true" />
                  {t('contact.form.sending')}
                </>
              ) : (
                <>
                  <Send className="w-5 h-5" aria-hidden="true" />
                  {t('contact.form.submit')}
                </>
              )}
            </button>
          </form>
        </div>
      </div>
    </Container>
  );
}

import type { Metadata } from 'next';

import { DiscoverClient } from './DiscoverClient';
import { prisma } from '@/lib/prisma';

export const metadata: Metadata = {
  title: 'Descubrir | Inkverse',
  description: 'Descubre nuevos mangas, tendencias y recomendaciones',
};

async function getDiscoverData() {
  const [trending, recent, topRated] = await Promise.all([
    prisma.mangaSeries.findMany({ orderBy: { totalViews: 'desc' }, take: 12, select: { id: true, title: true, slug: true, coverUrl: true, status: true, rating: true, totalViews: true, _count: { select: { chapters: true } } } }),
    prisma.mangaSeries.findMany({ orderBy: { createdAt: 'desc' }, take: 12, select: { id: true, title: true, slug: true, coverUrl: true, status: true, rating: true, totalViews: true, _count: { select: { chapters: true } } } }),
    prisma.mangaSeries.findMany({ orderBy: { rating: 'desc' }, where: { rating: { not: null } }, take: 12, select: { id: true, title: true, slug: true, coverUrl: true, status: true, rating: true, totalViews: true, _count: { select: { chapters: true } } } }),
  ]);

  const featuredManga = trending[Math.floor(Math.random() * Math.min(trending.length, 5))];

  return { trending: trending as any, recent: recent as any, topRated: topRated as any, featuredManga: featuredManga as any };
}

export default async function DiscoverPage() {
  const data = await getDiscoverData();

  return <DiscoverClient {...data} />;
}

'use client';

import { motion, useReducedMotion } from 'framer-motion';
import { Trophy, Users, Crown, Flame, BookOpen } from 'lucide-react';

import { LeaderboardTable } from '@/components/Rankings/LeaderboardTable';
import { Card } from '@/components/ui/Card';
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/components/ui/Tabs';
import { useT } from '@/i18n';

interface RankingsClientProps {
  leaderboards: {
    readers: any[];
    creators: any[];
    clans: any[];
    manga: any[];
  };
  currentUserId?: string;
}

const statCards = [
  {
    key: 'readers',
    labelKey: 'rankings.topReaders',
    count: (lb: RankingsClientProps['leaderboards']) => lb.readers.length,
    icon: Users,
    colorVar: '--info',
  },
  {
    key: 'creators',
    labelKey: 'rankings.topCreators',
    count: (lb: RankingsClientProps['leaderboards']) => lb.creators.length,
    icon: Crown,
    colorVar: '--accent-purple',
  },
  {
    key: 'clans',
    labelKey: 'rankings.topClans',
    count: (lb: RankingsClientProps['leaderboards']) => lb.clans.length,
    icon: Flame,
    colorVar: '--warning',
  },
  {
    key: 'manga',
    labelKey: 'rankings.mangaTrending',
    count: (lb: RankingsClientProps['leaderboards']) => lb.manga.length,
    icon: BookOpen,
    colorVar: '--success',
  },
];

export default function RankingsClient({ leaderboards, currentUserId }: RankingsClientProps) {
  const shouldReduceMotion = useReducedMotion();
  const t = useT();

  return (
    <div className="max-w-6xl mx-auto space-y-10 px-4 sm:px-6 lg:px-8 pt-20 pb-10">
      {/* Header */}
      <motion.div
        className="mb-8"
        initial={false}
        animate={{ opacity: 1, y: 0 }}
