﻿'use client';

import {
  LayoutDashboard,
  Users,
  BookOpen,
  FileText,
  MessageSquare,
  AlertTriangle,
  CheckCircle,
  XCircle,
  ArrowRight,
  Shield,
  TrendingUp,
} from 'lucide-react';
import dynamic from 'next/dynamic';
import Link from 'next/link';
import useSWR from 'swr';

import { useT } from '@/i18n';
import { StatCard } from '@/components/Admin/StatCard';
import { Badge } from '@/components/ui/Badge';
import { Button } from '@/components/ui/Button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/Card';

const ChartsSection = dynamic(() => import('@/components/Admin/ChartsSection').then(m => ({ default: m.ChartsSection })), { ssr: false });

interface DashboardStats {
  totalUsers: number;
  totalMangas: number;
  totalChapters: number;
  totalComments: number;
  pendingReports: number;
  newUsersToday: number;
  newMangasToday: number;
  newCommentsToday: number;
  activityData: { date: string; users: number; views: number }[];
  changes: {
    users: number;
    mangas: number;
    chapters: number;
    comments: number;
  };
}

interface ModerationAlert {
  id: string;
  type: 'report' | 'abuse' | 'spam';
  message: string;
  count: number;
  severity: 'low' | 'medium' | 'high';
}

const fetcher = (url: string) => fetch(url).then((res) => res.json());

export default function AdminDashboardPage() {
  const t = useT();
  const { data: stats, error: statsError, isLoading: statsLoading } = useSWR<DashboardStats>(
    '/api/admin/stats',
    fetcher,
    { refreshInterval: 60000 }
  );

  const { data: alertsData, error: _alertsError, isLoading: alertsLoading } = useSWR<{ alerts: ModerationAlert[] }>(
    '/api/admin/moderation/alerts',
    fetcher,
    { refreshInterval: 30000 }
  );

  const alerts = alertsData?.alerts || [];
  const isLoading = statsLoading || alertsLoading;

  if (isLoading) {
    return (
      <div className="animate-pulse space-y-6" role="status" aria-label="Cargando panel de administración">
        <div className="h-8 bg-[var(--surface-sunken)] rounded w-1/4"></div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          {[...Array(4)].map((_, i) => (
            <div key={i} className="h-32 bg-[var(--surface-sunken)] rounded"></div>
          ))}
        </div>
        <div className="h-64 bg-[var(--surface-sunken)] rounded"></div>
      </div>
    );
  }

  if (statsError) {
    return (
      <div className="text-center py-12" role="alert">
        <AlertTriangle className="w-12 h-12 mx-auto mb-4 text-[var(--error)]" aria-hidden="true" />
        <h2 className="text-xl font-semibold text-[var(--text-primary)]">{t('admin.failedToLoad')}</h2>
        <p className="text-[var(--text-tertiary)] mt-2">{t('common.retry')}</p>
        <Button onClick={() => window.location.reload()} className="mt-4">
          {t('admin.refresh')}
        </Button>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-[var(--text-primary)] flex items-center gap-2">
            <LayoutDashboard className="w-6 h-6 text-[var(--primary)]" />
            {t('admin.dashboard')}
          </h1>
          <p className="text-[var(--text-muted)]">{t('admin.overview')}</p>
        </div>
        <div className="text-sm text-[var(--text-tertiary)]">
          {t('admin.lastUpdated')}: {new Date().toLocaleTimeString()}
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <Link href="/admin/users" className="block">
          <StatCard
            title={t('admin.totalUsers')}
            value={stats?.totalUsers.toLocaleString() || '0'}
            description={t('admin.activeAccounts')}
            change={stats?.changes?.users}
            changeLabel={t('admin.fromLastMonth')}
            icon={Users}
            trend={stats?.changes?.users && stats.changes.users > 0 ? 'up' : stats?.changes?.users && stats.changes.users < 0 ? 'down' : 'neutral'}
          />
        </Link>
        <Link href="/admin/manga" className="block">
          <StatCard
            title={t('admin.totalMangas')}
            value={stats?.totalMangas.toLocaleString() || '0'}
            description={t('admin.publishedSeries')}
            change={stats?.changes?.mangas}
            changeLabel={t('admin.fromLastMonth')}
            icon={BookOpen}
            trend={stats?.changes?.mangas && stats.changes.mangas > 0 ? 'up' : stats?.changes?.mangas && stats.changes.mangas < 0 ? 'down' : 'neutral'}
          />
        </Link>
        <Link href="/admin/manga" className="block">
          <StatCard
            title={t('admin.chapters')}
            value={stats?.totalChapters.toLocaleString() || '0'}
            description={t('admin.publishedChapters')}
            change={stats?.changes?.chapters}
            changeLabel={t('admin.fromLastMonth')}
            icon={FileText}
            trend={stats?.changes?.chapters && stats.changes.chapters > 0 ? 'up' : stats?.changes?.chapters && stats.changes.chapters < 0 ? 'down' : 'neutral'}
          />
        </Link>
        <Link href="/admin/moderation" className="block">
          <StatCard
            title={t('admin.comments')}
            value={stats?.totalComments.toLocaleString() || '0'}
            description={t('admin.totalComments')}
            change={stats?.changes?.comments}
            changeLabel={t('admin.fromLastMonth')}
            icon={MessageSquare}
            trend={stats?.changes?.comments && stats.changes.comments > 0 ? 'up' : stats?.changes?.comments && stats.changes.comments < 0 ? 'down' : 'neutral'}
          />
        </Link>
      </div>

      <ChartsSection
        activityData={stats?.activityData}
        totalMangas={stats?.totalMangas}
        totalChapters={stats?.totalChapters}
        totalComments={stats?.totalComments}
      />

      {/* Today's Activity */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <Card>
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-[var(--text-tertiary)]">{t('admin.newUsersToday')}</p>
                <p className="text-3xl font-bold text-[var(--text-primary)] mt-1">
                  {stats?.newUsersToday || 0}
                </p>
              </div>
              <div className="p-3 bg-[var(--success)]/10 rounded-lg">
                <TrendingUp className="w-6 h-6 text-[var(--success)]" aria-hidden="true" />
              </div>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-[var(--text-tertiary)]">{t('admin.newMangasToday')}</p>
                <p className="text-3xl font-bold text-[var(--text-primary)] mt-1">
                  {stats?.newMangasToday || 0}
                </p>
              </div>
              <div className="p-3 bg-[var(--primary)]/10 rounded-lg">
                <BookOpen className="w-6 h-6 text-[var(--primary)]" aria-hidden="true" />
              </div>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-[var(--text-tertiary)]">{t('admin.newCommentsToday')}</p>
                <p className="text-3xl font-bold text-[var(--text-primary)] mt-1">
                  {stats?.newCommentsToday || 0}
                </p>
              </div>
              <div className="p-3 bg-[var(--warning)]/10 rounded-lg">
                <MessageSquare className="w-6 h-6 text-[var(--warning)]" aria-hidden="true" />
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Moderation Alerts */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">              <CardTitle className="flex items-center gap-2">
              <AlertTriangle className="w-5 h-5 text-[var(--warning)]" aria-hidden="true" />
              {t('admin.moderationAlerts')}
              {alerts.length > 0 && (
                <Badge variant="destructive" className="ml-2">
                  {alerts.length}
                </Badge>
              )}
            </CardTitle>
            <Link href="/admin/moderation" aria-label="Ver todos los reportes de moderación">
              <Button variant="ghost" size="sm">
                View All <ArrowRight className="w-4 h-4 ml-1" aria-hidden="true" />
              </Button>
            </Link>
          </div>
        </CardHeader>
        <CardContent>
          {alertsLoading ? (
            <div className="animate-pulse space-y-3">
              {[...Array(3)].map((_, i) => (
                <div key={i} className="h-16 bg-[var(--surface-sunken)] rounded"></div>
              ))}
            </div>
          ) : alerts.length === 0 ? (
            <div className="text-center py-8 text-[var(--text-tertiary)]">
              <CheckCircle className="w-12 h-12 mx-auto mb-3 text-[var(--success)]" aria-hidden="true" />
              <p>{t('admin.noPendingAlerts')}</p>
            </div>
          ) : (
            <div className="space-y-3">
              {alerts.map((alert) => (
                <div
                  key={alert.id}
                  className={`flex items-center justify-between p-4 rounded-lg border
                  ${alert.severity === 'high'
                      ? 'bg-[var(--error)]/5 border-[var(--error)]/20'
                      : alert.severity === 'medium'
                        ? 'bg-[var(--warning)]/5 border-[var(--warning)]/20'
                        : 'bg-[var(--surface)] border-[var(--border)]'
                    }`}
                >
                  <div className="flex items-center gap-3">
                    {alert.severity === 'high' ? (
                      <XCircle className="w-5 h-5 text-[var(--error)]" aria-hidden="true" />
                    ) : alert.severity === 'medium' ? (
                      <AlertTriangle className="w-5 h-5 text-[var(--warning)]" aria-hidden="true" />
                    ) : (
                      <CheckCircle className="w-5 h-5 text-[var(--primary)]" aria-hidden="true" />
                    )}
                    <div>
                      <p className="font-medium text-[var(--text-primary)]">{alert.message}</p>
                      <p className="text-sm text-[var(--text-tertiary)] capitalize">{alert.type}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-3">
                    <span className="text-sm font-medium text-[var(--text-muted)]">
                      {alert.count} items
                    </span>
                    <Link href="/admin/moderation">
                      <Button variant="outline" size="sm">
                        Review
                      </Button>
                    </Link>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Quick Actions */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <Link href="/admin/users" aria-label="Gestionar usuarios">
          <Card className="hover:shadow-md transition-shadow cursor-pointer h-full">
            <CardContent className="p-6 flex items-center gap-4">
              <div className="p-3 bg-[var(--primary)]/10 rounded-lg">
                <Users className="w-6 h-6 text-[var(--primary)]" aria-hidden="true" />
              </div>
              <div className="flex-1">
                <h3 className="font-semibold text-[var(--text-primary)]">{t('admin.manageUsers')}</h3>
                <p className="text-sm text-[var(--text-tertiary)]">{t('admin.manageUsersDesc')}</p>
              </div>
              <ArrowRight className="w-5 h-5 text-[var(--text-secondary)]" aria-hidden="true" />
            </CardContent>
          </Card>
        </Link>
        <Link href="/admin/moderation" aria-label="Panel de moderación">
          <Card className="hover:shadow-md transition-shadow cursor-pointer h-full">
            <CardContent className="p-6 flex items-center gap-4">
              <div className="p-3 bg-[var(--warning)]/10 rounded-lg">
                <Shield className="w-6 h-6 text-[var(--warning)]" aria-hidden="true" />
              </div>
              <div className="flex-1">
                <h3 className="font-semibold text-[var(--text-primary)]">{t('admin.moderation')}</h3>
                <p className="text-sm text-[var(--text-tertiary)]">{t('admin.moderationDesc')}</p>
              </div>
              <ArrowRight className="w-5 h-5 text-[var(--text-secondary)]" aria-hidden="true" />
            </CardContent>
          </Card>
        </Link>
        <Link href="/admin/manga" aria-label="Gestionar mangas">
          <Card className="hover:shadow-md transition-shadow cursor-pointer h-full">
            <CardContent className="p-6 flex items-center gap-4">
              <div className="p-3 bg-[var(--success)]/10 rounded-lg">
                <BookOpen className="w-6 h-6 text-[var(--success)]" aria-hidden="true" />
              </div>
              <div className="flex-1">
                <h3 className="font-semibold text-[var(--text-primary)]">{t('admin.manageManga')}</h3>
                <p className="text-sm text-[var(--text-tertiary)]">{t('admin.manageMangaDesc')}</p>
              </div>
              <ArrowRight className="w-5 h-5 text-[var(--text-secondary)]" aria-hidden="true" />
            </CardContent>
          </Card>
        </Link>
      </div>
    </div>
  );
}

'use client';

import {
  Globe,
  Shield,
  Settings,
  Coins,
  Save,
  Loader2,
  CheckCircle,
  AlertTriangle,
  Monitor,
  Sparkles,
  Banknote,
  Users,
} from 'lucide-react';
import { useState, useMemo } from 'react';
import useSWR, { mutate } from 'swr';

import { Button } from '@/components/ui/Button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/Card';
import { Input } from '@/components/ui/Input';
import { Label } from '@/components/ui/Label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/Select';
import { Switch } from '@/components/ui/Switch';
import { Textarea } from '@/components/ui/Textarea';
import { useT } from '@/i18n';

interface SiteSettings {
  siteName: string;
  siteDescription: string;
  maintenanceMode: boolean;
  maxUploadSize: number;
  allowedImageTypes: string[];
  defaultLanguage: string;
  enableRegistrations: boolean;
  enableAI: boolean;
  enableCrowdfunding: boolean;
  enableClans: boolean;
  inkcoinsRewardPerChapter: number;
  xpRewardPerChapter: number;
  minimumPayoutAmount: number;
}

const fetcher = (url: string) => fetch(url).then((res) => res.json());

export default function AdminSettingsPage() {
  const { data, error, isLoading } = useSWR<{ settings: SiteSettings; adminCount: number }>(
    '/api/admin/settings',
    fetcher,
    { revalidateOnFocus: false }
  );

  const t = useT();
  const [form, setForm] = useState<Partial<SiteSettings>>({});
  const [saving, setSaving] = useState(false);
  const [saveMessage, setSaveMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  // Use useMemo to derive form state from SWR data without setState in effect
  const effectiveForm = useMemo(() => data?.settings || form, [data?.settings, form]);

  const handleChange = (key: keyof SiteSettings, value: any) => {
    // Only update local form state, not SWR data
    setForm(prev => ({ ...prev, [key]: value }));
    setSaveMessage(null);
  };

  const handleSave = async () => {
    setSaving(true);
    setSaveMessage(null);
    try {
      const res = await fetch('/api/admin/settings', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(effectiveForm),
      });
      if (!res.ok) {
        const err = await res.json();
        throw new Error(err.error || 'Error al guardar');
      }
      mutate('/api/admin/settings');
      setSaveMessage({ type: 'success', text: t('admin.savedCorrectly') });
    } catch (err: any) {
      setSaveMessage({ type: 'error', text: err.message || t('admin.errorSavingSettings') });
    } finally {
      setSaving(false);
    }
  };

  if (isLoading) {
    return (
      <div className="animate-pulse space-y-6">
        <div className="h-8 bg-[var(--surface-sunken)] rounded w-1/4" />
        {[...Array(4)].map((_, i) => (
          <div key={i} className="h-48 bg-[var(--surface-sunken)] rounded-xl" />
        ))}
      </div>
    );
  }

  if (error) {
    return (
      <div className="text-center py-12">
        <AlertTriangle className="w-12 h-12 mx-auto mb-4 text-[var(--error)]" />
        <h2 className="text-xl font-semibold text-[var(--text-primary)]">{t('admin.errorLoadingSettings')}</h2>
        <Button onClick={() => mutate('/api/admin/settings')} className="mt-4">
          {t('admin.retry')}
        </Button>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-[var(--text-primary)] flex items-center gap-2">
            <Settings className="w-6 h-6 text-[var(--primary)]" />
            {t('admin.configuracion')}
          </h1>
          <p className="text-[var(--text-secondary)] mt-1">{t('admin.adminSettingsDesc')}</p>
        </div>
        <Button onClick={handleSave} disabled={saving}>
          {saving ? (
            <Loader2 className="w-4 h-4 mr-2 animate-spin" />
          ) : (
            <Save className="w-4 h-4 mr-2" />
          )}
          {t('admin.saveChanges')}
        </Button>
      </div>

      {saveMessage && (
        <div
          className={`flex items-center gap-2 p-3 rounded-lg ${
            saveMessage.type === 'success'
              ? 'bg-[var(--success)]/10 border border-[var(--success)]/20 text-[var(--success)]'
              : 'bg-[var(--error)]/10 border border-[var(--error)]/20 text-[var(--error)]'
          }`}
        >
          {saveMessage.type === 'success' ? (
            <CheckCircle className="w-5 h-5" />
          ) : (
            <AlertTriangle className="w-5 h-5" />
          )}
          <span className="text-sm">{saveMessage.text}</span>
        </div>
      )}

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Globe className="w-5 h-5 text-[var(--primary)]" />
            {t('admin.general')}
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <Label htmlFor="siteName" className="text-[var(--text-secondary)]">{t('admin.siteName')}</Label>
              <Input
                id="siteName"
                value={effectiveForm.siteName || ''}
                onChange={(e) => handleChange('siteName', e.target.value)}
                className="mt-1"
              />
            </div>
            <div>
              <Label htmlFor="defaultLanguage" className="text-[var(--text-secondary)]">{t('admin.defaultLanguage')}</Label>
              <Select
                value={effectiveForm.defaultLanguage || 'es'}
                onValueChange={(v) => handleChange('defaultLanguage', v)}
              >
                <SelectTrigger className="mt-1">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="es">Español</SelectItem>
                  <SelectItem value="en">English</SelectItem>
                  <SelectItem value="pt">Português</SelectItem>
                  <SelectItem value="ja">日本語</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>
          <div>              <Label htmlFor="siteDescription" className="text-[var(--text-secondary)]">{t('admin.siteDescription')}</Label>
            <Textarea
              id="siteDescription"                value={effectiveForm.siteDescription || ''}
              onChange={(e) => handleChange('siteDescription', e.target.value)}
              className="mt-1"
              rows={3}
            />
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Shield className="w-5 h-5 text-[var(--warning)]" />
            {t('admin.securityAccess')}
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex items-center justify-between p-4 bg-[var(--surface-sunken)] rounded-lg border border-[var(--border)]">
            <div>
              <p className="font-medium text-[var(--text-primary)]">{t('admin.maintenanceMode')}</p>
              <p className="text-sm text-[var(--text-tertiary)]">{t('admin.maintenanceModeDesc')}</p>
            </div>
            <Switch
              checked={effectiveForm.maintenanceMode || false}
              onCheckedChange={(v) => handleChange('maintenanceMode', v)}
            />
          </div>
          <div className="flex items-center justify-between p-4 bg-[var(--surface-sunken)] rounded-lg border border-[var(--border)]">
            <div>
              <p className="font-medium text-[var(--text-primary)]">{t('admin.registrationsOpen')}</p>
              <p className="text-sm text-[var(--text-tertiary)]">{t('admin.registrationsOpenDesc')}</p>
            </div>
            <Switch
              checked={effectiveForm.enableRegistrations ?? true}
              onCheckedChange={(v) => handleChange('enableRegistrations', v)}
            />
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Monitor className="w-5 h-5 text-[var(--accent-purple)]" />
            {t('admin.features')}
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex items-center justify-between p-4 bg-[var(--surface-sunken)] rounded-lg border border-[var(--border)]">
            <div className="flex items-center gap-3">
              <Sparkles className="w-5 h-5 text-[var(--accent-purple)]" />
              <div>
                <p className="font-medium text-[var(--text-primary)]">{t('admin.ai')}</p>
                <p className="text-sm text-[var(--text-tertiary)]">{t('admin.aiDesc')}</p>
              </div>
            </div>
            <Switch
              checked={effectiveForm.enableAI ?? true}
              onCheckedChange={(v) => handleChange('enableAI', v)}
            />
          </div>
          <div className="flex items-center justify-between p-4 bg-[var(--surface-sunken)] rounded-lg border border-[var(--border)]">
            <div className="flex items-center gap-3">
              <Banknote className="w-5 h-5 text-[var(--success)]" />
              <div>
                <p className="font-medium text-[var(--text-primary)]">{t('admin.crowdfunding')}</p>
                <p className="text-sm text-[var(--text-tertiary)]">{t('admin.crowdfundingDesc')}</p>
              </div>
            </div>
            <Switch
              checked={effectiveForm.enableCrowdfunding ?? true}
              onCheckedChange={(v) => handleChange('enableCrowdfunding', v)}
            />
          </div>
          <div className="flex items-center justify-between p-4 bg-[var(--surface-sunken)] rounded-lg border border-[var(--border)]">
            <div className="flex items-center gap-3">
              <Users className="w-5 h-5 text-[var(--info)]" />
              <div>
                <p className="font-medium text-[var(--text-primary)]">{t('admin.clanes')}</p>
                <p className="text-sm text-[var(--text-tertiary)]">{t('admin.clanesDesc')}</p>
              </div>
            </div>
            <Switch
              checked={effectiveForm.enableClans ?? true}
              onCheckedChange={(v) => handleChange('enableClans', v)}
            />
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Coins className="w-5 h-5 text-[var(--warning)]" />
            {t('admin.uploadsEconomy')}
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <Label htmlFor="maxUploadSize" className="text-[var(--text-secondary)]">
                {t('admin.maxUploadSize')}
              </Label>
              <Input
                id="maxUploadSize"
                type="number"
                min={1}
                max={50}
                value={effectiveForm.maxUploadSize ? effectiveForm.maxUploadSize / (1024 * 1024) : 10}
                onChange={(e) =>
                  handleChange('maxUploadSize', Number(e.target.value) * 1024 * 1024)
                }
                className="mt-1"
              />
            </div>
            <div>
              <Label htmlFor="minimumPayoutAmount" className="text-[var(--text-secondary)]">
                {t('admin.minimumPayout')}
              </Label>
              <Input
                id="minimumPayoutAmount"
                type="number"
                min={100}
                value={effectiveForm.minimumPayoutAmount || 1000}
                onChange={(e) => handleChange('minimumPayoutAmount', Number(e.target.value))}
                className="mt-1"
              />
            </div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <Label htmlFor="inkcoinsRewardPerChapter" className="text-[var(--text-secondary)]">
                {t('admin.inkcoinsPerChapter')}
              </Label>
              <Input
                id="inkcoinsRewardPerChapter"
                type="number"
                min={0}
                value={effectiveForm.inkcoinsRewardPerChapter ?? 10}
                onChange={(e) => handleChange('inkcoinsRewardPerChapter', Number(e.target.value))}
                className="mt-1"
              />
            </div>
            <div>
              <Label htmlFor="xpRewardPerChapter" className="text-[var(--text-secondary)]">
                {t('admin.xpPerChapter')}
              </Label>
              <Input
                id="xpRewardPerChapter"
                type="number"
                min={0}
                value={effectiveForm.xpRewardPerChapter ?? 25}
                onChange={(e) => handleChange('xpRewardPerChapter', Number(e.target.value))}
                className="mt-1"
              />
            </div>
          </div>
          <div>
            <Label className="text-[var(--text-secondary)]">{t('admin.allowedImageTypes')}</Label>
            <div className="flex flex-wrap gap-2 mt-2">
              {(effectiveForm.allowedImageTypes || []).map((type) => (
                <span
                  key={type}
                  className="px-2 py-1 bg-[var(--surface-sunken)] border border-[var(--border)] rounded text-sm text-[var(--text-secondary)]"
                >
                  {type}
                </span>
              ))}
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

﻿'use client';

import {
  useReactTable,
  getCoreRowModel,
  getFilteredRowModel,
  getSortedRowModel,
  getPaginationRowModel,
  flexRender,
  type ColumnDef,
} from '@tanstack/react-table';
import {
  Search,
  Users,
  Edit,
  Ban,
  Trash2,
  Eye,
  User,
  Check,
  Loader2,
} from 'lucide-react';
import Link from 'next/link';
import { useState, useMemo } from 'react';
import useSWR from 'swr';

import { OptimizedImage } from '@/components/Image/OptimizedImage';
import { Badge } from '@/components/ui/Badge';
import { Button } from '@/components/ui/Button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/Card';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from '@/components/ui/Dialog';
import { Input } from '@/components/ui/Input';
import { useT } from '@/i18n';

interface UserData {
  id: string;
  email: string;
  username: string;
  displayName: string | null;
  avatarUrl: string | null;
  role: string;
  xpPoints: number;
  inkcoinsBalance: number;
  level: number;
  readingStreak: number;
  createdAt: string;
  lastReadAt: string | null;
  mangaCount: number;
  chapterCount: number;
  commentCount: number;
}

const fetcher = (url: string) => fetch(url).then((res) => res.json());

export default function UsersPage() {
  // Always call useT first before any conditional logic
  const t = useT();
  const [users, setUsers] = useState<UserData[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedUser, setSelectedUser] = useState<UserData | null>(null);
  const [showUserDialog, setShowUserDialog] = useState(false);
  const [showActionDialog, setShowActionDialog] = useState(false);
  const [actionType, setActionType] = useState<'ban' | 'unban' | 'delete'>('ban');
  const [isActioning, setIsActioning] = useState(false);

  const { data: _data, error, isLoading, mutate } = useSWR<{ users: UserData[] }>(
    '/api/admin/users',
    fetcher,
    {
      refreshInterval: 60000,
      onSuccess: (data) => {
        if (data?.users) {
          setUsers(data.users);
        }
      },
    }
  );

  const handleAction = async () => {
    if (!selectedUser) return;
    setIsActioning(true);

    try {
      const response = await fetch(`/api/admin/users/${selectedUser.id}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: actionType }),
      });

      if (response.ok) {
        await mutate();
        setShowActionDialog(false);
        setSelectedUser(null);
      }
    } catch (error) {
      console.error('Action failed:', error);
    } finally {
      setIsActioning(false);
    }
  };

  const columns: ColumnDef<UserData>[] = useMemo(
    () => [
      {
        accessorKey: 'user',
        header: 'User',
        cell: ({ row }) => (
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-[var(--surface-sunken)] flex items-center justify-center overflow-hidden">
              {row.original.avatarUrl ? (
                <OptimizedImage
                  src={row.original.avatarUrl}
                  alt={row.original.username}
                  width={40}
                  height={40}
                  className="rounded-full"
                  objectFit="cover"
                />
              ) : (
                <User className="w-5 h-5 text-[var(--text-tertiary)]" />
              )}
            </div>
            <div>
              <p className="font-medium text-[var(--text-primary)]">
                {row.original.displayName || row.original.username}
              </p>
              <p className="text-xs text-[var(--text-tertiary)]">@{row.original.username}</p>
            </div>
          </div>
        ),
      },
      {
        accessorKey: 'email',
        header: 'Email',
        cell: ({ row }) => (
          <span className="text-sm text-[var(--text-muted)]">{row.original.email}</span>
        ),
      },
      {
        accessorKey: 'role',
        header: 'Role',
        cell: ({ row }) => (
          <Badge
            variant={row.original.role === 'ADMIN' ? 'destructive' : 'default'}
            className="capitalize"
          >
            {row.original.role.toLowerCase()}
          </Badge>
        ),
      },
      {
        accessorKey: 'level',
        header: 'Level',
        cell: ({ row }) => (
          <div className="text-center">
            <span className="font-medium">{row.original.level}</span>
          </div>
        ),
      },
      {
        accessorKey: 'xpPoints',
        header: 'XP',
        cell: ({ row }) => (
          <span className="text-sm text-[var(--text-muted)]">
            {row.original.xpPoints.toLocaleString()}
          </span>
        ),
      },
      {
        accessorKey: 'createdAt',
        header: 'Joined',
        cell: ({ row }) => (
          <span className="text-sm text-[var(--text-tertiary)]">
            {new Date(row.original.createdAt).toLocaleDateString()}
          </span>
        ),
      },
      {
        id: 'actions',
        header: 'Actions',
        cell: ({ row }) => (
          <div className="flex items-center gap-2">
            <Button
              variant="ghost"
              size="icon"
              onClick={() => {
                setSelectedUser(row.original);
                setShowUserDialog(true);
              }}
              title="View Profile"
        aria-label="Ver perfil"
            >
              <Eye className="w-4 h-4 text-[var(--primary)]" />
            </Button>
            <Link href={`/admin/users/${row.original.id}`}>
<Button variant="ghost" size="icon" title="Edit" aria-label="Editar usuario">
            <Edit className="w-4 h-4 text-[var(--primary)]" />
          </Button>
            </Link>
            <Button
              variant="ghost"
              size="icon"
              onClick={() => {
                setSelectedUser(row.original);
                setActionType('ban');
                setShowActionDialog(true);
              }}
              title="Ban User"
        aria-label="Banear usuario"
            >
              <Ban className="w-4 h-4 text-[var(--warning)]" />
            </Button>
            <Button
              variant="ghost"
              size="icon"
              onClick={() => {
                setSelectedUser(row.original);
                setActionType('delete');
                setShowActionDialog(true);
              }}
              title="Delete"
        aria-label="Eliminar usuario"
            >
              <Trash2 className="w-4 h-4 text-[var(--error)]" />
            </Button>
          </div>
        ),
      },
    ],
    []
  );

  const filteredData = useMemo(() => {
    if (!searchQuery) return users;
    const query = searchQuery.toLowerCase();
    return users.filter(
      (u) =>
        u.username.toLowerCase().includes(query) ||
        u.email.toLowerCase().includes(query) ||
        (u.displayName && u.displayName.toLowerCase().includes(query))
    );
  }, [users, searchQuery]);

  const table = useReactTable({
    data: filteredData,
    columns,
    getCoreRowModel: getCoreRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    initialState: { pagination: { pageSize: 10 } },
  });

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-[var(--text-primary)] flex items-center gap-2">
            <Users className="w-6 h-6 text-[var(--primary)]" />
            {t('admin.users')}
          </h1>
          <p className="text-[var(--text-muted)]">{t('admin.managePlatformUsers')}</p>
        </div>
      </div>

      {/* Search */}
      <Card>
        <CardContent className="p-4">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-[var(--text-secondary)]" />
            <Input
              placeholder={t('admin.searchUsers')}
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10"
              aria-label={t('admin.searchUsers')}
            />
          </div>
        </CardContent>
      </Card>

      {/* Users Table */}
      <Card>
        <CardHeader>
          <CardTitle>
            {t('admin.allUsers')} <span className="text-[var(--text-tertiary)] font-normal">({users.length})</span>
          </CardTitle>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <div className="flex items-center justify-center py-12" role="status">
              <Loader2 className="w-8 h-8 text-[var(--primary)] animate-spin" />
            </div>
          ) : error ? (
            <div className="text-center py-8 text-[var(--error)]">
              {t('admin.failedToLoad')}
            </div>
          ) : (
            <>
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead>
                    {table.getHeaderGroups().map((headerGroup) => (
                      <tr key={headerGroup.id} className="border-b">
                        {headerGroup.headers.map((header) => (
                          <th
                            key={header.id}
                            className="px-4 py-3 text-left text-sm font-medium text-[var(--text-tertiary)] cursor-pointer hover:text-[var(--text-secondary)]"
                            onClick={header.column.getToggleSortingHandler()}
                          >
                            {flexRender(
                              header.column.columnDef.header,
                              header.getContext()
                            )}
                          </th>
                        ))}
                      </tr>
                    ))}
                  </thead>
                  <tbody>
                    {table.getRowModel().rows.map((row) => (
                      <tr key={row.id} className="border-b hover:bg-[var(--surface)]">
                        {row.getVisibleCells().map((cell) => (
                          <td key={cell.id} className="px-4 py-3">
                            {flexRender(
                              cell.column.columnDef.cell,
                              cell.getContext()
                            )}
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>

              {/* Pagination */}
              <div className="flex items-center justify-between mt-4 pt-4 border-t">
                <div className="text-sm text-[var(--text-tertiary)]">
                  {t('admin.page')} {table.getState().pagination.pageIndex + 1} {t('admin.of')}{' '}
                  {table.getPageCount()}
                </div>
                <div className="flex items-center gap-2">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => table.previousPage()}
                    disabled={!table.getCanPreviousPage()}
                  >
                    {t('common.previous')}
                  </Button>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => table.nextPage()}
                    disabled={!table.getCanNextPage()}
                  >
                    {t('common.next')}
                  </Button>
                </div>
              </div>
            </>
          )}
        </CardContent>
      </Card>

      {/* User Profile Dialog */}
      <Dialog open={showUserDialog} onOpenChange={setShowUserDialog}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <User className="w-5 h-5" />
              {t('admin.userProfile')}
            </DialogTitle>
          </DialogHeader>
          {selectedUser && (
            <div className="space-y-6">
              {/* Header */}
              <div className="flex items-center gap-4">
                <div className="w-16 h-16 rounded-full bg-[var(--surface-sunken)] flex items-center justify-center overflow-hidden">
                  {selectedUser.avatarUrl ? (
                    <OptimizedImage
                      src={selectedUser.avatarUrl}
                      alt={selectedUser.username}
                      width={64}
                      height={64}
                      className="rounded-full"
                      objectFit="cover"
                    />
                  ) : (
                    <User className="w-8 h-8 text-[var(--text-tertiary)]" />
                  )}
                </div>
                <div>
                  <h3 className="text-lg font-semibold text-[var(--text-primary)]">
                    {selectedUser.displayName || selectedUser.username}
                  </h3>
                  <p className="text-sm text-[var(--text-tertiary)]">@{selectedUser.username}</p>
                  <div className="flex items-center gap-2 mt-1">
                    <Badge
                      variant={selectedUser.role === 'ADMIN' ? 'destructive' : 'default'}
                    >
                      {selectedUser.role}
                    </Badge>
                    <Badge variant="outline">Level {selectedUser.level}</Badge>
                  </div>
                </div>
              </div>

              {/* Stats Grid */}
              <div className="grid grid-cols-3 gap-4">
                <div className="bg-[var(--surface)] p-4 rounded-lg text-center">
                  <p className="text-2xl font-bold text-[var(--text-primary)]">
                    {selectedUser.xpPoints.toLocaleString()}
                  </p>
                  <p className="text-sm text-[var(--text-tertiary)]">{t('admin.xpPoints')}</p>
                </div>
                <div className="bg-[var(--surface)] p-4 rounded-lg text-center">
                  <p className="text-2xl font-bold text-[var(--text-primary)]">
                    {selectedUser.inkcoinsBalance.toLocaleString()}
                  </p>
                  <p className="text-sm text-[var(--text-tertiary)]">{t('admin.inkCoins')}</p>
                </div>
                <div className="bg-[var(--surface)] p-4 rounded-lg text-center">
                  <p className="text-2xl font-bold text-[var(--text-primary)]">
                    {selectedUser.readingStreak}
                  </p>
                  <p className="text-sm text-[var(--text-tertiary)]">{t('admin.readingStreak')}</p>
                </div>
              </div>

              {/* Details */}
              <div className="space-y-3">
                <div className="flex justify-between py-2 border-b">
                  <span className="text-[var(--text-tertiary)]">Email</span>
                  <span className="text-[var(--text-primary)]">{selectedUser.email}</span>
                </div>
                <div className="flex justify-between py-2 border-b">
                  <span className="text-[var(--text-tertiary)]">{t('admin.joined')}</span>
                  <span className="text-[var(--text-primary)]">
                    {new Date(selectedUser.createdAt).toLocaleDateString()}
                  </span>
                </div>
                <div className="flex justify-between py-2 border-b">
                  <span className="text-[var(--text-tertiary)]">{t('admin.mangasCreated')}</span>
                  <span className="text-[var(--text-primary)]">{selectedUser.mangaCount}</span>
                </div>
                <div className="flex justify-between py-2 border-b">
                  <span className="text-[var(--text-tertiary)]">{t('admin.chaptersUploaded')}</span>
                  <span className="text-[var(--text-primary)]">{selectedUser.chapterCount}</span>
                </div>
                <div className="flex justify-between py-2 border-b">
                  <span className="text-[var(--text-tertiary)]">{t('admin.commentsPosted')}</span>
                  <span className="text-[var(--text-primary)]">{selectedUser.commentCount}</span>
                </div>
              </div>

              <DialogFooter>
                <Button variant="outline" onClick={() => setShowUserDialog(false)}>
                  {t('admin.close')}
                </Button>
                <Link href={`/admin/users/${selectedUser.id}`}>
                  <Button>{t('admin.editUser')}</Button>
                </Link>
              </DialogFooter>
            </div>
          )}
        </DialogContent>
      </Dialog>

      {/* Action Dialog */}
      <Dialog open={showActionDialog} onOpenChange={setShowActionDialog}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>
              {actionType === 'ban' && t('admin.banUser')}
              {actionType === 'unban' && t('admin.unbanUser')}
              {actionType === 'delete' && t('admin.deleteUser')}
            </DialogTitle>
            <DialogDescription>
              {actionType === 'ban' && t('admin.banUserDesc')}
              {actionType === 'unban' && t('admin.unbanUserDesc')}
              {actionType === 'delete' && t('admin.deleteUserDesc')}
            </DialogDescription>
          </DialogHeader>
          {selectedUser && (
            <div className="bg-[var(--surface)] p-4 rounded-lg my-4">
              <p className="text-sm font-medium text-[var(--text-secondary)]">User:</p>
              <p className="text-sm text-[var(--text-primary)] mt-1">
                {selectedUser.displayName || selectedUser.username} (@{selectedUser.username})
              </p>
              <p className="text-xs text-[var(--text-tertiary)] mt-1">{selectedUser.email}</p>
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowActionDialog(false)} disabled={isActioning}>
              {t('admin.cancel')}
            </Button>
            <Button
              variant={actionType === 'delete' ? 'destructive' : 'default'}
              onClick={handleAction}
              disabled={isActioning}
            >
              {isActioning && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
              {actionType === 'ban' && (
                <>
                  <Ban className="w-4 h-4 mr-2" />
                  {t('admin.banUser')}
                </>
              )}
              {actionType === 'unban' && (
                <>
                  <Check className="w-4 h-4 mr-2" />
                  {t('admin.unbanUser')}
                </>
              )}
              {actionType === 'delete' && (
                <>
                  <Trash2 className="w-4 h-4 mr-2" />
                  {t('admin.deleteUser')}
                </>
              )}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

'use client';

import {
  Webhook,
  Plus,
  Trash2,
  Edit,
  TestTube,
  RefreshCw,
  Loader2,
  CheckCircle,
  XCircle,
  AlertTriangle,
  Clock,
  EyeOff,
} from 'lucide-react';
import { useState } from 'react';
import useSWR, { mutate } from 'swr';

import { Badge } from '@/components/ui/Badge';
import { Button } from '@/components/ui/Button';
import { Card, CardContent } from '@/components/ui/Card';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from '@/components/ui/Dialog';
import { Input } from '@/components/ui/Input';
import { Label } from '@/components/ui/Label';
import { Switch } from '@/components/ui/Switch';

interface WebhookEndpoint {
  id: string;
  userId: string;
  url: string;
  secret: string;
  events: string[];
  isActive: boolean;
  description: string | null;
  lastTriggeredAt: string | null;
  failureCount: number;
  createdAt: string;
  updatedAt: string;
  recentDeliveries?: WebhookDelivery[];
}

interface WebhookDelivery {
  id: string;
  endpointId: string;
  event: string;
  payload: string;
  status: string;
  statusCode: number | null;
  responseBody: string | null;
  durationMs: number | null;
  attemptCount: number;
  error: string | null;
  createdAt: string;
}

const AVAILABLE_EVENTS = [
  'CHAPTER_PUBLISHED',
  'MANGA_CREATED',
  'MANGA_UPDATED',
  'COMMENT_POSTED',
  'USER_REGISTERED',
  'ACHIEVEMENT_UNLOCKED',
  'NEW_CHAPTER',
  'CROWDFUNDING_GOAL_REACHED',
  'SPONSORSHIP_BID_SUBMITTED',
];

const fetcher = (url: string) => fetch(url).then((res) => res.json());

function DeliveryStatusBadge({ status }: { status: string }) {
  const config: Record<string, { variant: 'success' | 'destructive' | 'warning' | 'default'; icon: React.ElementType }> = {
    SUCCESS: { variant: 'success', icon: CheckCircle },
    FAILED: { variant: 'destructive', icon: XCircle },
    PENDING: { variant: 'warning', icon: Clock },
  };

  const c = config[status] || { variant: 'default' as const, icon: Clock };
  const Icon = c.icon;

  return (
    <Badge variant={c.variant} className="flex items-center gap-1">
      <Icon className="w-3 h-3" />
      {status}
    </Badge>
  );
}

export function WebhooksClient() {
  const { data, error, isLoading } = useSWR<{ endpoints: WebhookEndpoint[] }>(
    '/api/admin/webhooks',
    fetcher,
    { refreshInterval: 30000 }
  );

  const [showCreate, setShowCreate] = useState(false);
  const [showEdit, setShowEdit] = useState<WebhookEndpoint | null>(null);
  const [showDelete, setShowDelete] = useState<WebhookEndpoint | null>(null);
  const [showDeliveries, setShowDeliveries] = useState<WebhookEndpoint | null>(null);
  const [testingId, setTestingId] = useState<string | null>(null);
  const [redeliveringId, setRedeliveringId] = useState<string | null>(null);

  const [formUrl, setFormUrl] = useState('');
  const [formSecret, setFormSecret] = useState('');
  const [formDescription, setFormDescription] = useState('');
  const [formEvents, setFormEvents] = useState<string[]>([]);
  const [formActive, setFormActive] = useState(true);
  const [saving, setSaving] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const resetForm = () => {
    setFormUrl('');
    setFormSecret('');
    setFormDescription('');
    setFormEvents([]);
    setFormActive(true);
    setErrorMsg(null);
  };

  const handleCreate = async () => {
    if (!formUrl || formEvents.length === 0) {
      setErrorMsg('URL y al menos un evento son requeridos');
      return;
    }

    setSaving(true);
    setErrorMsg(null);

    try {
      const res = await fetch('/api/admin/webhooks', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          url: formUrl,
          secret: formSecret || undefined,
          events: formEvents,
          description: formDescription || undefined,
        }),
      });

      if (!res.ok) {
        const err = await res.json();
        throw new Error(err.error || 'Error al crear webhook');
      }

      resetForm();
      setShowCreate(false);
      mutate('/api/admin/webhooks');
    } catch (err: any) {
      setErrorMsg(err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleEdit = async () => {
    if (!showEdit) return;
    if (!formUrl || formEvents.length === 0) {
      setErrorMsg('URL y al menos un evento son requeridos');
      return;
    }

    setSaving(true);
    setErrorMsg(null);

    try {
      const body: Record<string, unknown> = {
        url: formUrl,
        events: formEvents,
        isActive: formActive,
      };
      if (formDescription !== undefined) body.description = formDescription;
      if (formSecret) body.secret = formSecret;

      const res = await fetch(`/api/admin/webhooks/${showEdit.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });

      if (!res.ok) {
        const err = await res.json();
        throw new Error(err.error || 'Error al actualizar webhook');
      }

      setShowEdit(null);
      resetForm();
      mutate('/api/admin/webhooks');
    } catch (err: any) {
      setErrorMsg(err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async () => {
    if (!showDelete) return;

    try {
      const res = await fetch(`/api/admin/webhooks/${showDelete.id}`, {
        method: 'DELETE',
      });

      if (!res.ok) {
        const err = await res.json();
        throw new Error(err.error || 'Error al eliminar webhook');
      }

      setShowDelete(null);
      mutate('/api/admin/webhooks');
    } catch (err: any) {
      setErrorMsg(err.message);
    }
  };

  const handleTest = async (endpoint: WebhookEndpoint) => {
    setTestingId(endpoint.id);
    try {
      await fetch(`/api/admin/webhooks/${endpoint.id}/test`, {
        method: 'POST',
      });
      mutate('/api/admin/webhooks');
    } catch {
      // error handled by SWR revalidation
    } finally {
      setTestingId(null);
    }
  };

  const handleRedeliver = async (deliveryId: string) => {
    setRedeliveringId(deliveryId);
    try {
      await fetch('/api/webhooks/outgoing/deliver', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ deliveryId }),
      });
    } catch {
      // ignore
    } finally {
      setRedeliveringId(null);
    }
  };

  const openEdit = (endpoint: WebhookEndpoint) => {
    setFormUrl(endpoint.url);
    setFormSecret('');
    setFormDescription(endpoint.description || '');
    setFormEvents(endpoint.events);
    setFormActive(endpoint.isActive);
    setErrorMsg(null);
    setShowEdit(endpoint);
  };

  const toggleEvent = (event: string) => {
    setFormEvents((prev) =>
      prev.includes(event) ? prev.filter((e) => e !== event) : [...prev, event]
    );
  };

  if (isLoading) {
    return (
      <div className="animate-pulse space-y-6">
        <div className="h-8 bg-[var(--surface-sunken)] rounded w-1/4" />
        {[...Array(3)].map((_, i) => (
          <div key={i} className="h-32 bg-[var(--surface-sunken)] rounded-xl" />
        ))}
      </div>
    );
  }

  if (error) {
    return (
      <div className="text-center py-12">
        <AlertTriangle className="w-12 h-12 mx-auto mb-4 text-[var(--error)]" />
        <h2 className="text-xl font-semibold text-[var(--text-primary)]">Error al cargar webhooks</h2>
        <Button onClick={() => mutate('/api/admin/webhooks')} className="mt-4">
          Reintentar
        </Button>
      </div>
    );
  }

  const endpoints = data?.endpoints || [];

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-[var(--text-primary)] flex items-center gap-2">
            <Webhook className="w-6 h-6 text-[var(--primary)]" />
            Webhooks
          </h1>
          <p className="text-[var(--text-secondary)] mt-1">
            Gestiona los webhooks salientes para integraciones externas.
          </p>
        </div>
        <Button onClick={() => { resetForm(); setShowCreate(true); }}>
          <Plus className="w-4 h-4 mr-2" />
          Nuevo Webhook
        </Button>
      </div>

      {endpoints.length === 0 ? (
        <Card>
          <CardContent className="py-12 text-center">
            <Webhook className="w-12 h-12 mx-auto mb-4 text-[var(--text-tertiary)]" />
            <h3 className="text-lg font-medium text-[var(--text-primary)] mb-2">No hay webhooks</h3>
            <p className="text-[var(--text-secondary)] mb-4">
              Crea tu primer webhook para empezar a recibir eventos.
            </p>
            <Button onClick={() => { resetForm(); setShowCreate(true); }}>
              <Plus className="w-4 h-4 mr-2" />
              Crear Webhook
            </Button>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-4">
          {endpoints.map((endpoint) => (
            <Card key={endpoint.id}>
              <CardContent className="p-6">
                <div className="flex items-start justify-between">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-3 mb-2">
                      <div className={`w-3 h-3 rounded-full ${endpoint.isActive ? 'bg-[var(--success)]' : 'bg-[var(--text-tertiary)]'}`} />
                      <h3 className="font-medium text-[var(--text-primary)] truncate">
                        {endpoint.description || endpoint.url}
                      </h3>
                      <Badge variant={endpoint.isActive ? 'success' : 'secondary'}>
                        {endpoint.isActive ? 'Activo' : 'Inactivo'}
                      </Badge>
                    </div>
                    <p className="text-sm text-[var(--text-tertiary)] truncate mb-2">{endpoint.url}</p>
                    <div className="flex flex-wrap gap-1.5 mb-3">
                      {endpoint.events.map((event) => (
                        <Badge key={event} variant="secondary" className="text-xs">
                          {event}
                        </Badge>
                      ))}
                    </div>
                    <div className="flex items-center gap-4 text-xs text-[var(--text-tertiary)]">
                      <span>Fallos: {endpoint.failureCount}</span>
                      {endpoint.lastTriggeredAt && (
                        <span>Último: {new Date(endpoint.lastTriggeredAt).toLocaleString()}</span>
                      )}
                      <span>Creado: {new Date(endpoint.createdAt).toLocaleDateString()}</span>
                    </div>
                  </div>
                  <div className="flex items-center gap-2 ml-4">
                    <Button
                      variant="ghost"
                      size="icon"
                      onClick={() => handleTest(endpoint)}
                      disabled={testingId === endpoint.id}
                      title="Probar webhook"
                    >
                      {testingId === endpoint.id ? (
                        <Loader2 className="w-4 h-4 animate-spin" />
                      ) : (
                        <TestTube className="w-4 h-4 text-[var(--primary)]" />
                      )}
                    </Button>
                    <Button
                      variant="ghost"
                      size="icon"
                      onClick={() => setShowDeliveries(endpoint)}
                      title="Ver entregas"
                    >
                      <Clock className="w-4 h-4 text-[var(--warning)]" />
                    </Button>
                    <Button
                      variant="ghost"
                      size="icon"
                      onClick={() => openEdit(endpoint)}
                      title="Editar"
                    >
                      <Edit className="w-4 h-4 text-[var(--primary)]" />
                    </Button>
                    <Button
                      variant="ghost"
                      size="icon"
                      onClick={() => setShowDelete(endpoint)}
                      title="Eliminar"
                    >
                      <Trash2 className="w-4 h-4 text-[var(--error)]" />
                    </Button>
                  </div>
                </div>

                {showDeliveries?.id === endpoint.id && (
                  <div className="mt-4 pt-4 border-t border-[var(--border)]">
                    <div className="flex items-center justify-between mb-3">
                      <h4 className="text-sm font-medium text-[var(--text-primary)]">
                        Entregas Recientes
                      </h4>
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => setShowDeliveries(null)}
                      >
                        <EyeOff className="w-4 h-4 mr-1" />
                        Ocultar
                      </Button>
                    </div>
                    {endpoint.recentDeliveries && endpoint.recentDeliveries.length > 0 ? (
                      <div className="space-y-2">
                        {endpoint.recentDeliveries.map((delivery) => (
                          <div
                            key={delivery.id}
                            className="flex items-center justify-between p-3 bg-[var(--surface-sunken)] rounded-lg"
                          >
                            <div className="flex items-center gap-3">
                              <DeliveryStatusBadge status={delivery.status} />
                              <span className="text-sm text-[var(--text-primary)]">{delivery.event}</span>
                              <span className="text-xs text-[var(--text-tertiary)]">
                                {new Date(delivery.createdAt).toLocaleString()}
                              </span>
                              {delivery.statusCode && (
                                <span className="text-xs text-[var(--text-tertiary)]">
                                  HTTP {delivery.statusCode}
                                </span>
                              )}
                              {delivery.durationMs !== null && (
                                <span className="text-xs text-[var(--text-tertiary)]">
                                  {delivery.durationMs}ms
                                </span>
                              )}
                            </div>
                            {delivery.status === 'FAILED' && (
                              <Button
                                variant="ghost"
                                size="sm"
                                onClick={() => handleRedeliver(delivery.id)}
                                disabled={redeliveringId === delivery.id}
                              >
                                {redeliveringId === delivery.id ? (
                                  <Loader2 className="w-3 h-3 animate-spin" />
                                ) : (
                                  <RefreshCw className="w-3 h-3" />
                                )}
                                Reintentar
                              </Button>
                            )}
                          </div>
                        ))}
                      </div>
                    ) : (
                      <p className="text-sm text-[var(--text-tertiary)]">Sin entregas recientes</p>
                    )}
                  </div>
                )}
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Create Dialog */}
      <Dialog open={showCreate} onOpenChange={setShowCreate}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Plus className="w-5 h-5" />
              Nuevo Webhook
            </DialogTitle>
            <DialogDescription>
              Configura un nuevo endpoint para recibir eventos de InkVerse.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <div>
              <Label htmlFor="webhook-url">URL del Webhook</Label>
              <Input
                id="webhook-url"
                placeholder="https://ejemplo.com/webhook"
                value={formUrl}
                onChange={(e) => setFormUrl(e.target.value)}
                className="mt-1"
              />
            </div>
            <div>
              <Label htmlFor="webhook-secret">Secreto (HMAC)</Label>
              <Input
                id="webhook-secret"
                placeholder="Dejar vacío para auto-generar"
                value={formSecret}
                onChange={(e) => setFormSecret(e.target.value)}
                className="mt-1"
              />
            </div>
            <div>
              <Label htmlFor="webhook-desc">Descripción</Label>
              <Input
                id="webhook-desc"
                placeholder="Opcional"
                value={formDescription}
                onChange={(e) => setFormDescription(e.target.value)}
                className="mt-1"
              />
            </div>
            <div>
              <Label>Eventos</Label>
              <div className="grid grid-cols-2 gap-2 mt-2">
                {AVAILABLE_EVENTS.map((event) => (
                  <label
                    key={event}
                    className={`flex items-center gap-2 p-2 rounded-lg border cursor-pointer transition-colors ${
                      formEvents.includes(event)
                        ? 'border-[var(--primary)] bg-[var(--primary)]/10'
                        : 'border-[var(--border)] hover:bg-[var(--surface-sunken)]'
                    }`}
                  >
                    <input
                      type="checkbox"
                      checked={formEvents.includes(event)}
                      onChange={() => toggleEvent(event)}
                      className="sr-only"
                    />
                    <div
                      className={`w-4 h-4 rounded border-2 flex items-center justify-center ${
                        formEvents.includes(event)
                          ? 'border-[var(--primary)] bg-[var(--primary)]'
                          : 'border-[var(--border)]'
                      }`}
                    >
                      {formEvents.includes(event) && (
                        <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                        </svg>
                      )}
                    </div>
                    <span className="text-sm text-[var(--text-primary)]">{event}</span>
                  </label>
                ))}
              </div>
            </div>
            {errorMsg && (
              <div className="flex items-center gap-2 p-3 bg-[var(--error)]/10 border border-[var(--error)]/20 rounded-lg text-sm text-[var(--error)]">
                <AlertTriangle className="w-4 h-4" />
                {errorMsg}
              </div>
            )}
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowCreate(false)}>
              Cancelar
            </Button>
            <Button onClick={handleCreate} disabled={saving}>
              {saving && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
              Crear Webhook
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Edit Dialog */}
      <Dialog open={!!showEdit} onOpenChange={(open) => { if (!open) setShowEdit(null); }}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Edit className="w-5 h-5" />
              Editar Webhook
            </DialogTitle>
            <DialogDescription>
              Actualiza la configuración del webhook.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <div>
              <Label htmlFor="edit-url">URL del Webhook</Label>
              <Input
                id="edit-url"
                value={formUrl}
                onChange={(e) => setFormUrl(e.target.value)}
                className="mt-1"
              />
            </div>
            <div>
              <Label htmlFor="edit-secret">Nuevo Secreto (dejar vacío para mantener)</Label>
              <Input
                id="edit-secret"
                placeholder="Dejar vacío para mantener el actual"
                value={formSecret}
                onChange={(e) => setFormSecret(e.target.value)}
                className="mt-1"
              />
            </div>
            <div>
              <Label htmlFor="edit-desc">Descripción</Label>
              <Input
                id="edit-desc"
                value={formDescription}
                onChange={(e) => setFormDescription(e.target.value)}
                className="mt-1"
              />
            </div>
            <div className="flex items-center justify-between p-3 bg-[var(--surface-sunken)] rounded-lg">
              <div>
                <p className="text-sm font-medium text-[var(--text-primary)]">Activo</p>
                <p className="text-xs text-[var(--text-tertiary)]">Habilitar o deshabilitar este webhook</p>
              </div>
              <Switch checked={formActive} onCheckedChange={setFormActive} />
            </div>
            <div>
              <Label>Eventos</Label>
              <div className="grid grid-cols-2 gap-2 mt-2">
                {AVAILABLE_EVENTS.map((event) => (
                  <label
                    key={event}
                    className={`flex items-center gap-2 p-2 rounded-lg border cursor-pointer transition-colors ${
                      formEvents.includes(event)
                        ? 'border-[var(--primary)] bg-[var(--primary)]/10'
                        : 'border-[var(--border)] hover:bg-[var(--surface-sunken)]'
                    }`}
                  >
                    <input
                      type="checkbox"
                      checked={formEvents.includes(event)}
                      onChange={() => toggleEvent(event)}
                      className="sr-only"
                    />
                    <div
                      className={`w-4 h-4 rounded border-2 flex items-center justify-center ${
                        formEvents.includes(event)
                          ? 'border-[var(--primary)] bg-[var(--primary)]'
                          : 'border-[var(--border)]'
                      }`}
                    >
                      {formEvents.includes(event) && (
                        <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                        </svg>
                      )}
                    </div>
                    <span className="text-sm text-[var(--text-primary)]">{event}</span>
                  </label>
                ))}
              </div>
            </div>
            {errorMsg && (
              <div className="flex items-center gap-2 p-3 bg-[var(--error)]/10 border border-[var(--error)]/20 rounded-lg text-sm text-[var(--error)]">
                <AlertTriangle className="w-4 h-4" />
                {errorMsg}
              </div>
            )}
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowEdit(null)}>
              Cancelar
            </Button>
            <Button onClick={handleEdit} disabled={saving}>
              {saving && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
              Guardar Cambios
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation */}
      <Dialog open={!!showDelete} onOpenChange={(open) => { if (!open) setShowDelete(null); }}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Trash2 className="w-5 h-5 text-[var(--error)]" />
              Eliminar Webhook
            </DialogTitle>
            <DialogDescription>
              Esta acción no se puede deshacer. Se eliminarán todas las entregas asociadas.
            </DialogDescription>
          </DialogHeader>
          {showDelete && (
            <div className="bg-[var(--surface-sunken)] p-4 rounded-lg my-4">
              <p className="text-sm font-medium text-[var(--text-primary)]">
                {showDelete.description || showDelete.url}
              </p>
              <p className="text-xs text-[var(--text-tertiary)] mt-1">{showDelete.url}</p>
            </div>
          )}
          {errorMsg && (
            <div className="flex items-center gap-2 p-3 bg-[var(--error)]/10 border border-[var(--error)]/20 rounded-lg text-sm text-[var(--error)]">
              <AlertTriangle className="w-4 h-4" />
              {errorMsg}
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowDelete(null)}>
              Cancelar
            </Button>
            <Button variant="destructive" onClick={handleDelete}>
              <Trash2 className="w-4 h-4 mr-2" />
              Eliminar
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

