'use client';

import { Shield, Target, Award, AlertTriangle, BookOpen, BarChart, Users, TrendingUp } from 'lucide-react';
import Link from 'next/link';
import { useSession } from 'next-auth/react';
import { useState, useEffect, useCallback, useMemo } from 'react';

import { AnalyticsDashboard } from '@/components/Analytics/AnalyticsDashboard';
import { DateRangePicker, type DateRangePreset, type DateRange } from '@/components/Analytics/DateRangePicker';
import { ExportAnalyticsButton } from '@/components/Analytics/ExportAnalyticsButton';
import { MangaSelector, type MangaOption } from '@/components/Analytics/MangaSelector';
import { OptimizedImage } from '@/components/Image/OptimizedImage';
import { useT } from '@/i18n';

interface CreatorData {
  views: number;
  reads: number;
  completions: number;
  completionRate: number;
  avgTimeSpent: number;
  avgScrollDepth?: number;
  popularChapters: Array<{
    chapterId: string;
    chapterNumber: number;
    title: string;
    views: number;
    reads?: number;
    completionRate?: number;
    mangaTitle: string;
  }>;
  dailyStats: Array<{
    date: string;
    views: number;
    reads: number;
  }>;
}

interface ReaderData {
  user: {
    username: string;
    displayName: string | null;
    avatarUrl: string | null;
    level: number;
    xpPoints: number;
    inkcoinsBalance: number;
  };
  stats: {
    totalChaptersRead: number;
    totalMangaInLibrary: number;
    totalAchievements: number;
    nextLevelXp: number;
  };
  achievements: Array<{
    id: string;
    unlockedAt: string;
    name: string;
    description: string;
    icon: string | null;
  }>;
  clan: {
    name: string;
    totalScore: number;
    monthlyScore: number;
    role: string;
    contributedScore: number;
    rank: number;
  } | null;
}

function getDefaultDateRange(): DateRange {
  const to = new Date();
  to.setHours(23, 59, 59, 999);
  const from = new Date();
  from.setDate(from.getDate() - 30);
  from.setHours(0, 0, 0, 0);
  return { from, to };
}

export default function AnalyticsPage() {
  const { data: session } = useSession();
  const t = useT();
  const [activeTab, setActiveTab] = useState<'creator' | 'reader'>('creator');

  const [creatorData, setCreatorData] = useState<CreatorData | null>(null);
  const [readerData, setReaderData] = useState<ReaderData | null>(null);

  const [dateRange, setDateRange] = useState<DateRange>(getDefaultDateRange());
  const [datePreset, setDatePreset] = useState<DateRangePreset>('30d');
  const [selectedMangaId, setSelectedMangaId] = useState<string | null>(null);
  const [creatorMangas, setCreatorMangas] = useState<MangaOption[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const fetchCreatorData = useCallback(async () => {
    try {
      const params = new URLSearchParams();
      if (selectedMangaId) params.append('mangaId', selectedMangaId);
      params.append('from', dateRange.from.toISOString());
      params.append('to', dateRange.to.toISOString());
      const res = await fetch(`/api/analytics/dashboard?${params.toString()}`);
      if (!res.ok) throw new Error('Failed to fetch creator analytics');
      const data = await res.json();
      setCreatorData(data);
    } catch (err) {
      console.error('Error fetching creator analytics:', err);
    }
  }, [selectedMangaId, dateRange]);

  const fetchCreatorMangas = useCallback(async () => {
    try {
      const res = await fetch('/api/creator/mangas');
      if (res.ok) {
        const data = await res.json();
        setCreatorMangas(data.mangas || data || []);
      }
    } catch {         
        setError(t('analytics.errorLoadingMangas'));
    }
  }, []);

  const fetchReaderData = useCallback(async () => {
    try {
      const res = await fetch('/api/me');
      if (!res.ok) throw new Error('Failed to fetch reader data');
      const data = await res.json();
      setReaderData(data);
    } catch (err) {
      console.error('Error fetching reader data:', err);
    }
  }, []);

  // Data fetching effect - setState is necessary for async SWR data loading
  const shouldFetch = session?.user?.id;

  /* eslint-disable react-hooks/set-state-in-effect */
  useEffect(() => {
    if (!shouldFetch) {
      return;
    }
    setIsLoading(true);
    setError(null);
    Promise.all([fetchCreatorMangas(), fetchCreatorData(), fetchReaderData()])
      .catch(() => {
        setError(t('analytics.errorLoading'));
      })
      .finally(() => setIsLoading(false));
  }, [shouldFetch, fetchCreatorMangas, fetchCreatorData, fetchReaderData]);
  /* eslint-enable react-hooks/set-state-in-effect */

  const xpForNextLevel = readerData?.stats.nextLevelXp || 2000;
  const currentXp = readerData?.user.xpPoints || 0;
  const prevLevelXp = xpForNextLevel - 500;
  const levelProgress = Math.min(((currentXp - prevLevelXp) / (xpForNextLevel - prevLevelXp)) * 100, 100);

  const analyticsDataForComponent = useMemo(() => {
    if (!creatorData) return undefined;
    const apiReads = creatorData.reads || 0;
    const apiCompletions = creatorData.completions || 0;
    return {
      views: creatorData.views,
      reads: apiReads,
      completions: apiCompletions,
      avgTimeSpent: creatorData.avgTimeSpent,
      avgScrollDepth: creatorData.avgScrollDepth ?? 0,
      popularChapters: creatorData.popularChapters.map(ch => ({
        chapterId: ch.chapterId,
        chapterNumber: ch.chapterNumber,
        views: ch.views,
        title: ch.title,
        reads: ch.reads ?? Math.round(ch.views * (apiReads && creatorData.views ? apiReads / creatorData.views : 0.6)),
        completionRate: ch.completionRate ?? (apiReads > 0 ? Math.round((apiCompletions / apiReads) * 100) : 0),
      })),
      dailyStats: creatorData.dailyStats,
    };
  }, [creatorData]);

  return (
    <div className="max-w-7xl mx-auto space-y-8 p-6">

        <header className="flex flex-col md:flex-row justify-between items-center gap-4 mt-2 border-b border-custom pb-6">
          <div className="flex items-center gap-4 w-full md:w-auto">
            <BarChart size={28} className="text-accent-blue" aria-hidden="true" />
            <h1 className="text-3xl font-extrabold tracking-tight">{t('analytics.title')}</h1>
          </div>

          <div className="flex items-center gap-4">
            <div role="tablist" aria-label="Tipo de analíticas" className="flex bg-tertiary rounded-lg p-1">
              <button
                role="tab"
                aria-selected={activeTab === 'creator'}
                aria-controls="analytics-creator-panel"
                tabIndex={activeTab === 'creator' ? 0 : -1}
                onClick={() => setActiveTab('creator')}
                className={`px-4 py-2 rounded-md text-sm font-bold transition-all ${activeTab === 'creator' ? 'bg-secondary shadow-sm text-accent-blue' : 'text-muted hover:text-fg-primary'}`}
              >
                {t('analytics.creatorStudio')}
              </button>
              <button
                role="tab"
                aria-selected={activeTab === 'reader'}
                aria-controls="analytics-reader-panel"
                tabIndex={activeTab === 'reader' ? 0 : -1}
                onClick={() => setActiveTab('reader')}
                className={`px-4 py-2 rounded-md text-sm font-bold transition-all ${activeTab === 'reader' ? 'bg-secondary shadow-sm text-accent-orange' : 'text-muted hover:text-fg-primary'}`}
              >
                {t('analytics.readerProfile')}
              </button>
            </div>
            <ExportAnalyticsButton activeTab={activeTab} />
          </div>
        </header>

        {isLoading && (
          <div className="space-y-6" role="status" aria-label="Cargando analíticas">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
              {[...Array(4)].map((_, i) => (
                <div key={i} className="card p-5 rounded-xl">
                  <div className="h-4 bg-tertiary rounded w-24 mb-3 animate-pulse" />
                  <div className="h-7 bg-tertiary rounded w-16 animate-pulse" />
                </div>
              ))}
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              <div className="h-80 bg-tertiary rounded-xl animate-pulse" />
              <div className="h-80 bg-tertiary rounded-xl animate-pulse" />
            </div>
          </div>
        )}

        {error && (
          <div className="card p-8 rounded-xl text-center" role="alert">
            <AlertTriangle size={32} className="text-accent-red mx-auto mb-3" aria-hidden="true" />
            <p className="text-muted mb-4">{error}</p>
            <button onClick={() => window.location.reload()} className="px-6 py-2 bg-accent-blue text-[var(--text-inverse)] rounded-lg hover:opacity-90 transition-opacity font-bold text-sm">
              {t('analytics.retry')}
            </button>
          </div>
        )}

        {!isLoading && !session?.user?.id && (
          <div className="card p-16 rounded-xl text-center">
            <BarChart size={40} className="text-muted mx-auto mb-4" />
            <p className="text-muted text-lg">{t('analytics.loginToView')}</p>
          </div>
        )}

        {activeTab === 'creator' && session?.user?.id && !isLoading && !error && (
          <div id="analytics-creator-panel" role="tabpanel" aria-labelledby="analytics-creator-tab" className="space-y-6 animate-fade-in-up">
            {creatorMangas.length > 0 && (
              <div className="flex flex-col sm:flex-row gap-4">
                <MangaSelector
                  mangas={creatorMangas}
                  selectedId={selectedMangaId}
                  onSelect={setSelectedMangaId}
                  allText={t('analytics.allManga')}
                  placeholder={t('analytics.selectManga')}
                  className="sm:w-72"
                />
                <DateRangePicker
                  value={dateRange}
                  preset={datePreset}
                  onChange={(range, preset) => {
                    setDateRange(range);
                    setDatePreset(preset);
                  }}
                />
              </div>
            )}

            <AnalyticsDashboard
              mangaId={selectedMangaId}
              dateRange={dateRange}
              customData={analyticsDataForComponent}
            />
          </div>
        )}

        {activeTab === 'reader' && session?.user?.id && !isLoading && !error && (
          <div id="analytics-reader-panel" role="tabpanel" aria-labelledby="analytics-reader-tab" className="space-y-6 animate-fade-in-up">
            {readerData ? (
              <>
                <div className="bg-gradient-to-r from-secondary to-tertiary p-8 rounded-2xl shadow-sm border border-custom flex flex-col md:flex-row items-center gap-8">
                  <div className="w-32 h-32 rounded-full border-4 border-accent-orange shadow-lg flex items-center justify-center bg-secondary relative overflow-hidden flex-shrink-0">
                    {readerData.user.avatarUrl ? (
                      <OptimizedImage src={readerData.user.avatarUrl} alt="Avatar" fill className="w-full h-full" />
                    ) : (
                      <OptimizedImage src={`https://ui-avatars.com/api/?name=${encodeURIComponent(readerData.user.displayName || readerData.user.username)}&size=128&background=random`} alt="Avatar" fill className="w-full h-full" />
                    )}
                    <div className="absolute bottom-0 w-full bg-black/60 text-[var(--text-inverse)] text-center text-xs font-bold py-1">{t('analytics.level')} {readerData.user.level}</div>
                  </div>
                  <div className="flex-1 space-y-4 w-full">
                    <div>
                      <h2 className="text-3xl font-bold flex items-center gap-2">
                        {readerData.user.displayName || readerData.user.username}
                        <Shield size={24} className="text-accent-purple" aria-hidden="true" />
                      </h2>
                      <p className="text-muted">
                        {readerData.clan ? `${t('analytics.memberOf')}: ${readerData.clan.name}` : t('analytics.noClanLabel')}
                        {' \u2022 '}InkCoins: {readerData.user.inkcoinsBalance.toLocaleString('es')}
                      </p>
                    </div>

                    <div className="space-y-1">
                      <div className="flex justify-between text-sm font-semibold">
                        <span>Nivel {readerData.user.level}</span>
                        <span>{currentXp.toLocaleString('es')} / {xpForNextLevel.toLocaleString('es')} XP</span>
                      </div>
                      <div className="w-full bg-secondary h-3 rounded-full border border-custom overflow-hidden" role="progressbar" aria-valuenow={Math.round(levelProgress)} aria-valuemin={0} aria-valuemax={100} aria-label={`Progreso de nivel: ${Math.round(levelProgress)}%`}>
                        <div className="bg-gradient-to-r from-accent-orange to-accent-red h-full transition-all" style={{ width: `${levelProgress}%` }}></div>
                      </div>
                    </div>

                    <div className="grid grid-cols-3 gap-4">
                      <div className="text-center">
                        <BookOpen size={20} className="text-accent-blue mx-auto mb-1" aria-hidden="true" />
                        <p className="text-lg font-bold">{readerData.stats.totalChaptersRead.toLocaleString('es')}</p>
                        <p className="text-xs text-muted">{t('analytics.chapters')}</p>
                      </div>
                      <div className="text-center">
                        <TrendingUp size={20} className="text-accent-green mx-auto mb-1" aria-hidden="true" />
                        <p className="text-lg font-bold">{readerData.stats.totalMangaInLibrary.toLocaleString('es')}</p>
                        <p className="text-xs text-muted">{t('analytics.inLibrary')}</p>
                      </div>
                      <div className="text-center">
                        <Award size={20} className="text-accent-orange mx-auto mb-1" aria-hidden="true" />
                        <p className="text-lg font-bold">{readerData.stats.totalAchievements.toLocaleString('es')}</p>
                        <p className="text-xs text-muted">{t('analytics.achievements')}</p>
                      </div>
                    </div>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="card p-6 rounded-xl">
                    <h3 className="font-bold text-lg mb-4 flex items-center gap-2"><Award size={20} className="text-accent-orange" aria-hidden="true" /> {t('analytics.unlockedAchievements')} ({readerData.stats.totalAchievements})</h3>
                    {readerData.achievements.length > 0 ? (
                      <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
                        {readerData.achievements.slice(0, 6).map((badge) => (
                          <div key={badge.id} className="flex flex-col items-center text-center p-3 bg-tertiary rounded-lg border border-custom hover:shadow-md transition-shadow cursor-pointer">
                            <div className="w-12 h-12 rounded-full mb-2 flex items-center justify-center font-bold text-xl bg-accent-orange/20 text-accent-orange">
                              {badge.icon || '\u2605'}
                            </div>
                            <span className="text-xs font-bold">{badge.name}</span>
                            <span className="text-[10px] text-muted">{badge.description}</span>
                          </div>
                        ))}
                      </div>
                    ) : (
                      <p className="text-muted text-sm">{t('analytics.noAchievements')}</p>
                    )}
                  </div>

                  <div className="card p-6 rounded-xl border-t-4 border-t-accent-purple" role="region" aria-label="Información del clan">
                    {readerData.clan ? (
                      <>
                        <h3 className="font-bold text-lg mb-4">{t('analytics.memberOf')}: {readerData.clan.name}</h3>
                        <div className="space-y-4">
                          <div className="flex justify-between items-center p-3 bg-tertiary rounded-lg">
                            <span className="font-semibold text-sm">{t('analytics.globalPosition')}</span>
                            <span className="text-xl font-black text-accent-purple">#{readerData.clan.rank}</span>
                          </div>
                          <div className="flex justify-between items-center p-3 bg-tertiary rounded-lg">
                            <span className="font-semibold text-sm">{t('analytics.monthlyContribution')}</span>
                            <span className="font-bold">{readerData.clan.contributedScore.toLocaleString('es')} XP</span>
                          </div>
                          <div className="flex justify-between items-center p-3 bg-tertiary rounded-lg">
                            <span className="font-semibold text-sm">{t('analytics.clanTotalScore')}</span>
                            <span className="font-bold">{readerData.clan.totalScore.toLocaleString('es')} XP</span>
                          </div>
                        </div>
                      </>
                    ) : (
                      <div className="text-center py-8">
                        <Users size={48} className="text-muted mx-auto mb-4" aria-hidden="true" />
                        <h3 className="font-bold text-lg mb-1">{t('analytics.noClan')}</h3>
                        <p className="text-muted text-sm mb-4">{t('analytics.joinClan')}</p>
                        <Link href="/community" className="px-4 py-2 bg-accent-purple text-[var(--text-inverse)] rounded-lg inline-block font-bold text-sm hover:bg-accent-purple/80 transition-colors">
                          {t('analytics.exploreClans')}
                        </Link>
                      </div>
                    )}
                  </div>
                </div>
              </>
            ) : (
              <div className="card p-16 rounded-xl text-center">
                <Target size={40} className="text-muted mx-auto mb-4" />
                <p className="text-muted">{t('analytics.profileLoadError')}</p>
              </div>
            )}
          </div>
        )}

    </div>
  );
}

import { NextRequest, NextResponse } from 'next/server';

import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { withRateLimit } from '@/lib/rate-limit-middleware';

// GET /api/admin/manga/[id] - Get specific manga details
export async function GET(
  _request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;
    const session = await auth();

    if (!session?.user?.id || session.user.role !== 'ADMIN') {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const manga = await prisma.mangaSeries.findUnique({
      where: { id },
      include: {
        author: {
          select: {
            id: true,
            username: true,
            displayName: true,
            email: true,
            avatarUrl: true,
          },
        },
        chapters: {
          orderBy: { chapterNumber: 'asc' },
          select: {
            id: true,
            chapterNumber: true,
            title: true,
            totalPages: true,
            viewCount: true,
            createdAt: true,
          },
        },
        _count: {
          select: {
            userMangas: true,
          },
        },
      },
    });

    if (!manga) {
      return NextResponse.json(
        { error: 'Manga not found' },
        { status: 404 }
      );
    }

    // Get comment counts for each chapter
    const chapterIds = manga.chapters.map((c: any) => c.id);
    const commentCounts = await prisma.comment.groupBy({
      by: ['chapterId'],
      where: { chapterId: { in: chapterIds } },
      _count: { id: true },
    });

    const commentCountMap = new Map(commentCounts.map((c: any) => [c.chapterId, c._count.id]));

    return NextResponse.json({
      manga: {
        id: manga.id,
        title: manga.title,
        slug: manga.slug,
        description: manga.description,
        coverUrl: manga.coverUrl,
        status: manga.status,
        tags: manga.tags ? JSON.parse(manga.tags) : [],
        totalViews: manga.totalViews,
        rating: manga.rating,
        authorId: manga.authorId,
        authorName: manga.authorName,
        author: manga.author,
        bookmarkCount: manga._count.userMangas,
        commentCount: commentCounts.reduce((sum: any, c: any) => sum + c._count.id, 0),
        chapters: manga.chapters.map((ch: any) => ({
          id: ch.id,
          chapterNumber: ch.chapterNumber,
          title: ch.title,
          totalPages: ch.totalPages,
          viewCount: ch.viewCount,
          commentCount: commentCountMap.get(ch.id) || 0,
          createdAt: ch.createdAt.toISOString(),
        })),
        createdAt: manga.createdAt.toISOString(),
        updatedAt: manga.updatedAt.toISOString(),
      },
    });
  } catch (error) {
    console.error('Error fetching manga:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

// PATCH /api/admin/manga/[id] - Update manga
export async function PATCH(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;
    const session = await auth();

    if (!session?.user?.id || session.user.role !== 'ADMIN') {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const rlResponse = await withRateLimit(request, session.user.id, 'default');
    if (rlResponse) return rlResponse;

    const body = await request.json();
    const { title, description, coverUrl, tags, status, authorId, authorName } = body;

    const updateData: { title?: string; description?: string | null; coverUrl?: string | null; status?: string; authorName?: string; authorId?: string; tags?: string } = {};
    if (title !== undefined) updateData.title = title;
    if (description !== undefined) updateData.description = description;
    if (coverUrl !== undefined) updateData.coverUrl = coverUrl;
    if (status !== undefined) updateData.status = status;
    if (authorName !== undefined) updateData.authorName = authorName;
    if (authorId !== undefined) {
      updateData.authorId = authorId;
      // Get new author name
      const author = await prisma.user.findUnique({
        where: { id: authorId },
        select: { displayName: true, username: true },
      });
      if (author) {
        updateData.authorName = author.displayName || author.username;
      }
    }
    if (tags !== undefined) {
      updateData.tags = Array.isArray(tags) ? JSON.stringify(tags) : '[]';
    }

    const manga = await prisma.mangaSeries.update({
      where: { id },
      data: updateData,
    });

    return NextResponse.json({
      message: 'Manga updated successfully',
      manga: {
        id: manga.id,
        title: manga.title,
        slug: manga.slug,
        description: manga.description,
        coverUrl: manga.coverUrl,
        status: manga.status,
        tags: manga.tags ? JSON.parse(manga.tags) : [],
        authorId: manga.authorId,
        authorName: manga.authorName,
        updatedAt: manga.updatedAt.toISOString(),
      },
    });
  } catch (error) {
    console.error('Error updating manga:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

// DELETE /api/admin/manga/[id] - Delete manga
export async function DELETE(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;
    const session = await auth();

    if (!session?.user?.id || session.user.role !== 'ADMIN') {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const rlResponse = await withRateLimit(request, session.user.id, 'default');
    if (rlResponse) return rlResponse;

    await prisma.mangaSeries.delete({
      where: { id },
    });

    return NextResponse.json({
      message: 'Manga deleted successfully',
    });
  } catch (error) {
    console.error('Error deleting manga:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';

import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { rateLimit, getRateLimitKey } from '@/lib/rate-limit';

// GET /api/admin/manga - Get all mangas for admin
export async function GET(request: NextRequest) {
  try {
    const session = await auth();

    if (!session?.user?.id || session.user.role !== 'ADMIN') {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const { searchParams } = new URL(request.url);
    const page = Math.max(parseInt(searchParams.get('page') || '1'), 1);
    const limit = Math.min(Math.max(parseInt(searchParams.get('limit') || '20'), 1), 100);
    const search = searchParams.get('search') || '';
    const status = searchParams.get('status') || 'all';

    const where: { OR?: { title?: { contains: string }; authorName?: { contains: string } }[]; status?: string } = {};

    if (search) {
      where.OR = [
        { title: { contains: search } },
        { authorName: { contains: search } },
      ];
    }

    if (status && status !== 'all') {
      where.status = status.toUpperCase();
    }

    const [mangas, total] = await Promise.all([
      prisma.mangaSeries.findMany({
        where,
        skip: (page - 1) * limit,
        take: limit,
        orderBy: { createdAt: 'desc' },
        include: {
          author: {
            select: {
              id: true,
              username: true,
              displayName: true,
              email: true,
            },
          },
          _count: {
            select: {
              chapters: true,
              userMangas: true,
            },
          },
        },
      }),
      prisma.mangaSeries.count({ where }),
    ]);

    // Get comment counts separately for each manga
    const mangaIds = mangas.map((m: any) => m.id);
    const commentCounts = await prisma.comment.groupBy({
      by: ['chapterId'],
      _count: {
        id: true,
      },
    });

    // Get chapter IDs for each manga
    const chapters = await prisma.chapter.findMany({
      where: { mangaId: { in: mangaIds } },
      select: { id: true, mangaId: true },
    });

    const chapterToMangaMap = new Map(chapters.map((c: any) => [c.id, c.mangaId]));
    const mangaCommentCounts = new Map<string, number>();

commentCounts.forEach((cc: any) => {
  const mangaId = chapterToMangaMap.get(cc.chapterId);
  if (mangaId) {
    mangaCommentCounts.set(mangaId, (mangaCommentCounts.get(mangaId) || 0) + cc._count.id);
  }
});

    const formattedMangas = mangas.map((manga: any) => ({
      id: manga.id,
      title: manga.title,
      slug: manga.slug,
      description: manga.description,
      coverUrl: manga.coverUrl,
      status: manga.status,
      tags: manga.tags ? JSON.parse(manga.tags) : [],
      totalViews: manga.totalViews,
      rating: manga.rating,
      authorId: manga.authorId,
      authorName: manga.authorName,
      author: manga.author,
      chapterCount: manga._count.chapters,
      bookmarkCount: manga._count.userMangas,
      commentCount: mangaCommentCounts.get(manga.id) || 0,
      createdAt: manga.createdAt.toISOString(),
      updatedAt: manga.updatedAt.toISOString(),
    }));

    return NextResponse.json({
      mangas: formattedMangas,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
      },
    });
  } catch (error) {
    console.error('Error fetching mangas:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

// POST /api/admin/manga - Create manga as admin
export async function POST(request: NextRequest) {
  try {
    const session = await auth();

    if (!session?.user?.id || session.user.role !== 'ADMIN') {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const userId = session?.user?.id || 'anonymous';
    const { allowed } = await rateLimit(getRateLimitKey('admin-manga', userId), 30, 60);
    if (!allowed) {
      return NextResponse.json({ error: 'Too many requests' }, { status: 429 });
    }

    const body = await request.json();
    const { title, description, coverUrl, tags, authorId, status } = body;

    if (!title || typeof title !== 'string' || title.trim().length === 0) {
      return NextResponse.json(
        { error: 'Title is required' },
        { status: 400 }
      );
    }

    // Generate slug
    const baseSlug = title
      .toLowerCase()
      .trim()
      .replace(/[^\w\s-]/g, '')
      .replace(/\s+/g, '-')
      .substring(0, 100);
    let slug = baseSlug;
    let counter = 1;

    while (await prisma.mangaSeries.findUnique({ where: { slug } })) {
      slug = `${baseSlug}-${counter}`;
      counter++;
    }

    // Get author info
    let authorName = 'Unknown';
    let finalAuthorId = authorId;

    if (finalAuthorId) {
      const author = await prisma.user.findUnique({
        where: { id: finalAuthorId },
        select: { displayName: true, username: true },
      });
      authorName = author?.displayName || author?.username || 'Unknown';
    } else {
      finalAuthorId = session.user.id;
      authorName = session.user.name || 'Admin';
    }

    const manga = await prisma.mangaSeries.create({
      data: {
        title: title.trim(),
        slug,
        description: description || null,
        coverUrl: coverUrl || null,
        authorId: finalAuthorId,
        authorName,
        status: status || 'ONGOING',
        tags: tags && Array.isArray(tags) ? JSON.stringify(tags) : '[]',
      },
    });

    return NextResponse.json({
      message: 'Manga created successfully',
      manga: {
        id: manga.id,
        title: manga.title,
        slug: manga.slug,
        description: manga.description,
        coverUrl: manga.coverUrl,
        status: manga.status,
        tags: manga.tags ? JSON.parse(manga.tags) : [],
        authorId: manga.authorId,
        authorName: manga.authorName,
        createdAt: manga.createdAt.toISOString(),
        updatedAt: manga.updatedAt.toISOString(),
      },
    });
  } catch (error) {
    console.error('Error creating manga:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { rateLimit, getRateLimitKey } from '@/lib/rate-limit';
import { autoTranslateNewsArticle } from '@/lib/translate';

const updateSchema = z.object({
  title: z.string().min(1).max(200).optional(),
  slug: z
    .string()
    .min(1)
    .max(200)
    .regex(/^[a-z0-9-]+$/, 'El slug solo puede contener letras minúsculas, números y guiones')
    .optional(),
  excerpt: z.string().min(1).max(500).optional(),
  content: z.string().min(1).optional(),
  titleEn: z.string().max(200).optional().nullable(),
  excerptEn: z.string().max(500).optional().nullable(),
  contentEn: z.string().optional().nullable(),
  coverUrl: z.string().url('URL de portada inválida').nullable().optional(),
  category: z.enum(['platform', 'community', 'tools', 'mobile', 'contest']).optional(),
  isPublished: z.boolean().optional(),
});

export async function GET(
  _request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;
    const session = await auth();
    if (!session?.user?.id || session.user.role !== 'ADMIN') {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const article = await prisma.newsArticle.findUnique({
      where: { id },
      include: {
        author: {
          select: {
            id: true,
            username: true,
            displayName: true,
            avatarUrl: true,
          },
        },
      },
    });

    if (!article) {
      return NextResponse.json({ error: 'Noticia no encontrada' }, { status: 404 });
    }

    return NextResponse.json({
      article: {
        ...article,
        publishedAt: article.publishedAt?.toISOString() ?? null,
        createdAt: article.createdAt.toISOString(),
        updatedAt: article.updatedAt.toISOString(),
      },
    });
  } catch (error) {
    console.error('Error fetching news article:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

export async function PATCH(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;
    const session = await auth();
    if (!session?.user?.id || session.user.role !== 'ADMIN') {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const userId = session.user.id;
    const { allowed } = await rateLimit(getRateLimitKey('admin-news-update', userId), 30, 60);
    if (!allowed) {
      return NextResponse.json({ error: 'Too many requests' }, { status: 429 });
    }

    const body = await request.json();
    const result = updateSchema.safeParse(body);

    if (!result.success) {
      return NextResponse.json(
        { error: 'Validation failed', details: result.error.flatten().fieldErrors },
        { status: 400 }
      );
    }

    const existing = await prisma.newsArticle.findUnique({ where: { id } });
    if (!existing) {
      return NextResponse.json({ error: 'Noticia no encontrada' }, { status: 404 });
    }

    const data = result.data;
    const updateData: Record<string, unknown> = {};

    if (data.title !== undefined) updateData.title = data.title;
    if (data.slug !== undefined) {
      // Check slug uniqueness (exclude current article)
      const slugExists = await prisma.newsArticle.findFirst({
        where: { slug: data.slug, id: { not: id } },
      });
      if (slugExists) {
        return NextResponse.json({ error: 'El slug ya está en uso' }, { status: 409 });
      }
      updateData.slug = data.slug;
    }
    if (data.excerpt !== undefined) updateData.excerpt = data.excerpt;
    if (data.content !== undefined) updateData.content = data.content;
    // Si cambiaron campos en español y no se proveyeron traducciones, auto-traducir
    const spanishFieldsChanged =
      data.title !== undefined || data.excerpt !== undefined || data.content !== undefined;
    const englishFieldsProvided =
      data.titleEn !== undefined || data.excerptEn !== undefined || data.contentEn !== undefined;

    if (spanishFieldsChanged && !englishFieldsProvided) {
      // Force re-translation only for fields whose Spanish actually changed
      const effectiveData = {
        title: data.title ?? existing.title,
        excerpt: data.excerpt ?? existing.excerpt,
        content: data.content ?? existing.content,
        titleEn: data.title !== undefined ? null : existing.titleEn,
        excerptEn: data.excerpt !== undefined ? null : existing.excerptEn,
        contentEn: data.content !== undefined ? null : existing.contentEn,
      };

      const translation = await autoTranslateNewsArticle(effectiveData).catch((err) => {
        console.warn('Auto-translation failed, continuing without it:', err.message);
        return null;
      });

      if (translation) {
        if (translation.titleEn !== null) updateData.titleEn = translation.titleEn;
        if (translation.excerptEn !== null) updateData.excerptEn = translation.excerptEn;
        if (translation.contentEn !== null) updateData.contentEn = translation.contentEn;
      }
    }

    if (data.titleEn !== undefined) updateData.titleEn = data.titleEn;
    if (data.excerptEn !== undefined) updateData.excerptEn = data.excerptEn;
    if (data.contentEn !== undefined) updateData.contentEn = data.contentEn;
    if (data.coverUrl !== undefined) updateData.coverUrl = data.coverUrl;
    if (data.category !== undefined) updateData.category = data.category;

    // Handle publishing/unpublishing
    if (data.isPublished !== undefined) {
      updateData.isPublished = data.isPublished;
      if (data.isPublished && !existing.publishedAt) {
        updateData.publishedAt = new Date();
      } else if (!data.isPublished) {
        updateData.publishedAt = null;
      }
    }

    const article = await prisma.newsArticle.update({
      where: { id },
      data: updateData,
      include: {
        author: {
          select: {
            id: true,
            username: true,
            displayName: true,
            avatarUrl: true,
          },
        },
      },
    });

    return NextResponse.json({
      article: {
        ...article,
        publishedAt: article.publishedAt?.toISOString() ?? null,
        createdAt: article.createdAt.toISOString(),
        updatedAt: article.updatedAt.toISOString(),
      },
    });
  } catch (error: any) {
    console.error('Error updating news:', error);
    const message = error?.message || 'Internal server error';
    const status = message === 'Noticia no encontrada' ? 404 : 400;
    return NextResponse.json({ error: message }, { status });
  }
}

export async function DELETE(
  _request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;
    const session = await auth();
    if (!session?.user?.id || session.user.role !== 'ADMIN') {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const userId = session.user.id;
    const { allowed } = await rateLimit(getRateLimitKey('admin-news-delete', userId), 20, 60);
    if (!allowed) {
      return NextResponse.json({ error: 'Too many requests' }, { status: 429 });
    }

    const existing = await prisma.newsArticle.findUnique({ where: { id } });
    if (!existing) {
      return NextResponse.json({ error: 'Noticia no encontrada' }, { status: 404 });
    }

    await prisma.newsArticle.delete({ where: { id } });

    return NextResponse.json({ success: true });
  } catch (error: any) {
    console.error('Error deleting news:', error);
    const message = error?.message || 'Internal server error';
    const status = message === 'Noticia no encontrada' ? 404 : 400;
    return NextResponse.json({ error: message }, { status });
  }
}

