// Types for stats response
interface DashboardStats {
  counts: {
    totalUsers: number;
    totalMangas: number;
    totalChapters: number;
    totalComments: number;
  };
  activity: {
    last24h: number;
    last7d: number;
    last30d: number;
  };
  today: {
    newUsers: number;
    newMangas: number;
    newChapters: number;
    newComments: number;
  };
  moderation: {
    pendingCorrections: number;
    flaggedComments: number;
    reportedContent: number;
  };
