    rating: number | null;
    chapterCount: number;
  }>;
}

// Helper to check if user is admin
async function checkAdmin(userId: string): Promise<boolean> {
  const user = await prisma.user.findUnique({
    where: { id: userId },
    select: { role: true },
  });
  return user?.role === 'ADMIN';
}

// GET /api/admin/stats - Get dashboard statistics
export async function GET(_request: NextRequest) {
  try {
    const session = await auth();

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'No autorizado' },
        { status: 401 }
      );
    }

    // Check if user is admin
    const isAdmin = await checkAdmin(session.user.id);
    if (!isAdmin) {
      return NextResponse.json(
        { error: 'Acceso denegado. Se requieren permisos de administrador' },
        { status: 403 }
      );
    }

    // Calculate time ranges
    const now = new Date();
    const today = new Date(now);
    today.setHours(0, 0, 0, 0);
    const tomorrow = new Date(today);
    tomorrow.setDate(tomorrow.getDate() + 1);
    const last24h = new Date(now.getTime() - 24 * 60 * 60 * 1000);
    const last7d = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
    const last30d = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

    // Get all counts in parallel
    const [
      totalUsers,
      totalMangas,
      totalChapters,
      totalComments,
      newUsersToday,
      newMangasToday,
      newChaptersToday,
      newCommentsToday,
      activity24h,
      activity7d,
      activity30d,
      pendingCorrections,
      flaggedComments,
      popularMangas,
    ] = await Promise.all([
      // Total counts
      prisma.user.count(),
      prisma.mangaSeries.count(),
      prisma.chapter.count(),
      prisma.comment.count(),

      // Today's new items
      prisma.user.count({
        where: { createdAt: { gte: today, lt: tomorrow } },
      }),
      prisma.mangaSeries.count({
        where: { createdAt: { gte: today, lt: tomorrow } },
      }),
      prisma.chapter.count({
        where: { createdAt: { gte: today, lt: tomorrow } },
      }),
      prisma.comment.count({
        where: { createdAt: { gte: today, lt: tomorrow } },
      }),

      // Activity counts (user activities in time ranges)
      prisma.userActivity.count({
        where: { createdAt: { gte: last24h } },
      }),
      prisma.userActivity.count({
        where: { createdAt: { gte: last7d } },
      }),
      prisma.userActivity.count({
        where: { createdAt: { gte: last30d } },
      }),

      // Moderation counts
      prisma.chapterCorrection.count({
        where: { status: 'PENDING' },
      }),
      prisma.comment.count({
        where: {
          OR: [
            { isHidden: true },
            { hiddenReason: { not: null } },
          ],
        },
      }),

      // Popular mangas (top 10 by views)
      prisma.mangaSeries.findMany({
        take: 10,
        orderBy: { totalViews: 'desc' },
        select: {
          id: true,
          title: true,
          slug: true,
          coverUrl: true,
          authorName: true,
          totalViews: true,
          rating: true,
          _count: {
            select: { chapters: true },
          },
        },
      }),
    ]);

    // Get reported content count from AnalyticsEvent (content reports)
  const reportedContent = await prisma.analyticsEvent.count({
    where: {
      eventType: 'REPORT',
      createdAt: { gte: last30d },
    },
  });

    const stats: DashboardStats = {
      counts: {
        totalUsers,
        totalMangas,
        totalChapters,
        totalComments,
      },
      activity: {
        last24h: activity24h,
        last7d: activity7d,
        last30d: activity30d,
      },
      today: {
        newUsers: newUsersToday,
        newMangas: newMangasToday,
        newChapters: newChaptersToday,
        newComments: newCommentsToday,
      },
      moderation: {
        pendingCorrections,
        flaggedComments,
        reportedContent,
      },
      popularMangas: popularMangas.map((manga: any) => ({
        id: manga.id,
        title: manga.title,
        slug: manga.slug,
        coverUrl: manga.coverUrl,
        authorName: manga.authorName,
        totalViews: manga.totalViews,
        rating: manga.rating,
        chapterCount: manga._count.chapters,
      })),
    };

    return NextResponse.json(stats);
  } catch (error) {
    console.error('Error obteniendo estadísticas del admin:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { rateLimit, getRateLimitKey } from '@/lib/rate-limit';

const updateUserSchema = z.object({
  displayName: z.string().min(1).max(50).optional(),
  email: z.string().email().max(254).optional(),
  role: z.enum(['USER', 'ADMIN', 'BANNED', 'CREATOR']).optional(),
  xpPoints: z.number().int().min(0).optional(),
  inkcoinsBalance: z.number().int().min(0).optional(),
  level: z.number().int().min(1).optional(),
});

// GET /api/admin/users/[id] - Get specific user details
export async function GET(
  _request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;
    const session = await auth();

    if (!session?.user?.id || session.user.role !== 'ADMIN') {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const user = await prisma.user.findUnique({
      where: { id },
      include: {
        _count: {
          select: {
            createdMangas: true,
            comments: true,
          },
        },
        createdMangas: {
          select: {
            id: true,
            title: true,
            status: true,
          },
        },
      },
    });

    if (!user) {
      return NextResponse.json(
        { error: 'User not found' },
        { status: 404 }
      );
    }

    // Get chapter counts for user's mangas
    const mangaIds = user.createdMangas.map((m: any) => m.id);
    const chapterCounts = await prisma.chapter.groupBy({
      by: ['mangaId'],
      where: { mangaId: { in: mangaIds } },
      _count: { id: true },
    });

const chapterCountMap = new Map(chapterCounts.map((c: any) => [c.mangaId, c._count.id]));
const totalChapters = chapterCounts.reduce((sum: any, c: any) => sum + c._count.id, 0);

    return NextResponse.json({
      user: {
        id: user.id,
        email: user.email,
        username: user.username,
        displayName: user.displayName,
        avatarUrl: user.avatarUrl,
        role: user.role,
        xpPoints: user.xpPoints,
        inkcoinsBalance: user.inkcoinsBalance,
        level: user.level,
        readingStreak: user.readingStreak,
        createdAt: user.createdAt.toISOString(),
        lastReadAt: user.lastReadAt?.toISOString() || null,
        mangaCount: user._count.createdMangas,
        chapterCount: totalChapters,
        commentCount: user._count.comments,
        mangas: user.createdMangas.map((m: any) => ({
          id: m.id,
          title: m.title,
          status: m.status,
          chapterCount: chapterCountMap.get(m.id) || 0,
        })),
      },
    });
  } catch (error) {
    console.error('Error fetching user:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

// POST /api/admin/users/[id] - Perform actions on user (ban, unban, delete)
export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;
    const session = await auth();

    if (!session?.user?.id || session.user.role !== 'ADMIN') {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const userId = session?.user?.id || 'anonymous';
    const { allowed } = await rateLimit(getRateLimitKey('admin-user-update', userId), 30, 60);
    if (!allowed) {
      return NextResponse.json({ error: 'Too many requests' }, { status: 429 });
    }

    const { action } = await request.json();

    // Prevent self-actions
    if (id === session.user.id) {
      return NextResponse.json(
        { error: 'Cannot perform actions on yourself' },
        { status: 400 }
      );
    }

    switch (action) {
      case 'ban':
        // Update user role to BANNED
        await prisma.user.update({
          where: { id },
          data: { role: 'BANNED' },
        });
        break;

      case 'unban':
        // Restore user role to USER
        await prisma.user.update({
          where: { id },
          data: { role: 'USER' },
        });
        break;

      case 'delete':
        // Delete user (cascade will handle related records)
        await prisma.user.delete({
          where: { id },
        });
        break;

      case 'promote':
        // Promote user to ADMIN
        await prisma.user.update({
          where: { id },
          data: { role: 'ADMIN' },
        });
        break;

      case 'demote':
        // Demote user to regular USER
        await prisma.user.update({
          where: { id },
          data: { role: 'USER' },
        });
        break;

      default:
        return NextResponse.json(
          { error: 'Invalid action' },
          { status: 400 }
        );
    }

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error('Error performing user action:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

// PATCH /api/admin/users/[id] - Update user details
export async function PATCH(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;
    const session = await auth();

    if (!session?.user?.id || session.user.role !== 'ADMIN') {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const userId = session?.user?.id || 'anonymous';
    const { allowed } = await rateLimit(getRateLimitKey('admin-user-update', userId), 30, 60);
    if (!allowed) {
      return NextResponse.json({ error: 'Too many requests' }, { status: 429 });
    }

    const body = await request.json();
    const result = updateUserSchema.safeParse(body);
    if (!result.success) {
      return NextResponse.json(
        { error: 'Validation failed', details: result.error.flatten().fieldErrors },
        { status: 400 }
      );
    }

    const { displayName, email, role, xpPoints, inkcoinsBalance, level } = result.data;

    const updateData: Record<string, unknown> = {};
    if (displayName !== undefined) updateData.displayName = displayName;
    if (email !== undefined) updateData.email = email;
    if (role !== undefined) updateData.role = role;
    if (xpPoints !== undefined) updateData.xpPoints = xpPoints;
    if (inkcoinsBalance !== undefined) updateData.inkcoinsBalance = inkcoinsBalance;
    if (level !== undefined) updateData.level = level;

    const user = await prisma.user.update({
      where: { id },
      data: updateData,
    });

    return NextResponse.json({ user });
  } catch (error) {
    console.error('Error updating user:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

import { NextResponse } from 'next/server';

import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

// GET /api/admin/users - Get all users for admin
export async function GET() {
  try {
    const session = await auth();

    if (!session?.user?.id || session.user.role !== 'ADMIN') {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const users = await prisma.user.findMany({
      orderBy: {
        createdAt: 'desc',
      },
      select: {
        id: true,
        email: true,
        username: true,
        displayName: true,
        avatarUrl: true,
        role: true,
        xpPoints: true,
        inkcoinsBalance: true,
        level: true,
        readingStreak: true,
        createdAt: true,
        lastReadAt: true,
        _count: {
          select: {
            createdMangas: true,
            comments: true,
          },
        },
      },
    });

    const userIds = users.map((u: any) => u.id);

    const [chapterCounts, mangaAuthorMap] = await Promise.all([
      prisma.chapter.groupBy({
        by: ['mangaId'],
        _count: { id: true },
      }),
      prisma.mangaSeries.findMany({
        where: { authorId: { in: userIds } },
        select: { id: true, authorId: true },
      }),
    ]);

    const chapterCountByManga = Object.fromEntries(
      chapterCounts.map((c: any) => [c.mangaId, c._count.id])
    );

    const userChapterCounts = new Map<string, number>();
    for (const manga of mangaAuthorMap) {
      const authorId = manga.authorId;
      const count = chapterCountByManga[manga.id] || 0;
      userChapterCounts.set(authorId, (userChapterCounts.get(authorId) || 0) + count);
    }

    const formattedUsers = users.map((user: any) => ({
      id: user.id,
      email: user.email,
      username: user.username,
      displayName: user.displayName,
      avatarUrl: user.avatarUrl,
      role: user.role,
      xpPoints: user.xpPoints,
      inkcoinsBalance: user.inkcoinsBalance,
      level: user.level,
      readingStreak: user.readingStreak,
      createdAt: user.createdAt.toISOString(),
      lastReadAt: user.lastReadAt?.toISOString() || null,
      mangaCount: user._count.createdMangas,
      chapterCount: userChapterCounts.get(user.id) || 0,
      commentCount: user._count.comments,
    }));

    return NextResponse.json({ users: formattedUsers });
  } catch (error) {
    console.error('Error fetching users:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

