/**
 * Analytics Dashboard API
 * 
 * Retorna estadísticas para el dashboard del creador.
 */

import { NextResponse } from 'next/server';

import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

export async function GET(request: Request) {
  try {
    const session = await auth();
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

  const { searchParams } = new URL(request.url);
  const mangaIdParam = searchParams.get('mangaId');
  const mangaIdsParam = searchParams.get('mangaIds');
  const dateFrom = searchParams.get('from');
  const dateTo = searchParams.get('to');

  const fromDate = dateFrom ? new Date(dateFrom) : new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
  const toDate = dateTo ? new Date(dateTo) : new Date();

  const where: any = {
    createdAt: {
      gte: fromDate,
      lte: toDate,
    },
  };

  if (mangaIdParam) {
    where.mangaId = mangaIdParam;
  } else if (mangaIdsParam) {
    const mangaIds = mangaIdsParam.split(',').map((s: string) => s.trim()).filter(Boolean);
    if (mangaIds.length > 0) {
      const userMangas = await prisma.mangaSeries.findMany({
        where: { id: { in: mangaIds }, authorId: session.user.id },
        select: { id: true },
      });
      where.mangaId = { in: userMangas.map((m: any) => m.id) };
    } else {
      const userMangas = await prisma.mangaSeries.findMany({
        where: { authorId: session.user.id },
        select: { id: true },
      });
      where.mangaId = { in: userMangas.map((m: any) => m.id) };
    }
  } else {
    const userMangas = await prisma.mangaSeries.findMany({
      where: { authorId: session.user.id },
      select: { id: true },
    });
    where.mangaId = { in: userMangas.map((m: any) => m.id) };
  }

  const authorizedMangaIds = where.mangaId === Object(where.mangaId) && 'in' in where.mangaId
    ? where.mangaId.in
    : where.mangaId
      ? [where.mangaId]
      : [];

  const popularChapterWhere = authorizedMangaIds.length > 0
    ? { mangaId: { in: authorizedMangaIds } }
    : { manga: { authorId: session.user.id } };

    // Obtener estadísticas
  const [
    views,
    reads,
    completions,
    timeSpent,
    dailyViews,
    dailyReads,
    popularChapters,
  ] = await Promise.all([
      // Total views
      prisma.analyticsEvent.count({
        where: { ...where, eventType: 'page_view' },
      }),

      // Total reads
      prisma.analyticsEvent.count({
        where: { ...where, eventType: 'chapter_read' },
      }),

      // Total completions
      prisma.analyticsEvent.count({
        where: { ...where, eventType: 'chapter_complete' },
      }),

      // Average time spent (usando ReadingSession)
      prisma.readingSession.aggregate({
        where: {
          chapter: { mangaId: { in: authorizedMangaIds.length > 0 ? authorizedMangaIds : undefined } },
          endedAt: { not: null },
        },
        _avg: {
          durationSeconds: true,
        },
      }),

      // Daily stats - views
      prisma.analyticsEvent.groupBy({
        by: ['createdAt'],
        where: { ...where, eventType: 'page_view' },
        _count: { id: true },
      }),

      // Daily stats - reads
      prisma.analyticsEvent.groupBy({
        by: ['createdAt'],
        where: { ...where, eventType: 'chapter_read' },
        _count: { id: true },
      }),

      // Popular chapters
      prisma.chapter.findMany({
        where: popularChapterWhere,
        orderBy: { viewCount: 'desc' },
        take: 10,
        include: {
          manga: {
            select: { title: true },
          },
        },
      }),
    ]);

  type DailyStat = { createdAt: Date; _count: { id: number } | null };

  const readsByDate = new Map(
    (dailyReads as DailyStat[]).map((stat) => [
      new Date(stat.createdAt).toISOString().split('T')[0],
      stat._count!.id,
    ])
  );

  const formattedDaily = (dailyViews as DailyStat[]).slice(0, 30).map((stat) => {
    const date = new Date(stat.createdAt).toISOString().split('T')[0];
    return {
      date,
      views: stat._count!.id,
      reads: readsByDate.get(date) || 0,
    };
  });

    // Calcular completion rate
    const completionRate = reads > 0 ? (completions / reads) * 100 : 0;

    return NextResponse.json({
      views,
      reads,
      completions,
      completionRate: Math.round(completionRate * 10) / 10,
      avgTimeSpent: timeSpent._avg.durationSeconds ? Math.round(timeSpent._avg.durationSeconds) : 0,
      dailyStats: formattedDaily,
      popularChapters: popularChapters.map((ch: any) => ({
        chapterId: ch.id,
        chapterNumber: ch.chapterNumber,
        title: ch.title,
        views: ch.viewCount,
        mangaTitle: ch.manga.title,
      })),
    });
  } catch (error) {
    console.error('[Analytics Dashboard API] Error:', error);
    return NextResponse.json(
      { error: 'Failed to fetch analytics' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';

import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { rateLimit, getRateLimitKey } from '@/lib/rate-limit';

// POST /api/analytics/export - Export analytics data
export async function POST(request: NextRequest) {
  try {
    const session = await auth();
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'No autorizado' }, { status: 401 });
    }

    const identifier = session.user.id;
    const { allowed } = await rateLimit(
      getRateLimitKey('analytics-export', identifier),
      5,
      3600
    );
    if (!allowed) {
      return NextResponse.json({ error: 'Demasiadas solicitudes. Intenta más tarde.' }, { status: 429 });
    }

    const body = await request.json();
    const { format = 'csv', type = 'reading' } = body;

    // Only allow users to export their own data or manga they created
    const userId = session.user.id;
    const isCreator = session.user.role === 'CREATOR' || session.user.role === 'ADMIN';

    let data: any[] = [];

    switch (type) {
      case 'reading':
        // Reading history
        data = await prisma.readingProgress.findMany({
          where: { userId },
          include: {
            manga: {
              select: {
                title: true,
                slug: true,
              },
            },
            chapter: {
              select: {
                chapterNumber: true,
                title: true,
              },
            },
          },
          orderBy: { updatedAt: 'desc' },
        });
        break;

      case 'manga':
        if (!isCreator) {
          return NextResponse.json(
            { error: 'Solo creadores pueden exportar datos de manga' },
            { status: 403 }
          );
        }
        // Manga created by user with stats
        data = await prisma.mangaSeries.findMany({
          where: { authorId: userId },
          include: {
            _count: {
              select: { chapters: true },
            },
            readingProgress: {
              select: {
                userId: true,
              },
              distinct: ['userId'],
            },
          },
          orderBy: { createdAt: 'desc' },
        });
        break;

      case 'activity':
        // User activity log
        data = await prisma.userActivity.findMany({
          where: { userId },
          orderBy: { createdAt: 'desc' },
          take: 1000,
        });
        break;

      default:
        return NextResponse.json(
          { error: 'Tipo de exportación no válido' },
          { status: 400 }
        );
    }

    // Format data
    let output: string;
    let contentType: string;
    let filename: string;

    if (format === 'csv') {
      // Convert to CSV
      const headers = Object.keys(data[0] || {}).join(',');
      const rows = data.map((row) => {
        return Object.values(row)
          .map((val) => {
            if (val === null || val === undefined) return '';
            if (typeof val === 'object') return JSON.stringify(val);
            if (typeof val === 'string' && val.includes(',')) return `"${val}"`;
            return String(val);
          })
          .join(',');
      });
      output = [headers, ...rows].join('\n');
      contentType = 'text/csv';
      filename = `inkverse-${type}-${new Date().toISOString().split('T')[0]}.csv`;
    } else if (format === 'json') {
      output = JSON.stringify(data, null, 2);
      contentType = 'application/json';
      filename = `inkverse-${type}-${new Date().toISOString().split('T')[0]}.json`;
    } else {
      return NextResponse.json(
        { error: 'Formato no soportado. Use csv o json' },
        { status: 400 }
      );
    }

    // Create response with file download
    return new NextResponse(output, {
      headers: {
        'Content-Type': contentType,
        'Content-Disposition': `attachment; filename="${filename}"`,
      },
    });
  } catch (error) {
    console.error('Error exporting analytics:', error);
    return NextResponse.json(
      { error: 'Error al exportar datos' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';

import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

export async function GET(request: NextRequest) {
  try {
    const session = await auth();
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const { searchParams } = new URL(request.url);
    const mangaId = searchParams.get('mangaId');
    const from = searchParams.get('from');
    const to = searchParams.get('to');

    if (!mangaId) {
      return NextResponse.json({ error: 'mangaId is required' }, { status: 400 });
    }

    const manga = await prisma.mangaSeries.findUnique({
      where: { id: mangaId },
      select: { id: true, title: true, authorId: true },
    });

    if (!manga) {
      return NextResponse.json({ error: 'Manga not found' }, { status: 404 });
    }

    const chapters = await prisma.chapter.findMany({
      where: { mangaId },
      orderBy: { chapterNumber: 'asc' },
      select: {
        id: true,
        chapterNumber: true,
        title: true,
        viewCount: true,
        crowdfundingGoal: true,
        crowdfundingCurrent: true,
        isCrowdfunded: true,
      },
    });

    const totalViews = chapters.reduce((sum: number, ch: any) => sum + ch.viewCount, 0);

    const dailyStats = await prisma.dailyStats.findMany({
      where: {
        mangaId,
        ...(from || to ? {
          date: {
            ...(from ? { gte: new Date(from) } : {}),
            ...(to ? { lte: new Date(to) } : {}),
          },
        } : {}),
      },
      orderBy: { date: 'asc' },
      take: 30,
    });

    return NextResponse.json({
      manga: { id: manga.id, title: manga.title },
      totalViews,
      totalChapters: chapters.length,
      chapters,
      dailyStats: dailyStats.map((s: any) => ({
        date: s.date.toISOString().split('T')[0],
        views: s.views,
        reads: s.reads,
        completions: s.completions,
      })),
    });
  } catch (error) {
    console.error('[Analytics Manga GET] Error:', error);
    return NextResponse.json({ error: 'Error interno del servidor' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { redis } from '@/lib/redis';

type _Output<T> = T extends { _zod: { output: infer O } } ? O : never;

// Analytics event types
const EventType = z.enum([
  'pageView',
  'chapterRead',
  'timeSpent',
  'scrollDepth',
  'chapterComplete',
  'mangaView',
  'searchQuery',
  'bookmarkAdd',
  'ratingGiven',
  'shareEvent',
  'commentPost',
]);

// Schema for single event
const eventSchema = z.object({
  type: EventType,
  mangaId: z.string().uuid().optional(),
  chapterId: z.string().uuid().optional(),
  metadata: z.object({}).passthrough().optional(),
  timestamp: z.string().datetime().optional(),
});

// Schema for batch events
const trackRequestSchema = z.object({
  event: eventSchema.optional(),
  events: z.array(eventSchema).optional(),
});

// Rate limiting: max 100 events per minute per user/IP
async function checkRateLimit(key: string): Promise<boolean> {
  const rateLimitKey = `rate_limit:analytics:${key}`;
  const current = await redis.incr(rateLimitKey);

  if (current === 1) {
    await redis.expire(rateLimitKey, 60); // 1 minute window
  }

  return current <= 100;
}

// Generate session ID
function generateSessionId(): string {
  return `sess_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
}

// Anonymize IP address
function anonymizeIp(ip?: string): string | undefined {
  if (!ip) return undefined;
  
  // IPv4: remove last octet
  if (ip.includes('.')) {
    return ip.split('.').slice(0, 3).join('.') + '.0';
  }
  
  // IPv6: keep first 4 segments
  if (ip.includes(':')) {
    return ip.split(':').slice(0, 4).join(':') + '::';
  }
  
  return ip;
}

// Process and save events
async function processEvents(
  events: _Output<typeof eventSchema>[],
  userId: string | undefined,
  userAgent: string | null,
  ipAddress: string | undefined,
  referrer: string | null
): Promise<void> {
  const sessionId = generateSessionId();
  const timestamp = new Date();

  await prisma.$transaction(async (tx: any) => {
    // Save events
    await tx.analyticsEvent.createMany({
      data: events.map((event) => ({
        eventType: event.type,
        mangaId: event.mangaId,
        chapterId: event.chapterId,
        userId,
        sessionId,
        metadata: event.metadata ? JSON.stringify(event.metadata) : null,
        timestamp: event.timestamp ? new Date(event.timestamp) : timestamp,
        userAgent,
        ipAddress: anonymizeIp(ipAddress),
        referrer,
      })),
    });

    // Update real-time counters and stats
    for (const event of events) {
      if (event.mangaId) {
        await updateMangaStats(tx, event, timestamp);
      }
      if (event.chapterId) {
        await updateChapterStats(tx, event, timestamp);
      }
    }
  });
}

// Update manga daily stats
async function updateMangaStats(
  tx: any,
  event: _Output<typeof eventSchema>,
  timestamp: Date
): Promise<void> {
  if (!event.mangaId) return;

  const date = new Date(timestamp);
  date.setHours(0, 0, 0, 0);

  const hour = timestamp.getHours();

  // Update daily stats
  await tx.dailyStats.upsert({
    where: {
      date_mangaId: {
        date,
        mangaId: event.mangaId,
      },
    },
    create: {
      date,
      mangaId: event.mangaId,
      views: event.type === 'pageView' || event.type === 'mangaView' ? 1 : 0,
      reads: event.type === 'chapterRead' ? 1 : 0,
      completions: event.type === 'chapterComplete' ? 1 : 0,
    },
    update: {
      views: event.type === 'pageView' || event.type === 'mangaView' ? { increment: 1 } : undefined,
      reads: event.type === 'chapterRead' ? { increment: 1 } : undefined,
      completions: event.type === 'chapterComplete' ? { increment: 1 } : undefined,
    },
  });

  // Update hourly stats
  await tx.hourlyStats.upsert({
    where: {
      date_hour_mangaId: {
        date,
        hour,
        mangaId: event.mangaId,
      },
    },
    create: {
      date,
      hour,
      mangaId: event.mangaId,
      views: event.type === 'pageView' || event.type === 'mangaView' ? 1 : 0,
      reads: event.type === 'chapterRead' ? 1 : 0,
    },
    update: {
      views: event.type === 'pageView' || event.type === 'mangaView' ? { increment: 1 } : undefined,
      reads: event.type === 'chapterRead' ? { increment: 1 } : undefined,
    },
  });
}

// Update chapter stats
async function updateChapterStats(
  tx: any,
  event: _Output<typeof eventSchema>,
  _timestamp: Date
): Promise<void> {
  if (!event.chapterId || !event.mangaId) return;

  // Get current chapter stats
  const existingStats = await tx.chapterStats.findUnique({
    where: { chapterId: event.chapterId },
  });

  if (!existingStats) {
    // Create new stats
    await tx.chapterStats.create({
      data: {
        chapterId: event.chapterId,
        mangaId: event.mangaId,
        views: event.type === 'pageView' || event.type === 'chapterRead' ? 1 : 0,
        reads: event.type === 'chapterRead' ? 1 : 0,
        completions: event.type === 'chapterComplete' ? 1 : 0,
        avgTimeSpent: event.metadata?.seconds || 0,
      },
    });
  } else {
    // Update existing stats
    const updates: any = {};

    if (event.type === 'pageView' || event.type === 'chapterRead') {
      updates.views = { increment: 1 };
      updates.reads = { increment: 1 };
    }
    if (event.type === 'chapterComplete') {
      updates.completions = { increment: 1 };
    }
    if (event.metadata?.seconds && typeof event.metadata.seconds === 'number') {
      // Calculate new average
      const newAvg = Math.round(
        (existingStats.avgTimeSpent * existingStats.reads + event.metadata.seconds) /
          (existingStats.reads + 1)
      );
      updates.avgTimeSpent = newAvg;
    }

    if (Object.keys(updates).length > 0) {
      await tx.chapterStats.update({
        where: { chapterId: event.chapterId },
        data: updates,
      });
    }
  }

  // Update chapter view count for reads
  if (event.type === 'chapterRead') {
    await tx.chapter.update({
      where: { id: event.chapterId },
      data: { viewCount: { increment: 1 } },
    });
  }
}

// POST /api/analytics/track - Track analytics events
export async function POST(request: NextRequest) {
  try {
    // Check rate limit by IP
    const forwarded = request.headers.get('x-forwarded-for');
    const ip = forwarded?.split(',')[0]?.trim() || 'unknown';
    const isAllowed = await checkRateLimit(ip);

    if (!isAllowed) {
      return NextResponse.json(
        { error: 'Rate limit exceeded' },
        { status: 429 }
      );
    }

    // Get user session (optional)
    const session = await auth();
    const userId = session?.user?.id;

    // Parse request body
    const body = await request.json();
    const result = trackRequestSchema.safeParse(body);

    if (!result.success) {
      return NextResponse.json(
        { error: 'Datos inválidos', details: result.error.flatten() },
        { status: 400 }
      );
    }

    // Collect events
    let events: _Output<typeof eventSchema>[] = [];
    if (result.data.events && result.data.events.length > 0) {
      events = result.data.events;
    } else if (result.data.event) {
      events = [result.data.event];
    }

    if (events.length === 0) {
      return NextResponse.json(
        { error: 'No events provided' },
        { status: 400 }
      );
    }

    // Limit batch size
    if (events.length > 50) {
      events = events.slice(0, 50);
    }

    // Get request metadata
    const userAgent = request.headers.get('user-agent');
    const referrer = request.headers.get('referer');

    // Process events
    await processEvents(events, userId, userAgent, ip, referrer);

    return NextResponse.json({
      success: true,
      tracked: events.length,
    });
  } catch (error) {
    console.error('Error tracking analytics event:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';

import { withCache, generateCacheKey, cacheConfig } from '@/lib/apiCache';
import { prisma } from '@/lib/prisma';

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const page = Math.max(1, parseInt(searchParams.get('page') || '1'));
    const limit = Math.min(50, Math.max(1, parseInt(searchParams.get('limit') || '20')));
    const tag = searchParams.get('tag');
    const status = searchParams.get('status');
    const sort = searchParams.get('sort') || 'popular';
    const search = searchParams.get('q');

    const cacheKey = generateCacheKey('browse', { page, limit, tag, status, sort, search });

    const result = await withCache(cacheKey, cacheConfig.manga.list.ttl, async () => {
      const where: any = {};
      if (tag) {
        where.tags = { contains: tag.toLowerCase() };
      }
      if (status) {
        where.status = status;
      }
      if (search) {
        where.OR = [
          { title: { contains: search } },
          { authorName: { contains: search } },
          { description: { contains: search } },
        ];
      }

      const orderBy: any = sort === 'popular'
        ? { totalViews: 'desc' }
        : sort === 'rating'
        ? { rating: 'desc' }
        : sort === 'newest'
        ? { createdAt: 'desc' }
        : sort === 'title'
        ? { title: 'asc' }
        : { totalViews: 'desc' };

      const [mangas, total] = await Promise.all([
        prisma.mangaSeries.findMany({
          where,
          select: {
            id: true,
            title: true,
            slug: true,
            description: true,
            coverUrl: true,
            status: true,
            tags: true,
            authorName: true,
            rating: true,
            totalViews: true,
            createdAt: true,
            updatedAt: true,
            _count: { select: { chapters: true, libraryEntries: true } },
          },
          orderBy,
          skip: (page - 1) * limit,
          take: limit,
        }),
        prisma.mangaSeries.count({ where }),
      ]);

      const tags = await prisma.mangaSeries.findMany({
        select: { tags: true },
        where: { tags: { not: '[]' } },
        distinct: ['tags'],
        take: 100,
      });

      const allTags = [...new Set(
        tags.flatMap((t: any) => {
          try { return JSON.parse(t.tags); } catch { return []; }
        })
      )].sort() as string[];

      return {
        mangas: mangas.map((m: any) => ({
          id: m.id,
          title: m.title,
          slug: m.slug,
          description: m.description,
          coverUrl: m.coverUrl,
          status: m.status,
          tags: (() => { try { return JSON.parse(m.tags); } catch { return []; } })(),
          authorName: m.authorName,
          rating: m.rating,
          totalViews: m.totalViews,
          chapterCount: m._count.chapters,
          libraryCount: m._count.libraryEntries,
          createdAt: m.createdAt,
          updatedAt: m.updatedAt,
        })),
        tags: allTags,
        pagination: {
          page,
          limit,
          total,
          totalPages: Math.ceil(total / limit),
        },
      };
    });

    return NextResponse.json(result, {
      headers: { 'Cache-Control': 'public, max-age=60' },
    });
  } catch (error) {
    console.error('Error browsing manga:', error);
    return NextResponse.json({ error: 'Error interno del servidor' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';

import { getNotificationService } from '@/core/services/NotificationService';
import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { withRateLimit } from '@/lib/rate-limit-middleware';

// POST /api/chapters/[id]/comments/[commentId]/like - Like a comment
export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string; commentId: string }> }
) {
  try {
    const { id: chapterId, commentId } = await params;
    const session = await auth();

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'No autorizado' },
        { status: 401 }
      );
    }

    const rlResponse = await withRateLimit(request, session?.user?.id, 'default');
    if (rlResponse) return rlResponse;

    const userId = session.user.id;

    // Check if comment exists and is not deleted
    const comment = await prisma.comment.findFirst({
      where: {
        id: commentId,
        chapterId,
        isDeleted: false,
      },
      select: {
        id: true,
        userId: true,
        likesCount: true,
        content: true,
        chapter: {
          select: {
            mangaId: true,
          },
        },
      },
    });

    if (!comment) {
      return NextResponse.json(
        { error: 'Comentario no encontrado' },
        { status: 404 }
      );
    }

    // Prevent liking own comment
    if (comment.userId === userId) {
      return NextResponse.json(
        { error: 'No puedes dar like a tu propio comentario' },
        { status: 400 }
      );
    }

    // Check if already liked (prevent duplicates)
    const existingLike = await prisma.commentLike.findUnique({
      where: {
        commentId_userId: {
          commentId,
          userId,
        },
      },
    });

    if (existingLike) {
      return NextResponse.json(
        { error: 'Ya has dado like a este comentario' },
        { status: 409 }
      );
    }

// Create like and increment likesCount in transaction
  const result = await prisma.$transaction(async (tx: any) => {
      // Create the like
      const like = await tx.commentLike.create({
        data: {
          commentId,
          userId,
        },
      });

      // Increment likesCount on comment
      const updatedComment = await tx.comment.update({
        where: { id: commentId },
        data: {
          likesCount: { increment: 1 },
        },
        select: {
          id: true,
          likesCount: true,
        },
      });

      return { like, updatedComment };
    });

  // Notify comment owner (async, don't wait)
  if (comment.userId !== userId) {
    try {
      await (await getNotificationService()).createNotification({
        userId: comment.userId,
        type: 'COMMENT_LIKE',
        title: '👍 Nuevo like',
        message: `${session.user.name || session.user.email || 'Usuario'} le dio like a tu comentario`,
        data: {
          likerId: userId,
          likerName: session.user.name || session.user.email || 'Usuario',
          likerImage: session.user.image || undefined,
          chapterId,
          commentId,
        },
        linkUrl: `/manga/${comment.chapter?.mangaId || ''}/chapter/${chapterId}`,
      } as any);
      } catch (error) {
        console.error('[Like] Error sending notification:', error);
      }
    }

    return NextResponse.json({
      success: true,
      likesCount: result.updatedComment.likesCount,
      isLiked: true,
    });
  } catch (error) {
    console.error('Error giving like to comment:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

// DELETE /api/chapters/[id]/comments/[commentId]/like - Unlike a comment
export async function DELETE(
  request: NextRequest,
  { params }: { params: Promise<{ id: string; commentId: string }> }
) {
