import { NextRequest, NextResponse } from 'next/server';

import { getNotificationService } from '@/core/services/NotificationService';
import { getEmailQueue } from '@/infrastructure/queue/EmailQueue';
import { invalidateCache } from '@/lib/apiCache';
import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { withRateLimit } from '@/lib/rate-limit-middleware';

// PATCH /api/chapters/[id]/finalize - Finalize chapter upload
export async function PATCH(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const session = await auth();

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'No autorizado' },
        { status: 401 }
      );
    }

    const rlResponse = await withRateLimit(request, session?.user?.id, 'default');
    if (rlResponse) return rlResponse;

    const { id: chapterId } = await params;

    // Get chapter with manga info
    const chapter = await prisma.chapter.findUnique({
      where: { id: chapterId },
      include: {
        manga: {
          select: {
            id: true,
            title: true,
            slug: true,
            coverUrl: true,
            authorId: true,
          },
        },
      },
    });

    if (!chapter) {
      return NextResponse.json(
        { error: 'Capítulo no encontrado' },
        { status: 404 }
      );
    }

    // Verify ownership
    if (chapter.manga.authorId !== session.user.id && session.user.role !== 'ADMIN') {
      return NextResponse.json(
        { error: 'No tienes permisos para finalizar este capítulo' },
        { status: 403 }
      );
    }

    // Parse pageUrls to verify images are uploaded
    let pageUrls: string[] = [];
    try {
      pageUrls = JSON.parse(chapter.pageUrls);
    } catch {
      pageUrls = [];
    }

    if (!Array.isArray(pageUrls) || pageUrls.length === 0) {
      return NextResponse.json(
        { error: 'El capítulo no tiene páginas. Sube al menos una imagen antes de finalizar.' },
        { status: 400 }
      );
    }

    // Verify all pages have valid URLs
    const validUrls = pageUrls.filter((url: string) => 
      typeof url === 'string' && url.trim() !== ''
    );

    if (validUrls.length === 0) {
      return NextResponse.json(
        { error: 'Las URLs de las páginas no son válidas' },
        { status: 400 }
      );
    }

    // Update chapter and manga in a transaction
    const [updatedChapter] = await prisma.$transaction([
      // Update chapter
      prisma.chapter.update({
        where: { id: chapterId },
        data: {
          totalPages: validUrls.length,
          pageUrls: JSON.stringify(validUrls),
        },
      }),
      // Update manga's updatedAt timestamp
      prisma.mangaSeries.update({
        where: { id: chapter.manga.id },
        data: { updatedAt: new Date() },
      }),
    ]);

    // Invalidate caches
    await invalidateCache('manga:chapters:list');
    await invalidateCache(`manga:${chapter.manga.id}`);
    await invalidateCache(`chapter:${chapterId}`);

    // Notify followers asynchronously
    try {
      const followers = await prisma.userManga.findMany({
        where: { mangaId: chapter.manga.id },
        include: {
          user: {
            select: {
              id: true,
              email: true,
              username: true,
            },
          },
        },
      });

      if (followers.length > 0) {
        const followerIds = followers.map((f: any) => f.userId);

        // Send push notifications
        (await getNotificationService())
          .notifyMultiple(followerIds, {
            type: 'NEW_CHAPTER',
            title: '📖 Nuevo Capítulo',
            message: `${chapter.manga.title} - Capítulo ${chapter.chapterNumber}${chapter.title ? `: ${chapter.title}` : ''}`,
            data: {
              mangaId: chapter.manga.id,
              mangaTitle: chapter.manga.title,
              chapterId: chapter.id,
              chapterNumber: chapter.chapterNumber,
              chapterTitle: chapter.title,
              coverUrl: chapter.manga.coverUrl,
            },
            imageUrl: chapter.manga.coverUrl || undefined,
            linkUrl: `/manga/${chapter.manga.slug}/chapter/${chapter.chapterNumber}`,
          })
          .catch((err) => console.error('Error notifying followers:', err));

        // Queue email notifications
        const emailQueue = getEmailQueue();

        // Process in batches to avoid overload
        const batchSize = 50;
        for (let i = 0; i < followers.length; i += batchSize) {
          const batch = followers.slice(i, i + batchSize);
          await Promise.all(
            batch.map((follower: any) =>
              emailQueue
                .addNewChapterEmail({
                  to: follower.user.email,
                  userId: follower.user.id,
                  username: follower.user.username,
                  mangaId: chapter.manga.id,
                  mangaTitle: chapter.manga.title,
                  mangaSlug: chapter.manga.slug,
                  mangaCoverUrl: chapter.manga.coverUrl,
                  chapterId: chapter.id,
                  chapterNumber: chapter.chapterNumber,
                  chapterTitle: chapter.title || undefined,
                })
                .catch((err) => {
                  console.error(
                    `[Finalize] Error queueing email for ${follower.user.email}:`,
                    err
                  );
                })
            )
          );
        }
      }
    } catch (notifyError) {
      console.error('Error notifying followers of finalized chapter:', notifyError);
      // Don't fail the request if notifications fail
    }

    return NextResponse.json({
      success: true,
      message: 'Capítulo finalizado exitosamente',
      chapter: {
        id: updatedChapter.id,
        mangaId: updatedChapter.mangaId,
        chapterNumber: updatedChapter.chapterNumber,
        title: updatedChapter.title,
        totalPages: updatedChapter.totalPages,
        pageUrls: validUrls,
        createdAt: updatedChapter.createdAt,
        viewCount: updatedChapter.viewCount,
      },
    });
  } catch (error) {
    console.error('Error finalizing chapter:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { rateLimit, getRateLimitKey } from '@/lib/rate-limit';

const sponsorSchema = z.object({
  bidAmount: z.number().int().min(10),
  sponsorName: z.string().min(1).max(50).optional(),
  message: z.string().max(100).optional(),
});

// POST /api/chapters/[id]/sponsor - Pujar por patrocinio
export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const session = await auth();

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'No autorizado' },
        { status: 401 }
      );
    }

    const userId = session?.user?.id || 'anonymous';
    const { allowed } = await rateLimit(getRateLimitKey('sponsor', userId), 10, 60);
    if (!allowed) {
      return NextResponse.json({ error: 'Too many requests' }, { status: 429 });
    }

    const { id: chapterId } = await params;
    const body = await request.json();
    const result = sponsorSchema.safeParse(body);

    if (!result.success) {
      return NextResponse.json(
        { error: 'Datos inválidos', details: result.error.flatten() },
        { status: 400 }
      );
    }

    const { bidAmount, sponsorName, message } = result.data;

    // Verificar capítulo
    const chapter = await prisma.chapter.findUnique({
      where: { id: chapterId },
    });

    if (!chapter) {
      return NextResponse.json(
        { error: 'Capítulo no encontrado' },
        { status: 404 }
      );
    }

    // Verificar fondos
    const user = await prisma.user.findUnique({
      where: { id: session.user.id },
      select: { inkcoinsBalance: true, username: true },
    });

    if (!user || user.inkcoinsBalance < bidAmount) {
      return NextResponse.json(
        { error: 'Fondos insuficientes', balance: user?.inkcoinsBalance || 0 },
        { status: 400 }
      );
    }

    // Verificar puja mínima
    const currentHighest = await prisma.sponsorshipBid.findFirst({
      where: { chapterId, status: 'ACTIVE' },
      orderBy: { bidAmount: 'desc' },
      select: { bidAmount: true },
    });

    const minBid = currentHighest ? currentHighest.bidAmount + 10 : 10;
    if (bidAmount < minBid) {
      return NextResponse.json(
        { error: `Puja mínima: ${minBid} InkCoins`, minBid },
        { status: 400 }
      );
    }

    // Marcar pujas anteriores como perdidas (incluyendo isWinning)
    await prisma.sponsorshipBid.updateMany({
      where: { chapterId, status: 'ACTIVE' },
      data: { status: 'LOST', isWinning: false },
    });

    // Crear puja como ganadora
    const bid = await prisma.sponsorshipBid.create({
      data: {
        chapterId,
        userId: session.user.id,
        bidAmount,
        status: 'ACTIVE',
        isWinning: true,
        sponsorName: sponsorName || user.username,
        message,
      },
    });

    // Reservar fondos
    await prisma.user.update({
      where: { id: session.user.id },
      data: { inkcoinsBalance: { decrement: bidAmount } },
    });

    // Registrar transacción
    await prisma.transaction.create({
      data: {
        userId: session.user.id,
        amount: -bidAmount,
        type: 'SPONSORSHIP_BID',
        referenceId: bid.id,
        description: `Puja patrocinio capítulo ${chapter.chapterNumber}`,
      },
    });

    return NextResponse.json({
      success: true,
      bid: {
        id: bid.id,
        amount: bidAmount,
        chapterId,
        sponsorName: bid.sponsorName,
        message: bid.message,
      },
      newBalance: user.inkcoinsBalance - bidAmount,
      isLeading: true,
      message: '¡Puja registrada! Eres el patrocinador líder.',
    });
  } catch (error) {
    console.error('Error en patrocinio:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

// GET /api/chapters/[id]/sponsor - Ver pujas activas
export async function GET(
  _request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id: chapterId } = await params;

    const bids = await prisma.sponsorshipBid.findMany({
      where: { chapterId },
      include: {
        user: {
          select: {
            id: true,
            username: true,
            avatarUrl: true,
          },
        },
      },
      orderBy: [{ status: 'asc' }, { bidAmount: 'desc' }],
      take: 10,
    });

    const currentWinner = bids.find((b: any) => b.status === 'ACTIVE');

    return NextResponse.json({
      chapterId,
      currentWinner: currentWinner
        ? {
            userId: currentWinner.userId,
            username: currentWinner.user.username,
            avatarUrl: currentWinner.user.avatarUrl,
            bidAmount: currentWinner.bidAmount,
            sponsorName: currentWinner.sponsorName,
            message: currentWinner.message,
            createdAt: currentWinner.createdAt,
          }
        : null,
      bids: bids.map((b: any) => ({
        id: b.id,
        userId: b.userId,
        username: b.user.username,
        bidAmount: b.bidAmount,
        status: b.status,
        createdAt: b.createdAt,
      })),
      bidCount: bids.length,
      minNextBid: currentWinner ? currentWinner.bidAmount + 10 : 10,
    });
  } catch (error) {
    console.error('Error obteniendo pujas:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';

import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { withRateLimit } from '@/lib/rate-limit-middleware';

// POST /api/clans/[id]/promote - Ascender/Degradar miembro
export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;
    const session = await auth();

    if (!session?.user) {
      return NextResponse.json(
        { error: 'No autorizado' },
        { status: 401 }
      );
    }

    const rlResponse = await withRateLimit(request, session?.user?.id, 'default');
    if (rlResponse) return rlResponse;

    const body = await request.json();
    const { userId, role } = body;

    if (!userId || !role) {
      return NextResponse.json(
        { error: 'Faltan datos requeridos' },
        { status: 400 }
      );
    }

    // Valid roles: MEMBER, OFFICER, LEADER
    if (!['MEMBER', 'OFFICER', 'LEADER'].includes(role)) {
      return NextResponse.json(
        { error: 'Rol inválido' },
        { status: 400 }
      );
    }

    // Check if current user is the clan leader
    const leaderMembership = await prisma.clanMembership.findFirst({
      where: {
        clanId: id,
        userId: session.user.id,
        role: 'LEADER',
      },
    });

    if (!leaderMembership) {
      return NextResponse.json(
        { error: 'Solo el líder puede cambiar roles' },
        { status: 403 }
      );
    }

    // Cannot change own role
    if (userId === session.user.id) {
      return NextResponse.json(
        { error: 'No puedes cambiar tu propio rol' },
        { status: 400 }
      );
    }

    // Check if target user is a member of this clan
    const targetMembership = await prisma.clanMembership.findFirst({
      where: {
        clanId: id,
        userId,
      },
    });

    if (!targetMembership) {
      return NextResponse.json(
        { error: 'Usuario no es miembro de este clan' },
        { status: 404 }
      );
    }

    // If promoting to LEADER, demote current leader first
    if (role === 'LEADER') {
      await prisma.$transaction(async (tx: any) => {
        // Demote current leader to OFFICER
        await tx.clanMembership.update({
          where: { id: leaderMembership.id },
          data: { role: 'OFFICER' },
        });

        // Promote target user to LEADER
        await tx.clanMembership.update({
          where: { id: targetMembership.id },
          data: { role: 'LEADER' },
        });

        // Update clan leaderId
        await tx.clan.update({
          where: { id },
          data: { leaderId: userId },
        });
      });
    } else {
      // Simple role update
      await prisma.clanMembership.update({
        where: { id: targetMembership.id },
        data: { role },
      });
    }

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error('Error promoting member:', error);
    return NextResponse.json(
      { error: 'Error al cambiar el rol del miembro' },
      { status: 500 }
    );
  }
}

