) {
  try {
    const { id } = await params;
    const session = await auth();
    const { searchParams } = new URL(req.url);
    const byName = searchParams.get('byName') === '1';

    const whereClause: any = byName ? { name: id } : { id };

    const clan = await prisma.clan.findFirst({
      where: whereClause,
      include: {
        members: {
          include: {
            user: {
              select: {
                id: true,
                username: true,
                displayName: true,
                avatarUrl: true,
                xpPoints: true,
                level: true,
              },
            },
          },
          orderBy: [
