    }

    let userMembership = null;
    if (session?.user?.id) {
      const userId = session.user.id;
      userMembership = clan.members.find((m: any) => m.userId === userId) || null;
    }

    return NextResponse.json({
      clan: {
        ...clan,
        memberCount: clan.members.length,
      },
      userMembership,
