// Schema de validación
const reportSchema = z.object({
  chapterId: z.string().min(1, 'Chapter ID es requerido'),
  issueType: z.union([
    z.literal('QUALITY'),
    z.literal('ERROR'),
    z.literal('SPOILER'),
    z.literal('OTHER'),
  ]),
  severity: z.union([
    z.literal('LOW'),
    z.literal('MEDIUM'),
    z.literal('HIGH'),
  ]),
  description: z.string().min(10, 'La descripción debe tener al menos 10 caracteres').max(1000),
  // Opcionales
  pageNumber: z.number().int().positive().optional(),
  panelNumber: z.number().int().positive().optional(),
  coords: z.object({ x: z.number(), y: z.number() }).optional(),
});

// POST /api/crowdsource/report - Crear reporte
export async function POST(request: NextRequest) {
  try {
    const session = await auth();

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'No autorizado. Inicia sesión para reportar.' },
        { status: 401 }
      );
    }

    const rlResponse = await withRateLimit(request, session?.user?.id, 'report');
    if (rlResponse) return rlResponse;

    const body = await request.json();
    const result = reportSchema.safeParse(body);

    if (!result.success) {
      return NextResponse.json(
        {
          error: 'Datos inválidos',
          details: result.error.flatten(),
        },
        { status: 400 }
      );
    }

    const { chapterId, issueType, severity, description, pageNumber, panelNumber } = result.data;

    await dbConnect();

    // Verificar que el usuario no haya reportado el mismo capítulo recientemente (anti-spam)
    const recentReport = await QualityReportModel.findOne({
      chapterId,
      reportedBy: session.user.id,
      createdAt: { $gte: new Date(Date.now() - 24 * 60 * 60 * 1000) },
    });

    if (recentReport) {
      return NextResponse.json(
        {
          error: 'Ya has reportado este capítulo recientemente. Por favor espera 24 horas.',
        },
        { status: 429 }
      );
    }

    // Crear el reporte
    const report = await QualityReportModel.create({
      chapterId,
      reportedBy: session.user.id,
      issueType,
      severity,
      description,
      pageNumber,
      panelNumber,
      status: 'PENDING',
    });

    return NextResponse.json({
      success: true,
      message: 'Reporte creado exitosamente',
      report: {
        id: report._id.toString(),
        chapterId: report.chapterId,
        issueType: report.issueType,
        severity: report.severity,
        status: report.status,
        description: report.description,
        createdAt: report.createdAt,
      },
    }, { status: 201 });
  } catch (error) {
    console.error('Error creating quality report:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

// GET /api/crowdsource/report - Obtener reportes del usuario
export async function GET(request: NextRequest) {
  try {
    const session = await auth();

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'No autorizado' },
        { status: 401 }
      );
    }

    const { searchParams } = new URL(request.url);
    const chapterId = searchParams.get('chapterId');
    const status = searchParams.get('status') as 'PENDING' | 'RESOLVED' | 'DISMISSED' | null;

    await dbConnect();

    // Construir query
    const query: any = {
      reportedBy: session.user.id,
    };

    if (chapterId) {
      query.chapterId = chapterId;
    }

    if (status) {
      query.status = status;
    }

    const reports = await QualityReportModel.find(query)
      .sort({ createdAt: -1 })
      .limit(50)
      .lean();

    return NextResponse.json({
      success: true,
      reports: reports.map((r) => ({
        id: r._id.toString(),
        chapterId: r.chapterId,
        issueType: r.issueType,
        severity: r.severity,
        status: r.status,
        description: r.description,
        pageNumber: r.pageNumber,
        panelNumber: r.panelNumber,
        createdAt: r.createdAt,
        resolvedAt: r.resolvedAt,
        resolution: r.resolution,
      })),
    });
  } catch (error) {
    console.error('Error fetching user reports:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

/**
 * GET /api/crowdsource/reports
 *
 * API para listar reportes (solo para admins/moderadores).
 * Permite filtrar y obtener estadísticas de reportes.
 */

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

import { QualityReportModel } from '@/infrastructure/persistence/mongodb/models/QualityReport';
import { auth } from '@/lib/auth';
import dbConnect from '@/lib/mongoose';

// Query schema
const querySchema = z.object({
  status: z.enum(['PENDING', 'RESOLVED', 'DISMISSED']).optional(),
  severity: z.enum(['LOW', 'MEDIUM', 'HIGH']).optional(),
  issueType: z.enum(['QUALITY', 'ERROR', 'SPOILER', 'OTHER']).optional(),
  chapterId: z.string().optional(),
  limit: z.string().transform((v: any) => parseInt(v) || 20).optional(),
  offset: z.string().transform((v: any) => parseInt(v) || 0).optional(),
  sortBy: z.enum(['createdAt', 'severity', 'status']).default('createdAt'),
  sortOrder: z.enum(['asc', 'desc']).default('desc'),
});

// GET /api/crowdsource/reports - Listar reportes (admin/moderador)
export async function GET(request: NextRequest) {
  try {
    const session = await auth();

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'No autorizado' },
        { status: 401 }
      );
    }

    // Verificar que el usuario es admin o moderador
    // Aquí deberías verificar el rol del usuario
    // Por ahora, solo permitimos acceso si tiene session
    const isAdmin = session.user.role === 'ADMIN' || session.user.role === 'MODERATOR';
    if (!isAdmin) {
      return NextResponse.json(
        { error: 'No tienes permisos para ver esta información' },
        { status: 403 }
      );
    }

    // Parse query params
    const { searchParams } = new URL(request.url);
    const queryResult = querySchema.safeParse({
      status: searchParams.get('status') || undefined,
      severity: searchParams.get('severity') || undefined,
      issueType: searchParams.get('issueType') || undefined,
      chapterId: searchParams.get('chapterId') || undefined,
      limit: searchParams.get('limit') || undefined,
      offset: searchParams.get('offset') || undefined,
      sortBy: searchParams.get('sortBy') || 'createdAt',
      sortOrder: searchParams.get('sortOrder') || 'desc',
    });

    if (!queryResult.success) {
      return NextResponse.json(
        { error: 'Parámetros inválidos', details: queryResult.error.flatten() },
        { status: 400 }
      );
    }

    const { status, severity, issueType, chapterId, limit, offset, sortBy, sortOrder } = queryResult.data;

    await dbConnect();

    // Construir query
    const query: any = {};
    if (status) query.status = status;
    if (severity) query.severity = severity;
    if (issueType) query.issueType = issueType;
    if (chapterId) query.chapterId = chapterId;

    // Build sort
    const sort: any = {};
    sort[sortBy] = sortOrder === 'asc' ? 1 : -1;

    // Ejecutar queries en paralelo
    const [reports, total, stats] = await Promise.all([
      QualityReportModel.find(query)
        .sort(sort)
        .skip(offset || 0)
        .limit(limit || 20)
        .lean(),
      QualityReportModel.countDocuments(query),
      // Estadísticas de reportes
      QualityReportModel.aggregate([
        {
          $group: {
            _id: null,
            totalPending: { $sum: { $cond: [{ $eq: ['$status', 'PENDING'] }, 1, 0] } },
            totalResolved: { $sum: { $cond: [{ $eq: ['$status', 'RESOLVED'] }, 1, 0] } },
            totalDismissed: { $sum: { $cond: [{ $eq: ['$status', 'DISMISSED'] }, 1, 0] } },
            highSeverity: { $sum: { $cond: [{ $eq: ['$severity', 'HIGH'] }, 1, 0] } },
            mediumSeverity: { $sum: { $cond: [{ $eq: ['$severity', 'MEDIUM'] }, 1, 0] } },
            lowSeverity: { $sum: { $cond: [{ $eq: ['$severity', 'LOW'] }, 1, 0] } },
          },
        },
      ]),
    ]);

    const statsData = stats[0] || {
      totalPending: 0,
      totalResolved: 0,
      totalDismissed: 0,
      highSeverity: 0,
      mediumSeverity: 0,
      lowSeverity: 0,
    };

    return NextResponse.json({
      success: true,
      reports: reports.map((r: any) => ({
        id: r._id.toString(),
        chapterId: r.chapterId,
        reportedBy: r.reportedBy,
        issueType: r.issueType,
        severity: r.severity,
        description: r.description,
        status: r.status,
        pageNumber: r.pageNumber,
        panelNumber: r.panelNumber,
        createdAt: r.createdAt,
        resolvedAt: r.resolvedAt,
        resolvedBy: r.resolvedBy,
        resolution: r.resolution,
      })),
      pagination: {
        total,
        limit: limit || 20,
        offset: offset || 0,
        hasMore: (offset || 0) + (limit || 20) < total,
      },
      stats: {
        total,
        byStatus: {
          pending: statsData.totalPending,
          resolved: statsData.totalResolved,
          dismissed: statsData.totalDismissed,
        },
        bySeverity: {
          high: statsData.highSeverity,
          medium: statsData.mediumSeverity,
          low: statsData.lowSeverity,
        },
      },
    });
  } catch (error) {
    console.error('Error fetching reports:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { withRateLimit } from '@/lib/rate-limit-middleware';
import { sanitizeText } from '@/lib/sanitize';

// Schema para DMCA takedown request
const dmcaSchema = z.object({
  requesterName: z.string().min(2).max(100),
  requesterEmail: z.string().email(),
  requesterAddress: z.string().min(10).max(500),
  infringingMangaId: z.string().uuid().optional(),
  infringingChapterId: z.string().uuid().optional(),
  originalWorkUrl: z.string().url().optional(),
  originalWorkDescription: z.string().min(10).max(1000),
  goodFaithStatement: z.literal(true),
  signature: z.string().min(2).max(100),
});

// POST /api/dmca - Submit DMCA takedown request
export async function POST(request: NextRequest) {
  try {
    const body = await request.json();

    const rlResponse = await withRateLimit(request, undefined, 'dmca');
    if (rlResponse) return rlResponse;

    const result = dmcaSchema.safeParse(body);

    if (!result.success) {
      return NextResponse.json(
        { error: 'Datos inválidos', details: result.error.flatten() },
        { status: 400 }
      );
    }

    const {
      requesterName,
      requesterEmail,
      requesterAddress,
      infringingMangaId,
      infringingChapterId,
      originalWorkUrl,
      originalWorkDescription,
      signature,
    } = result.data;

    // Verificar que al menos un contenido infractor está especificado
    if (!infringingMangaId && !infringingChapterId) {
      return NextResponse.json(
        { error: 'Debes especificar el contenido infractor (manga o capítulo)' },
        { status: 400 }
      );
    }

    // Verificar rate limiting (1 DMCA cada 24 horas por IP)
    const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);
    
    const recentDMCAs = await prisma.dMCATakedown.count({
      where: {
        requesterEmail: requesterEmail.toLowerCase(),
        submittedAt: { gte: oneDayAgo },
      },
    });

    if (recentDMCAs >= 3) {
      return NextResponse.json(
        { error: 'Demasiadas solicitudes DMCA. Espera 24 horas antes de enviar otra.' },
        { status: 429 }
      );
    }

    // Verificar que el contenido existe
    if (infringingMangaId) {
      const manga = await prisma.mangaSeries.findUnique({
        where: { id: infringingMangaId },
        select: { id: true, title: true },
      });
      if (!manga) {
        return NextResponse.json(
          { error: 'Manga no encontrado' },
          { status: 404 }
        );
      }
    }

    if (infringingChapterId) {
      const chapter = await prisma.chapter.findUnique({
        where: { id: infringingChapterId },
        select: { id: true, title: true },
      });
      if (!chapter) {
        return NextResponse.json(
          { error: 'Capítulo no encontrado' },
          { status: 404 }
        );
      }
    }

    // Crear DMCA request
    const dmca = await prisma.dMCATakedown.create({
      data: {
        requesterName: sanitizeText(requesterName),
        requesterEmail: requesterEmail.toLowerCase(),
        requesterAddress: sanitizeText(requesterAddress),
        infringingContentId: infringingMangaId || infringingChapterId,
        infringingContentType: infringingMangaId ? 'MANGA' : 'CHAPTER',
        originalWorkUrl,
        originalWorkDescription: sanitizeText(originalWorkDescription),
        goodFaithStatement: true,
        signature: sanitizeText(signature),
        status: 'PENDING',
      },
    });

    // Notificar a administradores
    const admins = await prisma.user.findMany({
      where: { role: 'ADMIN' },
      select: { id: true },
    });

    for (const admin of admins) {
      await prisma.notification.create({
        data: {
          userId: admin.id,
          type: 'DMCA_REQUEST',
          title: 'Nueva solicitud DMCA',
          message: `${requesterName} ha reportado contenido infractor. Revisión requerida.`,
        },
      });
    }

    // Log de seguridad
    // console.log(`[Security] DMCA request submitted: ${dmca.id} by ${requesterEmail}`);

    return NextResponse.json({
      success: true,
      dmca: {
        id: dmca.id,
        status: dmca.status,
        submittedAt: dmca.submittedAt,
      },
      message: 'Solicitud DMCA recibida. Será revisada por nuestro equipo legal en un plazo de 48 horas.',
    });
  } catch (error) {
    console.error('Error submitting DMCA:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

// GET /api/dmca - List DMCA requests (admin only)
export async function GET(request: NextRequest) {
  try {
    const session = await auth();

    if (!session?.user?.id || session.user.role !== 'ADMIN') {
      return NextResponse.json(
        { error: 'No autorizado' },
        { status: 401 }
      );
    }

    const { searchParams } = new URL(request.url);
    const status = searchParams.get('status') || 'PENDING';
    const page = parseInt(searchParams.get('page') || '1');
    const limit = parseInt(searchParams.get('limit') || '20');

    const where: Record<string, unknown> = {};
    if (status && status !== 'ALL') {
      where.status = status;
    }

    const [dmcas, total] = await Promise.all([
      prisma.dMCATakedown.findMany({
        where,
        skip: (page - 1) * limit,
        take: limit,
        orderBy: { submittedAt: 'desc' },
      }),
      prisma.dMCATakedown.count({ where }),
    ]);

    // Estadísticas
    const stats = await prisma.dMCATakedown.groupBy({
      by: ['status'],
      _count: { status: true },
    });

    return NextResponse.json({
      dmcas,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
      },
      stats: stats.reduce((acc: any, s: any) => {
        acc[s.status] = s._count.status;
        return acc;
      }, {} as Record<string, number>),
    });
  } catch (error) {
    console.error('Error fetching DMCAs:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';

import { GetBalanceUseCase, IUserBalanceRepository } from '@/application/use-cases/economy/GetBalanceUseCase';
import { paymentService } from '@/infrastructure/adapters/paymentService';
import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { rateLimit, getRateLimitKey } from '@/lib/rate-limit';

class PrismaUserBalanceRepository implements IUserBalanceRepository {
  async findById(id: string) {
    const user = await prisma.user.findUnique({
      where: { id },
      select: {
        id: true,
        xpPoints: true,
        level: true,
      },
    });
    if (!user) return null;
    const xpLevel = Math.floor(user.xpPoints / 1000) + 1;
    const progress = user.xpPoints % 1000;
    return {
      id: user.id,
      xp: {
        amount: user.xpPoints,
        level: xpLevel,
        rank: xpLevel >= 50 ? 'Legendario' : xpLevel >= 30 ? 'Élite' : xpLevel >= 20 ? 'Maestro' : xpLevel >= 10 ? 'Avanzado' : xpLevel >= 5 ? 'Intermedio' : 'Principiante',
        progressToNextLevel: Math.round((progress / 1000) * 100),
      },
    };
  }
}

const getBalanceUseCase = new GetBalanceUseCase(
  new PrismaUserBalanceRepository(),
  paymentService
);

// GET /api/economy/balance - Obtener balance actual del usuario
export async function GET(request: NextRequest) {
  try {
    const session = await auth();

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'No autorizado' },
        { status: 401 }
      );
    }

    const ip = request.headers.get('x-forwarded-for')?.split(',')[0]?.trim() || 'unknown';
    const identifier = session?.user?.id || ip;
    const rlResult = await rateLimit(getRateLimitKey('economy-balance', identifier), 60, 60);
    if (!rlResult.allowed) {
      return NextResponse.json({ error: 'Demasiadas solicitudes. Intenta de nuevo más tarde.' }, {
        status: 429,
        headers: { 'Retry-After': String(Math.ceil((rlResult.resetAt - Date.now()) / 1000)) },
      });
    }

    const result = await getBalanceUseCase.execute({
      userId: session.user.id,
    });

    return NextResponse.json(result);
  } catch (error) {
    // console.error('Error obteniendo balance:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';

import { ListTransactionsUseCase, ITransactionQueryRepository, TransactionRecord } from '@/application/use-cases/economy/ListTransactionsUseCase';
import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { rateLimit, getRateLimitKey } from '@/lib/rate-limit';

class PrismaTransactionQueryRepository implements ITransactionQueryRepository {
  async findByUserId(
    userId: string,
    options: { skip: number; take: number; type?: string }
  ): Promise<TransactionRecord[]> {
    const where: { userId: string; type?: { in: string[] } } = {
      userId,
    };

    if (options.type === 'income') {
      where.type = {
        in: ['REGISTRATION_BONUS', 'CHAPTER_COMPLETE', 'COMMENT_POSTED', 'CORRECTION_APPROVED', 'ACHIEVEMENT_UNLOCKED', 'DAILY_STREAK', 'TIP_RECEIVED'],
      };
    } else if (options.type === 'expense') {
      where.type = {
        in: ['TIP_SENT', 'SPONSORSHIP_BID', 'CROWDFUND_CONTRIBUTE'],
      };
    }

    const transactions = await prisma.transaction.findMany({
      where,
      skip: options.skip,
      take: options.take,
      orderBy: { timestamp: 'desc' },
    });

    return transactions.map((t: any) => ({
      id: t.id,
      amount: t.amount,
      type: t.type,
      description: t.description,
      referenceId: t.referenceId,
      timestamp: t.timestamp,
    }));
  }

  async countByUserId(userId: string, type?: string): Promise<number> {
    const where: { userId: string; type?: { in: string[] } } = {
      userId,
    };

    if (type === 'income') {
      where.type = {
        in: ['REGISTRATION_BONUS', 'CHAPTER_COMPLETE', 'COMMENT_POSTED', 'CORRECTION_APPROVED', 'ACHIEVEMENT_UNLOCKED', 'DAILY_STREAK', 'TIP_RECEIVED'],
      };
    } else if (type === 'expense') {
      where.type = {
        in: ['TIP_SENT', 'SPONSORSHIP_BID', 'CROWDFUND_CONTRIBUTE'],
      };
    }

    return prisma.transaction.count({ where });
  }

  async getBalance(userId: string): Promise<number> {
    const user = await prisma.user.findUnique({
      where: { id: userId },
      select: { inkcoinsBalance: true },
    });
    return user?.inkcoinsBalance || 0;
  }
}

const listTransactionsUseCase = new ListTransactionsUseCase(
