import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { withRateLimit } from '@/lib/rate-limit-middleware';

const createEventSchema = z.object({
  title: z.string().min(3).max(200),
  description: z.string().min(1).max(2000),
  type: z.enum(['ART_CHALLENGE', 'SPEEDREADING', 'COMMUNITY']).default('ART_CHALLENGE'),
  basePrompt: z.string().max(5000).optional(),
  prize: z.string().min(1).max(200),
  startDate: z.string().datetime(),
  endDate: z.string().datetime(),
  imageUrl: z.string().url().optional(),
  color: z.string().optional(),
  borderColor: z.string().optional(),
});

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = request.nextUrl;
    const status = searchParams.get('status') || 'ACTIVE';
    const type = searchParams.get('type');
    const search = searchParams.get('search') || '';
    const page = parseInt(searchParams.get('page') || '1', 10);
    const limit = parseInt(searchParams.get('limit') || '20', 10);
    const includeVoting = searchParams.get('includeVoting') === 'true';
    const skip = (page - 1) * limit;

    // Support comma-separated statuses for 'PAST' (COMPLETED,CANCELLED)
    const statuses = status.split(',').filter(Boolean);
    const where: any = {};
    if (statuses.length === 1) where.status = statuses[0];
    else if (statuses.length > 1) where.status = { in: statuses };
    if (type) where.type = type;
    if (search) where.title = { contains: search, mode: 'insensitive' };

    const now = new Date();
    if (status === 'ACTIVE') {
      where.startDate = { lte: now };
      where.endDate = { gte: now };
    } else if (status === 'VOTING') {
      where.endDate = { lt: now };
      where.status = 'VOTING';
    } else if (status === 'PAST') {
      where.status = 'COMPLETED';
    }

    const [events, total, votingEvent] = await Promise.all([
      prisma.event.findMany({
        where,
        orderBy: { endDate: 'asc' },
        skip,
        take: limit,
        include: {
          creator: {
            select: { id: true, username: true, displayName: true, avatarUrl: true },
          },
          _count: { select: { submissions: true } },
        },
      }),
      prisma.event.count({ where }),
      includeVoting
        ? prisma.event.findFirst({
            where: { status: 'VOTING' },
            include: {
              _count: { select: { submissions: true } },
              submissions: {
                include: {
                  user: {
                    select: { id: true, username: true, displayName: true, avatarUrl: true },
                  },
                },
                orderBy: { votes: 'desc' },
              },
            },
          })
        : Promise.resolve(null),
    ]);

    return NextResponse.json({
      events,
      voting: votingEvent
        ? {
            event: votingEvent,
            submissions: votingEvent.submissions,
          }
        : null,
      pagination: { page, limit, total, totalPages: Math.ceil(total / limit) },
    });
  } catch (error) {
    console.error('[Events] GET error:', error);
    return NextResponse.json({ error: 'Error al obtener eventos' }, { status: 500 });
  }
}

export async function POST(request: NextRequest) {
  try {
    const session = await auth();
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'No autorizado' }, { status: 401 });
    }

    const rlResponse = await withRateLimit(request, session?.user?.id, 'default');
    if (rlResponse) return rlResponse;

    const role = session.user.role;
    if (role !== 'ADMIN' && role !== 'CREATOR') {
      return NextResponse.json({ error: 'Solo admins o creadores pueden crear eventos' }, { status: 403 });
    }

    const body = await request.json();
    const data = createEventSchema.parse(body);

    const event = await prisma.event.create({
      data: {
        title: data.title,
        description: data.description,
        type: data.type,
        basePrompt: data.basePrompt,
        prize: data.prize,
        startDate: new Date(data.startDate),
        endDate: new Date(data.endDate),
        imageUrl: data.imageUrl,
        color: data.color,
        borderColor: data.borderColor,
        createdBy: session.user.id,
      },
      include: {
        creator: {
          select: { id: true, username: true, displayName: true, avatarUrl: true },
        },
      },
    });

    return NextResponse.json({ event }, { status: 201 });
  } catch (error) {
    if (error instanceof z.ZodError) {
      return NextResponse.json({ error: 'Datos inválidos', details: error.issues }, { status: 400 });
    }
    console.error('[Events] POST error:', error);
    return NextResponse.json({ error: 'Error al crear evento' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';

import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

// GET /api/feed - Get activity feed
export async function GET(request: NextRequest) {
  try {
    const session = await auth();

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'No autorizado' },
        { status: 401 }
      );
    }

    const { searchParams } = new URL(request.url);
    const type = searchParams.get('type') || 'ALL'; // ALL, READING, SOCIAL, MINE
    const page = parseInt(searchParams.get('page') || '1');
    const limit = parseInt(searchParams.get('limit') || '20');
    const skip = (page - 1) * limit;

    const userId = session.user.id;
    let where: Record<string, unknown> = { isPublic: true };

    if (type === 'MINE') {
      // User's own activities
      where = { userId };
    } else if (type === 'SOCIAL') {
      // Activities from followed users
      const following = await prisma.follow.findMany({
        where: { followerId: userId, followingType: 'USER' },
        select: { followingId: true },
      });
      const followingIds = following.map((f: any) => f.followingId);
      where = {
        userId: { in: [...followingIds, userId] },
        isPublic: true,
      };
    }

    // If type is READING, filter only reading activities
    if (type === 'READING') {
      where = {
        ...where,
        activityType: { in: ['READ_CHAPTER', 'COMPLETED_MANGA'] },
      };
    }

    const [activities, total] = await Promise.all([
      prisma.activity.findMany({
        where,
        skip,
        take: limit,
        orderBy: { createdAt: 'desc' },
        include: {
          user: {
            select: {
              id: true,
              username: true,
              displayName: true,
              avatarUrl: true,
            },
          },
        },
      }),
      prisma.activity.count({ where }),
    ]);

    // Enrich with target data
    const enriched = await Promise.all(
      activities.map(async (activity: any) => {
        let target = null;

        if (activity.targetId) {
          if (activity.targetType === 'MANGA') {
            target = await prisma.mangaSeries.findUnique({
              where: { id: activity.targetId },
              select: {
                id: true,
                title: true,
                coverUrl: true,
                slug: true,
              },
            });
          } else if (activity.targetType === 'USER') {
            target = await prisma.user.findUnique({
              where: { id: activity.targetId },
              select: {
                id: true,
                username: true,
                displayName: true,
                avatarUrl: true,
              },
            });
          }
        }

        // Parse metadata
        let metadata = {};
        try {
          if (activity.metadata) {
            metadata = JSON.parse(activity.metadata);
          }
        } catch {
          // Ignore parse errors
        }

        // Generate message based on activity type
        let message = '';
        switch (activity.activityType) {
          case 'READ_CHAPTER':
            message = `leyó el capítulo ${(metadata as any).chapterNumber || ''} de`;
            break;
          case 'FOLLOW_USER':
            message = 'comenzó a seguir a';
            break;
          case 'FOLLOW_MANGA':
            message = 'comenzó a seguir';
            break;
          case 'COMMENT':
            message = 'comentó en';
            break;
          case 'ACHIEVEMENT_UNLOCKED':
            message = 'desbloqueó el logro';
            break;
          case 'COMPLETED_MANGA':
            message = 'completó';
            break;
          case 'JOINED_CLAN':
            message = 'se unió al clan';
            break;
          case 'CREATED_MANGA':
            message = 'publicó un nuevo manga';
            break;
          default:
            message = activity.activityType.toLowerCase().replace(/_/g, ' ');
        }

        return {
          id: activity.id,
          type: activity.activityType,
          message,
          user: activity.user,
          target,
          metadata,
          createdAt: activity.createdAt,
        };
      })
    );

    return NextResponse.json({
      activities: enriched,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
      },
    });
  } catch (error) {
    console.error('Error fetching feed:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

