export async function GET(request: NextRequest) {
  try {
    const { searchParams } = request.nextUrl;
    const categorySlug = searchParams.get('category');
    const page = parseInt(searchParams.get('page') || '1', 10);
    const limit = parseInt(searchParams.get('limit') || '20', 10);
    const skip = (page - 1) * limit;

    const where: any = {};
    if (categorySlug) {
      const category = await prisma.forumCategory.findUnique({
        where: { slug: categorySlug },
      });
      if (category) where.categoryId = category.id;
    }

    const [threads, total] = await Promise.all([
      prisma.forumThread.findMany({
        where,
        orderBy: [{ isPinned: 'desc' }, { createdAt: 'desc' }],
        skip,
        take: limit,
        include: {
          author: {
            select: { id: true, username: true, displayName: true, avatarUrl: true, role: true },
          },
          category: { select: { id: true, name: true, slug: true, icon: true } },
          _count: { select: { posts: true } },
        },
      }),
      prisma.forumThread.count({ where }),
    ]);

    return NextResponse.json({
      threads,
      pagination: { page, limit, total, totalPages: Math.ceil(total / limit) },
    });
  } catch (error) {
    console.error('[Forum Threads] GET error:', error);
    return NextResponse.json({ error: 'Error al obtener hilos' }, { status: 500 });
  }
}

export async function POST(request: NextRequest) {
  try {
    const session = await auth();
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'No autorizado' }, { status: 401 });
    }

    const rlResponse = await withRateLimit(request, session?.user?.id, 'default');
    if (rlResponse) return rlResponse;

    const role = session.user.role;
    if (role !== 'CREATOR' && role !== 'ADMIN') {
      return NextResponse.json({ error: 'Solo creadores pueden crear hilos' }, { status: 403 });
    }

    const body = await request.json();
    const data = createThreadSchema.parse(body);

    const category = await prisma.forumCategory.findUnique({
      where: { id: data.categoryId },
    });
    if (!category) {
      return NextResponse.json({ error: 'Categoría no encontrada' }, { status: 404 });
    }

    const slug = data.title
      .toLowerCase()
      .replace(/[^a-z0-9áéíóúñü]+/g, '-')
      .replace(/^-|-$/g, '')
      + '-' + Date.now().toString(36);

    const thread = await prisma.forumThread.create({
      data: {
        title: data.title,
        slug,
        content: data.content,
        categoryId: data.categoryId,
        authorId: session.user.id,
        tags: JSON.stringify(data.tags || []),
      },
      include: {
        author: {
          select: { id: true, username: true, displayName: true, avatarUrl: true, role: true },
        },
        category: { select: { id: true, name: true, slug: true } },
      },
    });

    return NextResponse.json({ thread }, { status: 201 });
  } catch (error) {
    if (error instanceof z.ZodError) {
      return NextResponse.json({ error: 'Datos inválidos', details: error.issues }, { status: 400 });
    }
    console.error('[Forum Threads] POST error:', error);
    return NextResponse.json({ error: 'Error al crear hilo' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { z } from 'zod';

import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { rateLimit, getRateLimitKey } from '@/lib/rate-limit';

const sponsorSchema = z.object({
  chapterId: z.string().min(1),
  bidAmount: z.number().int().positive(),
});

export async function POST(request: Request) {
  try {
    const session = await auth();
    if (!session?.user?.id) {
      return NextResponse.json({ success: false, error: 'No autorizado' }, { status: 401 });
    }

    const ip = request.headers.get('x-forwarded-for')?.split(',')[0]?.trim() || 'unknown';
    const identifier = session?.user?.id || ip;
    const rlResult = await rateLimit(getRateLimitKey('gamification-sponsor', identifier), 10, 60);
    if (!rlResult.allowed) {
      return NextResponse.json({ error: 'Demasiadas solicitudes. Intenta de nuevo más tarde.' }, {
        status: 429,
        headers: { 'Retry-After': String(Math.ceil((rlResult.resetAt - Date.now()) / 1000)) },
      });
    }

    const body = await request.json();
    const parsed = sponsorSchema.safeParse(body);
    if (!parsed.success) {
      return NextResponse.json(
        { success: false, error: 'Datos inválidos', details: parsed.error.issues },
        { status: 400 }
      );
    }

    const { chapterId, bidAmount } = parsed.data;
    const userId = session.user.id;

    const result = await prisma.$transaction(async (tx: any) => {
      const user = await tx.user.findUnique({ where: { id: userId } });
      if (!user) throw new Error('User not found');
      if (user.inkcoinsBalance < bidAmount) throw new Error('Insufficient InkCoins balance');

      const chapter = await tx.chapter.findUnique({ where: { id: chapterId } });
      if (!chapter) throw new Error('Chapter not found');

      const updatedUser = await tx.user.update({
        where: { id: userId },
        data: { inkcoinsBalance: user.inkcoinsBalance - bidAmount }
      });

      const bid = await tx.sponsorshipBid.create({
        data: { userId, chapterId, bidAmount, status: 'active' }
      });

      await tx.transaction.create({
        data: { userId, amount: -bidAmount, type: 'bid', referenceId: bid.id }
      });

      return { bid, remainingBalance: updatedUser.inkcoinsBalance };
    });

    return NextResponse.json({ success: true, data: result });
  } catch (error: any) {
    if (error.message === 'Insufficient InkCoins balance' || error.message === 'Chapter not found') {
      return NextResponse.json({ success: false, error: error.message }, { status: 400 });
    }
    console.error('Error processing sponsor bid:', error);
    return NextResponse.json({ success: false, error: 'Internal Server Error' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { z } from 'zod';

import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { rateLimit, getRateLimitKey } from '@/lib/rate-limit';

const transactionSchema = z.object({
  amount: z.number().int(),
  type: z.string().min(1).max(50),
  referenceId: z.string().optional(),
});

export async function POST(request: Request) {
  try {
    const session = await auth();
    if (!session?.user?.id) {
      return NextResponse.json({ success: false, error: 'No autorizado' }, { status: 401 });
    }

    const ip = request.headers.get('x-forwarded-for')?.split(',')[0]?.trim() || 'unknown';
    const identifier = session?.user?.id || ip;
    const rlResult = await rateLimit(getRateLimitKey('gamification-transaction', identifier), 30, 60);
    if (!rlResult.allowed) {
      return NextResponse.json({ error: 'Demasiadas solicitudes. Intenta de nuevo más tarde.' }, {
        status: 429,
        headers: { 'Retry-After': String(Math.ceil((rlResult.resetAt - Date.now()) / 1000)) },
      });
    }

    const body = await request.json();
    const parsed = transactionSchema.safeParse(body);
    if (!parsed.success) {
      return NextResponse.json(
        { success: false, error: 'Datos inválidos', details: parsed.error.issues },
        { status: 400 }
      );
    }

    const { amount, type, referenceId } = parsed.data;
    const userId = session.user.id;

    const result = await prisma.$transaction(async (tx: any) => {
      const user = await tx.user.findUnique({ where: { id: userId } });
      if (!user) throw new Error('User not found');

      if (amount < 0 && user.inkcoinsBalance < Math.abs(amount)) {
        throw new Error('Insufficient InkCoins balance');
      }

      const newBalance = user.inkcoinsBalance + amount;

      const transaction = await tx.transaction.create({
        data: { userId, amount, type, referenceId }
      });

      const updatedUser = await tx.user.update({
        where: { id: userId },
        data: { inkcoinsBalance: newBalance }
      });

      return { transaction, balance: updatedUser.inkcoinsBalance };
    });

    return NextResponse.json({ success: true, data: result });
  } catch (error: any) {
    if (error.message === 'Insufficient InkCoins balance') {
      return NextResponse.json({ success: false, error: error.message }, { status: 400 });
    }
    console.error('Error processing transaction:', error);
    return NextResponse.json({ success: false, error: 'Internal Server Error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

import { XP } from '@/core/value-objects/XP';
import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { rateLimit, getRateLimitKey } from '@/lib/rate-limit';

const addXPSchema = z.object({
  amount: z.number().int().min(1).max(1000),
  reason: z.string().min(1).max(100),
  referenceId: z.string().optional(),
});

// POST /api/gamification/xp - Agregar XP a usuario
export async function POST(request: NextRequest) {
  try {
    const session = await auth();

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'No autorizado' },
        { status: 401 }
      );
    }

    const ip = request.headers.get('x-forwarded-for')?.split(',')[0]?.trim() || 'unknown';
    const identifier = session?.user?.id || ip;
    const rlResult = await rateLimit(getRateLimitKey('gamification-xp', identifier), 30, 60);
    if (!rlResult.allowed) {
      return NextResponse.json({ error: 'Demasiadas solicitudes. Intenta de nuevo más tarde.' }, {
        status: 429,
        headers: { 'Retry-After': String(Math.ceil((rlResult.resetAt - Date.now()) / 1000)) },
      });
    }

    const body = await request.json();
    const result = addXPSchema.safeParse(body);

    if (!result.success) {
      return NextResponse.json(
        { error: 'Datos inválidos', details: result.error.flatten() },
        { status: 400 }
      );
    }

    const { amount, reason: _reason, referenceId: _referenceId } = result.data;

    // Obtener usuario actual
    const user = await prisma.user.findUnique({
      where: { id: session.user.id },
      select: { id: true, xpPoints: true, level: true },
    });

    if (!user) {
      return NextResponse.json(
        { error: 'Usuario no encontrado' },
        { status: 404 }
      );
    }

    // Calcular nuevo XP y nivel
    const currentXP = XP.create(user.xpPoints);
    const addedXP = XP.create(amount);
    const newXP = currentXP.add(addedXP);
    const newLevel = newXP.level;

    // Actualizar usuario
    await prisma.user.update({
      where: { id: user.id },
      data: {
        xpPoints: newXP.amount,
        level: newLevel,
      },
    });

    // Registrar transacción de XP (opcional, para auditoría)
    // Aquí podríamos guardar en MongoDB un log del XP ganado

    return NextResponse.json({
      success: true,
      xpEarned: amount,
      totalXP: newXP.amount,
      oldLevel: user.level,
      newLevel: newLevel,
      levelUp: newLevel > user.level,
      rank: newXP.rank,
      progressToNextLevel: newXP.progressToNextLevel,
      xpToNextLevel: newXP.xpToNextLevel,
    });
  } catch (error) {
    console.error('Error agregando XP:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

