/**
 * Library API
 * 
 * GET: Lista de biblioteca del usuario con filtros
 * POST: Agregar manga a la biblioteca
 */

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

import { auth } from '@/lib/auth';
import { generateCacheKey, getCache, setCache, invalidateUserCache } from '@/lib/cache';
import { prisma } from '@/lib/prisma';
import { rateLimit, getRateLimitKey } from '@/lib/rate-limit';


const CACHE_TTL = 60;

// Validation schema
const addToLibrarySchema = z.object({
  mangaId: z.string().uuid(),
  status: z.enum(['READING', 'COMPLETED', 'ON_HOLD', 'DROPPED', 'PLAN_TO_READ']).default('READING'),
});

/**
 * GET /api/library
 * Query params:
 * - status: filter by status
 * - sort: recent_update|progress|rating|title
 * - page, limit: pagination
 */
export async function GET(request: NextRequest) {
  const session = await auth();
  if (!session?.user?.id) {
    return Response.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const { searchParams } = new URL(request.url);
  const status = searchParams.get('status');
  const sort = searchParams.get('sort') || 'updatedAt';
  const page = Math.max(1, parseInt(searchParams.get('page') || '1'));
  const limit = Math.min(50, Math.max(1, parseInt(searchParams.get('limit') || '24')));

  // Generate cache key
  const cacheKey = generateCacheKey('library', { userId: session.user.id, status, sort, page, limit });
  
  // Try cache
  const cached = await getCache(cacheKey);
  if (cached) {
    return Response.json(cached, {
      headers: {
        'Cache-Control': 'private, max-age=60',
        'X-Cache': 'HIT',
      },
    });
  }

  try {
    const where = {
      userId: session.user.id,
      ...(status && { status }),
    };

    // Build orderBy based on sort
    const orderBy: any = { updatedAt: 'desc' };
    switch (sort) {
      case 'title':
        orderBy.manga = { title: 'asc' };
        break;
      case 'rating':
        orderBy.rating = 'desc';
        break;
      case 'progress':
        orderBy.currentChapter = 'desc';
        break;
    }

    const [entries, total] = await Promise.all([
      prisma.userLibrary.findMany({
        where,
        include: {
          manga: {
            select: {
              id: true,
              title: true,
              slug: true,
              coverUrl: true,
              status: true,
              authorName: true,
              totalViews: true,
              rating: true,
              chapters: {
                select: { id: true, chapterNumber: true },
                orderBy: { chapterNumber: 'desc' },
                take: 1,
              },
            },
          },
        },
        orderBy,
        skip: (page - 1) * limit,
        take: limit,
      }),
      prisma.userLibrary.count({ where }),
    ]);

    // Enrich with latest chapter info
    const enrichedEntries = entries.map((entry: any) => ({
      id: entry.id,
      mangaId: entry.mangaId,
      status: entry.status,
      currentChapter: entry.currentChapter,
      rating: entry.rating,
      addedAt: entry.addedAt,
      updatedAt: entry.updatedAt,
      manga: entry.manga,
      totalChapters: entry.manga.chapters.length,
      progress: entry.manga.chapters[0] 
        ? Math.round((entry.currentChapter / entry.manga.chapters[0].chapterNumber) * 100)
        : 0,
    }));

    const result = {
      entries: enrichedEntries,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
        hasNextPage: page * limit < total,
        hasPrevPage: page > 1,
      },
    };

    // Cache the result
    await setCache(cacheKey, result, CACHE_TTL);

    return Response.json(result, {
      headers: {
        'Cache-Control': 'private, max-age=60',
        'X-Cache': 'MISS',
      },
    });
  } catch (error) {
    console.error('Error fetching library:', error);
    return Response.json({ error: 'Failed to fetch library' }, { status: 500 });
  }
}

/**
 * POST /api/library
 * Body: { mangaId: string, status?: string }
 */
export async function POST(request: NextRequest) {
  const session = await auth();
  if (!session?.user?.id) {
    return Response.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const userId = session?.user?.id || 'anonymous';
  const { allowed } = await rateLimit(getRateLimitKey('library', userId), 20, 60);
  if (!allowed) {
    return NextResponse.json({ error: 'Too many requests' }, { status: 429 });
  }

  try {
    const body = await request.json();
    const { mangaId, status } = addToLibrarySchema.parse(body);

    // Check if manga exists
    const manga = await prisma.mangaSeries.findUnique({
      where: { id: mangaId },
      select: { id: true },
    });

    if (!manga) {
      return Response.json({ error: 'Manga not found' }, { status: 404 });
    }

    // Upsert library entry
    const entry = await prisma.userLibrary.upsert({
      where: {
        userId_mangaId: {
          userId: session.user.id,
          mangaId,
        },
      },
      update: {
        status,
        updatedAt: new Date(),
      },
      create: {
        userId: session.user.id,
        mangaId,
        status,
      },
      include: {
        manga: {
          select: {
            id: true,
            title: true,
            slug: true,
            coverUrl: true,
          },
        },
      },
    });

    // Invalidate library cache
    await invalidateUserCache(session.user.id);

    return Response.json(entry, { status: 201 });
  } catch (error) {
if (error instanceof z.ZodError) {
return Response.json({ error: 'Invalid input', details: error.issues }, { status: 400 });
    }
    console.error('Error adding to library:', error);
    return Response.json({ error: 'Failed to add to library' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';

import { getNotificationService } from '@/core/services/NotificationService';
import { withCache, generateCacheKey, cacheConfig, invalidateCache } from '@/lib/apiCache';
import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { withRateLimit } from '@/lib/rate-limit-middleware';

// GET /api/manga/[id]/chapters - Listar capítulos del manga
export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;

    // Verificar que el manga existe
    const manga = await prisma.mangaSeries.findUnique({
      where: { id },
      select: { id: true },
    });

    if (!manga) {
      return NextResponse.json(
        { error: 'Manga no encontrado' },
        { status: 404 }
      );
    }

    const { searchParams } = new URL(request.url);
    const page = parseInt(searchParams.get('page') || '1');
    const limit = parseInt(searchParams.get('limit') || '50');

    // Generate cache key
    const cacheKey = generateCacheKey('manga:chapters:list', {
      mangaId: id,
      page,
      limit,
    });

    const result = await withCache(
      cacheKey,
      cacheConfig.manga.list.ttl,
      async () => {
        const [chapters, total] = await Promise.all([
          prisma.chapter.findMany({
            where: { mangaId: id },
            skip: (page - 1) * limit,
            take: limit,
            orderBy: { chapterNumber: 'asc' },
            select: {
              id: true,
              chapterNumber: true,
              title: true,
              totalPages: true,
              createdAt: true,
              viewCount: true,
              crowdfundingGoal: true,
              crowdfundingCurrent: true,
              isCrowdfunded: true,
            },
          }),
          prisma.chapter.count({ where: { mangaId: id } }),
        ]);

        return {
          chapters: chapters.map((ch: any) => ({
            id: ch.id,
            chapterNumber: ch.chapterNumber,
            title: ch.title,
            totalPages: ch.totalPages,
            createdAt: ch.createdAt,
            viewCount: ch.viewCount,
            crowdfunding: ch.crowdfundingGoal
              ? {
                  goal: ch.crowdfundingGoal,
                  current: ch.crowdfundingCurrent,
                  isFunded: ch.isCrowdfunded,
                  progress: Math.round((ch.crowdfundingCurrent / ch.crowdfundingGoal) * 100),
                }
              : null,
          })),
          pagination: {
            page,
            limit,
            total,
            totalPages: Math.ceil(total / limit),
          },
        };
      }
    );

    // Add cache headers
    const response = NextResponse.json(result);
    response.headers.set('Cache-Control', 'public, s-maxage=60, stale-while-revalidate=300');
    return response;
  } catch (error) {
    console.error('Error listando capítulos:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

// POST /api/manga/[id]/chapters - Crear capítulo
export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const session = await auth();

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'No autorizado' },
        { status: 401 }
      );
    }

    const rlResponse = await withRateLimit(request, session?.user?.id, 'default');
    if (rlResponse) return rlResponse;

    const { id } = await params;
    const body = await request.json();
    const { chapterNumber, title, pageUrls } = body;

    // Verificar que el manga existe y el usuario es el autor
    const manga = await prisma.mangaSeries.findUnique({
      where: { id },
      select: { authorId: true, title: true },
    });

    if (!manga) {
      return NextResponse.json(
        { error: 'Manga no encontrado' },
        { status: 404 }
      );
    }

    if (manga.authorId !== session.user.id && session.user.role !== 'ADMIN') {
      return NextResponse.json(
        { error: 'No tienes permisos para agregar capítulos a este manga' },
        { status: 403 }
      );
    }

    // Validaciones
    if (chapterNumber === undefined || chapterNumber === null) {
      return NextResponse.json(
        { error: 'El número de capítulo es requerido' },
        { status: 400 }
      );
    }

    const chapterNum = parseInt(chapterNumber);
    if (isNaN(chapterNum) || chapterNum < 1) {
      return NextResponse.json(
        { error: 'El número de capítulo debe ser un entero positivo' },
        { status: 400 }
      );
    }

    // Verificar que chapterNumber sea único
    const existingChapter = await prisma.chapter.findUnique({
      where: {
        mangaId_chapterNumber: {
          mangaId: id,
          chapterNumber: chapterNum,
        },
      },
    });

    if (existingChapter) {
      return NextResponse.json(
        { error: `El capítulo ${chapterNum} ya existe en este manga` },
        { status: 409 }
      );
    }

    // Validar pageUrls
    if (!pageUrls || !Array.isArray(pageUrls) || pageUrls.length === 0) {
      return NextResponse.json(
        { error: 'Debe proporcionar al menos una página (pageUrls)' },
        { status: 400 }
      );
    }

    // Validar que todas las URLs sean strings válidos
    const validUrls = pageUrls.filter((url: string) => typeof url === 'string' && url.trim() !== '');
    if (validUrls.length === 0) {
      return NextResponse.json(
        { error: 'Las URLs de páginas deben ser strings válidos' },
        { status: 400 }
      );
    }

    // Calcular totalPages automáticamente
    const totalPages = validUrls.length;

    // Crear el capítulo
    const chapter = await prisma.chapter.create({
      data: {
        mangaId: id,
        chapterNumber: chapterNum,
        title: title || null,
        totalPages,
        pageUrls: JSON.stringify(validUrls),
      },
    });

    // Actualizar la fecha de actualización del manga
    await prisma.mangaSeries.update({
      where: { id },
      data: { updatedAt: new Date() },
    });

    // Invalidar caches
    await invalidateCache('manga:chapters:list');
    await invalidateCache(`manga:${id}`);
    await invalidateCache('user:mangas:list');

    // Notificar a seguidores del manga
    try {
      const followers = await prisma.userManga.findMany({
        where: { mangaId: id },
        include: { user: { select: { id: true, email: true, username: true } } },
      });

      if (followers.length > 0) {
        const mangaData = await prisma.mangaSeries.findUnique({
          where: { id },
        });

        if (mangaData) {
          // Notificacion push
          const followerIds = followers.map((f: any) => f.userId);
          (await getNotificationService()).notifyMultiple(
            followerIds,
            {
              type: 'NEW_CHAPTER',
              title: '📖 Nuevo Capítulo',
              message: `${mangaData.title} - Capítulo ${chapterNum}${title ? `: ${title}` : ''}`,
              data: {
                mangaId: id,
                mangaTitle: mangaData.title,
                chapterId: chapter.id,
                chapterNumber: chapterNum,
                chapterTitle: title,
                coverUrl: mangaData.coverUrl,
              },
              imageUrl: mangaData.coverUrl || undefined,
              linkUrl: `/manga/${mangaData.slug}/chapter/${chapterNum}`,
            }
          ).catch(err => console.error('Error notifying followers:', err));

          // Emails a seguidores (asincrono)
          const { getEmailQueue } = await import('@/infrastructure/queue/EmailQueue');
          const emailQueue = getEmailQueue();

          // Procesar en lotes de 50 para evitar sobrecarga
          const batchSize = 50;
          for (let i = 0; i < followers.length; i += batchSize) {
            const batch = followers.slice(i, i + batchSize);
            await Promise.all(
              batch.map((follower: any) =>
                emailQueue.addNewChapterEmail({
                  to: follower.user.email,
                  userId: follower.user.id,
                  username: follower.user.username,
                  mangaId: id,
                  mangaTitle: mangaData.title,
                  mangaSlug: mangaData.slug,
                  mangaCoverUrl: mangaData.coverUrl,
                  chapterId: chapter.id,
                  chapterNumber: chapterNum,
                  chapterTitle: title || undefined,
                }).catch(err => {
                  console.error(`[NewChapter] Error queueing email for ${follower.user.email}:`, err);
                })
              )
            );
          }
        }
      }
    } catch (notifyError) {
      console.error('Error notifying followers of new chapter:', notifyError);
    }

    return NextResponse.json(
      {
        message: 'Capítulo creado exitosamente',
        chapter: {
          id: chapter.id,
          mangaId: chapter.mangaId,
          chapterNumber: chapter.chapterNumber,
          title: chapter.title,
          totalPages: chapter.totalPages,
          pageUrls: validUrls,
          createdAt: chapter.createdAt,
          viewCount: chapter.viewCount,
        },
      },
      { status: 201 }
    );
  } catch (error) {
    console.error('Error creando capítulo:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';

import { invalidateCache } from '@/lib/apiCache';
import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { withRateLimit } from '@/lib/rate-limit-middleware';

// Helper para generar slug
function generateSlug(title: string): string {
  return title
    .toLowerCase()
    .trim()
    .replace(/[^\w\s-]/g, '')
    .replace(/\s+/g, '-')
    .substring(0, 100);
}

// GET /api/manga/[id] - Obtener manga con sus capítulos
export async function GET(
  _request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;

    const manga = await prisma.mangaSeries.findUnique({
      where: { id },
    });

    if (!manga) {
      return NextResponse.json(
        { error: 'Manga no encontrado' },
        { status: 404 }
      );
    }

    // Obtener capítulos del manga
    const chapters = await prisma.chapter.findMany({
      where: { mangaId: id },
      orderBy: { chapterNumber: 'asc' },
      select: {
        id: true,
        chapterNumber: true,
        title: true,
        totalPages: true,
        createdAt: true,
        viewCount: true,
        crowdfundingGoal: true,
        crowdfundingCurrent: true,
        isCrowdfunded: true,
      },
    });

    // Incrementar views (fire and forget, no await to not block response)
    prisma.mangaSeries.update({
      where: { id },
      data: { totalViews: { increment: 1 } },
    }).catch(err => console.error('[Manga] View count increment failed:', err));

    // Add cache headers for stale-while-revalidate
    const response = NextResponse.json({
      id: manga.id,
      title: manga.title,
      slug: manga.slug,
      description: manga.description,
      coverUrl: manga.coverUrl,
      status: manga.status,
      tags: manga.tags ? JSON.parse(manga.tags) : [],
      authorId: manga.authorId,
      authorName: manga.authorName,
      rating: manga.rating,
      totalViews: manga.totalViews + 1,
      createdAt: manga.createdAt,
      updatedAt: manga.updatedAt,
      chapters: chapters.map((ch: any) => ({
        id: ch.id,
        chapterNumber: ch.chapterNumber,
        title: ch.title,
        totalPages: ch.totalPages,
        createdAt: ch.createdAt,
        viewCount: ch.viewCount,
        crowdfunding: ch.crowdfundingGoal
          ? {
              goal: ch.crowdfundingGoal,
              current: ch.crowdfundingCurrent,
              isFunded: ch.isCrowdfunded,
              progress: Math.round((ch.crowdfundingCurrent / ch.crowdfundingGoal) * 100),
            }
          : null,
      })),
    });

  // Set cache headers for stale-while-revalidate
  response.headers.set('Cache-Control', 'public, s-maxage=60, stale-while-revalidate=300');
  response.headers.set('X-Cache-Tag', 'manga:' + id);

  return response;
  } catch (error) {
    console.error('Error obteniendo manga:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

// PUT /api/manga/[id] - Actualizar manga (solo owner)
export async function PUT(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const session = await auth();

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'No autorizado' },
        { status: 401 }
      );
    }

    const rlResponse = await withRateLimit(request, session.user.id, 'default');
    if (rlResponse) return rlResponse;

    const { id } = await params;
    const body = await request.json();

    // Verificar que el manga existe
    const manga = await prisma.mangaSeries.findUnique({
      where: { id },
      select: { authorId: true, slug: true },
    });

    if (!manga) {
      return NextResponse.json(
        { error: 'Manga no encontrado' },
        { status: 404 }
      );
    }

    // Verificar ownership
    if (manga.authorId !== session.user.id && session.user.role !== 'ADMIN') {
      return NextResponse.json(
        { error: 'No tienes permisos para editar este manga' },
        { status: 403 }
      );
    }

    // Validar campos si están presentes
    if (body.title && (typeof body.title !== 'string' || body.title.trim().length === 0)) {
      return NextResponse.json(
        { error: 'El título no puede estar vacío' },
        { status: 400 }
      );
    }

    // Preparar datos de actualización
    const updateData: Record<string, unknown> = {};

    if (body.title !== undefined) {
      updateData.title = body.title.trim();
      // Regenerar slug si cambia el título
      const baseSlug = generateSlug(body.title);
      let newSlug = baseSlug;
      let counter = 1;

      while (
        await prisma.mangaSeries.findFirst({
          where: { slug: newSlug, id: { not: id } },
        })
      ) {
        newSlug = `${baseSlug}-${counter}`;
        counter++;
      }
      updateData.slug = newSlug;
    }

    if (body.description !== undefined) {
      updateData.description = body.description;
    }

    if (body.coverUrl !== undefined) {
      updateData.coverUrl = body.coverUrl;
    }

    if (body.status !== undefined) {
      const validStatuses = ['ONGOING', 'COMPLETED', 'HIATUS', 'CANCELLED'];
      if (!validStatuses.includes(body.status.toUpperCase())) {
        return NextResponse.json(
          { error: 'Estado inválido. Valores permitidos: ONGOING, COMPLETED, HIATUS, CANCELLED' },
          { status: 400 }
        );
      }
      updateData.status = body.status.toUpperCase();
    }

    if (body.tags !== undefined) {
      if (Array.isArray(body.tags)) {
        updateData.tags = JSON.stringify(body.tags.map((t: string) => t.toLowerCase().trim()));
      } else {
        return NextResponse.json(
          { error: 'Las etiquetas deben ser un array' },
          { status: 400 }
        );
      }
    }

    const updated = await prisma.mangaSeries.update({
      where: { id },
      data: updateData,
    });

    // Invalidar caches
    await invalidateCache(`manga:${id}`);
    await invalidateCache('manga:list');
    await invalidateCache('user:mangas:list');

    return NextResponse.json({
      message: 'Manga actualizado exitosamente',
      manga: {
        id: updated.id,
        title: updated.title,
        slug: updated.slug,
        description: updated.description,
        coverUrl: updated.coverUrl,
        status: updated.status,
        tags: updated.tags ? JSON.parse(updated.tags) : [],
        authorId: updated.authorId,
        authorName: updated.authorName,
        rating: updated.rating,
        totalViews: updated.totalViews,
        updatedAt: updated.updatedAt,
      },
    });
  } catch (error) {
    console.error('Error actualizando manga:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

// DELETE /api/manga/[id] - Eliminar manga y todos sus capítulos (solo owner)
export async function DELETE(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const session = await auth();

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'No autorizado' },
        { status: 401 }
      );
    }

    const rlResponse = await withRateLimit(request, session.user.id, 'default');
    if (rlResponse) return rlResponse;

    const { id } = await params;

    // Verificar que el manga existe
    const manga = await prisma.mangaSeries.findUnique({
      where: { id },
      select: { authorId: true, title: true },
    });

    if (!manga) {
      return NextResponse.json(
        { error: 'Manga no encontrado' },
        { status: 404 }
      );
    }

    // Verificar ownership
    if (manga.authorId !== session.user.id && session.user.role !== 'ADMIN') {
      return NextResponse.json(
        { error: 'No tienes permisos para eliminar este manga' },
        { status: 403 }
      );
    }

    // Eliminar manga y capítulos en transacción
    await prisma.$transaction([
      prisma.chapter.deleteMany({ where: { mangaId: id } }),
      prisma.mangaSeries.delete({ where: { id } }),
    ]);

    // Invalidar caches
    await invalidateCache(`manga:${id}`);
    await invalidateCache('manga:list');
    await invalidateCache('user:mangas:list');

    return NextResponse.json({
      message: `Manga "${manga.title}" eliminado exitosamente`,
      deleted: true,
    });
  } catch (error) {
    console.error('Error eliminando manga:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';

import { withCache, generateCacheKey, cacheConfig, invalidateCache } from '@/lib/apiCache';
import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { withRateLimit } from '@/lib/rate-limit-middleware';

// Helper para generar slug desde el título
function generateSlug(title: string): string {
  return title
    .toLowerCase()
    .trim()
    .replace(/[^\w\s-]/g, '')
    .replace(/\s+/g, '-')
    .substring(0, 100);
}

// GET /api/manga - Listar mangas del usuario autenticado
export async function GET(request: NextRequest) {
  try {
    const session = await auth();

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'No autorizado' },
        { status: 401 }
      );
    }

    const { searchParams } = new URL(request.url);
    const page = parseInt(searchParams.get('page') || '1');
    const limit = parseInt(searchParams.get('limit') || '20');

    // Generate cache key
    const cacheKey = generateCacheKey('user:mangas:list', {
      userId: session.user.id,
      page,
      limit,
    });

    const userId = session.user.id;

    const result = await withCache(
      cacheKey,
      cacheConfig.manga.list.ttl,
      async () => {
        const where = { authorId: userId };

        const [mangas, total] = await Promise.all([
          prisma.mangaSeries.findMany({
            where,
            skip: (page - 1) * limit,
            take: limit,
            orderBy: { createdAt: 'desc' },
          }),
          prisma.mangaSeries.count({ where }),
        ]);

        // Obtener conteo de capítulos para cada manga
        const mangaIds = mangas.map((m: any) => m.id);
        const chapterCounts = await prisma.chapter.groupBy({
          by: ['mangaId'],
          where: { mangaId: { in: mangaIds } },
          _count: { mangaId: true },
        });

        const chapterCountMap = new Map(chapterCounts.map((c: any) => [c.mangaId, c._count.mangaId]));

        return {
          mangas: mangas.map((manga: any) => ({
            id: manga.id,
            title: manga.title,
            slug: manga.slug,
            description: manga.description,
            coverUrl: manga.coverUrl,
            status: manga.status,
            tags: manga.tags ? JSON.parse(manga.tags) : [],
            authorId: manga.authorId,
            authorName: manga.authorName,
            rating: manga.rating,
            totalViews: manga.totalViews,
            chapterCount: chapterCountMap.get(manga.id) || 0,
            createdAt: manga.createdAt,
            updatedAt: manga.updatedAt,
          })),
          pagination: {
            page,
            limit,
            total,
            totalPages: Math.ceil(total / limit),
          },
        };
      }
    );

    return NextResponse.json(result);
  } catch (error) {
    console.error('Error listando mangas del usuario:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

// POST /api/manga - Crear nuevo manga
export async function POST(request: NextRequest) {
  try {
    const session = await auth();

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'No autorizado' },
        { status: 401 }
      );
    }

    const rlResponse = await withRateLimit(request, session?.user?.id, 'default');
    if (rlResponse) return rlResponse;

    const body = await request.json();
    const { title, description, coverUrl, tags } = body;

    // Validaciones
    if (!title || typeof title !== 'string' || title.trim().length === 0) {
      return NextResponse.json(
        { error: 'El título es requerido' },
        { status: 400 }
      );
    }

    if (title.trim().length > 200) {
      return NextResponse.json(
        { error: 'El título no puede exceder 200 caracteres' },
        { status: 400 }
      );
    }

    // Generar slug automáticamente desde el título
    const baseSlug = generateSlug(title);
    let slug = baseSlug;
    let counter = 1;

    // Verificar unicidad del slug y generar uno único si es necesario
    while (await prisma.mangaSeries.findUnique({ where: { slug } })) {
      slug = `${baseSlug}-${counter}`;
      counter++;
    }

    // Obtener información del usuario para el authorName
    const user = await prisma.user.findUnique({
      where: { id: session.user.id },
      select: { displayName: true, username: true },
    });

    const authorName = user?.displayName || user?.username || 'Unknown';

    // Crear el manga
    const manga = await prisma.mangaSeries.create({
      data: {
        title: title.trim(),
        slug,
        description: description || null,
        coverUrl: coverUrl || null,
        authorId: session.user.id,
        authorName,
        tags: tags && Array.isArray(tags) ? JSON.stringify(tags.map((t: string) => t.toLowerCase().trim())) : '[]',
        status: 'ONGOING',
      },
    });

    // Invalidar cache de listas
    await invalidateCache('user:mangas:list');
    await invalidateCache('manga:list');

    return NextResponse.json(
      {
        message: 'Manga creado exitosamente',
        manga: {
          id: manga.id,
          title: manga.title,
          slug: manga.slug,
          description: manga.description,
          coverUrl: manga.coverUrl,
          authorId: manga.authorId,
          authorName: manga.authorName,
          status: manga.status,
          tags: manga.tags ? JSON.parse(manga.tags) : [],
          totalViews: manga.totalViews,
          createdAt: manga.createdAt,
          updatedAt: manga.updatedAt,
        },
      },
      { status: 201 }
    );
  } catch (error) {
    console.error('Error creando manga:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

