case 'READING_PROGRESS': {
const { mangaId, chapterId, currentPage, percentage } = action.data || {};
if (!mangaId || !chapterId) {
return NextResponse.json(
{ error: 'mangaId y chapterId requeridos' },
{ status: 400 }
);
}
await prisma.readingProgress.upsert({
where: {
userId_mangaId_chapterId: { userId, mangaId, chapterId },
},
create: {
userId,
mangaId,
chapterId,
currentPage: currentPage || 0,
percentage: percentage || 0,
},
update: {
currentPage: currentPage || 0,
percentage: percentage || 0,
},
});
break;
}

      case 'CHAPTER_READ': {
        const { mangaId: readMangaId, chapterId } = action.data || {};
        if (!readMangaId || !chapterId) {
          return NextResponse.json(
            { error: 'mangaId y chapterId requeridos' },
            { status: 400 }
          );
        }
await prisma.analyticsEvent.create({
data: {
eventType: 'chapter_read',
userId,
metadata: JSON.stringify({ mangaId: readMangaId, chapterId, timestamp: new Date(action.timestamp || new Date()).toISOString() }),
} as any,
        });
        break;
      }

      case 'FOLLOW': {
        const { followingId, followingType } = action.data || {};
        if (!followingId || !followingType) {
          return NextResponse.json(
            { error: 'followingId y followingType requeridos' },
            { status: 400 }
          );
        }
        await prisma.follow.upsert({
          where: {
            followerId_followingId_followingType: {
              followerId: userId,
              followingId,
              followingType,
            },
          },
          create: {
            followerId: userId,
            followingId,
            followingType,
          },
          update: {},
        });
        break;
      }

      case 'UNFOLLOW': {
        const { followingId: unfollowId, followingType: unfollowType } = action.data || {};
        if (!unfollowId || !unfollowType) {
          return NextResponse.json(
            { error: 'followingId y followingType requeridos' },
            { status: 400 }
          );
        }
        await prisma.follow.deleteMany({
          where: {
            followerId: userId,
            followingId: unfollowId,
            followingType: unfollowType,
          },
        });
        break;
      }

      case 'LIKE': {
        const { targetType, targetId } = action.data || {};
        if (!targetType || !targetId) {
          return NextResponse.json(
            { error: 'targetType y targetId requeridos' },
            { status: 400 }
          );
        }
        if (targetType === 'comment') {
          await prisma.commentLike.upsert({
where: {
commentId_userId: { commentId: targetId, userId },
            },
            create: { userId, commentId: targetId },
            update: {},
          });
        }
        break;
      }

  case 'BOOKMARK': {
      const { chapterId: bookmarkChapterId, pageNumber: bookmarkPage } = action.data || {};
      if (!bookmarkChapterId) {
        return NextResponse.json(
          { error: 'chapterId requerido' },
          { status: 400 }
        );
      }
      const chapter = await prisma.chapter.findUnique({
        where: { id: bookmarkChapterId },
        select: { mangaId: true },
      });
      if (!chapter) {
        return NextResponse.json(
          { error: 'Capítulo no encontrado' },
          { status: 404 }
        );
      }
      await prisma.readingProgress.upsert({
        where: {
          userId_mangaId_chapterId: { userId, mangaId: chapter.mangaId, chapterId: bookmarkChapterId },
        },
        create: {
          userId,
          mangaId: chapter.mangaId,
          chapterId: bookmarkChapterId,
          currentPage: bookmarkPage || 0,
        },
        update: {
          currentPage: bookmarkPage || 0,
        },
      });
      break;
    }

      default:
        return NextResponse.json(
          { error: `Tipo de acción desconocido: ${action.type}` },
          { status: 400 }
        );
    }

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error('Error en sync:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';

import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { withRateLimit } from '@/lib/rate-limit-middleware';
import { deleteFile, extractPathname } from '@/lib/storage';

interface DeleteRequest {
  url: string;
}

interface DeleteResponse {
  success: boolean;
  message?: string;
}

/**
 * DELETE /api/upload/delete
 * Elimina una imagen por URL
 * Requiere autenticación y ser el dueño del recurso asociado
 * Body: { url: string }
 */
export async function DELETE(request: NextRequest) {
  try {
    // Verificar autenticación
    const session = await auth();
    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'No autorizado. Inicia sesión para eliminar archivos.' },
        { status: 401 }
      );
    }

    const rlResponse = await withRateLimit(request, session?.user?.id, 'upload');
    if (rlResponse) return rlResponse;

    const userId = session.user.id;

    // Parsear el body
    let body: DeleteRequest;
    try {
      body = await request.json();
    } catch {
      return NextResponse.json(
        { error: 'Body inválido. Se requiere JSON con campo "url"' },
        { status: 400 }
      );
    }

    const { url } = body;

    if (!url || typeof url !== 'string') {
      return NextResponse.json(
        { error: 'Se requiere una URL válida' },
        { status: 400 }
      );
    }

    // Validar que la URL sea de Vercel Blob
    if (!new URL(url).hostname.endsWith('.public.blob.vercel-storage.com') && !new URL(url).hostname.endsWith('.blob.vercel-storage.com')) {
      return NextResponse.json(
        { error: 'URL no válida. Solo se pueden eliminar archivos del sistema.' },
        { status: 400 }
      );
    }

    // Extraer el pathname para verificar ownership
    const pathname = extractPathname(url);
    if (!pathname) {
      return NextResponse.json(
        { error: 'No se pudo procesar la URL' },
        { status: 400 }
      );
    }

    // Verificar ownership basado en el path
    let isOwner = false;
    let resourceType: 'manga' | 'chapter' | 'upload' | 'cover' | null = null;

    // Analizar el path para determinar el tipo de recurso
    if (pathname.startsWith('covers/')) {
      // Portada de manga: covers/{mangaId}/{filename}
      resourceType = 'cover';
      const mangaId = pathname.split('/')[1];
      
      if (mangaId) {
        const manga = await prisma.mangaSeries.findUnique({
          where: { id: mangaId },
          select: { authorId: true },
        });
        isOwner = manga?.authorId === userId;
      }
    } else if (pathname.startsWith('chapters/')) {
      // Páginas de capítulo: chapters/{mangaId}/{chapterNumber}/{filename}
      resourceType = 'chapter';
      const mangaId = pathname.split('/')[1];
      
      if (mangaId) {
        const manga = await prisma.mangaSeries.findUnique({
          where: { id: mangaId },
          select: { authorId: true },
        });
        isOwner = manga?.authorId === userId;
      }
    } else if (pathname.startsWith(`uploads/${userId}/`)) {
      // Subida directa del usuario
      resourceType = 'upload';
      isOwner = true;
    } else if (pathname.startsWith('uploads/')) {
      // Subida de otro usuario - verificar si es admin
      const user = await prisma.user.findUnique({
        where: { id: userId },
        select: { role: true },
      });
      isOwner = user?.role === 'ADMIN';
    }

    // Verificar también si la URL está asociada a un manga del usuario
    if (!isOwner) {
      const mangaWithCover = await prisma.mangaSeries.findFirst({
        where: {
          authorId: userId,
          coverUrl: url,
        },
      });
      
      if (mangaWithCover) {
        isOwner = true;
        resourceType = 'cover';
      }
    }

  if (!isOwner) {
    const chapters = await prisma.chapter.findMany({
      where: {
        pageUrls: { contains: url },
      },
      select: {
        mangaId: true,
      },
    });

    if (chapters.length > 0) {
      const uniqueMangaIds = [...new Set(chapters.map((c: any) => c.mangaId))];
      const mangas = await prisma.mangaSeries.findMany({
        where: { id: { in: uniqueMangaIds } },
        select: { id: true, authorId: true },
      });
      const mangaMap = new Map(mangas.map((m: any) => [m.id, m.authorId]));

      for (const chapter of chapters) {
        const authorId = mangaMap.get(chapter.mangaId);
        if (authorId === userId) {
          isOwner = true;
          resourceType = 'chapter';
          break;
        }
      }
    }
  }

    if (!isOwner) {
      return NextResponse.json(
        { error: 'No tienes permiso para eliminar este archivo' },
        { status: 403 }
      );
    }

    // Eliminar el archivo
    const deleteResult = await deleteFile(url);

    if (!deleteResult.success) {
      return NextResponse.json(
        { error: deleteResult.error || 'Error al eliminar el archivo' },
        { status: 500 }
      );
    }

    // Actualizar referencias en la base de datos según el tipo
    if (resourceType === 'cover') {
      await prisma.mangaSeries.updateMany({
        where: { coverUrl: url },
        data: { coverUrl: null },
      });
    } else if (resourceType === 'chapter') {
      // Buscar capítulos que contengan esta URL
      const chapters = await prisma.chapter.findMany({
        where: {
          pageUrls: { contains: url },
        },
      });

      for (const chapter of chapters) {
        const pageUrls = JSON.parse(chapter.pageUrls || '[]') as string[];
        const filteredUrls = pageUrls.filter((u) => u !== url);
        
        await prisma.chapter.update({
          where: { id: chapter.id },
          data: {
            pageUrls: JSON.stringify(filteredUrls),
            totalPages: filteredUrls.length,
          },
        });
      }
    }

    const response: DeleteResponse = {
      success: true,
      message: 'Archivo eliminado exitosamente',
    };

    return NextResponse.json(response);

  } catch (error) {
    console.error('Error en upload/delete:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor al eliminar el archivo' },
      { status: 500 }
    );
  }
}

