 * POST alternativo para eliminar (para compatibilidad con formularios)
 */
export async function POST(request: NextRequest) {
  return DELETE(request);
}

import { NextRequest, NextResponse } from 'next/server';

import { PrismaWebhookRepository } from '@/infrastructure/adapters/PrismaWebhookRepository';
import { WebhookDeliveryService } from '@/infrastructure/adapters/WebhookDeliveryService';
import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

const repo = new PrismaWebhookRepository();

export async function POST(request: NextRequest) {
  try {
    const session = await auth();
    if (!session?.user?.id || session.user.role !== 'ADMIN') {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const body = await request.json();
    const { endpointId, event, payload } = body;

    if (!endpointId || !event) {
      return NextResponse.json(
        { error: 'endpointId and event are required' },
        { status: 400 }
      );
    }

    const endpoint = await prisma.webhookEndpoint.findUnique({
      where: { id: endpointId },
    });

    if (!endpoint) {
      return NextResponse.json({ error: 'Endpoint not found' }, { status: 404 });
    }

    if (endpoint.userId !== session.user.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const deliveryService = new WebhookDeliveryService(repo);
    const delivery = await deliveryService.deliver(
      endpoint as any,
      event,
      payload || { message: 'Manual delivery' }
    );

    return NextResponse.json({ delivery });
  } catch (error) {
    console.error('Error delivering webhook:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

/**
 * Stripe Webhook
 * 
 * Handle Stripe events:
 * - checkout.session.completed: Add InkCoins to user or activate subscription
 * - checkout.session.expired: Log failed attempt
 * - customer.subscription.created/updated/deleted: Manage subscription status
 * - invoice.payment_succeeded/failed: Handle billing
 */

import { NextRequest } from 'next/server';

import { prisma } from '@/lib/prisma';
import { stripe, verifyStripeWebhook, SUBSCRIPTION_PLANS } from '@/lib/stripe';

/**
 * POST /api/webhooks/stripe
 * Handle Stripe webhook events
 */
export async function POST(request: NextRequest) {
  const payload = await request.text();
  const signature = request.headers.get('stripe-signature') || '';

  // Verify webhook
  const event = await verifyStripeWebhook(payload, signature);
  if (!event) {
    return Response.json({ error: 'Invalid webhook signature' }, { status: 400 });
  }

  try {
    switch (event.type) {
      case 'checkout.session.completed': {
        const session = event.data.object;
        const { userId, inkcoinsAmount, type, planId } = session.metadata || {};

        // Handle subscription checkout
        if (type === 'subscription' && userId && planId) {
          const subscription = await stripe.subscriptions.retrieve(session.subscription as string);
          const subData = subscription as { current_period_end: number };
          await prisma.user.update({
            where: { id: userId },
            data: {
              subscriptionId: subscription.id,
              subscriptionStatus: subscription.status,
              subscriptionTier: planId,
              subscriptionEndsAt: new Date(subData.current_period_end * 1000),
              stripeCustomerId: session.customer as string,
            },
          });
          // console.log(`[Stripe Webhook] Subscription activated for user ${userId}: ${planId}`);
          break;
        }

        // Handle InkCoins purchase (existing)
        if (!userId || !inkcoinsAmount) {
          console.error('[Stripe Webhook] Missing metadata');
          return Response.json({ error: 'Missing metadata' }, { status: 400 });
        }

        await prisma.user.update({
          where: { id: userId },
          data: {
            inkcoinsBalance: {
              increment: parseInt(inkcoinsAmount),
            },
          },
        });

        await prisma.transaction.create({
          data: {
            userId,
            amount: parseInt(inkcoinsAmount),
            type: 'INKCOIN_PURCHASE',
            referenceId: session.id,
            description: `Purchased ${inkcoinsAmount} InkCoins via Stripe`,
          },
        });

        // console.log(`[Stripe Webhook] Added ${inkcoinsAmount} InkCoins to user ${userId}`);
        break;
      }

      case 'checkout.session.expired': {
        // console.log('[Stripe Webhook] Checkout session expired');
        break;
      }

      case 'payment_intent.payment_failed': {
        // console.log('[Stripe Webhook] Payment failed');
        break;
      }

      case 'customer.subscription.created':
      case 'customer.subscription.updated': {
        const subscription = event.data.object;
        const customerId = (subscription as { customer: string }).customer;
        const status = (subscription as { status: string }).status;

        const user = await prisma.user.findFirst({
          where: { stripeCustomerId: customerId },
          select: { id: true },
        });

        if (!user) {
          console.error(`[Stripe Webhook] No user found for customer ${customerId}`);
          break;
        }

        const sub = subscription as { id: string; current_period_end: number; items?: { data: Array<{ price: { id: string } }> } };
        const updateData: Record<string, unknown> = {
          subscriptionId: sub.id,
          subscriptionStatus: status,
          subscriptionEndsAt: new Date(sub.current_period_end * 1000),
        };

        // Only update tier on creation or if it hasn't been set
        if (event.type === 'customer.subscription.created') {
          const items = subscription.items?.data || [];
          const priceId = items[0]?.price?.id;
          const plan = SUBSCRIPTION_PLANS.find(p => p.priceId === priceId);
          if (plan) {
            updateData.subscriptionTier = plan.id;
          }
        }

        await prisma.user.update({
          where: { id: user.id },
          data: updateData,
        });

        // console.log(`[Stripe Webhook] Subscription ${status} for user ${user.id}`);
        break;
      }

      case 'customer.subscription.deleted': {
        const subscription = event.data.object as { customer: string };
        const customerId = subscription.customer;

        const user = await prisma.user.findFirst({
          where: { stripeCustomerId: customerId },
          select: { id: true },
        });

        if (!user) {
          console.error(`[Stripe Webhook] No user found for customer ${customerId}`);
          break;
        }

        await prisma.user.update({
          where: { id: user.id },
          data: {
            subscriptionStatus: 'canceled',
            subscriptionId: null,
            subscriptionTier: null,
            subscriptionEndsAt: null,
          },
        });

        // console.log(`[Stripe Webhook] Subscription canceled for user ${user.id}`);
        break;
      }

      case 'invoice.payment_succeeded': {
        const invoice = event.data.object as { subscription: string };
        const subscriptionId = invoice.subscription;

        if (!subscriptionId) break;

        const sub = await stripe.subscriptions.retrieve(subscriptionId);
        const custId = sub.customer as string;

        const user = await prisma.user.findFirst({
          where: { stripeCustomerId: custId },
          select: { id: true },
        });

        if (!user) break;

        const subData = sub as { current_period_end: number };
        await prisma.user.update({
          where: { id: user.id },
          data: {
            subscriptionStatus: sub.status,
            subscriptionEndsAt: new Date(subData.current_period_end * 1000),
          },
        });
        break;
      }

      case 'invoice.payment_failed': {
        const failedInvoice = event.data.object as { subscription: string };
        const failedSubId = failedInvoice.subscription;

        if (!failedSubId) break;

        const failedSub = await stripe.subscriptions.retrieve(failedSubId);
        const failedCustId = failedSub.customer as string;

        const failedUser = await prisma.user.findFirst({
          where: { stripeCustomerId: failedCustId },
          select: { id: true },
        });

        if (!failedUser) break;

        await prisma.user.update({
          where: { id: failedUser.id },
          data: { subscriptionStatus: 'past_due' },
        });

        // console.log(`[Stripe Webhook] Invoice payment failed for user ${failedUser.id}`);
        break;
      }

      default:
        // console.log(`[Stripe Webhook] Unhandled event type: ${event.type}`);
    }

    return Response.json({ received: true });
  } catch (error) {
    // console.error('[Stripe Webhook] Error processing event:', error);
    return Response.json({ error: 'Failed to process webhook' }, { status: 500 });
  }
}

/**
 * GET /api/webhooks/stripe
 * For Stripe webhook verification
 */
export async function GET() {
  return Response.json({ status: 'Stripe webhook endpoint active' });
}

'use client';

import { ArrowLeft, Mail, Loader2, CheckCircle, ArrowRight } from 'lucide-react';
import Link from 'next/link';
import React, { useState } from 'react';
import { z } from 'zod';

import { ErrorMessage } from '@/components/ui/ErrorMessage';
import { useToast } from '@/components/ui/Toast';
import { useAuthError } from '@/hooks/useAuthError';
import { useT } from '@/i18n';
import { cn } from '@/lib/utils';

export default function ForgotPasswordPage() {
  const t = useT();
  const [email, setEmail] = useState('');
  const [formState, setFormState] = useState<'initial' | 'loading' | 'success' | 'error'>('initial');
  const { toast } = useToast();
  const { error, clearError, handleNetworkError, handleValidationError } = useAuthError();

  const forgotPasswordSchema = z.object({
    email: z
      .string()
      .min(1, t('auth.validation.emailRequired'))
      .email(t('auth.validation.emailInvalid')),
  });
  
  const [touched, setTouched] = useState(false);
  const [validationError, setValidationError] = useState('');
  const emailErrorId = 'forgot-email-error';

  const validateEmail = (value: string): boolean => {
    try {
      forgotPasswordSchema.parse({ email: value });
      setValidationError('');
      return true;
    } catch (err) {
      if (err instanceof z.ZodError) {
        const message = (err as any).issues?.[0]?.message || (err as any).errors?.[0]?.message || t('auth.validation.emailInvalid');
        setValidationError(message);
        return false;
      }
      return false;
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setEmail(value);
    clearError();
    
    if (touched) {
      validateEmail(value);
    }
  };

  const handleBlur = () => {
    setTouched(true);
    validateEmail(email);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setTouched(true);
    clearError();

    if (!validateEmail(email)) {
      handleValidationError('email', validationError);
      setFormState('error');
      return;
    }

    setFormState('loading');

    try {
      const response = await fetch('/api/auth/forgot-password', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ email: email.trim() }),
      });

      const data = await response.json();

      if (!response.ok) {
        if (data.error?.includes('not found') || data.error?.includes('no existe')) {
          setFormState('success');
          toast({
            title: t('auth.forgotPassword.toastTitle'),
            description: t('auth.forgotPassword.toastDesc'),
            variant: 'default',
          });
          return;
        }
        throw new Error(data.error || t('auth.forgotPassword.submitError'));
      }

      setFormState('success');
      toast({
        title: t('auth.forgotPassword.toastSuccessTitle'),
        description: t('auth.forgotPassword.toastSuccessDesc'),
        variant: 'default',
      });
    } catch (err) {
      handleNetworkError(() => handleSubmit(e));
      setFormState('error');
      
      setTimeout(() => {
        setFormState('success');
        toast({
          title: t('auth.forgotPassword.toastTitle'),
          description: t('auth.forgotPassword.toastDesc'),
          variant: 'default',
        });
      }, 100);
    }
  };

  const isValidEmail = touched && !validationError && email.length > 0;
  const hasError = (touched && validationError) || (formState === 'error' && error);

  return (
    <div className="min-h-screen bg-background font-sans text-fg-primary flex flex-col">
      <div className="p-6">
        <Link href="/" className="inline-flex items-center gap-2 text-muted hover:text-fg-primary transition-colors">
          <ArrowLeft size={20} /> {t('auth.resetPassword.backToHome')}
        </Link>
      </div>

      <div className="flex-1 flex items-center justify-center p-6">
        <div className="w-full max-w-md animate-fade-in-up">
          <div className="text-center mb-8">
            <h1 className="text-4xl font-extrabold tracking-tight mb-2">
              {formState === 'success' ? t('auth.forgotPassword.successTitle') : t('auth.forgotPassword.title')}
            </h1>
            <p className="text-muted">
              {formState === 'success'
                ? t('auth.forgotPassword.successSubtitle')
                : t('auth.forgotPassword.subtitle')}
            </p>
          </div>

          <div className="bg-secondary border border-custom rounded-2xl p-8 shadow-xl">
            {formState === 'success' ? (
              <div className="text-center py-4">
                <div className="w-16 h-16 bg-[var(--success)]/20 rounded-full flex items-center justify-center mx-auto mb-4">
                  <CheckCircle className="w-8 h-8 text-[var(--success)]" />
                </div>
                <h3 className="text-xl font-semibold mb-2 text-[var(--text-primary)]">{t('auth.forgotPassword.emailSent')}</h3>
                <p className="text-muted mb-6">
                  {t('auth.forgotPassword.emailSentDesc', { email })}
                </p>
                <div className="space-y-3">
                  <Link
                    href="/auth/login"
                    className="inline-flex items-center justify-center gap-2 w-full px-4 py-3 bg-accent-blue hover:bg-accent-blue-hover text-[var(--text-inverse)] font-semibold rounded-xl transition-colors"
                  >
                    <ArrowLeft size={18} />
                    {t('auth.forgotPassword.backToLogin')}
                  </Link>
                  <button
                    onClick={() => {
                      setFormState('initial');
                      setEmail('');
                      setTouched(false);
                    }}
                    className="inline-flex items-center justify-center gap-2 w-full px-4 py-3 text-accent-blue hover:text-accent-blue-hover font-semibold transition-colors"
                  >
                    {t('auth.forgotPassword.sendAgain')}
                    <ArrowRight size={18} />
                  </button>
                </div>
              </div>
            ) : (
              <>
                {error && (
                  <div className="mb-6">
                    <ErrorMessage
                      title={error.title}
                      message={error.message}
                      severity={error.severity}
                      onDismiss={clearError}
                      action={error.action}
                    />
                  </div>
                )}

                <form onSubmit={handleSubmit} className="space-y-5">
                  <div>
                    <label htmlFor="forgot-email" className="block text-sm font-semibold mb-2">{t('auth.email')}</label>
                    <div className="relative">
                      <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-muted" size={18} />
                      <input
                        id="forgot-email"
                        type="email"
                        value={email}
                        onChange={handleChange}
                        onBlur={handleBlur}
                        disabled={formState === 'loading'}
                        className={cn(
                          'w-full pl-10 pr-12 py-3 bg-tertiary border rounded-xl outline-none transition-all text-sm',
                          hasError
                            ? 'border-[var(--error)] focus:border-[var(--error)] focus:ring-1 focus:ring-[var(--error)]'
                            : isValidEmail
                              ? 'border-[var(--success)] focus:border-[var(--success)] focus:ring-1 focus:ring-[var(--success)]'
                              : 'border-custom focus:border-accent-blue focus:ring-1 focus:ring-accent-blue'
                        )}
                        placeholder={t('auth.forgotPassword.emailPlaceholder')}
                        aria-invalid={!!hasError}
                        aria-describedby={validationError ? emailErrorId : undefined}
                        aria-required="true"
                        autoComplete="email"
                      />
                      {isValidEmail && (
                        <CheckCircle className="absolute right-3 top-1/2 -translate-y-1/2 text-[var(--success)]" size={18} />
                      )}
                    </div>
                    {touched && validationError && (
                      <div id={emailErrorId} className="mt-2" role="alert">
                        <ErrorMessage
                          message={validationError}
                          severity="warning"
                          icon={<Mail className="w-4 h-4" />}
                        />
                      </div>
                    )}
                    <p className="mt-2 text-xs text-muted">
                      {t('auth.forgotPassword.emailHelp')}
                    </p>
                  </div>

                  <button
                    type="submit"
                    disabled={formState === 'loading' || !!validationError}
                    className="w-full bg-accent-blue hover:bg-accent-blue-hover text-[var(--text-inverse)] font-bold py-3 rounded-xl transition-all shadow-md flex justify-center items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    {formState === 'loading' ? (
                      <>
                        <Loader2 size={18} className="animate-spin" />
                        {t('auth.forgotPassword.sending')}
                      </>
                    ) : (
                      <>
                        <Mail size={18} />
                        {t('auth.forgotPassword.submit')}
                      </>
                    )}
                  </button>
                </form>

                <div className="mt-6 pt-6 border-t border-custom">
                  <p className="text-sm text-muted">
                    <strong className="text-[var(--text-primary)]">{t('auth.forgotPassword.noEmail')}</strong>
                    <br />
                    {t('auth.forgotPassword.noEmailHint')}
                  </p>
                </div>
              </>
            )}
          </div>

          {formState !== 'success' && (
            <p className="text-center text-sm text-muted mt-8">
              {t('auth.forgotPassword.rememberedPassword')}{' '}
              <Link href="/auth/login" className="text-accent-blue font-semibold hover:underline">
                {t('auth.forgotPassword.loginHere')}
              </Link>
            </p>
          )}
        </div>
      </div>
    </div>
  );
}

