'use client';

import { 
  ArrowLeft, 
  Lock, 
  Loader2, 
  CheckCircle, 
  AlertCircle, 
  Eye, 
  EyeOff,
  Shield,
  KeyRound
} from 'lucide-react';
import Link from 'next/link';
import { useRouter, useSearchParams } from 'next/navigation';
import React, { useState, useEffect, Suspense } from 'react';
import { z } from 'zod';

import { ErrorMessage } from '@/components/ui/ErrorMessage';
import { useToast } from '@/components/ui/Toast';
import { useAuthError } from '@/hooks/useAuthError';
import { useT } from '@/i18n';
import { cn } from '@/lib/utils';

function Content() {
  const t = useT();
  const router = useRouter();
  const searchParams = useSearchParams();
  const token = searchParams.get('token');
  const { toast } = useToast();
  const { error, clearError, handleNetworkError, handlePasswordResetError } = useAuthError();
  
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [formState, setFormState] = useState<'initial' | 'loading' | 'success' | 'error' | 'invalid_token'>('initial');
  const [countdown, setCountdown] = useState(5);

  const [touched, setTouched] = useState({ password: false, confirmPassword: false });
  const [validationErrors, setValidationErrors] = useState<{ password?: string; confirmPassword?: string }>({});

  const resetPasswordSchema = z.object({
    password: z
      .string()
      .min(8, t('auth.validation.passwordMin'))
      .regex(/[A-Z]/, t('auth.validation.passwordUppercase'))
      .regex(/[a-z]/, t('auth.validation.passwordLowercase'))
      .regex(/[0-9]/, t('auth.validation.passwordNumber')),
    confirmPassword: z.string(),
  }).refine((data: { password: string; confirmPassword: string }) => data.password === data.confirmPassword, {
    message: t('auth.validation.passwordMismatch'),
    path: ['confirmPassword'],
  });

  const validateField = (field: 'password' | 'confirmPassword', value: string) => {
    try {
      if (field === 'password') {
        const fieldSchema = resetPasswordSchema.shape.password;
        fieldSchema.parse(value);
      } else {
        if (value !== password) {
          setValidationErrors((prev) => ({ ...prev, confirmPassword: t('auth.validation.passwordMismatch') }));
          return false;
        }
      }
      setValidationErrors((prev) => ({ ...prev, [field]: undefined }));
      return true;
    } catch (err: unknown) {
      if (err instanceof z.ZodError) {
        const message = err.errors[0]?.message || t('auth.validation.passwordMin');
        setValidationErrors((prev) => ({ ...prev, [field]: message }));
        return false;
      }
      return false;
    }
  };

  const handlePasswordChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setPassword(value);
    clearError();
    if (touched.password) {
      validateField('password', value);
    }
    if (touched.confirmPassword && confirmPassword) {
      validateField('confirmPassword', confirmPassword);
    }
  };

  const handleConfirmChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setConfirmPassword(value);
    clearError();
    if (touched.confirmPassword) {
      validateField('confirmPassword', value);
    }
  };

  const handleBlur = (field: 'password' | 'confirmPassword') => {
    setTouched((prev) => ({ ...prev, [field]: true }));
    validateField(field, field === 'password' ? password : confirmPassword);
  };

  // Validar token al cargar - necesario para sincronizar estado con URL
  /* eslint-disable react-hooks/set-state-in-effect */
  useEffect(() => {
    if (!token) {
      setFormState('invalid_token');
      handlePasswordResetError('INVALID_TOKEN');
    }
  }, [token]);
  /* eslint-enable react-hooks/set-state-in-effect */

  useEffect(() => {
    if (formState === 'success' && countdown > 0) {
      const timer = setTimeout(() => setCountdown(countdown - 1), 1000);
      return () => clearTimeout(timer);
    } else if (formState === 'success' && countdown === 0) {
      router.push('/auth/login');
    }
  }, [formState, countdown, router]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setTouched({ password: true, confirmPassword: true });
    clearError();

    if (!token) {
      handlePasswordResetError('INVALID_TOKEN', {
        label: t('auth.resetPassword.requestNewLink'),
        onClick: () => router.push('/auth/forgot-password'),
      });
      setFormState('invalid_token');
      return;
    }

    try {
      resetPasswordSchema.parse({ password, confirmPassword });
    } catch (err: unknown) {
      if (err instanceof z.ZodError) {
        const errors: { password?: string; confirmPassword?: string } = {};
        err.errors.forEach((error) => {
          const field = error.path[0] as 'password' | 'confirmPassword';
          errors[field] = error.message;
        });
        setValidationErrors(errors);
        setFormState('error');
        return;
      }
    }

    setFormState('loading');

    try {
      const response = await fetch('/api/auth/reset-password', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          token,
          newPassword: password,
        }),
      });

      const data = await response.json();

      if (!response.ok) {
        if (data.error?.includes('expired') || data.error?.includes('expirado')) {
          handlePasswordResetError('TOKEN_EXPIRED', {
            label: t('auth.resetPassword.requestNewLink'),
            onClick: () => router.push('/auth/forgot-password'),
          });
          setFormState('invalid_token');
          return;
        }
        
        if (data.error?.includes('token') || data.error?.includes('inválido')) {
          handlePasswordResetError('INVALID_TOKEN', {
            label: t('auth.resetPassword.requestNewLink'),
            onClick: () => router.push('/auth/forgot-password'),
          });
          setFormState('invalid_token');
          return;
        }

        throw new Error(data.error || t('errors.generic'));
      }

      setFormState('success');
      toast({
        title: t('auth.resetPassword.toastTitle'),
        description: t('auth.resetPassword.toastDesc'),
        variant: 'default',
      });
    } catch (err) {
      handleNetworkError(() => handleSubmit(e));
      setFormState('error');
    }
  };

  if (formState === 'invalid_token') {
    return (
      <div className="min-h-screen bg-background font-sans text-fg-primary flex flex-col">
        <div className="p-6">
          <Link href="/" className="inline-flex items-center gap-2 text-muted hover:text-fg-primary transition-colors">
            <ArrowLeft size={20} /> {t('auth.resetPassword.backToHome')}
          </Link>
        </div>

        <div className="flex-1 flex items-center justify-center p-6">
          <div className="w-full max-w-md animate-fade-in-up">
            <div className="bg-secondary border border-custom rounded-2xl p-8 shadow-xl text-center">
              <div className="w-16 h-16 bg-[var(--error)]/10 rounded-full flex items-center justify-center mx-auto mb-4">
                <Shield className="w-8 h-8 text-[var(--error)]" />
              </div>
          <h2 className="text-xl font-semibold mb-2 text-[var(--text-primary)]">
            {t('auth.resetPassword.invalidToken')}
          </h2>
              <p className="text-muted mb-6">
                {t('auth.resetPassword.invalidTokenDesc')}
              </p>
              <div className="space-y-3">
                <Link
                  href="/auth/forgot-password"
                  className="inline-flex items-center justify-center gap-2 w-full px-4 py-3 bg-accent-blue hover:bg-accent-blue-hover text-[var(--text-inverse)] font-semibold rounded-xl transition-colors"
                >
                  <KeyRound size={18} />
                  {t('auth.resetPassword.requestNewLink')}
                </Link>
                <Link
                  href="/auth/login"
                  className="inline-flex items-center justify-center gap-2 w-full px-4 py-3 text-accent-blue hover:text-accent-blue-hover font-semibold transition-colors"
                >
                  <ArrowLeft size={18} />
                  {t('auth.resetPassword.backToLogin')}
                </Link>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  const passwordStrength = getPasswordStrength(password, t);

  return (
    <div className="min-h-screen bg-background font-sans text-fg-primary flex flex-col">
      <div className="p-6">
        <Link href="/" className="inline-flex items-center gap-2 text-muted hover:text-fg-primary transition-colors">
          <ArrowLeft size={20} /> {t('auth.resetPassword.backToHome')}
        </Link>
      </div>

      <div className="flex-1 flex items-center justify-center p-6">
        <div className="w-full max-w-md animate-fade-in-up">
          <div className="text-center mb-8">
            <h1 className="text-4xl font-extrabold tracking-tight mb-2">
              {formState === 'success' ? t('auth.resetPassword.successTitle') : t('auth.resetPassword.title')}
            </h1>
            <p className="text-muted">
              {formState === 'success'
                ? t('auth.resetPassword.successSubtitle', { countdown })
                : t('auth.resetPassword.subtitle')}
            </p>
          </div>

          <div className="bg-secondary border border-custom rounded-2xl p-8 shadow-xl">
            {formState === 'success' ? (
              <div className="text-center py-4">
                <div className="w-16 h-16 bg-[var(--success)]/20 rounded-full flex items-center justify-center mx-auto mb-4">
                  <CheckCircle className="w-8 h-8 text-[var(--success)]" />
                </div>
                <h2 className="text-xl font-semibold mb-2 text-[var(--text-primary)]">
                  {t('auth.resetPassword.passwordUpdated')}
                </h2>
                <p className="text-muted mb-6">
                  {t('auth.resetPassword.passwordUpdatedDesc')}
                </p>
                <Link
                  href="/auth/login"
                  className="inline-flex items-center justify-center gap-2 w-full px-4 py-3 bg-accent-blue hover:bg-accent-blue-hover text-[var(--text-inverse)] font-semibold rounded-xl transition-colors"
                >
                  <ArrowLeft size={18} />
                  {t('auth.resetPassword.goToLogin')}
                </Link>
              </div>
            ) : (
              <>
                {error && (
                  <div className="mb-6">
                    <ErrorMessage
                      title={error.title}
                      message={error.message}
                      severity={error.severity}
                      onDismiss={clearError}
                      action={error.action}
                    />
                  </div>
                )}

                <form onSubmit={handleSubmit} className="space-y-5">
                  <div>
                    <label htmlFor="reset-password" className="block text-sm font-semibold mb-2">{t('auth.resetPassword.newPassword')}</label>
                    <div className="relative">
                      <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-muted" size={18} />
                      <input
                        id="reset-password"
                        type={showPassword ? 'text' : 'password'}
                        value={password}
                        onChange={handlePasswordChange}
                        onBlur={() => handleBlur('password')}
                        disabled={formState === 'loading'}
                        aria-invalid={!!(touched.password && validationErrors.password)}
                        aria-describedby={touched.password && validationErrors.password ? 'reset-password-error' : undefined}
                        aria-required
                        autoComplete="new-password"
                        className={cn(
                          'w-full pl-10 pr-12 py-3 bg-tertiary border rounded-xl outline-none transition-all text-sm',
                          touched.password && validationErrors.password
                            ? 'border-[var(--error)] focus:border-[var(--error)] focus:ring-1 focus:ring-[var(--error)]'
                            : touched.password && !validationErrors.password && password
                              ? 'border-[var(--success)] focus:border-[var(--success)] focus:ring-1 focus:ring-[var(--success)]'
                              : 'border-custom focus:border-accent-blue focus:ring-1 focus:ring-accent-blue'
                        )}
                        placeholder={t('auth.resetPassword.passwordPlaceholder')}
                      />
                      <button
                        type="button"
                        onClick={() => setShowPassword(!showPassword)}
                        className="absolute right-3 top-1/2 -translate-y-1/2 text-muted hover:text-fg-primary transition-colors"
                        tabIndex={-1}
                      >
                        {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                      </button>
                    </div>

                    {password && (
                      <div className="mt-2">
                        <div className="flex gap-1 h-1">
                          {[1, 2, 3, 4, 5].map((level) => (
                            <div
                              key={level}
                              className={cn(
                                'flex-1 rounded-full transition-colors',
                                passwordStrength.strength >= level
                                  ? passwordStrength.color
                                  : 'bg-[var(--border)]'
                              )}
                            />
                          ))}
                        </div>
                        <p className="mt-1 text-xs text-muted">
                          {t('auth.passwordStrengthLabel')} <span className={cn('font-medium', passwordStrength.color.replace('bg-', 'text-'))}>
                            {passwordStrength.label}
                          </span>
                        </p>
                      </div>
                    )}

                    {touched.password && validationErrors.password && (
                      <p id="reset-password-error" className="mt-1 text-xs text-[var(--error)] flex items-center gap-1" role="alert">
                        <AlertCircle className="w-3 h-3" />
                        {validationErrors.password}
                      </p>
                    )}
                  </div>

                  <div>
                    <label htmlFor="reset-confirm-password" className="block text-sm font-semibold mb-2">{t('auth.resetPassword.confirmPassword')}</label>
                    <div className="relative">
                      <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-muted" size={18} />
                      <input
                        id="reset-confirm-password"
                        type={showConfirmPassword ? 'text' : 'password'}
                        value={confirmPassword}
                        onChange={handleConfirmChange}
                        onBlur={() => handleBlur('confirmPassword')}
                        disabled={formState === 'loading'}
                        aria-invalid={!!(touched.confirmPassword && validationErrors.confirmPassword)}
                        aria-describedby={touched.confirmPassword && validationErrors.confirmPassword ? 'reset-confirm-password-error' : undefined}
                        aria-required
                        autoComplete="new-password"
                        className={cn(
                          'w-full pl-10 pr-12 py-3 bg-tertiary border rounded-xl outline-none transition-all text-sm',
                          touched.confirmPassword && validationErrors.confirmPassword
                            ? 'border-[var(--error)] focus:border-[var(--error)] focus:ring-1 focus:ring-[var(--error)]'
                            : touched.confirmPassword && !validationErrors.confirmPassword && confirmPassword
                              ? 'border-[var(--success)] focus:border-[var(--success)] focus:ring-1 focus:ring-[var(--success)]'
                              : 'border-custom focus:border-accent-blue focus:ring-1 focus:ring-accent-blue'
                        )}
                        placeholder={t('auth.resetPassword.confirmPlaceholder')}
                      />
                      <button
                        type="button"
                        onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                        className="absolute right-3 top-1/2 -translate-y-1/2 text-muted hover:text-fg-primary transition-colors"
                        tabIndex={-1}
                      >
                        {showConfirmPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                      </button>
                    </div>
                    {touched.confirmPassword && validationErrors.confirmPassword && (
                      <p id="reset-confirm-password-error" className="mt-1 text-xs text-[var(--error)] flex items-center gap-1" role="alert">
                        <AlertCircle className="w-3 h-3" />
                        {validationErrors.confirmPassword}
                      </p>
                    )}
                  </div>

                  <button
                    type="submit"
                    disabled={formState === 'loading'}
                    className="w-full bg-accent-blue hover:bg-accent-blue-hover text-[var(--text-inverse)] font-bold py-3 rounded-xl transition-all shadow-md flex justify-center items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    {formState === 'loading' ? (
                      <>
                        <Loader2 size={18} className="animate-spin" />
                        {t('auth.resetPassword.updating')}
                      </>
                    ) : (
                      <>
                        <Lock size={18} />
                        {t('auth.resetPassword.submit')}
                      </>
                    )}
                  </button>
                </form>

                <div className="mt-6 pt-6 border-t border-custom">
                  <p className="text-sm text-muted">
                    <strong className="text-[var(--text-primary)]">{t('auth.resetPassword.securityTip')}</strong>
                    <br />
                    {t('auth.resetPassword.securityTipDesc')}
                  </p>
                </div>
              </>
            )}
          </div>

          {formState !== 'success' && (
            <p className="text-center text-sm text-muted mt-8">
              {t('auth.resetPassword.rememberedPassword')}{' '}
              <Link href="/auth/login" className="text-accent-blue font-semibold hover:underline">
                {t('auth.resetPassword.loginHere')}
              </Link>
            </p>
          )}
        </div>
      </div>
    </div>
  );
}

function getPasswordStrength(password: string, t: (key: string) => string): { strength: number; label: string; color: string } {
  if (!password) return { strength: 0, label: '', color: '' };
  
  let strength = 0;
  if (password.length >= 8) strength++;
  if (/[A-Z]/.test(password)) strength++;
  if (/[a-z]/.test(password)) strength++;
  if (/[0-9]/.test(password)) strength++;
  if (/[^A-Za-z0-9]/.test(password)) strength++;

  const labels = [t('auth.passwordStrength.weak'), t('auth.passwordStrength.weak'), t('auth.passwordStrength.fair'), t('auth.passwordStrength.good'), t('auth.passwordStrength.strong'), t('auth.passwordStrength.veryStrong')];
  const colors = ['bg-[var(--error)]', 'bg-[var(--error)]', 'bg-[var(--warning)]', 'bg-[var(--info)]', 'bg-[var(--success)]', 'bg-[var(--success)]'];
  
  return {
    strength,
    label: labels[strength],
    color: colors[strength],
  };
}

function LoadingSpinner() {
  return (
    <div className="min-h-screen bg-background font-sans text-fg-primary flex items-center justify-center" role="status">
      <div className="flex items-center gap-3 text-muted">
        <Loader2 size={24} className="animate-spin" />
        <span>Loading...</span>
      </div>
    </div>
  );
}

export default function ResetPasswordPage() {
  return (
    <Suspense fallback={<LoadingSpinner />}>
      <Content />
    </Suspense>
  );
}

﻿/**
 * Checkout Page
 * 
 * Página para comprar InkCoins con Stripe.
 */

'use client';

import { loadStripe } from '@stripe/stripe-js/pure';
import { 
  Coins, 
  CreditCard, 
  CheckCircle, 
  Loader2,
  Sparkles,
  Zap,
  Crown
} from 'lucide-react';
import { useRouter } from 'next/navigation';
import { useSession } from 'next-auth/react';
import { useState } from 'react';

import { Button } from '@/components/ui/Button';
import { useT } from '@/i18n';
import { INKCOIN_PACKAGES, formatAmount } from '@/lib/stripe';
import { cn } from '@/lib/utils';

const stripePromise = loadStripe(process.env.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY || '');

export default function CheckoutPage() {
  const router = useRouter();
  const { data: session, status } = useSession();
  const t = useT();
  const [selectedPackage, _setSelectedPackage] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handlePurchase = async (packageId: string) => {
    if (!session?.user) {
      router.push('/auth/login?callbackUrl=/checkout');
      return;
    }

    setIsLoading(true);
    setError(null);

    try {
      // Create checkout session
      const response = await fetch('/api/checkout', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ packageId }),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.error || 'Failed to create checkout');
      }

      // Redirect to Stripe Checkout
      const stripe = await stripePromise;
      if (stripe) {
        const { error: stripeError } = await (stripe as any).redirectToCheckout({
          sessionId: data.sessionId,
        });
        if (stripeError) {
          throw new Error(stripeError.message);
        }
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'An error occurred');
      setIsLoading(false);
    }
  };

  if (status === 'loading') {
    return (
      <div className="min-h-screen bg-[var(--background)] pt-20 flex items-center justify-center" role="status">
        <Loader2 className="w-8 h-8 animate-spin text-[var(--primary)]" />
      </div>
    );
  }

  if (status === 'unauthenticated') {
    return (
      <div className="min-h-screen bg-[var(--background)] pt-20 text-center px-4">
          <h1 className="text-2xl font-bold text-[var(--text-primary)] mb-4">{t('checkout.loginRequired')}</h1>
          <p className="text-[var(--text-secondary)] mb-6">{t('checkout.loginRequiredDesc')}</p>
          <Button onClick={() => router.push('/auth/login?callbackUrl=/checkout')}>
            {t('checkout.login')}
          </Button>
        </div>
    );
  }

  return (
    <div className="pt-20 pb-16 px-4">
        <div className="max-w-5xl mx-auto">
          {/* Header */}
          <div className="text-center mb-12">
            <div className="inline-flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-[var(--warning)]/20 to-[var(--warning)]/10 rounded-full border border-[var(--warning)]/30 mb-6">
              <Coins className="w-5 h-5 text-[var(--warning)]" aria-hidden="true" />
              <span className="text-[var(--warning)] font-medium">{t('checkout.badge')}</span>
            </div>
            <h1 className="text-4xl font-bold text-[var(--text-primary)] mb-4">
              {t('checkout.title')}
            </h1>
            <p className="text-[var(--text-secondary)] text-lg max-w-2xl mx-auto">
              {t('checkout.description')}
            </p>
          </div>

          {/* Error */}
          {error && (
            <div className="mb-8 bg-[var(--error)]/10 border border-[var(--error)]/30 rounded-xl p-4 text-center" role="alert">
              <p className="text-[var(--error)]">{error}</p>
            </div>
          )}

          {/* Packages */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
            {INKCOIN_PACKAGES.map((pkg, index) => (
              <div
                key={pkg.id}
                className={cn(
                  'relative bg-[var(--surface)]/50 rounded-2xl p-6 border transition-all duration-300',
                  selectedPackage === pkg.id
                    ? 'border-[var(--primary)] bg-[var(--primary)]/10'
                    : 'border-[var(--border)] hover:border-[var(--border-strong)]'
                )}
              >
                {/* Popular badge */}
                {index === 1 && (
                  <div className="absolute -top-3 left-1/2 -translate-x-1/2 px-3 py-1 bg-[var(--primary)] text-[var(--text-primary)] text-xs font-bold rounded-full">
                    {t('checkout.popular')}
                  </div>
                )}

                {/* Icon */}
                <div className={cn(
                  'w-12 h-12 rounded-xl flex items-center justify-center mb-4',
                  index === 0 && 'bg-[var(--surface-sunken)]',
                  index === 1 && 'bg-[var(--primary)]/20',
                  index === 2 && 'bg-[var(--accent-purple)]/20',
                  index === 3 && 'bg-[var(--warning)]/20'
                )}>
                  {index === 0 && <Coins className="w-6 h-6 text-[var(--text-secondary)]" aria-hidden="true" />}
                  {index === 1 && <Zap className="w-6 h-6 text-[var(--primary)]" aria-hidden="true" />}
                  {index === 2 && <Sparkles className="w-6 h-6 text-[var(--accent-purple)]" aria-hidden="true" />}
                  {index === 3 && <Crown className="w-6 h-6 text-[var(--warning)]" aria-hidden="true" />}
                </div>

                {/* Amount */}
                <div className="text-3xl font-bold text-[var(--text-primary)] mb-1">
                  {pkg.amount.toLocaleString()}
                </div>
                <div className="text-sm text-[var(--text-secondary)] mb-4">{t('checkout.inkCoins')}</div>

                {/* Price */}
                <div className="text-2xl font-bold text-[var(--text-primary)] mb-1">
                  {formatAmount(pkg.priceUSD)}
                </div>
                <div className="text-xs text-[var(--text-tertiary)] mb-6">USD</div>

                {/* Savings */}
                {index > 0 && (
                  <div className="text-xs text-[var(--success)] mb-4">
                    {t('checkout.save')} {Math.round((1 - pkg.priceUSD / (pkg.amount * 1)) * 100)}%
                  </div>
                )}

                {/* Button */}
                <Button
                  onClick={() => handlePurchase(pkg.id)}
                  disabled={isLoading}
                  variant={selectedPackage === pkg.id ? 'default' : 'outline'}
                  className="w-full"
                >
                  {isLoading ? (
                    <Loader2 className="w-4 h-4 animate-spin" />
                  ) : (
                    <>
                      <CreditCard className="w-4 h-4 mr-2" />
                      {t('checkout.buy')}
                    </>
                  )}
                </Button>
              </div>
            ))}
          </div>

          {/* Features */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
            <div className="bg-[var(--surface)]/30 rounded-xl p-6 border border-[var(--border)]">
              <CheckCircle className="w-8 h-8 text-[var(--success)] mb-4" aria-hidden="true" />
              <h3 className="font-semibold text-[var(--text-primary)] mb-2">{t('checkout.securePayment')}</h3>
              <p className="text-sm text-[var(--text-secondary)]">
                {t('checkout.securePaymentDesc')}
              </p>
            </div>
            <div className="bg-[var(--surface)]/30 rounded-xl p-6 border border-[var(--border)]">
              <Coins className="w-8 h-8 text-[var(--warning)] mb-4" aria-hidden="true" />
              <h3 className="font-semibold text-[var(--text-primary)] mb-2">{t('checkout.instantDelivery')}</h3>
              <p className="text-sm text-[var(--text-secondary)]">
                {t('checkout.instantDeliveryDesc')}
              </p>
            </div>
            <div className="bg-[var(--surface)]/30 rounded-xl p-6 border border-[var(--border)]">
              <Sparkles className="w-8 h-8 text-[var(--accent-purple)] mb-4" aria-hidden="true" />
              <h3 className="font-semibold text-[var(--text-primary)] mb-2">{t('checkout.noExpiration')}</h3>
              <p className="text-sm text-[var(--text-secondary)]">
                {t('checkout.noExpirationDesc')}
              </p>
            </div>
          </div>

          {/* FAQ */}
          <div className="max-w-2xl mx-auto">
            <h2 className="text-2xl font-bold text-[var(--text-primary)] mb-6 text-center">{t('checkout.faq')}</h2>
            <div className="space-y-4">
              <details className="bg-[var(--surface)]/30 rounded-xl border border-[var(--border)]">
                <summary className="p-4 cursor-pointer font-medium text-[var(--text-primary)]">
                  {t('checkout.faq1Q')}
                </summary>
                <div className="px-4 pb-4 text-[var(--text-secondary)] text-sm">
                  {t('checkout.faq1A')}
                </div>
              </details>
              <details className="bg-[var(--surface)]/30 rounded-xl border border-[var(--border)]">
                <summary className="p-4 cursor-pointer font-medium text-[var(--text-primary)]">
                  {t('checkout.faq2Q')}
                </summary>
                <div className="px-4 pb-4 text-[var(--text-secondary)] text-sm">
                  {t('checkout.faq2A')}
                </div>
              </details>
              <details className="bg-[var(--surface)]/30 rounded-xl border border-[var(--border)]">
                <summary className="p-4 cursor-pointer font-medium text-[var(--text-primary)]">
                  {t('checkout.faq3Q')}
                </summary>
                <div className="px-4 pb-4 text-[var(--text-secondary)] text-sm">
                  {t('checkout.faq3A')}
                </div>
              </details>
            </div>
          </div>
        </div>
    </div>
  );
}

