interface ClanMember {
  id: string;
  userId: string;
  role: string;
  joinedAt: string;
  contributedScore: number;
  user: {
    id: string;
    username: string;
    displayName: string | null;
    avatarUrl: string | null;
    xpPoints: number;
    level: number;
  };
}

interface ClanData {
  id: string;
  name: string;
  description: string | null;
  emblemUrl: string | null;
  totalScore: number;
  monthlyScore: number;
  currentSeason: number;
  leaderId: string | null;
  createdAt: string;
  members: ClanMember[];
  memberCount: number;
}

