// ── Main Component ─────────────────────────────────────

interface ClanDetailClientProps {
  clan: ClanData;
  userMembership: { role: 'MEMBER' | 'LEADER' | 'OFFICER' } | null;
  userId: string | null;
}

export default function ClanDetailClient({
  clan,
  userMembership: initialMembership,
  userId,
}: ClanDetailClientProps) {
  const t = useT();
  const [userMembership, setUserMembership] = useState(initialMembership);
  const [joining, setJoining] = useState(false);
  const [actionError, setActionError] = useState<string | null>(null);
  const shouldReduceMotion = useReducedMotion();

  async function handleJoinLeave() {
    setJoining(true);
    setActionError(null);
    try {
      if (userMembership) {
        const res = await fetch(`/api/clans/${clan.id}/leave`, { method: 'POST' });
        if (!res.ok) {
          const data = await res.json();
          throw new Error(data.error || t('clanDetail.errorLeave'));
        }
        setUserMembership(null);
      } else {
        const res = await fetch(`/api/clans/${clan.id}/join`, { method: 'POST' });
        if (!res.ok) {
          const data = await res.json();
          throw new Error(data.error || t('clanDetail.errorJoin'));
        }
        setUserMembership({ role: 'MEMBER' });
      }
    } catch (err: any) {
      setActionError(err.message);
    } finally {
      setJoining(false);
    }
  }

  const joinedLabel = userMembership
    ? userMembership.role === 'LEADER'
      ? t('clanDetail.youAreLeader')
      : userMembership.role === 'OFFICER'
        ? t('clanDetail.youAreOfficer')
        : t('clanDetail.youAreMember')
    : null;

  return (
    <div className="min-h-screen bg-[var(--background)] text-[var(--text-primary)] pb-16">
      {/* ═══ Hero Banner ═══ */}
      <header className="relative bg-gradient-to-br from-[var(--accent-purple)]/20 via-[var(--primary)]/10 to-[var(--background)] border-b border-[var(--border)] overflow-hidden">
        {/* Background pattern */}
        <div
          className="absolute inset-0 opacity-[0.03] dark:opacity-[0.06]"
          style={{
            backgroundImage:
              'radial-gradient(circle at 25% 25%, var(--accent-purple) 1px, transparent 1px), radial-gradient(circle at 75% 75%, var(--primary) 1px, transparent 1px)',
            backgroundSize: '48px 48px',
          }}
          aria-hidden="true"
        />
        {/* Glow orbs */}
        <div className="absolute top-10 left-10 w-72 h-72 bg-[var(--accent-purple)]/15 rounded-full blur-3xl" aria-hidden="true" />
        <div className="absolute bottom-10 right-10 w-64 h-64 bg-[var(--primary)]/10 rounded-full blur-3xl" aria-hidden="true" />

        <div className="max-w-5xl mx-auto px-6 py-12 relative z-10">
          <div className="flex flex-col md:flex-row items-center md:items-end gap-8">
            {/* Emblem */}
            <HeroEmblem clan={clan} />

            {/* Info */}
            <motion.div
              className="flex-1 text-center md:text-left"
              initial={shouldReduceMotion ? {} : { opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.2, duration: 0.5 }}
            >
              {/* Badge: season */}
              <div className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-[var(--accent-purple)]/15 text-[var(--accent-purple)] text-xs font-bold mb-3">
                <Flame size={13} />
                {t('clanDetail.season')} {clan.currentSeason}
              </div>

              <h1 className="text-4xl md:text-5xl font-extrabold tracking-tight text-[var(--text-primary)] mb-3">
                {clan.name}
              </h1>

              <p className="text-[var(--text-secondary)] text-lg max-w-xl leading-relaxed">
                {clan.description || t('clanDetail.defaultDescription')}
              </p>

              {/* Meta pills */}
              <div className="flex flex-wrap items-center justify-center md:justify-start gap-3 mt-5">
                <span className="inline-flex items-center gap-1.5 text-sm font-semibold text-[var(--text-secondary)] bg-[var(--surface)] border border-[var(--border)] rounded-full px-3 py-1.5">
                  <Users size={15} className="text-[var(--primary)]" />
                  {clan.memberCount} {t('clanDetail.members')}
                </span>
                <span className="inline-flex items-center gap-1.5 text-sm font-semibold text-[var(--text-secondary)] bg-[var(--surface)] border border-[var(--border)] rounded-full px-3 py-1.5">
                  <Calendar size={15} className="text-[var(--accent-purple)]" />
                  {t('clanDetail.founded')} {new Date(clan.createdAt).toLocaleDateString('es-ES', { month: 'short', year: 'numeric' })}
                </span>
                <span className="inline-flex items-center gap-1.5 text-sm font-semibold text-[var(--text-secondary)] bg-[var(--surface)] border border-[var(--border)] rounded-full px-3 py-1.5">
                  <Hash size={15} className="text-[var(--text-muted)]" />
                  {clan.totalScore.toLocaleString()} {t('clanDetail.totalPts')}
                </span>
              </div>
            </motion.div>

            {/* Join/Leave Button */}
            <motion.div
              className="flex-shrink-0"
              initial={shouldReduceMotion ? {} : { opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ delay: 0.4, duration: 0.4 }}
            >
              {userId ? (
                <div className="flex flex-col items-center gap-2">
                  {joinedLabel && (
                    <span className="text-xs font-semibold text-[var(--text-muted)]">{joinedLabel}</span>
                  )}
                  <button
                    onClick={handleJoinLeave}
                    disabled={joining}
                    className={`px-6 py-3 rounded-xl font-bold transition-all flex items-center gap-2 shadow-lg cursor-pointer text-sm ${
                      userMembership
                        ? 'bg-[var(--surface)] border-2 border-[var(--border)] text-[var(--text-secondary)] hover:border-[var(--error)]/40 hover:text-[var(--error)] hover:bg-[var(--error)]/5'
                        : 'bg-gradient-to-r from-[var(--accent-purple)] to-[var(--primary)] text-white hover:shadow-xl hover:shadow-[var(--accent-purple)]/25 hover:scale-105 active:scale-95'
                    }`}
                  >
                    {joining ? (
                      <Loader2 size={18} className="animate-spin" />
                    ) : userMembership ? (
                      <>
                        <Shield size={18} />
                        {t('clanDetail.leaveClan')}
                      </>
                    ) : (
                      <>
                        <Plus size={18} />
                        {t('clanDetail.joinClan')}
                      </>
                    )}
                  </button>
                </div>
              ) : (
                <div className="text-center">
                  <p className="text-xs text-[var(--text-muted)] mb-2">{t('clanDetail.loginToJoin')}</p>
                  <Link
                    href="/auth/login"
                    className="px-6 py-3 rounded-xl font-bold bg-gradient-to-r from-[var(--accent-purple)] to-[var(--primary)] text-white hover:shadow-xl hover:shadow-[var(--accent-purple)]/25 transition-all inline-flex items-center gap-2 text-sm"
                  >
                    <Plus size={18} />
                    {t('clanDetail.joinClan')}
                  </Link>
                </div>
              )}
            </motion.div>
          </div>
        </div>
      </header>

      {/* ═══ Main Content ═══ */}
      <div className="max-w-5xl mx-auto px-6 mt-8 grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Error banner */}
        {actionError && (
          <div className="lg:col-span-3 bg-[var(--error)]/10 border border-[var(--error)]/30 text-[var(--error)] rounded-xl p-4 text-sm font-medium flex items-center gap-3">
            <AlertTriangle size={18} />
            {actionError}
            <button
              onClick={() => setActionError(null)}
              className="ml-auto text-[var(--error)]/70 hover:text-[var(--error)]"
              aria-label={t('clanDetail.closeError')}
            >
              ✕
            </button>
          </div>
        )}

        {/* Left Column: Stats */}
        <div className="space-y-5">
          {/* Quick Stats Grid */}
          <div className="grid grid-cols-2 gap-3">
            <StatCard
              icon={Users}
              label={t('clanDetail.members')}
              value={clan.memberCount.toString()}
              colorClass="bg-[var(--primary)]/15 text-[var(--primary)]"
              index={0}
            />
            <StatCard
              icon={Flame}
              label={t('clanDetail.monthlyScore')}
              value={clan.monthlyScore.toLocaleString()}
              colorClass="bg-[var(--accent-purple)]/15 text-[var(--accent-purple)]"
              index={1}
            />
          </div>

          <SeasonProgress clan={clan} />
          <TotalScoreCard clan={clan} />
        </div>

        {/* Right Column: Members */}
        <div className="lg:col-span-2">
          <MembersSection clan={clan} />
        </div>
      </div>
    </div>
  );
}

'use client';

import { ArrowLeft, Users, ImageIcon, AlertCircle, Loader2 } from 'lucide-react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { useSession } from 'next-auth/react';
import React, { useState, useEffect } from 'react';

import { OptimizedImage } from '@/components/Image/OptimizedImage';


export default function CreateClanPage() {
  const { status } = useSession();
  const router = useRouter();
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    emblemUrl: '',
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (status === 'unauthenticated') {
      router.push('/auth/login?callbackUrl=/community/clans/create');
    }
  }, [status, router]);

  if (status === 'loading' || status === 'unauthenticated') {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center" role="status">
        <Loader2 className="w-8 h-8 animate-spin text-accent-purple" />
      </div>
    );
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    // Validation
    if (formData.name.trim().length < 3) {
      setError('El nombre debe tener al menos 3 caracteres');
      return;
    }

    if (formData.name.trim().length > 50) {
      setError('El nombre no puede exceder 50 caracteres');
      return;
    }

    try {
      setLoading(true);
      const response = await fetch('/api/clans', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: formData.name.trim(),
          description: formData.description.trim() || undefined,
          emblemUrl: formData.emblemUrl.trim() || undefined,
        }),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.error || 'Error al crear el clan');
      }

      // Redirect to the new clan
      router.push(`/community/clan/${data.clan.id}`);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  return (
    <div className="bg-background font-sans text-fg-primary pt-20 pb-10">

    {/* Header */}
      <div className="bg-secondary border-b border-custom">
        <div className="max-w-3xl mx-auto px-6 pb-8">
          <Link
            href="/community/clans"
            className="inline-flex items-center gap-2 text-muted hover:text-fg-primary transition-colors mb-4"
          >
          <ArrowLeft size={18} aria-hidden="true" />
          Volver a Clanes
        </Link>
        <h1 className="text-3xl font-extrabold tracking-tight flex items-center gap-3">
          <Users className="text-[var(--primary)]" size={30} aria-hidden="true" />
            Crear Nuevo Clan
          </h1>
          <p className="text-muted mt-2">
            Funda tu propio clan y reúne a otros lectores para competir juntos
          </p>
        </div>
      </div>

      <div className="max-w-3xl mx-auto px-6 mt-8">
        <form onSubmit={handleSubmit} className="bg-secondary border border-custom rounded-2xl p-8 shadow-sm">
        {error && (
          <div className="bg-accent-red/10 border border-accent-red/30 rounded-xl p-4 mb-6 flex items-start gap-3" role="alert" id="clan-error">
            <AlertCircle className="text-accent-red flex-shrink-0 mt-0.5" size={20} aria-hidden="true" />
            <p className="text-accent-red text-sm">{error}</p>
          </div>
        )}

          {/* Clan Name */}
          <div className="mb-6">
            <label htmlFor="name" className="block text-sm font-bold mb-2">
              Nombre del Clan <span className="text-accent-red">*</span>
            </label>
            <input
              type="text"
              id="name"
              name="name"
              value={formData.name}
              onChange={handleChange}
              placeholder="Ej: Los Guardianes de la Lectura"
              maxLength={50}
              className="w-full bg-tertiary border border-custom rounded-xl px-4 py-3 text-fg-primary placeholder:text-muted focus:outline-none focus:border-accent-purple transition-colors"
              required
              autoComplete="off"
              aria-describedby="name-count clan-error"
            />
            <p id="name-count" className="text-xs text-muted mt-2">
              {formData.name.length}/50 caracteres
            </p>
          </div>

          {/* Description */}
          <div className="mb-6">
            <label htmlFor="description" className="block text-sm font-bold mb-2">
              Descripción
            </label>
            <textarea
              id="description"
              name="description"
              value={formData.description}
              onChange={handleChange}
              placeholder="Describe tu clan, sus objetivos y qué tipo de miembros buscas..."
              rows={4}
              maxLength={500}
              className="w-full bg-tertiary border border-custom rounded-xl px-4 py-3 text-fg-primary placeholder:text-muted focus:outline-none focus:border-accent-purple transition-colors resize-none"
              aria-describedby="desc-count"
            />
            <p id="desc-count" className="text-xs text-muted mt-2">
              {formData.description.length}/500 caracteres
            </p>
          </div>

          {/* Emblem URL */}
          <div className="mb-8">
            <label htmlFor="emblemUrl" className="block text-sm font-bold mb-2">
              URL del Emblema
            </label>
            <div className="relative">
              <ImageIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-muted" size={18} aria-hidden="true" />
              <input
                type="url"
                id="emblemUrl"
                name="emblemUrl"
                value={formData.emblemUrl}
                onChange={handleChange}
                placeholder="https://ejemplo.com/emblema.png"
                className="w-full bg-tertiary border border-custom rounded-xl pl-11 pr-4 py-3 text-fg-primary placeholder:text-muted focus:outline-none focus:border-accent-purple transition-colors"
                autoComplete="url"
                aria-describedby="emblem-hint"
              />
            </div>
            <p id="emblem-hint" className="text-xs text-muted mt-2">
              URL de una imagen para el emblema de tu clan (recomendado: 256x256px)
            </p>
          </div>

          {/* Preview */}
          {formData.name && (
            <div className="bg-tertiary border border-custom rounded-xl p-6 mb-8">
              <h3 className="text-sm font-bold text-muted uppercase mb-4">Vista Previa</h3>
              <div className="flex items-center gap-4">
                <div className="w-16 h-16 rounded-xl bg-gradient-to-br from-accent-purple to-accent-blue flex items-center justify-center text-3xl shadow-lg">
                  {formData.emblemUrl ? (
                    <OptimizedImage
                      src={formData.emblemUrl}
                      alt="Emblema"
                      width={64}
                      height={64}
                      className="rounded-xl"
                      objectFit="cover"
                    />
                  ) : (
                    '👑'
                  )}
                </div>
                <div>
                  <h4 className="font-bold text-lg">{formData.name}</h4>
                  <p className="text-sm text-muted">
                    {formData.description || 'Sin descripción'}
                  </p>
                </div>
              </div>
            </div>
          )}

          {/* Submit Button */}
          <div className="flex flex-col sm:flex-row gap-4">
            <button
              type="submit"
              disabled={loading}
              className="flex-1 bg-accent-purple hover:bg-[var(--accent-purple-hover)] disabled:opacity-50 disabled:cursor-not-allowed text-[var(--text-primary)] px-6 py-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2 shadow-lg shadow-accent-purple/20"
            >
              {loading ? (
                <>
                <Loader2 className="animate-spin" size={20} aria-hidden="true" />
                Creando...
              </>
            ) : (
              <>
                <Users size={20} aria-hidden="true" />
                  Crear Clan
                </>
              )}
            </button>
            <Link
              href="/community/clans"
              className="flex-1 sm:flex-none bg-tertiary border border-custom hover:border-accent-purple/50 text-fg-primary px-6 py-4 rounded-xl font-bold transition-all text-center"
            >
              Cancelar
            </Link>
          </div>
        </form>

        {/* Info Box */}
        <div className="mt-8 bg-accent-blue/10 border border-accent-blue/30 rounded-xl p-6">
          <h3 className="font-bold text-accent-blue mb-2">¿Qué es un Clan?</h3>
          <ul className="text-sm text-muted space-y-2">
            <li>• Los clanes compiten entre sí en temporadas mensuales</li>
            <li>• Gana puntos para tu clan leyendo manga y haciendo correcciones</li>
            <li>• Los mejores clanes reciben recompensas al final de cada temporada</li>
            <li>• Solo puedes ser miembro de un clan a la vez</li>
            <li>• El creador del clan será el líder automáticamente</li>
          </ul>
        </div>
      </div>
    </div>
  );
}

