'use client';

import {
  Users,
  Search,
  MessageSquare,
  Pin,
  TrendingUp,
  BookOpen,
  Palette,
  Lightbulb,
  Megaphone,
  Heart,
  Filter,
  Plus,
  ChevronRight,
  Loader2,
  X,
  AlertTriangle,
} from 'lucide-react';
import { useState, useEffect, useCallback } from 'react';

import { Button } from '@/components/ui/Button';
import { Card, CardContent } from '@/components/ui/Card';
import { Input } from '@/components/ui/Input';

interface ForumAuthor {
  id: string;
  username: string;
  displayName?: string | null;
  avatarUrl?: string | null;
  role: string;
}

interface ApiForumThread {
  id: string;
  title: string;
  slug: string;
  content: string;
  isPinned: boolean;
  isLocked: boolean;
  tags: string;
  viewCount: number;
  createdAt: string;
  updatedAt: string;
  author: ForumAuthor;
  category: { id: string; name: string; slug: string; icon?: string | null };
  _count: { posts: number };
}

interface ForumCategory {
  id: string;
  name: string;
  slug: string;
  description?: string | null;
  icon?: string | null;
  _count: { threads: number };
}

const categoryIconMap: Record<string, React.ElementType> = {
  general: MessageSquare,
  techniques: Palette,
  prompts: Lightbulb,
  publishing: BookOpen,
  growth: TrendingUp,
  announcements: Megaphone,
};

const FALLBACK_THREADS: ApiForumThread[] = [
  {
    id: '1', title: 'Guía de mejores prácticas para subida de capítulos', slug: 'guia-mejores-practicas',
    content: 'Recomendaciones para optimizar la calidad y tamaño de tus imágenes al subir capítulos...',
