import type { Metadata } from 'next';
import { redirect } from 'next/navigation';

import { CreatorSponsors } from '@/components/Sponsorships/CreatorSponsors';
import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

export const metadata: Metadata = {
  title: 'Patrocinios | Creador | Inkverse',
  description: 'Gestiona los patrocinios de tus capítulos',
};

async function getCreatorSponsors(userId: string) {
  const mangas = await prisma.mangaSeries.findMany({
    where: { authorId: userId },
    select: {
      id: true,
      title: true,
      slug: true,
      chapters: {
        select: {
          id: true,
          chapterNumber: true,
          title: true,
          sponsorshipBids: {
            where: { status: 'ACTIVE' },
            include: {
              user: { select: { id: true, username: true, avatarUrl: true } },
            },
            orderBy: { bidAmount: 'desc' },
          },
        },
        orderBy: { chapterNumber: 'desc' },
        take: 10,
      },
    },
    orderBy: { updatedAt: 'desc' },
  });

  const recentBids = await prisma.sponsorshipBid.findMany({
    where: {
      chapter: { manga: { authorId: userId } },
    },
    include: {
      user: { select: { id: true, username: true, avatarUrl: true } },
      chapter: { select: { id: true, chapterNumber: true, title: true, manga: { select: { title: true, slug: true } } } },
    },
    orderBy: { createdAt: 'desc' },
    take: 50,
  });

  const stats = {
    totalBids: recentBids.length,
    activeBids: recentBids.filter(b => b.status === 'ACTIVE').length,
    totalRevenue: recentBids.reduce((sum, b) => sum + b.bidAmount, 0),
    uniqueSponsors: new Set(recentBids.map(b => b.userId)).size,
  };

  return { mangas, recentBids, stats };
}

export default async function CreatorSponsorsPage() {
  const session = await auth();
  if (!session?.user?.id) redirect('/auth/login');

  const { mangas, recentBids, stats } = await getCreatorSponsors(session.user.id);

  return (
    <div className="max-w-5xl mx-auto px-4 py-8">
      <div className="mb-8">
        <h1 className="text-2xl font-bold mb-2">Patrocinios</h1>
        <p className="text-muted">Gestiona los patrocinios de tus capítulos</p>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
        <div className="bg-secondary border border-custom rounded-xl p-4">
          <p className="text-2xl font-bold">{stats.totalBids}</p>
          <p className="text-xs text-muted">Pujas totales</p>
        </div>
        <div className="bg-secondary border border-custom rounded-xl p-4">
          <p className="text-2xl font-bold text-accent-green">{stats.activeBids}</p>
          <p className="text-xs text-muted">Pujas activas</p>
        </div>
        <div className="bg-secondary border border-custom rounded-xl p-4">
          <p className="text-2xl font-bold text-[var(--warning)]">{stats.totalRevenue.toLocaleString()}</p>
          <p className="text-xs text-muted">IC recaudados</p>
        </div>
        <div className="bg-secondary border border-custom rounded-xl p-4">
          <p className="text-2xl font-bold text-accent-blue">{stats.uniqueSponsors}</p>
          <p className="text-xs text-muted">Patrocinadores únicos</p>
        </div>
      </div>

      <CreatorSponsors mangas={mangas as any} recentBids={recentBids as any} />
    </div>
  );
}

﻿'use client';

import html2canvas from 'html2canvas';
import { Pencil, Eye, Download, Upload, Trash2 } from 'lucide-react';
import React, { useState } from 'react';

import { OptimizedImage } from '@/components/Image/OptimizedImage';
import { PanelTextOverlay } from '@/components/Reader/PanelTextOverlay';
import { Button } from '@/components/ui/Button';
import { usePanelTexts } from '@/hooks/usePanelTexts';

// Demo image - you can replace with your own manga panel
const DEMO_IMAGE = 'https://placehold.co/800x600/1a1a2e/ffffff?text=Panel+de+Manga';

export default function PanelTextsDemoPage() {
  const [isEditing, setIsEditing] = useState(true);
  const [exportUrl, setExportUrl] = useState<string | null>(null);
  const overlayRef = React.useRef<HTMLDivElement>(null);

  const {
    texts,
    setTexts,
    isDirty,
    clearTexts,
    exportAsJSON,
    importFromJSON,
  } = usePanelTexts({
    initialTexts: [
      {
        id: 'demo-1',
        text: '¡Hola!\nSoy un diálogo',
        x: 30,
        y: 25,
        fontSize: 16,
        color: '#1a1a1a',
        backgroundColor: 'rgba(255,255,255,0.95)',
        borderRadius: 50,
        padding: 16,
        rotation: 0,
        type: 'speech',
      },
      {
        id: 'demo-2',
        text: 'Pensando en...',
        x: 70,
        y: 40,
        fontSize: 15,
        color: '#4a4a4a',
        backgroundColor: 'rgba(240,240,240,0.95)',
        borderRadius: 30,
        padding: 14,
        rotation: 0,
        type: 'thought',
      },
    ],
  });

  const handleExportImage = async () => {
    if (!overlayRef.current) return;
    
    try {
      const canvas = await html2canvas(overlayRef.current, {
        useCORS: true,
        allowTaint: true,
        backgroundColor: null,
        scale: 2,
      });
      
      const url = canvas.toDataURL('image/png');
      setExportUrl(url);
      
      // Auto download
      const link = document.createElement('a');
      link.download = `inkverse-panel-${Date.now()}.png`;
      link.href = url;
      link.click();
    } catch (error) {
      console.error('Error exporting:', error);
      alert('Error al exportar la imagen');
    }
  };

  const handleExportJSON = () => {
    const json = exportAsJSON();
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.download = `panel-texts-${Date.now()}.json`;
    link.href = url;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleImportJSON = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    
    const reader = new FileReader();
    reader.onload = (event) => {
      const json = event.target?.result as string;
      importFromJSON(json);
    };
    reader.readAsText(file);
  };

  return (
    <div className="min-h-screen bg-[var(--surface)] py-8">
      <div className="max-w-6xl mx-auto px-4">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-[var(--text-primary)] mb-2">
            🎨 Editor de Viñetas
          </h1>
          <p className="text-[var(--text-secondary)]">
            Demostración del componente PanelTextOverlay. Añade, edita y posiciona viñetas de texto sobre paneles de manga.
          </p>
        </div>

        {/* Toolbar */}
        <div className="flex flex-wrap gap-3 mb-6 p-4 bg-[var(--surface-sunken)] rounded-xl">
          <Button
            onClick={() => setIsEditing(!isEditing)}
            variant={isEditing ? 'default' : 'outline'}
            className="flex items-center gap-2"
          >
            {isEditing ? <Eye className="w-4 h-4" /> : <Pencil className="w-4 h-4" />}
            {isEditing ? 'Vista previa' : 'Editar'}
          </Button>

          <Button
            onClick={handleExportImage}
            variant="outline"
            className="flex items-center gap-2"
          >
            <Download className="w-4 h-4" />
            Exportar imagen
          </Button>

          <Button
            onClick={handleExportJSON}
            variant="outline"
            className="flex items-center gap-2"
          >
            <Upload className="w-4 h-4" />
            Exportar JSON
          </Button>

          <label className="cursor-pointer">
            <input
              type="file"
              accept=".json"
              onChange={handleImportJSON}
              className="hidden"
            />
            <span className="inline-flex items-center gap-2 px-4 py-2 bg-[var(--surface-sunken)] hover:bg-[var(--surface-sunken)] text-[var(--text-primary)] rounded-lg transition-colors">
              <Upload className="w-4 h-4" />
              Importar JSON
            </span>
          </label>

          {isDirty && (
            <span className="flex items-center text-[var(--warning)] text-sm">
              • Cambios sin guardar
            </span>
          )}

          {texts.length > 0 && (
            <Button
              onClick={clearTexts}
              variant="outline"
              className="flex items-center gap-2 text-[var(--error)] hover:text-[var(--error)] ml-auto"
            >
              <Trash2 className="w-4 h-4" />
              Limpiar todo
            </Button>
          )}
        </div>

        {/* Main content */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Canvas */}
          <div className="lg:col-span-2">
            <div className="bg-[var(--surface-sunken)] rounded-xl p-4">
              <div ref={overlayRef} className="inline-block">
                <PanelTextOverlay
                  imageUrl={DEMO_IMAGE}
                  texts={texts}
                  onTextsChange={setTexts}
                  isEditing={isEditing}
                  readOnly={false}
                />
              </div>
            </div>
          </div>

          {/* Sidebar info */}
          <div className="space-y-4">
            {/* Instructions */}
            <div className="bg-[var(--surface-sunken)] rounded-xl p-4">
              <h3 className="font-semibold text-[var(--text-primary)] mb-3">📖 Instrucciones</h3>
              <ul className="space-y-2 text-sm text-[var(--text-secondary)]">
                <li className="flex items-start gap-2">
                  <span className="text-accent-blue">1.</span>
                  <span>Haz clic en "Editar" para activar el modo edición</span>
                </li>
                <li className="flex items-start gap-2">
                  <span className="text-accent-blue">2.</span>
                  <span>Usa el menú izquierdo para añadir viñetas</span>
                </li>
                <li className="flex items-start gap-2">
                  <span className="text-accent-blue">3.</span>
                  <span>Arrastra las viñetas para moverlas</span>
                </li>
                <li className="flex items-start gap-2">
                  <span className="text-accent-blue">4.</span>
                  <span>Haz clic en una viñeta para editar su texto</span>
                </li>
                <li className="flex items-start gap-2">
                  <span className="text-accent-blue">5.</span>
                  <span>Usa el panel derecho para personalizar estilos</span>
                </li>
              </ul>
            </div>

            {/* Stats */}
            <div className="bg-[var(--surface-sunken)] rounded-xl p-4">
              <h3 className="font-semibold text-[var(--text-primary)] mb-3">📊 Estadísticas</h3>
              <div className="space-y-2 text-sm">
                <div className="flex justify-between">
                  <span className="text-[var(--text-secondary)]">Total viñetas:</span>
                  <span className="text-[var(--text-primary)] font-medium">{texts.length}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-[var(--text-secondary)]">Diálogos:</span>
                  <span className="text-[var(--text-primary)] font-medium">
                    {texts.filter(t => t.type === 'speech').length}
                  </span>
                </div>
                <div className="flex justify-between">
                  <span className="text-[var(--text-secondary)]">Pensamientos:</span>
                  <span className="text-[var(--text-primary)] font-medium">
                    {texts.filter(t => t.type === 'thought').length}
                  </span>
                </div>
                <div className="flex justify-between">
                  <span className="text-[var(--text-secondary)]">Narración:</span>
                  <span className="text-[var(--text-primary)] font-medium">
                    {texts.filter(t => t.type === 'narration').length}
                  </span>
                </div>
                <div className="flex justify-between">
                  <span className="text-[var(--text-secondary)]">Sonidos:</span>
                  <span className="text-[var(--text-primary)] font-medium">
                    {texts.filter(t => t.type === 'sound').length}
                  </span>
                </div>
              </div>
            </div>

            {/* Types info */}
            <div className="bg-[var(--surface-sunken)] rounded-xl p-4">
              <h3 className="font-semibold text-[var(--text-primary)] mb-3">🎭 Tipos de viñetas</h3>
              <div className="space-y-3 text-sm">
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 rounded-full bg-[var(--surface-elevated)] flex-shrink-0"></div>
                  <div>
                    <p className="text-[var(--text-primary)] font-medium">Diálogo</p>
                    <p className="text-[var(--text-tertiary)] text-xs">Burbuja redonda con cola</p>
                  </div>
                </div>
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 rounded-full border-2 border-[var(--border)] border-dashed flex-shrink-0"></div>
                  <div>
                    <p className="text-[var(--text-primary)] font-medium">Pensamiento</p>
                    <p className="text-[var(--text-tertiary)] text-xs">Nube con bordes suaves</p>
                  </div>
                </div>
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 bg-[var(--text-primary)] border border-[var(--border)] flex-shrink-0"></div>
                  <div>
                    <p className="text-[var(--text-primary)] font-medium">Narración</p>
                    <p className="text-[var(--text-tertiary)] text-xs">Caja con fondo oscuro</p>
                  </div>
                </div>
                <div className="flex items-center gap-3">
                  <div className="text-[var(--error)] font-black text-lg">!</div>
                  <div>
                    <p className="text-[var(--text-primary)] font-medium">Efecto de sonido</p>
                    <p className="text-[var(--text-tertiary)] text-xs">Texto rotado, sin fondo</p>
                  </div>
                </div>
              </div>
            </div>

            {/* Export preview */}
            {exportUrl && (
              <div className="bg-[var(--surface-sunken)] rounded-xl p-4">
                <h3 className="font-semibold text-[var(--text-primary)] mb-3">👁️ Vista previa</h3>
                <div className="relative w-full rounded-lg overflow-hidden" style={{ aspectRatio: '16/9' }}>
                  <OptimizedImage 
                    src={exportUrl} 
                    alt="Export preview" 
                    fill
                    objectFit="contain"
                  />
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

