  const { locale } = useLocale();
  const dateLocale = locale === 'es' ? es : enUS;
  const shouldReduceMotion = useReducedMotion();
  const xpForNextLevel = user.level * 100;
  const xpProgress = Math.min(100, (user.xpPoints / xpForNextLevel) * 100);

