import type { Metadata } from 'next';
import { notFound } from 'next/navigation';

import { UserProfileClient } from './UserProfileClient';
import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';


interface UserProfilePageProps {
  params: Promise<{ username: string }>;
}

async function getUserData(username: string) {
  const user = await prisma.user.findUnique({
    where: { username },
    include: {
      _count: {
        select: {
          library: true,
          collections: true,
          following: true,
          achievements: true,
          createdMangas: true,
          activitiesFeed: true,
        },
      },
      achievements: {
        include: { achievement: true },
        orderBy: { unlockedAt: 'desc' },
        take: 6,
      },
      createdMangas: {
        orderBy: { createdAt: 'desc' },
        take: 4,
        select: {
          id: true,
          title: true,
          slug: true,
          coverUrl: true,
          status: true,
          rating: true,
          totalViews: true,
          _count: { select: { chapters: true } },
        },
      },
      clanMemberships: {
        take: 1,
        orderBy: { joinedAt: 'desc' },
        include: {
          clan: {
            select: { id: true, name: true, emblemUrl: true },
          },
        },
      },
      readingProgress: {
        orderBy: { updatedAt: 'desc' },
        take: 5,
        include: {
          manga: {
            select: { id: true, title: true, slug: true, coverUrl: true },
          },
          chapter: {
            select: { chapterNumber: true },
          },
        },
      },
      activitiesFeed: {
        where: { isPublic: true },
        orderBy: { createdAt: 'desc' },
        take: 10,
      },
      collections: {
        where: { isPublic: true },
        orderBy: { updatedAt: 'desc' },
        take: 12,
        include: {
          _count: { select: { items: true, likes: true } },
        },
      },
    },
  });

  return user as any;
}

export async function generateMetadata({ params }: UserProfilePageProps): Promise<Metadata> {
  const { username } = await params;
  const user = await getUserData(username);

  if (!user) {
    return { title: 'Usuario no encontrado | InkVerse' };
  }

  const displayName = user.displayName || user.username;
  const title = `${displayName} | InkVerse`;
  const description = `Perfil de ${displayName} en InkVerse · Nivel ${user.level} · ${user._count.createdMangas} mangas creados`;
  const ogImage = user.avatarUrl || undefined;

  return {
    title,
    description,
    openGraph: {
      title,
      description,
      type: 'profile',
      images: ogImage ? [{ url: ogImage, width: 400, height: 400, alt: displayName }] : undefined,
      username: user.username,
    },
    twitter: {
      card: 'summary',
      title,
      description,
      images: ogImage ? [ogImage] : undefined,
    },
    alternates: { canonical: `/user/${username}` },
  };
}

export default async function UserProfilePage({ params }: UserProfilePageProps) {
  const { username } = await params;
  const session = await auth();
  const user = await getUserData(username);

  if (!user) {
    notFound();
  }

  const isOwnProfile = session?.user?.id === user.id;

  return (
    <UserProfileClient
      user={user}
      isOwnProfile={isOwnProfile}
      sessionUserId={session?.user?.id}
    />
  );
}

import { DomainError } from '../../../core/errors/DomainError';
import type { Notification } from '../../../core/services/NotificationService';

export interface DeleteNotificationInputDTO {
  userId: string;
  notificationId: string;
}

export interface DeleteNotificationOutputDTO {
  success: boolean;
  notificationId: string;
}

export interface INotificationDeleteRepository {
  findById(notificationId: string): Promise<Notification | null>;
  deleteNotification(notificationId: string, userId?: string): Promise<boolean>;
}

export class DeleteNotificationUseCase {
  constructor(
    private readonly notificationRepo: INotificationDeleteRepository
  ) {}

  async execute(input: DeleteNotificationInputDTO): Promise<DeleteNotificationOutputDTO> {
    if (!input.userId || input.userId.trim().length === 0) {
      throw new ValidationError('ID de usuario requerido');
    }

    if (!input.notificationId || input.notificationId.trim().length === 0) {
      throw new ValidationError('ID de notificación requerido');
    }

    const notification = await this.notificationRepo.findById(input.notificationId);
    if (!notification) {
      throw new NotificationNotFoundError(input.notificationId);
    }

    if (notification.userId !== input.userId) {
      throw new UnauthorizedError('No autorizado para eliminar esta notificación');
    }

    const deleted = await this.notificationRepo.deleteNotification(input.notificationId, input.userId);
    if (!deleted) {
      throw new (DomainError as any)('Error al eliminar la notificación');
    }

    return {
      success: true,
      notificationId: input.notificationId,
    };
  }
}

class ValidationError extends DomainError {
  readonly code = 'VALIDATION_ERROR';
  readonly isOperational = true;
  constructor(message: string) {
    super(message);
  }
}

class NotificationNotFoundError extends DomainError {
  readonly code = 'NOTIFICATION_NOT_FOUND';
  readonly isOperational = true;
  constructor(notificationId: string) {
    super(`Notificación no encontrada: ${notificationId}`);
  }
}

class UnauthorizedError extends DomainError {
  readonly code = 'UNAUTHORIZED';
  readonly isOperational = true;
  constructor(message: string) {
    super(message);
  }
}

import { DomainError } from '../../../core/errors/DomainError';
import type { Notification } from '../../../core/services/NotificationService';

export interface MarkNotificationReadInputDTO {
  userId: string;
  notificationId: string;
}

export interface MarkAllNotificationsReadInputDTO {
  userId: string;
}

export interface MarkNotificationReadOutputDTO {
  success: boolean;
  notificationId?: string;
  markedCount?: number;
  unreadCount: number;
}

export interface INotificationWriteRepository {
  markAsRead(notificationId: string): Promise<Notification | null>;
  markAllAsRead(userId: string): Promise<number>;
  getUnreadCount(userId: string): Promise<number>;
  findById(notificationId: string): Promise<Notification | null>;
}

export class MarkNotificationReadUseCase {
  constructor(
    private readonly notificationRepo: INotificationWriteRepository
  ) {}

  async execute(input: MarkNotificationReadInputDTO): Promise<MarkNotificationReadOutputDTO> {
    if (!input.userId || input.userId.trim().length === 0) {
      throw new ValidationError('ID de usuario requerido');
    }

    if (!input.notificationId || input.notificationId.trim().length === 0) {
      throw new ValidationError('ID de notificación requerido');
    }

    const notification = await this.notificationRepo.findById(input.notificationId);
    if (!notification) {
      throw new NotificationNotFoundError(input.notificationId);
    }

    if (notification.userId !== input.userId) {
      throw new UnauthorizedError('No autorizado para modificar esta notificación');
    }

    const updated = await this.notificationRepo.markAsRead(input.notificationId);
    if (!updated) {
      throw new (DomainError as any)('Error al marcar notificación como leída');
    }

    const unreadCount = await this.notificationRepo.getUnreadCount(input.userId);

    return {
      success: true,
      notificationId: input.notificationId,
      unreadCount,
    };
  }

  async executeMarkAll(input: MarkAllNotificationsReadInputDTO): Promise<MarkNotificationReadOutputDTO> {
    if (!input.userId || input.userId.trim().length === 0) {
      throw new ValidationError('ID de usuario requerido');
    }

    const markedCount = await this.notificationRepo.markAllAsRead(input.userId);

    return {
      success: true,
      markedCount,
      unreadCount: 0,
    };
  }
}

class ValidationError extends DomainError {
  readonly code = 'VALIDATION_ERROR';
  readonly isOperational = true;
  constructor(message: string) {
    super(message);
  }
}

class NotificationNotFoundError extends DomainError {
  readonly code = 'NOTIFICATION_NOT_FOUND';
  readonly isOperational = true;
  constructor(notificationId: string) {
    super(`Notificación no encontrada: ${notificationId}`);
  }
}

class UnauthorizedError extends DomainError {
  readonly code = 'UNAUTHORIZED';
  readonly isOperational = true;
  constructor(message: string) {
    super(message);
  }
}

"use client";

import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
} from "recharts";

function getChartColors() {
  if (typeof document === 'undefined') return { grid: '#e5e5e5', axis: '#a3a3a3', text: '#6b6b6b' };
  const style = getComputedStyle(document.documentElement);
  return {
    grid: style.getPropertyValue('--border').trim() || '#e5e5e5',
    axis: style.getPropertyValue('--text-tertiary').trim() || '#a3a3a3',
    text: style.getPropertyValue('--text-secondary').trim() || '#6b6b6b',
  };
}

export interface MetricsLineChartDataPoint {
  [key: string]: string | number;
}

interface MetricsLineChartProps {
  data: MetricsLineChartDataPoint[];
  xKey: string;
  yKey: string;
  color?: string;
  unit?: string;
  name?: string;
}

const CustomTooltip = ({ active, payload, label, unit }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-[var(--surface-elevated)] border border-[var(--border)] rounded-lg p-3 shadow-lg">
        <p className="text-[var(--text-secondary)] text-xs mb-1">{label}</p>
        <p className="text-[var(--text-primary)] font-medium">
          {payload[0].value}
          {unit && <span className="text-[var(--text-tertiary)] ml-1">{unit}</span>}
        </p>
      </div>
    );
  }
  return null;
};

export function MetricsLineChart({
  data,
  xKey,
  yKey,
  color = "#3b82f6",
  unit = "",
  name = "Value",
}: MetricsLineChartProps) {
  const colors = getChartColors();

  return (
    <ResponsiveContainer width="100%" height={200}>
      <LineChart data={data} margin={{ top: 5, right: 5, left: 0, bottom: 5 }}>
        <CartesianGrid strokeDasharray="3 3" stroke={colors.grid} />
        <XAxis
          dataKey={xKey}
          tick={{ fill: colors.text, fontSize: 11 }}
          axisLine={{ stroke: colors.axis }}
          tickLine={{ stroke: colors.axis }}
        />
        <YAxis
          tick={{ fill: colors.text, fontSize: 11 }}
          axisLine={{ stroke: colors.axis }}
          tickLine={{ stroke: colors.axis }}
        />
        <Tooltip content={<CustomTooltip unit={unit} />} />
        <Line
          type="monotone"
          dataKey={yKey}
          stroke={color}
          strokeWidth={2}
          dot={{ fill: color, strokeWidth: 2, r: 3 }}
          activeDot={{ r: 5, stroke: color, strokeWidth: 2 }}
          name={name}
        />
      </LineChart>
    </ResponsiveContainer>
  );
}

export default MetricsLineChart;

"use client";

import {
  PieChart,
  Pie,
  Cell,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from "recharts";

export interface ModelUsageDataPoint {
  name: string;
  value: number;
  color: string;
}

interface ModelUsagePieChartProps {
  data: ModelUsageDataPoint[];
  innerRadius?: number;
}

const CustomTooltip = ({ active, payload }: any) => {
  if (active && payload && payload.length) {
    const data = payload[0].payload;
    const total = payload[0].payload.total || 100;
    const percentage = ((data.value / total) * 100).toFixed(1);
    
    return (
      <div className="bg-[var(--surface-elevated)] border border-[var(--border)] rounded-lg p-3 shadow-lg">
        <div className="flex items-center gap-2 mb-1">
          <div
            className="w-3 h-3 rounded-full"
            style={{ backgroundColor: data.color }}
          />
          <span className="text-[var(--text-primary)] font-medium">{data.name}</span>
        </div>
        <p className="text-[var(--text-secondary)] text-sm">
          {data.value.toLocaleString()} requests
        </p>
        <p className="text-[var(--text-tertiary)] text-xs">{percentage}% of total</p>
      </div>
    );
  }
  return null;
};

const CustomLegend = ({ payload }: any) => {
  if (!payload) return null;
  
  const total = payload.reduce((sum: number, entry: any) => 
    sum + (entry.payload?.value || 0), 0
  );
  
  return (
    <div className="flex flex-wrap justify-center gap-4 mt-4">
      {payload.map((entry: any, index: number) => {
        const percentage = total > 0 
          ? ((entry.payload.value / total) * 100).toFixed(1) 
          : "0.0";
        
        return (
          <div key={`legend-${index}`} className="flex items-center gap-2">
            <div
              className="w-3 h-3 rounded-full"
              style={{ backgroundColor: entry.color }}
            />
            <span className="text-[var(--text-secondary)] text-xs">
              {entry.value} ({percentage}%)
            </span>
          </div>
        );
      })}
    </div>
  );
};

export function ModelUsagePieChart({
  data,
  innerRadius = 60,
}: ModelUsagePieChartProps) {
  const total = data.reduce((sum, item) => sum + item.value, 0);
  const dataWithTotal = data.map(item => ({ ...item, total }));

  return (
    <ResponsiveContainer width="100%" height={250}>
      <PieChart>
        <Pie
          data={dataWithTotal}
          cx="50%"
          cy="45%"
          innerRadius={innerRadius}
          outerRadius={80}
          paddingAngle={2}
          dataKey="value"
          nameKey="name"
        >
          {dataWithTotal.map((entry, index) => (
            <Cell key={`cell-${index}`} fill={entry.color} stroke="none" />
          ))}
        </Pie>
        <Tooltip content={<CustomTooltip />} />
        <Legend content={<CustomLegend />} />
      </PieChart>
    </ResponsiveContainer>
  );
}

export default ModelUsagePieChart;

"use client";

import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from "recharts";

function getChartColors() {
  if (typeof document === 'undefined') return { grid: '#e5e5e5', axis: '#a3a3a3', text: '#6b6b6b' };
  const style = getComputedStyle(document.documentElement);
  return {
    grid: style.getPropertyValue('--border').trim() || '#e5e5e5',
    axis: style.getPropertyValue('--text-tertiary').trim() || '#a3a3a3',
    text: style.getPropertyValue('--text-secondary').trim() || '#6b6b6b',
