          <linearGradient id="mediumGradient" x1="0" y1="0" x2="0" y2="1">
            <stop offset="5%" stopColor="#f59e0b" stopOpacity={0.8} />
            <stop offset="95%" stopColor="#f59e0b" stopOpacity={0.2} />
          </linearGradient>
          <linearGradient id="lowGradient" x1="0" y1="0" x2="0" y2="1">
            <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.8} />
            <stop offset="95%" stopColor="#3b82f6" stopOpacity={0.2} />
          </linearGradient>
        </defs>
      <CartesianGrid strokeDasharray="3 3" stroke={colors.grid} />
      <XAxis
        dataKey="time"
        tick={{ fill: colors.text, fontSize: 11 }}
        axisLine={{ stroke: colors.axis }}
        tickLine={{ stroke: colors.axis }}
      />
      <YAxis
        tick={{ fill: colors.text, fontSize: 11 }}
        axisLine={{ stroke: colors.axis }}
        tickLine={{ stroke: colors.axis }}
        allowDecimals={false}
      />
        <Tooltip content={<CustomTooltip />} />
        <Legend content={<CustomLegend />} />
        {showHigh && (
          <Area
            type="monotone"
            dataKey="high"
            name={priorityConfig.high.name}
            stackId="1"
            stroke={priorityConfig.high.color}
            fill="url(#highGradient)"
            strokeWidth={2}
          />
        )}
        {showMedium && (
          <Area
            type="monotone"
            dataKey="medium"
            name={priorityConfig.medium.name}
            stackId="1"
            stroke={priorityConfig.medium.color}
            fill="url(#mediumGradient)"
            strokeWidth={2}
          />
        )}
        {showLow && (
          <Area
            type="monotone"
            dataKey="low"
            name={priorityConfig.low.name}
            stackId="1"
            stroke={priorityConfig.low.color}
            fill="url(#lowGradient)"
            strokeWidth={2}
          />
        )}
      </AreaChart>
    </ResponsiveContainer>
  );
}

export default QueueAreaChart;

