﻿'use client';

import { Heart, Coins, Loader2, Check, X, MessageSquare } from 'lucide-react';
import { useState, useEffect } from 'react';

import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';

interface TipButtonProps {
  chapterId: string;
  authorName: string;
  onTipSent?: () => void;
}

const PRESET_AMOUNTS = [10, 50, 100, 250, 500];

interface UserBalance {
  balance: number;
}

export default function TipButton({ chapterId, authorName, onTipSent }: TipButtonProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [selectedAmount, setSelectedAmount] = useState<number | null>(100);
  const [customAmount, setCustomAmount] = useState('');
  const [message, setMessage] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [userBalance, setUserBalance] = useState<number | null>(null);
  const [isLoadingBalance, setIsLoadingBalance] = useState(false);

  useEffect(() => {
    if (isOpen && userBalance === null) {
      fetchBalance();
    }
  }, [isOpen]);

  const fetchBalance = async () => {
    setIsLoadingBalance(true);
    try {
      const response = await fetch('/api/economy/balance');
      if (response.ok) {
        const data: UserBalance = await response.json();
        setUserBalance(data.balance);
      }
    } catch (error) {
      console.error('Error fetching balance:', error);
    } finally {
      setIsLoadingBalance(false);
    }
  };

  const getAmount = (): number => {
    if (selectedAmount !== null) return selectedAmount;
    const custom = parseInt(customAmount, 10);
    return isNaN(custom) ? 0 : custom;
  };

  const validateTip = (): string | null => {
    const amount = getAmount();
    if (amount < 1) return 'El monto mínimo es 1 InkCoin';
    if (userBalance !== null && amount > userBalance) return 'Saldo insuficiente';
    return null;
  };

  const handleSendTip = async () => {
    const validationError = validateTip();
    if (validationError) {
      setError(validationError);
      return;
    }

    setIsLoading(true);
    setError(null);

    try {
      const response = await fetch('/api/tips', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          chapterId,
          amount: getAmount(),
          message: message.trim() || undefined,
        }),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.error || 'Error al enviar propina');
      }

      setIsSuccess(true);
      setUserBalance(data.newBalance);
      onTipSent?.();
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Error al enviar propina');
    } finally {
      setIsLoading(false);
    }
  };

  const handleClose = () => {
    setIsOpen(false);
    setIsSuccess(false);
    setError(null);
    setSelectedAmount(100);
    setCustomAmount('');
    setMessage('');
  };

  const handlePresetClick = (amount: number) => {
    setSelectedAmount(amount);
    setCustomAmount('');
    setError(null);
  };

  const handleCustomAmountChange = (value: string) => {
    const numericValue = value.replace(/[^0-9]/g, '');
    setCustomAmount(numericValue);
    setSelectedAmount(null);
    setError(null);
  };

  if (!isOpen) {
    return (
      <Button
        onClick={() => setIsOpen(true)}
        variant="ink"
        size="sm"
        className="flex items-center gap-2"
      >
        <Heart size={16} className="fill-current" />
        <span>Enviar Propina</span>
      </Button>
    );
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm animate-fade-in">
      <div className="bg-[var(--surface)] w-full max-w-md rounded-2xl shadow-2xl p-6 border border-[var(--border)] relative" role="dialog" aria-modal="true" aria-labelledby="tip-modal-title">
        <button
          onClick={handleClose}
          className="absolute top-4 right-4 p-1 rounded-full hover:bg-[var(--surface-sunken)] text-[var(--text-tertiary)] transition-colors cursor-pointer"
          aria-label="Cerrar"
        >
          <X size={20} />
        </button>

        {!isSuccess ? (
          <>
            <div className="text-center mb-6">
              <div className="inline-flex items-center justify-center w-14 h-14 rounded-full bg-[var(--accent-purple)]/10 text-[var(--accent-purple)] mb-4">
                <Heart size={28} className="fill-current" />
              </div>
              <h2 id="tip-modal-title" className="text-2xl font-bold text-[var(--text-primary)] mb-1">
                Enviar Propina
              </h2>
              <p className="text-sm text-[var(--text-secondary)]">
                Apoya a <span className="font-semibold text-[var(--text-primary)]">{authorName}</span> con InkCoins
              </p>
            </div>

            <div className="bg-[var(--surface-sunken)] rounded-xl p-3 mb-6 flex items-center justify-between">
              <span className="text-sm text-[var(--text-secondary)]">Tu saldo:</span>
              <div className="flex items-center gap-1 font-bold text-[var(--text-primary)]">
                <Coins size={16} className="text-[var(--warning)]" />
                {isLoadingBalance ? (
                  <Loader2 size={14} className="animate-spin" />
                ) : (
                  <span>{userBalance?.toLocaleString() || '0'} IC</span>
                )}
              </div>
            </div>

            <div className="mb-4">
              <label className="block text-sm font-semibold text-[var(--text-primary)] mb-3">
                Selecciona un monto
              </label>
              <div className="grid grid-cols-5 gap-2">
                {PRESET_AMOUNTS.map((amount) => (
                  <button
                    key={amount}
                    onClick={() => handlePresetClick(amount)}
                    className={`
                      py-2 px-1 rounded-lg text-sm font-medium transition-all cursor-pointer
                      ${selectedAmount === amount
                        ? 'bg-[var(--accent-purple)] text-[var(--text-inverse)] shadow-md'
                        : 'bg-[var(--surface-sunken)] text-[var(--text-primary)] hover:bg-[var(--border)]'
                      }
                    `}
                  >
                    {amount}
                  </button>
                ))}
              </div>
            </div>

            <div className="mb-4">
              <label htmlFor="custom-tip-amount" className="block text-sm font-semibold text-[var(--text-primary)] mb-2">
                O ingresa un monto personalizado
              </label>
              <div className="relative">
                <Coins
                  size={18}
                  className="absolute left-3 top-1/2 -translate-y-1/2 text-[var(--warning)]"
                  aria-hidden="true"
                />
                <Input
                  id="custom-tip-amount"
                  type="text"
                  inputMode="numeric"
                  value={customAmount}
                  onChange={(e) => handleCustomAmountChange(e.target.value)}
                  placeholder="Monto personalizado"
                  className="pl-10 text-center font-mono"
                />
              </div>
            </div>

            <div className="mb-6">
              <label htmlFor="tip-message" className="block text-sm font-semibold text-[var(--text-primary)] mb-2">
                <MessageSquare size={14} className="inline mr-1" aria-hidden="true" />
                Mensaje opcional
              </label>
              <textarea
                id="tip-message"
                value={message}
                onChange={(e) => setMessage(e.target.value)}
                placeholder="Escribe un mensaje de apoyo..."
                maxLength={200}
                className="w-full h-20 px-3 py-2 rounded-lg border border-[var(--border)] bg-[var(--surface-sunken)] text-[var(--text-primary)] text-sm resize-none focus:outline-none focus:ring-2 focus:ring-[var(--accent-purple)] focus:border-transparent placeholder:text-[var(--text-tertiary)]"
                aria-describedby="tip-message-count"
              />
              <p id="tip-message-count" className="text-xs text-[var(--text-tertiary)] text-right mt-1">
                {message.length}/200
              </p>
            </div>

            {error && (
              <div className="mb-4 p-3 bg-[var(--error)]/10 border border-[var(--error)]/20 rounded-lg" role="alert">
                <p className="text-sm text-[var(--error)] text-center">{error}</p>
              </div>
            )}

            <Button
              onClick={handleSendTip}
              disabled={isLoading || getAmount() < 1}
              isLoading={isLoading}
              className="w-full"
              variant="ink"
            >
              {isLoading ? (
                'Enviando...'
              ) : (
                <>
                  <Heart size={18} className="mr-2 fill-current" />
                  Enviar {getAmount() > 0 ? `${getAmount().toLocaleString()} IC` : 'Propina'}
                </>
              )}
            </Button>
          </>
        ) : (
          <div className="text-center py-4">
            <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-[var(--success)]/20 text-[var(--success)] mb-6">
              <Check size={40} />
            </div>
            <h2 className="text-2xl font-bold text-[var(--text-primary)] mb-2">
              ¡Propina Enviada!
            </h2>
            <p className="text-[var(--text-secondary)] mb-2">
              Has enviado{' '}
              <span className="font-bold text-[var(--accent-purple)]">
                {getAmount().toLocaleString()} InkCoins
              </span>{' '}
              a {authorName}
            </p>
            {message && (
              <p className="text-sm text-[var(--text-tertiary)] italic mb-4">
                &ldquo;{message}&rdquo;
              </p>
            )}
            <p className="text-sm text-[var(--text-secondary)]">
              Nuevo saldo: <span className="font-bold">{userBalance?.toLocaleString()} IC</span>
            </p>
            <Button
              onClick={handleClose}
              className="mt-6"
              variant="secondary"
            >
              Cerrar
            </Button>
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import { Flame, Target, Trophy, Loader2, RotateCw, ChevronDown, ChevronUp } from 'lucide-react';
import { useState, useCallback } from 'react';
import { toast } from 'sonner';
import useSWR from 'swr';

import { QuestCard } from './QuestCard';
import type { ActiveQuest } from '@/core/services/QuestService';
import { useT } from '@/i18n';
import { cn } from '@/lib/utils';

interface QuestPanelProps {
  className?: string;
  compact?: boolean;
}

interface QuestsResponse {
  quests: ActiveQuest[];
  todayXP: number;
  weekXP: number;
  dailyCompletions: number;
  dailyTotal: string;
  weeklyTotal: string;
  totalDailyXP: number;
  totalWeeklyXP: number;
}

const fetcher = async (url: string) => {
  const res = await fetch(url);
  if (!res.ok) throw new Error('Failed to fetch quests');
  return res.json();
};

export function QuestPanel({ className, compact = false }: QuestPanelProps) {
  const t = useT();
  const { data, error, mutate } = useSWR<QuestsResponse>(
    '/api/gamification/quests',
    fetcher,
    { refreshInterval: 30000 }, // refresh every 30s
  );

  const [showCompletedDaily, setShowCompletedDaily] = useState(false);
  const [showCompletedWeekly, setShowCompletedWeekly] = useState(false);
  const [claimingQuestId, setClaimingQuestId] = useState<string | null>(null);

  const handleClaim = useCallback(
    async (questId: string) => {
      setClaimingQuestId(questId);
      try {
        const res = await fetch('/api/gamification/quests/claim', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ questId }),
        });
        if (res.ok) {
          const data = await res.json();
          toast.success(t('quests.rewardClaimed'), {
            description: `+${data.xpAwarded ?? 0} XP${data.inkcoinsAwarded > 0 ? ` + ${data.inkcoinsAwarded} 🪙` : ''}`,
          });
          await mutate();
        } else {
          const errorData = await res.json().catch(() => null);
          toast.error(errorData?.error || t('quests.claimError'));
        }
      } catch (err) {
        console.error('Error claiming quest:', err);
        toast.error(t('quests.connectionError'));
      } finally {
        setClaimingQuestId(null);
      }
    },
    [mutate],
  );

  if (error) {
    return (
      <div
        className={cn(
          'p-6 text-center rounded-xl bg-[var(--surface-elevated)] border border-[var(--border)]',
          className,
        )}
      >
        <p className="text-sm text-[var(--text-tertiary)]">
          {t('quests.errorLoading')}
        </p>
        <button
          onClick={() => mutate()}
          className="mt-2 inline-flex items-center gap-1.5 text-xs text-[var(--primary)] hover:underline"
        >
          <RotateCw className="w-3 h-3" />
          {t('quests.retry')}
        </button>
      </div>
    );
  }

  if (!data) {
    return (
      <div
        className={cn(
          'flex items-center justify-center p-8 rounded-xl bg-[var(--surface-elevated)] border border-[var(--border)]',
          className,
        )}
      >
        <Loader2 className="w-5 h-5 animate-spin text-[var(--text-tertiary)]" />
      </div>
    );
  }

  const { quests: questsList = [], todayXP = 0, weekXP = 0, totalDailyXP = 0, totalWeeklyXP = 0 } = data;

  const dailyQuests = questsList.filter((q) => q.category === 'DAILY');
  const weeklyQuests = questsList.filter((q) => q.category === 'WEEKLY');

  const dailyCompleted = dailyQuests.filter((q) => q.completed || q.claimed).length;
  const weeklyCompleted = weeklyQuests.filter((q) => q.completed || q.claimed).length;

  const activeDailyQuests = dailyQuests.filter((q) => !q.claimed);
  const activeWeeklyQuests = weeklyQuests.filter((q) => !q.claimed);

  const completedDailyQuests = dailyQuests.filter((q) => q.claimed);
  const completedWeeklyQuests = weeklyQuests.filter((q) => q.claimed);

  if (compact) {
    return (
      <div className={cn('space-y-2', className)}>
        {/* Compact header */}
        <div className="flex items-center justify-between px-1">
          <div className="flex items-center gap-2">
            <Target className="w-4 h-4 text-[var(--primary)]" />
            <span className="text-xs font-semibold text-[var(--text-primary)]">
              {t('quests.title')}
            </span>
          </div>
          <div className="flex items-center gap-2 text-[10px] text-[var(--text-tertiary)]">
            <span>{t('quests.xpToday', { xp: todayXP })}</span>
          </div>
        </div>

        {/* Compact quest list */}
        {activeDailyQuests.slice(0, 2).map((quest) => (
          <QuestCard
            key={quest.questId}
            quest={quest}
            onClaim={handleClaim}
            isClaiming={claimingQuestId === quest.questId}
            compact
          />
        ))}

        {activeDailyQuests.length === 0 && activeWeeklyQuests.length > 0 && (
          <QuestCard
            key={activeWeeklyQuests[0].questId}
            quest={activeWeeklyQuests[0]}
            onClaim={handleClaim}
            isClaiming={claimingQuestId === activeWeeklyQuests[0].questId}
            compact
          />
        )}
      </div>
    );
  }

  return (
    <div className={cn('space-y-5', className)}>
      {/* Header section */}
      <div className="rounded-xl bg-gradient-to-br from-[var(--surface-elevated)] to-[var(--surface-sunken)] border border-[var(--border)] p-4">
        <div className="flex items-center gap-3 mb-4">
          <div className="w-10 h-10 rounded-xl bg-[var(--primary)]/10 flex items-center justify-center">
            <Trophy className="w-5 h-5 text-[var(--primary)]" />
          </div>
          <div>
            <h3 className="font-semibold text-[var(--text-primary)] text-sm">
              {t('quests.title')}
            </h3>
            <p className="text-xs text-[var(--text-tertiary)]">
              {t('quests.subtitle')}
            </p>
          </div>
        </div>

        {/* XP summary */}
        <div className="grid grid-cols-2 gap-3">
          <div className="rounded-lg bg-[var(--surface-sunken)] p-3 text-center">
            <p className="text-[10px] text-[var(--text-tertiary)] uppercase tracking-wider">
              {t('quests.dailyLabel')}
            </p>
            <div className="mt-1 flex items-center justify-center gap-1.5">
              <Flame className="w-3.5 h-3.5 text-[var(--accent-red)]" />
              <span className="text-lg font-bold text-[var(--text-primary)]">
                {todayXP}
              </span>
              <span className="text-xs text-[var(--text-tertiary)]">
                / {totalDailyXP} XP
              </span>
            </div>
            <div className="mt-1 h-1.5 bg-[var(--surface-elevated)] rounded-full overflow-hidden">
              <div
                className="h-full rounded-full bg-gradient-to-r from-[var(--accent-red)] to-[var(--primary)] transition-all duration-500"
                style={{
                  width: `${totalDailyXP > 0 ? Math.round((todayXP / totalDailyXP) * 100) : 0}%`,
                }}
              />
            </div>
          </div>

          <div className="rounded-lg bg-[var(--surface-sunken)] p-3 text-center">
            <p className="text-[10px] text-[var(--text-tertiary)] uppercase tracking-wider">
              {t('quests.weeklyLabel')}
            </p>
            <div className="mt-1 flex items-center justify-center gap-1.5">
              <Flame className="w-3.5 h-3.5 text-[var(--accent-purple)]" />
              <span className="text-lg font-bold text-[var(--text-primary)]">
                {weekXP}
              </span>
              <span className="text-xs text-[var(--text-tertiary)]">
                / {totalWeeklyXP} XP
              </span>
            </div>
            <div className="mt-1 h-1.5 bg-[var(--surface-elevated)] rounded-full overflow-hidden">
              <div
                className="h-full rounded-full bg-gradient-to-r from-[var(--accent-purple)] to-[var(--primary)] transition-all duration-500"
                style={{
                  width: `${totalWeeklyXP > 0 ? Math.round((weekXP / totalWeeklyXP) * 100) : 0}%`,
                }}
              />
            </div>
          </div>
        </div>
      </div>

      {/* Daily quests */}
      <div>
        <div className="flex items-center justify-between mb-3">
          <div className="flex items-center gap-2">
            <h4 className="text-sm font-semibold text-[var(--text-primary)]">
              {t('quests.daily')}
            </h4>
            <span className="text-[10px] px-1.5 py-0.5 rounded-full bg-[var(--accent-blue)]/10 text-[var(--accent-blue)] font-medium">
              {dailyCompleted}/{dailyQuests.length}
            </span>
          </div>
        </div>

        <div className="space-y-2.5">
          {activeDailyQuests.map((quest) => (
            <QuestCard
              key={quest.questId}
              quest={quest}
              onClaim={handleClaim}
              isClaiming={claimingQuestId === quest.questId}
            />
          ))}

          {completedDailyQuests.length > 0 && (
            <>
              <button
                onClick={() => setShowCompletedDaily(!showCompletedDaily)}
                className="w-full flex items-center justify-center gap-1.5 py-1.5 text-[11px] text-[var(--text-tertiary)] hover:text-[var(--text-secondary)] transition-colors"
              >
                {showCompletedDaily ? (
                  <>
                    <ChevronUp className="w-3 h-3" />
                    {t('quests.hideCompleted')}
                  </>
                ) : (
                  <>
                    <ChevronDown className="w-3 h-3" />
                    {t('quests.showCompleted', { count: completedDailyQuests.length })}
                  </>
                )}
              </button>

              {showCompletedDaily &&
                completedDailyQuests.map((quest) => (
                  <QuestCard key={`done-${quest.questId}`} quest={quest} />
                ))}
            </>
          )}
        </div>
      </div>

      {/* Weekly quests */}
      <div>
        <div className="flex items-center justify-between mb-3">
          <div className="flex items-center gap-2">
            <h4 className="text-sm font-semibold text-[var(--text-primary)]">
              {t('quests.weekly')}
            </h4>
            <span className="text-[10px] px-1.5 py-0.5 rounded-full bg-[var(--accent-purple)]/10 text-[var(--accent-purple)] font-medium">
              {weeklyCompleted}/{weeklyQuests.length}
            </span>
          </div>
        </div>

        <div className="space-y-2.5">
          {activeWeeklyQuests.map((quest) => (
            <QuestCard
              key={quest.questId}
              quest={quest}
              onClaim={handleClaim}
              isClaiming={claimingQuestId === quest.questId}
            />
          ))}

          {completedWeeklyQuests.length > 0 && (
            <>
              <button
                onClick={() => setShowCompletedWeekly(!showCompletedWeekly)}
                className="w-full flex items-center justify-center gap-1.5 py-1.5 text-[11px] text-[var(--text-tertiary)] hover:text-[var(--text-secondary)] transition-colors"
              >
                {showCompletedWeekly ? (
                  <>
                    <ChevronUp className="w-3 h-3" />
                    {t('quests.hideCompleted')}
                  </>
                ) : (
                  <>
                    <ChevronDown className="w-3 h-3" />
                    {t('quests.showCompleted', { count: completedWeeklyQuests.length })}
                  </>
                )}
              </button>

              {showCompletedWeekly &&
                completedWeeklyQuests.map((quest) => (
                  <QuestCard key={`done-${quest.questId}`} quest={quest} />
                ))}
            </>
          )}
        </div>
      </div>
    </div>
  );
}

﻿'use client';

import {
  Trophy,
  Medal,
  Crown,
  Flame,
  Eye,
  Star,
  Users,
  BookOpen,
  ChevronLeft,
  ChevronRight,
} from 'lucide-react';
import Link from 'next/link';
import { useState } from 'react';

import { OptimizedImage } from '@/components/Image/OptimizedImage';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/Avatar';
import { Badge } from '@/components/ui/Badge';
import { Button } from '@/components/ui/Button';
import { Card } from '@/components/ui/Card';
import { cn } from '@/lib/utils';


type LeaderboardType = 'readers' | 'creators' | 'clans' | 'manga';

interface LeaderboardTableProps {
  type: LeaderboardType;
  data: any[];
  currentUserId?: string;
}

const ITEMS_PER_PAGE = 25;

export function LeaderboardTable({ type, data, currentUserId }: LeaderboardTableProps) {
  const [page, setPage] = useState(1);
  const totalPages = Math.ceil(data.length / ITEMS_PER_PAGE);
  const startIndex = (page - 1) * ITEMS_PER_PAGE;
  const paginatedData = data.slice(startIndex, startIndex + ITEMS_PER_PAGE);

  const getRankIcon = (rank: number) => {
    if (rank === 1) return <Crown className="w-5 h-5 text-[var(--warning)]" />;
    if (rank === 2) return <Medal className="w-5 h-5 text-[var(--text-secondary)]" />;
    if (rank === 3) return <Medal className="w-5 h-5 text-[var(--accent-orange)]" />;
    return <span className="text-[var(--text-tertiary)] font-medium w-5 text-center">{rank}</span>;
  };

  const getRankStyle = (rank: number) => {
    if (rank === 1) return 'bg-[var(--warning)]/10 border-[var(--warning)]/30';
    if (rank === 2) return 'bg-[var(--text-tertiary)]/10 border-[var(--text-tertiary)]/30';
    if (rank === 3) return 'bg-[var(--accent-orange)]/10 border-[var(--accent-orange)]/30';
    return '';
  };

  const renderReaderRow = (item: any, rank: number) => (
    <>
      <td className="py-4 px-4">
        <div className="flex items-center justify-center">{getRankIcon(rank)}</div>
      </td>
      <td className="py-4 px-4">
        <Link
          href={`/user/${item.username}`}
          className="flex items-center gap-3 group"
        >
          <Avatar className="w-10 h-10">
            <AvatarImage src={item.avatarUrl || undefined} />
            <AvatarFallback className="bg-[var(--surface-sunken)]">
              {item.displayName?.[0] || item.username[0]}
            </AvatarFallback>
          </Avatar>
          <div>
            <p className="font-medium text-[var(--text-primary)] group-hover:text-[var(--primary)] transition-colors">
              {item.displayName || item.username}
            </p>
            <p className="text-xs text-[var(--text-tertiary)]">@{item.username}</p>
          </div>
        </Link>
      </td>
      <td className="py-4 px-4 text-right">
        <div className="flex items-center justify-end gap-2">
          <Trophy className="w-4 h-4 text-[var(--warning)]" />
          <span className="font-semibold text-[var(--text-primary)]">{item.xpPoints.toLocaleString()}</span>
          <span className="text-xs text-[var(--text-tertiary)]">XP</span>
        </div>
        <p className="text-xs text-[var(--text-tertiary)]">Nivel {item.level}</p>
      </td>
      <td className="py-4 px-4 text-right">
        <div className="flex items-center justify-end gap-2">
          <Flame className="w-4 h-4 text-[var(--accent-orange)]" />
          <span className="font-medium text-[var(--text-primary)]">{item.readingStreak}</span>
          <span className="text-xs text-[var(--text-tertiary)]">días</span>
        </div>
      </td>
      <td className="py-4 px-4 text-right">
        <span className="text-[var(--text-secondary)]">
          {item._count.readingProgress} capítulos
        </span>
      </td>
    </>
  );

  const renderCreatorRow = (item: any, rank: number) => (
    <>
      <td className="py-4 px-4">
        <div className="flex items-center justify-center">{getRankIcon(rank)}</div>
      </td>
      <td className="py-4 px-4">
        <Link
          href={`/user/${item.username}`}
          className="flex items-center gap-3 group"
        >
          <Avatar className="w-10 h-10">
            <AvatarImage src={item.avatarUrl || undefined} />
            <AvatarFallback className="bg-[var(--surface-sunken)]">
              {item.displayName?.[0] || item.username[0]}
            </AvatarFallback>
          </Avatar>
          <div>
            <p className="font-medium text-[var(--text-primary)] group-hover:text-[var(--primary)] transition-colors">
              {item.displayName || item.username}
            </p>
            <p className="text-xs text-[var(--text-tertiary)]">@{item.username}</p>
          </div>
        </Link>
      </td>
      <td className="py-4 px-4 text-right">
        <div className="flex items-center justify-end gap-2">
          <Eye className="w-4 h-4 text-[var(--primary)]" />
          <span className="font-semibold text-[var(--text-primary)]">{item.totalViews.toLocaleString()}</span>
        </div>
        <p className="text-xs text-[var(--text-tertiary)]">vistas totales</p>
      </td>
      <td className="py-4 px-4 text-right">
        <div className="flex items-center justify-end gap-2">
          <BookOpen className="w-4 h-4 text-[var(--success)]" />
          <span className="font-medium text-[var(--text-primary)]">{item._count.createdMangas}</span>
          <span className="text-xs text-[var(--text-tertiary)]">mangas</span>
        </div>
      </td>
      <td className="py-4 px-4 text-right">
        <span className="text-[var(--text-secondary)]">
          {item.totalChapters} capítulos
        </span>
      </td>
    </>
  );

  const renderClanRow = (item: any, rank: number) => (
