import { getNotificationService } from '@/core/services/NotificationService';

export interface SendTipDTO {
  chapterId: string;
  fromUserId: string;
  amount: number;
  message?: string;
}

export interface ContributeDTO {
  chapterId: string;
  userId: string;
  amount: number;
  isAnonymous?: boolean;
  message?: string;
}

export interface TipWithRelations extends TipWithRelationsRecord {}

