export class PaymentService {
  constructor(private readonly repository: IPaymentRepository) {}

  async sendTip(data: SendTipDTO): Promise<{ success: boolean; newBalance: number; tip: TipRecord }> {
    const { chapterId, fromUserId, amount, message } = data;

    if (amount < 1) {
      throw new Error('El monto mínimo es 1 InkCoin');
    }

    const chapter = await this.repository.getChapterWithAuthor(chapterId);

    if (!chapter) {
      throw new Error('Capítulo no encontrado');
    }

    const toUserId = chapter.authorId;

    if (fromUserId === toUserId) {
      throw new Error('No puedes enviarte propina a ti mismo');
    }

    const hasBalance = await this.repository.validateBalance(fromUserId, amount);
    if (!hasBalance) {
      throw new Error('Saldo insuficiente');
    }

    const sender = await this.repository.getUserBasicInfo(fromUserId);

    if (!sender) {
      throw new Error('Usuario emisor no encontrado');
    }

    const { tip, newSenderBalance } = await this.repository.sendTipTransaction({
      chapterId,
      fromUserId,
      toUserId,
      amount,
      message: message || null,
      authorName: chapter.authorName,
      chapterNumber: chapter.chapterNumber,
    });

    try {
      await (await getNotificationService()).notifyTipReceived(
        toUserId,
        amount,
        { id: chapter.id, chapterNumber: chapter.chapterNumber, title: chapter.title },
        { id: sender.id, username: sender.username, displayName: sender.displayName || undefined },
        message
      );
    } catch (error) {
      console.error('Error sending tip notification:', error);
    }

    return {
      success: true,
      newBalance: newSenderBalance,
      tip,
    };
  }

  async getChapterTips(chapterId: string): Promise<TipWithRelationsRecord[]> {
    return this.repository.getChapterTips(chapterId);
  }

  async getUserTipsReceived(userId: string, limit: number = 50): Promise<TipWithRelationsRecord[]> {
    return this.repository.getUserTipsReceived(userId, limit);
  }

  async getUserTipsGiven(userId: string, limit: number = 50): Promise<TipWithRelationsRecord[]> {
    return this.repository.getUserTipsGiven(userId, limit);
  }

  async getTotalTipsReceived(userId: string): Promise<number> {
    return this.repository.getTotalTipsReceived(userId);
  }

  async contributeToCrowdfunding(data: ContributeDTO): Promise<{
    success: boolean;
    newTotal: number;
    goalReached: boolean;
    contribution: CrowdfundingContributionRecord;
  }> {
    const { chapterId, userId, amount, isAnonymous = false, message } = data;

    if (amount < 1) {
      throw new Error('El monto mínimo es 1 InkCoin');
    }

    const chapter = await this.repository.getChapterWithCrowdfunding(chapterId);

    if (!chapter) {
      throw new Error('Capítulo no encontrado');
    }

    if (!chapter.crowdfundingGoal) {
      throw new Error('Este capítulo no tiene crowdfunding activo');
    }

    const hasBalance = await this.repository.validateBalance(userId, amount);
    if (!hasBalance) {
      throw new Error('Saldo insuficiente');
    }

    const contributor = await this.repository.getUserBasicInfo(userId);

    if (!contributor) {
      throw new Error('Usuario contribuyente no encontrado');
    }

    const authorId = chapter.authorId;

    const { contribution, newCrowdfundingCurrent } = await this.repository.contributeTransaction({
      chapterId,
      userId,
      amount,
      isAnonymous,
      message: message || null,
      chapterNumber: chapter.chapterNumber,
    });

    const goalReached = newCrowdfundingCurrent >= (chapter.crowdfundingGoal || 0);

    try {
      await (await getNotificationService()).notifyCrowdfundingContribution(
        authorId,
        amount,
        { id: chapter.id, chapterNumber: chapter.chapterNumber, title: chapter.title },
        { id: contributor.id, username: contributor.username, displayName: contributor.displayName || undefined },
        isAnonymous,
        newCrowdfundingCurrent,
        chapter.crowdfundingGoal || 0
      );
    } catch (error) {
      console.error('Error sending crowdfunding notification:', error);
    }

    return {
      success: true,
      newTotal: newCrowdfundingCurrent,
      goalReached,
      contribution,
    };
  }

  async getChapterCrowdfunding(chapterId: string): Promise<CrowdfundingStatus> {
    const chapter = await this.repository.getChapterCrowdfunding(chapterId);

    if (!chapter || !chapter.crowdfundingGoal) {
      return {
        current: 0,
        goal: 0,
        contributors: 0,
        percentage: 0,
        isGoalReached: false,
      };
    }

    const contributorsCount = await this.repository.countChapterContributors(chapterId);

    const percentage = Math.min(
      Math.round((chapter.crowdfundingCurrent / chapter.crowdfundingGoal) * 100),
      100
    );

    return {
      current: chapter.crowdfundingCurrent,
      goal: chapter.crowdfundingGoal,
      contributors: contributorsCount,
      percentage,
      isGoalReached: chapter.crowdfundingCurrent >= chapter.crowdfundingGoal,
    };
  }

  async getChapterContributors(chapterId: string): Promise<ContributionWithRelationsRecord[]> {
    return this.repository.getChapterContributors(chapterId);
  }

  async getUserContribution(chapterId: string, userId: string): Promise<CrowdfundingContributionRecord | null> {
    return this.repository.getUserContribution(chapterId, userId);
  }

  async getUserBalance(userId: string): Promise<number> {
    return this.repository.getUserBalance(userId);
  }

  async getUserTipStats(userId: string): Promise<{
    totalGiven: number;
    totalReceived: number;
    countGiven: number;
    countReceived: number;
  }> {
    return this.repository.getUserTipStats(userId);
  }

  async getUserCrowdfundingStats(userId: string): Promise<{
    totalRaised: number;
    totalContributors: number;
    activeCampaigns: number;
    completedCampaigns: number;
  }> {
    return this.repository.getUserCrowdfundingStats(userId);
  }
}

export const AVAILABLE_EVENTS = [
  'CHAPTER_PUBLISHED',
  'MANGA_CREATED',
  'MANGA_UPDATED',
  'COMMENT_POSTED',
  'USER_REGISTERED',
  'ACHIEVEMENT_UNLOCKED',
  'NEW_CHAPTER',
  'CROWDFUNDING_GOAL_REACHED',
  'SPONSORSHIP_BID_SUBMITTED',
] as const;

export type WebhookEvent = (typeof AVAILABLE_EVENTS)[number];

export interface WebhookEndpointDTO {
  id: string;
  userId: string;
  url: string;
  secret: string;
  events: string[];
  isActive: boolean;
  description: string | null;
  lastTriggeredAt: string | null;
  failureCount: number;
  createdAt: string;
  updatedAt: string;
  recentDeliveries?: WebhookDeliveryDTO[];
}

export interface WebhookDeliveryDTO {
  id: string;
  endpointId: string;
  event: string;
  payload: string;
  status: string;
  statusCode: number | null;
  responseBody: string | null;
  durationMs: number | null;
  attemptCount: number;
  error: string | null;
  createdAt: string;
}

import type {
  IWebhookRepository,
  WebhookEndpointRecord,
  WebhookDeliveryRecord,
} from './IWebhookRepository';

function toEndpointDTO(record: WebhookEndpointRecord, deliveries?: WebhookDeliveryRecord[]): WebhookEndpointDTO {
  return {
    id: record.id,
    userId: record.userId,
    url: record.url,
    secret: record.secret,
    events: JSON.parse(record.events) as string[],
    isActive: record.isActive,
    description: record.description,
    lastTriggeredAt: record.lastTriggeredAt?.toISOString() ?? null,
    failureCount: record.failureCount,
    createdAt: record.createdAt.toISOString(),
    updatedAt: record.updatedAt.toISOString(),
    recentDeliveries: deliveries?.map(toDeliveryDTO),
  };
}

function toDeliveryDTO(record: WebhookDeliveryRecord): WebhookDeliveryDTO {
  return {
    id: record.id,
    endpointId: record.endpointId,
    event: record.event,
    payload: record.payload,
    status: record.status,
    statusCode: record.statusCode,
    responseBody: record.responseBody,
    durationMs: record.durationMs,
    attemptCount: record.attemptCount,
    error: record.error,
    createdAt: record.createdAt.toISOString(),
  };
}

export class WebhookService {
  constructor(private readonly repo: IWebhookRepository) {}

  async create(
    userId: string,
    url: string,
    secret: string,
    events: string[],
    description?: string
  ): Promise<WebhookEndpointDTO> {
    const invalidEvents = events.filter(e => !(AVAILABLE_EVENTS as readonly string[]).includes(e));
    if (invalidEvents.length > 0) {
      throw new Error(`Invalid events: ${invalidEvents.join(', ')}`);
    }

    try {
      new URL(url);
    } catch {
      throw new Error('Invalid URL format');
    }

    const record = await this.repo.createEndpoint({
      userId,
      url,
      secret,
      events: JSON.stringify(events),
      description: description ?? null,
    });

    return toEndpointDTO(record);
  }

  async update(
    id: string,
    userId: string,
    data: { url?: string; secret?: string; events?: string[]; isActive?: boolean; description?: string }
  ): Promise<WebhookEndpointDTO> {
    const existing = await this.repo.findEndpointById(id);
    if (!existing) {
      throw new Error('Webhook endpoint not found');
    }
    if (existing.userId !== userId) {
      throw new Error('Unauthorized');
    }

    if (data.url) {
      try {
        new URL(data.url);
      } catch {
        throw new Error('Invalid URL format');
      }
    }

    if (data.events) {
      const invalidEvents = data.events.filter(e => !(AVAILABLE_EVENTS as readonly string[]).includes(e));
      if (invalidEvents.length > 0) {
        throw new Error(`Invalid events: ${invalidEvents.join(', ')}`);
      }
    }

    const updateData: Record<string, unknown> = {};
    if (data.url !== undefined) updateData.url = data.url;
    if (data.secret !== undefined) updateData.secret = data.secret;
    if (data.events !== undefined) updateData.events = JSON.stringify(data.events);
    if (data.isActive !== undefined) updateData.isActive = data.isActive;
    if (data.description !== undefined) updateData.description = data.description;

    const record = await this.repo.updateEndpoint(id, updateData as any);
    return toEndpointDTO(record);
  }

  async delete(id: string, userId: string): Promise<void> {
    const existing = await this.repo.findEndpointById(id);
    if (!existing) {
      throw new Error('Webhook endpoint not found');
    }
    if (existing.userId !== userId) {
      throw new Error('Unauthorized');
    }
    await this.repo.deleteEndpoint(id);
  }

  async list(userId: string): Promise<WebhookEndpointDTO[]> {
    const records = await this.repo.findEndpointsByUserId(userId);
    return Promise.all(
      records.map(async (r) => {
        const deliveries = await this.repo.findDeliveriesByEndpointId(r.id, 1, 5);
        return toEndpointDTO(r, deliveries.items);
      })
    );
  }

  async getDeliveries(
    endpointId: string,
    userId: string,
    page: number = 1
  ): Promise<{ deliveries: WebhookDeliveryDTO[]; total: number; totalPages: number }> {
    const existing = await this.repo.findEndpointById(endpointId);
    if (!existing) {
      throw new Error('Webhook endpoint not found');
    }
    if (existing.userId !== userId) {
      throw new Error('Unauthorized');
    }

    const result = await this.repo.findDeliveriesByEndpointId(endpointId, page, 20);
    return {
      deliveries: result.items.map(toDeliveryDTO),
      total: result.total,
      totalPages: result.totalPages,
    };
  }

  async redeliver(deliveryId: string, userId: string): Promise<void> {
    const delivery = await this.repo.findDeliveryById(deliveryId);
    if (!delivery) {
      throw new Error('Delivery not found');
    }

    const endpoint = await this.repo.findEndpointById(delivery.endpointId);
    if (!endpoint) {
      throw new Error('Endpoint not found');
    }
    if (endpoint.userId !== userId) {
      throw new Error('Unauthorized');
    }

    const { WebhookDeliveryService } = await import('@/infrastructure/adapters/WebhookDeliveryService');
    const deliveryService = new WebhookDeliveryService(this.repo);
    await deliveryService.deliver(endpoint, delivery.event, JSON.parse(delivery.payload));
  }

  async getAvailableEvents(): Promise<string[]> {
    return [...AVAILABLE_EVENTS];
  }

  async testEndpoint(endpointId: string, userId: string): Promise<WebhookDeliveryDTO> {
    const endpoint = await this.repo.findEndpointById(endpointId);
    if (!endpoint) {
      throw new Error('Webhook endpoint not found');
    }
    if (endpoint.userId !== userId) {
      throw new Error('Unauthorized');
    }

    const { WebhookDeliveryService } = await import('@/infrastructure/adapters/WebhookDeliveryService');
    const deliveryService = new WebhookDeliveryService(this.repo);
    const testPayload = { message: 'This is a test webhook from InkVerse' };
    const delivery = await deliveryService.deliver(endpoint, 'TEST', testPayload);
    return toDeliveryDTO(delivery);
  }
}

import { renderHook, act, waitFor } from '@testing-library/react';
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

import type { PanelText } from '@/components/Reader/PanelTextOverlay';
import { usePanelTexts } from '@/hooks/usePanelTexts';

// Mock PanelText type for tests
const createMockPanelText = (overrides: Partial<PanelText> = {}): PanelText => ({
  id: `text-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
  x: 100,
  y: 100,
  text: 'Test text',
  type: 'speech',
  fontSize: 16,
  color: '#000000',
  backgroundColor: 'transparent',
  borderRadius: 0,
  padding: 4,
  rotation: 0,
  ...overrides,
});

describe('usePanelTexts', () => {
  beforeEach(() => {
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  it('initializes with empty texts by default', () => {
    const { result } = renderHook(() => usePanelTexts());
    expect(result.current.texts).toEqual([]);
    expect(result.current.isDirty).toBe(false);
    expect(result.current.isSaving).toBe(false);
    expect(result.current.error).toBeNull();
    expect(result.current.lastSaved).toBeNull();
  });

  it('initializes with provided initial texts', () => {
    const initialTexts = [createMockPanelText({ text: 'Initial' })];
    const { result } = renderHook(() => usePanelTexts({ initialTexts }));
    expect(result.current.texts).toHaveLength(1);
    expect(result.current.texts[0].text).toBe('Initial');
  });

  it('adds a new text', () => {
    const { result } = renderHook(() => usePanelTexts());

    act(() => {
    result.current.addText({
      x: 50,
      y: 50,
      text: 'New text',
      type: 'thought',
      fontSize: 14,
      color: '#ffffff',
      backgroundColor: 'transparent',
      borderRadius: 0,
      padding: 4,
      rotation: 45,
    });
    });

    expect(result.current.texts).toHaveLength(1);
    expect(result.current.texts[0].text).toBe('New text');
    expect(result.current.texts[0].type).toBe('thought');
    expect(result.current.isDirty).toBe(true);
    expect(result.current.texts[0].id).toBeDefined();
  });

  it('updates an existing text', () => {
    const initialTexts = [createMockPanelText({ text: 'Original' })];
    const { result } = renderHook(() => usePanelTexts({ initialTexts }));

    const textId = result.current.texts[0].id;

    act(() => {
      result.current.updateText(textId, { text: 'Updated' });
    });

    expect(result.current.texts[0].text).toBe('Updated');
    expect(result.current.texts[0].x).toBe(100); // Original value preserved
    expect(result.current.isDirty).toBe(true);
  });

  it('deletes a text', () => {
    const initialTexts = [
      createMockPanelText({ text: 'Text 1' }),
      createMockPanelText({ text: 'Text 2' }),
    ];
    const { result } = renderHook(() => usePanelTexts({ initialTexts }));

    const textIdToDelete = result.current.texts[0].id;

    act(() => {
      result.current.deleteText(textIdToDelete);
    });

    expect(result.current.texts).toHaveLength(1);
    expect(result.current.texts[0].text).toBe('Text 2');
    expect(result.current.isDirty).toBe(true);
  });

  it('reorders texts', () => {
    const initialTexts = [
      createMockPanelText({ text: 'First' }),
      createMockPanelText({ text: 'Second' }),
      createMockPanelText({ text: 'Third' }),
    ];
    const { result } = renderHook(() => usePanelTexts({ initialTexts }));

    act(() => {
      result.current.reorderTexts(0, 2); // Move first to last
    });

    expect(result.current.texts[0].text).toBe('Second');
    expect(result.current.texts[1].text).toBe('Third');
    expect(result.current.texts[2].text).toBe('First');
  });

  it('clears all texts', () => {
    const initialTexts = [createMockPanelText()];
    const { result } = renderHook(() => usePanelTexts({ initialTexts }));

    act(() => {
      result.current.clearTexts();
    });

    expect(result.current.texts).toEqual([]);
    expect(result.current.isDirty).toBe(true);
  });

  it('resets to initial texts', () => {
    const initialTexts = [createMockPanelText({ text: 'Initial' })];
    const { result } = renderHook(() => usePanelTexts({ initialTexts }));

    act(() => {
      result.current.addText({
      x: 0,
      y: 0,
      backgroundColor: 'transparent',
      borderRadius: 0,
      padding: 4,
        text: 'Added',
        type: 'speech',
        fontSize: 14,
        color: '#000000',
        rotation: 0,
      });
    });

    expect(result.current.texts).toHaveLength(2);

    act(() => {
      result.current.resetToInitial();
    });

    expect(result.current.texts).toHaveLength(1);
    expect(result.current.texts[0].text).toBe('Initial');
    expect(result.current.isDirty).toBe(false);
  });

  it('exports texts as JSON', () => {
    const initialTexts = [createMockPanelText({ text: 'Export me' })];
    const { result } = renderHook(() => usePanelTexts({ initialTexts }));

    const json = result.current.exportAsJSON();
    const parsed = JSON.parse(json);

    expect(parsed).toHaveLength(1);
    expect(parsed[0].text).toBe('Export me');
  });

  it('imports texts from JSON', () => {
    const textsToImport = [
      createMockPanelText({ text: 'Imported 1' }),
      createMockPanelText({ text: 'Imported 2' }),
    ];
    const json = JSON.stringify(textsToImport);

    const { result } = renderHook(() => usePanelTexts());

    act(() => {
      const success = result.current.importFromJSON(json);
      expect(success).toBe(true);
    });

    expect(result.current.texts).toHaveLength(2);
    expect(result.current.texts[0].text).toBe('Imported 1');
    expect(result.current.isDirty).toBe(true);
  });

  it('handles invalid JSON import', () => {
    const { result } = renderHook(() => usePanelTexts());

    act(() => {
      const success = result.current.importFromJSON('invalid json');
      expect(success).toBe(false);
    });

    expect(result.current.error).toBeTruthy();
  });

  it('filters texts by type', () => {
    const initialTexts = [
      createMockPanelText({ type: 'speech' }),
      createMockPanelText({ type: 'thought' }),
      createMockPanelText({ type: 'speech' }),
    ];
    const { result } = renderHook(() => usePanelTexts({ initialTexts }));

    const speechTexts = result.current.getTextsByType('speech');
    expect(speechTexts).toHaveLength(2);

    const thoughtTexts = result.current.getTextsByType('thought');
    expect(thoughtTexts).toHaveLength(1);
  });

  it('duplicates a text with offset', () => {
    const initialTexts = [
      createMockPanelText({ x: 100, y: 100, text: 'Original' }),
    ];
    const { result } = renderHook(() => usePanelTexts({ initialTexts }));

    const originalId = result.current.texts[0].id;

    act(() => {
      result.current.duplicateText(originalId);
    });

    expect(result.current.texts).toHaveLength(2);
    expect(result.current.texts[1].text).toBe('Original');
    expect(result.current.texts[1].x).toBe(105); // Original x + 5
    expect(result.current.texts[1].y).toBe(105); // Original y + 5
    expect(result.current.texts[1].id).not.toBe(originalId);
  });

  it('returns null when duplicating non-existent text', () => {
    const { result } = renderHook(() => usePanelTexts());

    const returnValue = result.current.duplicateText('non-existent');
    expect(returnValue).toBeNull();
  });

  it('saves texts successfully', async () => {
    const mockSave = vi.fn().mockResolvedValue(undefined);
    const initialTexts = [createMockPanelText()];

    const { result } = renderHook(() =>
      usePanelTexts({ initialTexts, onSave: mockSave })
    );

    // Make dirty first
    act(() => {
      result.current.addText({
      x: 0,
      y: 0,
      backgroundColor: 'transparent',
      borderRadius: 0,
      padding: 4,
        text: 'New',
        type: 'speech',
        fontSize: 14,
        color: '#000000',
        rotation: 0,
      });
    });

    await act(async () => {
      await result.current.saveTexts();
    });

    expect(mockSave).toHaveBeenCalledWith(result.current.texts);
    expect(result.current.isDirty).toBe(false);
    expect(result.current.lastSaved).toBeInstanceOf(Date);
    expect(result.current.isSaving).toBe(false);
  });

  it('handles save error', async () => {
    const mockSave = vi.fn().mockRejectedValue(new Error('Save failed'));
    const initialTexts = [createMockPanelText()];

    const { result } = renderHook(() =>
      usePanelTexts({ initialTexts, onSave: mockSave })
    );

    // Make dirty first
    act(() => {
      result.current.addText({
      x: 0,
      y: 0,
      backgroundColor: 'transparent',
      borderRadius: 0,
      padding: 4,
        text: 'New',
        type: 'speech',
        fontSize: 14,
        color: '#000000',
        rotation: 0,
      });
    });

    await act(async () => {
      try {
        await result.current.saveTexts();
      } catch (e) {
        // Expected to throw
      }
    });

    expect(result.current.error).toBe('Save failed');
    expect(result.current.isSaving).toBe(false);
  });

  it('auto-saves after delay when enabled', async () => {
    vi.useRealTimers();
    const mockSave = vi.fn().mockResolvedValue(undefined);

    const { result } = renderHook(() =>
      usePanelTexts({
        onSave: mockSave,
        autoSave: true,
        autoSaveDelay: 100,
      })
    );

    act(() => {
      result.current.addText({
      x: 0,
      y: 0,
      backgroundColor: 'transparent',
      borderRadius: 0,
      padding: 4,
        text: 'Auto save test',
        type: 'speech',
        fontSize: 14,
        color: '#000000',
        rotation: 0,
      });
    });

    // Should not save immediately
    expect(mockSave).not.toHaveBeenCalled();
    expect(result.current.isDirty).toBe(true);

    // Wait for auto-save to trigger
    await waitFor(() => expect(mockSave).toHaveBeenCalled(), { timeout: 500 });

    vi.useFakeTimers();
  }, 10000);

  it('prevents concurrent saves', async () => {
    let resolveSave: (value: unknown) => void;
    const mockSave = vi.fn().mockReturnValue(
      new Promise((resolve) => {
        resolveSave = resolve;
      })
    );

    const initialTexts = [createMockPanelText()];
    const { result } = renderHook(() =>
      usePanelTexts({ initialTexts, onSave: mockSave })
    );

    // Make dirty
    act(() => {
      result.current.addText({
      x: 0,
      y: 0,
      backgroundColor: 'transparent',
      borderRadius: 0,
      padding: 4,
        text: 'New',
        type: 'speech',
        fontSize: 14,
        color: '#000000',
        rotation: 0,
      });
    });

    // Start first save - use act to properly handle the async state update
    let savePromise: Promise<void>;
    await act(async () => {
      savePromise = result.current.saveTexts();
    });

    // After act, isSaving should be true
    expect(result.current.isSaving).toBe(true);
    expect(mockSave).toHaveBeenCalledTimes(1);

    // Try second save while first is in progress - should not call onSave again
    await act(async () => {
      await result.current.saveTexts();
    });
    expect(mockSave).toHaveBeenCalledTimes(1);

    // Resolve first save
    resolveSave!(undefined);
    await act(async () => {
      await savePromise!;
    });

    expect(result.current.isSaving).toBe(false);
  });

  it('cleans up auto-save timer on unmount', () => {
    const mockSave = vi.fn().mockResolvedValue(undefined);

    const { unmount } = renderHook(() =>
      usePanelTexts({
        onSave: mockSave,
        autoSave: true,
        autoSaveDelay: 1000,
      })
    );

    unmount();

    // Advance timers - should not throw
    act(() => {
      vi.advanceTimersByTime(2000);
    });

    expect(mockSave).not.toHaveBeenCalled();
  });

  it('updates texts using function callback', () => {
    const initialTexts = [createMockPanelText({ text: 'Original' })];
    const { result } = renderHook(() => usePanelTexts({ initialTexts }));

    act(() => {
      result.current.setTexts((prev) =>
        prev.map((t) => ({ ...t, text: 'Mapped' }))
      );
    });

    expect(result.current.texts[0].text).toBe('Mapped');
  });
});

