'use client';

import { useSession } from 'next-auth/react';
import { useCallback, useMemo, useState } from 'react';
import useSWR, { SWRConfiguration } from 'swr';

import { invalidateMangaCache } from '@/lib/cache';
import { swrConfigs, fetcher } from '@/lib/swr-config';

// Tipos exportados
export interface Manga {
  id: string;
  title: string;
  slug: string;
  description: string;
  coverUrl: string | null;
  status: 'ONGOING' | 'COMPLETED' | 'HIATUS' | 'DROPPED';
  tags: string[];
  authorId: string;
  authorName: string;
  rating: number;
  totalViews: number;
  createdAt: string;
  updatedAt?: string;
  chapters?: Chapter[];
  stats?: {
    totalViews: number;
    totalReaders: number;
    monthlyGrowth: number;
    avgViewsPerChapter: number;
  };
  _count?: {
    chapters: number;
  };
}

export interface Chapter {
  id: string;
  mangaId: string;
  chapterNumber: number;
  title: string | null;
  pageCount: number;
  viewCount: number;
  createdAt: string;
  updatedAt?: string;
  crowdfunding?: {
    goal: number;
    current: number;
    isFunded: boolean;
    progress: number;
  } | null;
}

export interface CreateMangaInput {
  title: string;
  description: string;
  coverUrl?: string;
  status?: Manga['status'];
  tags?: string[];
}

export interface UpdateMangaInput {
  title?: string;
  description?: string;
  coverUrl?: string;
  status?: Manga['status'];
  tags?: string[];
}

export interface CreateChapterInput {
  mangaId: string;
  chapterNumber: number;
  title?: string;
  pageCount: number;
}

export interface UpdateChapterInput {
  title?: string;
  chapterNumber?: number;
}

export interface UseMangaOptions {
  mangaId?: string;
  page?: number;
  limit?: number;
  search?: string;
  swrOptions?: SWRConfiguration;
}

export interface UseMangaReturn {
  mangas: Manga[];
  manga: Manga | null;
  chapters: Chapter[];
  isLoading: boolean;
  isValidating: boolean;
  isMutating: boolean;
  error: Error | null;
  createManga: (input: CreateMangaInput) => Promise<Manga | null>;
  updateManga: (id: string, input: UpdateMangaInput) => Promise<Manga | null>;
  deleteManga: (id: string) => Promise<boolean>;
  createChapter: (input: CreateChapterInput) => Promise<Chapter | null>;
  updateChapter: (id: string, input: UpdateChapterInput) => Promise<Chapter | null>;
  deleteChapter: (id: string) => Promise<boolean>;
  loadMangas: (options?: { page?: number; limit?: number; search?: string }) => Promise<void>;
  refresh: () => Promise<void>;
  mutate: (data?: { mangas?: Manga[]; manga?: Manga | null; chapters?: Chapter[] }, shouldRevalidate?: boolean) => Promise<void>;
}

export function useManga(options: UseMangaOptions = {}): UseMangaReturn {
  const { mangaId, page: initialPage = 1, limit: initialLimit = 20, search: initialSearch, swrOptions = {} } = options;
  const { data: session } = useSession();
  const [isMutating, setIsMutating] = useState(false);

  const listKey = useMemo(() => {
    if (mangaId) return null;
    return `/api/manga?page=${initialPage}&limit=${initialLimit}${initialSearch ? `&search=${encodeURIComponent(initialSearch)}` : ''}`;
  }, [mangaId, initialPage, initialLimit, initialSearch]);

  const detailKey = useMemo(() => {
    if (!mangaId) return null;
    return `/api/manga/${mangaId}`;
  }, [mangaId]);

  const { data: listData, error: listError, isLoading: isListLoading, isValidating: isListValidating, mutate: mutateList } = 
    useSWR<{ mangas: Manga[]; pagination: { total: number; totalPages: number } }>(listKey, listKey ? fetcher : null, { ...swrConfigs.mangaList, ...swrOptions });

  const { data: detailData, error: detailError, isLoading: isDetailLoading, isValidating: isDetailValidating, mutate: mutateDetail } = 
    useSWR<{ manga: Manga; chapters: Chapter[] }>(detailKey, detailKey ? fetcher : null, { ...swrConfigs.mangaDetail, ...swrOptions });

  const isLoading = mangaId ? isDetailLoading : isListLoading;
  const isValidating = mangaId ? isDetailValidating : isListValidating;
  const error = mangaId ? detailError : listError;

  const mangas = listData?.mangas || [];
  const manga = detailData?.manga || null;
  const chapters = detailData?.chapters || [];

  const fetchWithAuth = useCallback(async <T>(url: string, options?: RequestInit): Promise<T> => {
    const response = await fetch(url, { ...options, headers: { 'Content-Type': 'application/json', ...options?.headers } });
    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error || `Error ${response.status}: ${response.statusText}`);
    }
    return response.json();
  }, []);

  const loadMangas = useCallback(async (opts: { page?: number; limit?: number; search?: string } = {}) => {
    const { page = initialPage, limit = initialLimit, search = initialSearch } = opts;
    const key = `/api/manga?page=${page}&limit=${limit}${search ? `&search=${encodeURIComponent(search)}` : ''}`;
    await mutateList(fetcher(key), { revalidate: true });
  }, [initialPage, initialLimit, initialSearch, mutateList]);

  const createManga = useCallback(async (input: CreateMangaInput): Promise<Manga | null> => {
    if (!session?.user) return null;
    setIsMutating(true);
    try {
      const data = await fetchWithAuth<{ manga: Manga }>('/api/manga', { method: 'POST', body: JSON.stringify(input) });
      await mutateList((current) => current ? { ...current, mangas: [data.manga, ...current.mangas] } : current, false);
      await invalidateMangaCache();
      return data.manga;
    } catch (err) {
      console.error('Error creating manga:', err);
      return null;
    } finally {
      setIsMutating(false);
    }
  }, [fetchWithAuth, mutateList, session]);

  const updateManga = useCallback(async (id: string, input: UpdateMangaInput): Promise<Manga | null> => {
    if (!session?.user) return null;
    setIsMutating(true);
    try {
      const data = await fetchWithAuth<{ manga: Manga }>(`/api/manga/${id}`, { method: 'PUT', body: JSON.stringify(input) });
      if (mangaId === id) {
        await mutateDetail((current) => current ? { ...current, manga: data.manga } : current, false);
      }
      await mutateList((current) => current ? { ...current, mangas: current.mangas.map((m) => (m.id === id ? data.manga : m)) } : current, false);
      await invalidateMangaCache(id);
      return data.manga;
    } catch (err) {
      console.error('Error updating manga:', err);
      return null;
    } finally {
      setIsMutating(false);
    }
  }, [fetchWithAuth, mutateList, mutateDetail, mangaId, session]);

  const deleteManga = useCallback(async (id: string): Promise<boolean> => {
    if (!session?.user) return false;
    setIsMutating(true);
    try {
      await fetchWithAuth(`/api/manga/${id}`, { method: 'DELETE' });
      await mutateList((current) => current ? { ...current, mangas: current.mangas.filter((m) => m.id !== id) } : current, false);
      if (mangaId === id) await mutateDetail(undefined, { revalidate: false });
      await invalidateMangaCache(id);
      return true;
    } catch (err) {
      console.error('Error deleting manga:', err);
      return false;
    } finally {
      setIsMutating(false);
    }
  }, [fetchWithAuth, mutateList, mutateDetail, mangaId, session]);

  const createChapter = useCallback(async (input: CreateChapterInput): Promise<Chapter | null> => {
    if (!session?.user) return null;
    setIsMutating(true);
    try {
      const data = await fetchWithAuth<{ chapter: Chapter }>('/api/chapters', { method: 'POST', body: JSON.stringify(input) });
      if (mangaId === input.mangaId) {
        await mutateDetail((current) => current ? { ...current, chapters: [...current.chapters, data.chapter] } : current, false);
      }
      await invalidateMangaCache(input.mangaId);
      return data.chapter;
    } catch (err) {
      console.error('Error creating chapter:', err);
      return null;
    } finally {
      setIsMutating(false);
    }
  }, [fetchWithAuth, mutateDetail, mangaId, session]);

  const updateChapter = useCallback(async (id: string, input: UpdateChapterInput): Promise<Chapter | null> => {
    if (!session?.user) return null;
    setIsMutating(true);
    try {
      const data = await fetchWithAuth<{ chapter: Chapter }>(`/api/chapters/${id}`, { method: 'PUT', body: JSON.stringify(input) });
      await mutateDetail((current) => current ? { ...current, chapters: current.chapters.map((c) => (c.id === id ? data.chapter : c)) } : current, false);
      if (manga?.id) await invalidateMangaCache(manga.id);
      return data.chapter;
    } catch (err) {
      console.error('Error updating chapter:', err);
      return null;
    } finally {
      setIsMutating(false);
    }
  }, [fetchWithAuth, mutateDetail, manga?.id, session]);

  const deleteChapter = useCallback(async (id: string): Promise<boolean> => {
    if (!session?.user) return false;
    setIsMutating(true);
    try {
      await fetchWithAuth(`/api/chapters/${id}`, { method: 'DELETE' });
      await mutateDetail((current) => current ? { ...current, chapters: current.chapters.filter((c) => c.id !== id) } : current, false);
      if (manga?.id) await invalidateMangaCache(manga.id);
      return true;
    } catch (err) {
      console.error('Error deleting chapter:', err);
      return false;
    } finally {
      setIsMutating(false);
    }
  }, [fetchWithAuth, mutateDetail, manga?.id, session]);

  const refresh = useCallback(async () => {
    if (mangaId) await mutateDetail();
    else await mutateList();
  }, [mangaId, mutateDetail, mutateList]);

  const mutateData = useCallback(async (data?: { mangas?: Manga[]; manga?: Manga | null; chapters?: Chapter[] }, shouldRevalidate = true) => {
    if (data?.mangas !== undefined) {
      await mutateList({ mangas: data.mangas, pagination: listData?.pagination || { total: data.mangas.length, totalPages: 1 } }, { revalidate: shouldRevalidate });
    }
    if (data?.manga !== undefined || data?.chapters !== undefined) {
      const newData = data?.manga || data?.chapters
        ? { manga: (data.manga || manga) as Manga, chapters: data.chapters || chapters }
        : undefined;
      if (newData) {
        await mutateDetail(newData, { revalidate: shouldRevalidate });
      }
    }
  }, [mutateList, mutateDetail, listData, manga, chapters]);

  return { mangas, manga, chapters, isLoading, isValidating, isMutating, error, createManga, updateManga, deleteManga, createChapter, updateChapter, deleteChapter, loadMangas, refresh, mutate: mutateData };
}

export function useMangaData(mangaId: string, swrOptions?: SWRConfiguration) {
  return useManga({ mangaId, swrOptions });
}

export default useManga;

'use client';

import { useState, useRef, useCallback } from 'react';

import { UploadResult, UploadError } from '@/types/storage';

// Tipos exportados
export interface UploadProgress {
  /** Porcentaje de progreso (0-100) */
  percent: number;
  /** Bytes subidos */
  loaded: number;
  /** Total de bytes */
  total: number;
  /** Estado del upload */
  status: 'idle' | 'uploading' | 'success' | 'error' | 'cancelled';
}

export interface ChapterUploadProgress {
  /** Progreso general del capítulo */
  overall: UploadProgress;
  /** Progreso individual de cada archivo */
  files: Map<string, UploadProgress>;
  /** Archivos completados */
  completed: UploadResult[];
  /** Archivos fallidos */
  failed: Array<{ fileName: string; error: UploadError }>;
}

export interface UseMangaUploadReturn {
  /** Estado de carga */
  isUploading: boolean;
  /** Progreso actual de la subida */
  progress: UploadProgress;
  /** Error actual si existe */
  error: UploadError | null;
  /** URLs de las imágenes subidas exitosamente */
  urls: string[];
  /** Subir una imagen individual */
  uploadImage: (file: File, options?: UploadImageOptions) => Promise<UploadResult | null>;
  /** Subir múltiples imágenes como un capítulo */
  uploadChapter: (
    files: File[],
    mangaId: string,
    chapterNumber: number,
    options?: UploadChapterOptions
  ) => Promise<ChapterUploadResult>;
  /** Eliminar una imagen subida */
  deleteImage: (url: string) => Promise<boolean>;
  /** Cancelar la subida actual */
  cancelUpload: () => void;
  /** Resetear el estado */
  reset: () => void;
}

export interface UploadImageOptions {
  /** Nombre de archivo personalizado */
  fileName?: string;
  /** Metadata adicional */
  metadata?: Record<string, string>;
  /** Callback de progreso */
  onProgress?: (progress: UploadProgress) => void;
}

export interface UploadChapterOptions {
  /** Título del capítulo */
  title?: string;
  /** Continuar si un archivo falla */
  continueOnError?: boolean;
  /** Máximo de subidas concurrentes */
  maxConcurrency?: number;
  /** Callback de progreso general */
  onOverallProgress?: (progress: ChapterUploadProgress['overall']) => void;
  /** Callback cuando se completa un archivo */
  onFileComplete?: (result: UploadResult) => void;
  /** Callback cuando falla un archivo */
  onFileError?: (fileName: string, error: UploadError) => void;
}

export interface ChapterUploadResult {
  /** Archivos subidos exitosamente */
  successful: UploadResult[];
  /** Archivos que fallaron */
  failed: Array<{ fileName: string; error: UploadError }>;
  /** ID del capítulo creado */
  chapterId?: string;
  /** Tiempo total en ms */
  duration: number;
}

// Constantes
const MAX_RETRIES = 3;
const DEFAULT_CONCURRENCY = 3;

/**
 * Hook para manejar la subida de imágenes de manga
 * Soporta progreso en tiempo real, cancelación y reintentos
 */
export function useMangaUpload(): UseMangaUploadReturn {
  const [isUploading, setIsUploading] = useState(false);
  const [progress, setProgress] = useState<UploadProgress>({
    percent: 0,
    loaded: 0,
    total: 0,
    status: 'idle',
  });
  const [error, setError] = useState<UploadError | null>(null);
  const [urls, setUrls] = useState<string[]>([]);

  // AbortController para cancelación
  const abortControllerRef = useRef<AbortController | null>(null);
  const activeUploadsRef = useRef<Map<string, AbortController>>(new Map());

  /**
   * Crear un nuevo AbortController
   */
  const createAbortController = useCallback(() => {
    abortControllerRef.current = new AbortController();
    return abortControllerRef.current;
  }, []);

  /**
   * Cancelar todas las subidas activas
   */
  const cancelUpload = useCallback(() => {
    // Cancelar el controlador principal
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
    }

    // Cancelar subidas individuales
    activeUploadsRef.current.forEach((controller) => {
      controller.abort();
    });
    activeUploadsRef.current.clear();

    setProgress((prev) => ({ ...prev, status: 'cancelled' }));
    setIsUploading(false);
  }, []);

  /**
   * Resetear el estado del hook
   */
  const reset = useCallback(() => {
    cancelUpload();
    setProgress({
      percent: 0,
      loaded: 0,
      total: 0,
      status: 'idle',
    });
    setError(null);
    setUrls([]);
  }, [cancelUpload]);

  /**
   * Validar archivo antes de subir
   */
  const validateFile = useCallback((file: File): UploadError | null => {
    // Tamaño máximo: 10MB para imágenes individuales
    const MAX_FILE_SIZE = 10 * 1024 * 1024;
    
    // Formatos aceptados
    const ACCEPTED_FORMATS = [
      'image/jpeg',
      'image/png',
      'image/webp',
      'image/gif',
    ];

    if (!file || file.size === 0) {
      return {
        code: 'EMPTY_FILE',
        message: 'El archivo está vacío',
      };
    }

    if (file.size > MAX_FILE_SIZE) {
      return {
        code: 'FILE_TOO_LARGE',
        message: `El archivo excede el tamaño máximo de ${MAX_FILE_SIZE / 1024 / 1024}MB`,
        details: { maxSize: MAX_FILE_SIZE, actualSize: file.size },
      };
    }

    if (!ACCEPTED_FORMATS.includes(file.type)) {
      return {
        code: 'INVALID_FORMAT',
        message: `Formato no soportado: ${file.type}. Use: ${ACCEPTED_FORMATS.join(', ')}`,
        details: { acceptedFormats: ACCEPTED_FORMATS },
      };
    }

    return null;
  }, []);

  /**
   * Subir una imagen individual
   */
  const uploadImage = useCallback(
    async (
      file: File,
      options: UploadImageOptions = {}
    ): Promise<UploadResult | null> => {
      const { fileName, metadata, onProgress } = options;

      // Validar archivo
      const validationError = validateFile(file);
      if (validationError) {
        setError(validationError);
        return null;
      }

      setIsUploading(true);
      setError(null);
      
      const controller = createAbortController();
      const uploadId = crypto.randomUUID();
      activeUploadsRef.current.set(uploadId, controller);

      try {
        const formData = new FormData();
        formData.append('file', file);
        
        if (fileName) {
          formData.append('fileName', fileName);
        }
        
        if (metadata) {
          formData.append('metadata', JSON.stringify(metadata));
        }

        // Simular progreso (el fetch API no soporta progreso real nativamente)
        // Para progreso real se necesitaría XMLHttpRequest
        setProgress({
          percent: 0,
          loaded: 0,
          total: file.size,
          status: 'uploading',
        });

        // Simular progreso incremental
        const progressInterval = setInterval(() => {
          setProgress((prev) => {
            const newPercent = Math.min(prev.percent + 10, 90);
            const newLoaded = Math.floor((newPercent / 100) * file.size);
            const newProgress = {
              ...prev,
              percent: newPercent,
              loaded: newLoaded,
            };
            onProgress?.(newProgress);
            return newProgress;
          });
        }, 100);

        const response = await fetch('/api/upload', {
          method: 'POST',
          body: formData,
          signal: controller.signal,
        });

        clearInterval(progressInterval);

        if (!response.ok) {
          const errorData = await response.json().catch(() => ({}));
          throw {
            code: 'UPLOAD_FAILED',
            message: errorData.error || `Error ${response.status}: ${response.statusText}`,
            details: errorData,
          } as UploadError;
        }

        const result: UploadResult = await response.json();
        
        setProgress({
          percent: 100,
          loaded: file.size,
          total: file.size,
          status: 'success',
        });
        
        setUrls((prev) => [...prev, result.url]);
        
        return result;
      } catch (err: any) {
        if (err.name === 'AbortError') {
          setProgress((prev) => ({ ...prev, status: 'cancelled' }));
          return null;
        }

        const uploadError: UploadError = err.code
          ? err
          : {
              code: 'NETWORK_ERROR',
              message: err.message || 'Error de red al subir el archivo',
              details: { originalError: err },
            };

        setError(uploadError);
        setProgress((prev) => ({ ...prev, status: 'error' }));
        return null;
      } finally {
        setIsUploading(false);
        activeUploadsRef.current.delete(uploadId);
      }
    },
    [createAbortController, validateFile]
  );

  /**
   * Subir múltiples imágenes como un capítulo (batch upload)
   */
  const uploadChapter = useCallback(
    async (
      files: File[],
      mangaId: string,
      chapterNumber: number,
      options: UploadChapterOptions = {}
    ): Promise<ChapterUploadResult> => {
      const {
        title,
        continueOnError = true,
        maxConcurrency = DEFAULT_CONCURRENCY,
        onOverallProgress,
        onFileComplete,
        onFileError,
      } = options;

      const startTime = Date.now();
      const successful: UploadResult[] = [];
      const failed: Array<{ fileName: string; error: UploadError }> = [];

      setIsUploading(true);
      setError(null);

      // Crear el capítulo primero
      let chapterId: string | undefined;
      try {
        const chapterResponse = await fetch('/api/chapters', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            mangaId,
            chapterNumber,
            title,
            pageCount: files.length,
          }),
        });

        if (!chapterResponse.ok) {
          throw new Error('Error al crear el capítulo');
        }

        const chapterData = await chapterResponse.json();
        chapterId = chapterData.id;
      } catch (err: any) {
        setIsUploading(false);
        setError({
          code: 'UPLOAD_FAILED',
          message: 'Error al crear el capítulo: ' + err.message,
        });
        return {
          successful: [],
          failed: files.map((f) => ({
            fileName: f.name,
            error: {
              code: 'UPLOAD_FAILED',
              message: 'Capítulo no creado',
            },
          })),
          duration: Date.now() - startTime,
        };
      }

      // Subir archivos en lotes con concurrencia controlada
      const totalBytes = files.reduce((sum, f) => sum + f.size, 0);
      let uploadedBytes = 0;

      const uploadFileWithRetry = async (
        file: File,
        pageNumber: number,
        retries = 0
      ): Promise<UploadResult | null> => {
        try {
          const controller = new AbortController();
          const uploadId = `${chapterId}-${pageNumber}`;
          activeUploadsRef.current.set(uploadId, controller);

          const formData = new FormData();
          formData.append('file', file);
          formData.append('chapterId', chapterId!);
          formData.append('pageNumber', pageNumber.toString());
          formData.append('mangaId', mangaId);

          const response = await fetch('/api/upload', {
            method: 'POST',
            body: formData,
            signal: controller.signal,
          });

          activeUploadsRef.current.delete(uploadId);

          if (!response.ok) {
            throw new Error(`HTTP ${response.status}`);
          }

          const result: UploadResult = await response.json();
          
          uploadedBytes += file.size;
          const overallPercent = Math.round((uploadedBytes / totalBytes) * 100);
          
          const overallProgress: UploadProgress = {
            percent: overallPercent,
            loaded: uploadedBytes,
            total: totalBytes,
            status: 'uploading',
          };
          
          setProgress(overallProgress);
          onOverallProgress?.(overallProgress);
          
          onFileComplete?.(result);
          return result;
        } catch (err: any) {
          if (err.name === 'AbortError') {
            return null;
          }

          // Reintentar si es posible
          if (retries < MAX_RETRIES) {
            await new Promise((r) => setTimeout(r, 1000 * (retries + 1)));
            return uploadFileWithRetry(file, pageNumber, retries + 1);
          }

          const uploadError: UploadError = {
            code: 'UPLOAD_FAILED',
            message: err.message || 'Error al subir archivo',
          };
          
          onFileError?.(file.name, uploadError);
          return null;
        }
      };

      // Procesar archivos en lotes
      const fileEntries = files.map((file, index) => ({
        file,
        pageNumber: index + 1,
      }));

      for (let i = 0; i < fileEntries.length; i += maxConcurrency) {
        const batch = fileEntries.slice(i, i + maxConcurrency);
        
        const results = await Promise.all(
          batch.map(({ file, pageNumber }) => uploadFileWithRetry(file, pageNumber))
        );

        results.forEach((result, index) => {
          const { file } = batch[index];
          if (result) {
            successful.push(result);
          } else {
            failed.push({
              fileName: file.name,
              error: {
                code: 'UPLOAD_FAILED',
                message: 'Fallo después de reintentos',
              },
            });
          }
        });

        // Si hay un error crítico y no debemos continuar
        if (!continueOnError && failed.length > 0) {
          break;
        }
      }

      // Finalizar el capítulo
      try {
        await fetch(`/api/chapters/${chapterId}/finalize`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            uploadedPages: successful.length,
            failedPages: failed.length,
          }),
        });
      } catch (err) {
        console.error('Error finalizando capítulo:', err);
      }

      setIsUploading(false);
      setProgress({
        percent: 100,
        loaded: totalBytes,
        total: totalBytes,
        status: failed.length === 0 ? 'success' : 'error',
      });

      setUrls((prev) => [...prev, ...successful.map((r) => r.url)]);

      return {
        successful,
        failed,
        chapterId,
        duration: Date.now() - startTime,
      };
    },
    []
  );

  /**
   * Eliminar una imagen subida
   */
  const deleteImage = useCallback(async (url: string): Promise<boolean> => {
    try {
      const response = await fetch('/api/upload/delete', {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url }),
      });

      if (!response.ok) {
        const error = await response.json().catch(() => ({}));
        throw new Error(error.message || 'Error al eliminar imagen');
      }

      // Remover de la lista local
      setUrls((prev) => prev.filter((u) => u !== url));
      
      return true;
    } catch (err: any) {
      setError({
        code: 'DELETE_FAILED',
        message: err.message || 'Error al eliminar la imagen',
      });
      return false;
    }
  }, []);

  return {
    isUploading,
    progress,
    error,
    urls,
    uploadImage,
    uploadChapter,
    deleteImage,
    cancelUpload,
    reset,
  };
}

export default useMangaUpload;

