'use client';

import { useState, useEffect, useCallback } from 'react';


interface PushNotificationState {
  isSupported: boolean;
  isSubscribed: boolean;
  isLoading: boolean;
  error: string | null;
}

/**
 * Hook para gestionar notificaciones push del navegador
 */
export function usePushNotifications(): PushNotificationState & {
  subscribe: () => Promise<void>;
  unsubscribe: () => Promise<void>;
  requestPermission: () => Promise<NotificationPermission>;
} {
  const [isSupported, setIsSupported] = useState(false);
  const [isSubscribed, setIsSubscribed] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    // Verificar soporte
    const supported = 
      'serviceWorker' in navigator &&
      'PushManager' in window &&
      'Notification' in window;
    
    setIsSupported(supported);

    if (supported) {
      checkSubscription();
    }
  }, []);

  const checkSubscription = async () => {
    try {
      const registration = await navigator.serviceWorker.ready;
      const subscription = await registration.pushManager.getSubscription();
      setIsSubscribed(!!subscription);
    } catch (err) {
      console.error('Error checking subscription:', err);
    }
  };

  const requestPermission = useCallback(async (): Promise<NotificationPermission> => {
    if (!isSupported) {
      throw new Error('Push notifications not supported');
    }

    const permission = await Notification.requestPermission();
    return permission;
  }, [isSupported]);

  const subscribe = useCallback(async () => {
    if (!isSupported) {
      setError('Push notifications not supported');
      return;
    }

    setIsLoading(true);
    setError(null);

    try {
      // Solicitar permiso
      const permission = await requestPermission();
      
      if (permission !== 'granted') {
        throw new Error('Permission denied');
      }

      // Obtener clave pública VAPID
      const response = await fetch('/api/notifications/vapid-public-key');
      const { publicKey } = await response.json();

      if (!publicKey) {
        throw new Error('VAPID public key not available');
      }

      // Suscribirse
      const registration = await navigator.serviceWorker.ready;
      const subscription = await registration.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: urlBase64ToUint8Array(publicKey) as unknown as string,
      });

      // Guardar en servidor
      await fetch('/api/notifications/push', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(subscription),
      });

      setIsSubscribed(true);
    } catch (err: any) {
      setError(err.message || 'Failed to subscribe');
      console.error('Push subscription error:', err);
    } finally {
      setIsLoading(false);
    }
  }, [isSupported, requestPermission]);

  const unsubscribe = useCallback(async () => {
    if (!isSupported) return;

    setIsLoading(true);
    setError(null);

    try {
      const registration = await navigator.serviceWorker.ready;
      const subscription = await registration.pushManager.getSubscription();

      if (subscription) {
        // Eliminar del servidor
        await fetch('/api/notifications/push', {
          method: 'DELETE',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ endpoint: subscription.endpoint }),
        });

        // Cancelar suscripción local
        await subscription.unsubscribe();
      }

      setIsSubscribed(false);
    } catch (err: any) {
      setError(err.message || 'Failed to unsubscribe');
    } finally {
      setIsLoading(false);
    }
  }, [isSupported]);

  return {
    isSupported,
    isSubscribed,
    isLoading,
    error,
    subscribe,
    unsubscribe,
    requestPermission,
  };
}

/**
 * Convertir URL base64 a Uint8Array para VAPID
 */
function urlBase64ToUint8Array(base64String: string): Uint8Array {
  const padding = '='.repeat((4 - base64String.length % 4) % 4);
  const base64 = (base64String + padding)
    .replace(/\-/g, '+')
    .replace(/\_/g, '/');

  const rawData = window.atob(base64);
  const outputArray = new Uint8Array(rawData.length);

  for (let i = 0; i < rawData.length; ++i) {
    outputArray[i] = rawData.charCodeAt(i);
  }

  return outputArray;
}

export default usePushNotifications;

/**
 * useReadingAnalytics Hook
 *
 * Hook especializado para tracking de analytics durante la lectura.
 * Incluye: inicio de lectura, cambios de página, y completado.
 */

'use client';

import { useEffect, useRef, useCallback, useState } from 'react';

import { trackEvent } from './useAnalytics';

interface ReadingAnalyticsOptions {
  mangaId: string;
  chapterId: string;
  chapterNumber: number;
  totalPages: number;
}

export function useReadingAnalytics({
  mangaId,
  chapterId,
  chapterNumber,
  totalPages,
}: ReadingAnalyticsOptions) {
  const hasStartedRef = useRef(false);
  const hasCompletedRef = useRef(false);
  const pagesViewedRef = useRef<Set<number>>(new Set());
  const startTimeRef = useRef<number>(0);
  const lastPageRef = useRef<number>(0);

  // Use state for values needed during render (purity rule)
  const [pagesViewedCount, setPagesViewedCount] = useState(0);
  const [hasCompleted, setHasCompleted] = useState(false);

  // Track start reading
  const trackStartReading = useCallback(() => {
    if (hasStartedRef.current) return;
    hasStartedRef.current = true;

    trackEvent({
      type: 'chapter_read',
      mangaId,
      chapterId,
      metadata: {
        chapterNumber,
        totalPages,
        timestamp: new Date().toISOString(),
      },
    });
  }, [mangaId, chapterId, chapterNumber, totalPages]);

  // Track page turn
  const trackPageTurn = useCallback((pageNumber: number) => {
    // Track that this page was viewed
    pagesViewedRef.current.add(pageNumber);
    lastPageRef.current = pageNumber;
    setPagesViewedCount(pagesViewedRef.current.size);

    trackEvent({
      type: 'page_view',
      mangaId,
      chapterId,
      metadata: {
        chapterNumber,
        pageNumber,
        totalPages,
        pagesViewed: pagesViewedRef.current.size,
      },
    });
  }, [mangaId, chapterId, chapterNumber, totalPages]);

  // Track completion
  const trackCompletion = useCallback(() => {
    if (hasCompletedRef.current) return;
    hasCompletedRef.current = true;
    setHasCompleted(true);

    const timeSpent = Date.now() - startTimeRef.current;
    const percentageRead = (pagesViewedRef.current.size / totalPages) * 100;

    trackEvent({
      type: 'chapter_complete',
      mangaId,
      chapterId,
      metadata: {
        chapterNumber,
        totalPages,
        pagesViewed: pagesViewedRef.current.size,
        percentageRead,
        timeSpent,
        timeSpentSeconds: Math.round(timeSpent / 1000),
      },
    });
  }, [mangaId, chapterId, chapterNumber, totalPages]);

  // Track time spent on unmount
  useEffect(() => {
    return () => {
      const timeSpent = Date.now() - startTimeRef.current;
      const pagesViewed = pagesViewedRef.current.size;

      if (hasStartedRef.current) {
        trackEvent({
          type: 'time_spent',
          mangaId,
          chapterId,
          metadata: {
            chapterNumber,
            timeSpent,
            timeSpentSeconds: Math.round(timeSpent / 1000),
            pagesViewed,
            percentageRead: totalPages > 0 ? (pagesViewed / totalPages) * 100 : 0,
            completed: hasCompletedRef.current,
          },
        });
      }
    };
  }, [mangaId, chapterId, chapterNumber, totalPages]);

  // Auto-start tracking after 3 seconds of being on page
  useEffect(() => {
    startTimeRef.current = Date.now();
    const timer = setTimeout(() => {
      trackStartReading();
    }, 3000);

    return () => clearTimeout(timer);
  }, [trackStartReading]);

  return {
    trackStartReading,
    trackPageTurn,
    trackCompletion,
    pagesViewed: pagesViewedCount,
    hasCompleted: hasCompleted,
  };
}

export default useReadingAnalytics;

