'use client';

import { useState, useCallback, useRef, useEffect } from 'react';

interface UseRetryOptions {
  maxRetries?: number;
  retryDelay?: number;
  backoffMultiplier?: number;
  onRetry?: (attempt: number) => void;
  onMaxRetriesReached?: () => void;
}

interface RetryState<T> {
  data: T | null;
  isLoading: boolean;
  error: Error | null;
  retryCount: number;
  isRetrying: boolean;
}

interface UseRetryReturn<T> extends RetryState<T> {
  execute: (...args: unknown[]) => Promise<T | null>;
  retry: () => Promise<T | null>;
  reset: () => void;
}

export function useRetry<T>(
  asyncFn: (...args: unknown[]) => Promise<T>,
  options: UseRetryOptions = {}
): UseRetryReturn<T> {
  const {
    maxRetries = 3,
    retryDelay = 1000,
    backoffMultiplier = 2,
    onRetry,
    onMaxRetriesReached,
  } = options;

  const [state, setState] = useState<RetryState<T>>({
    data: null,
    isLoading: false,
    error: null,
    retryCount: 0,
    isRetrying: false,
  });

  const argsRef = useRef<unknown[]>([]);
  const timeoutRef = useRef<NodeJS.Timeout | null>(null);

  const execute = useCallback(
    async (...args: unknown[]): Promise<T | null> => {
      // Clear any pending timeouts
      if (timeoutRef.current) {
        clearTimeout(timeoutRef.current);
        timeoutRef.current = null;
      }

      argsRef.current = args;
      
      setState((prev) => ({
        ...prev,
        isLoading: true,
        error: null,
        isRetrying: prev.retryCount > 0,
      }));

      try {
        const result = await asyncFn(...args);
        setState({
          data: result,
          isLoading: false,
          error: null,
          retryCount: 0,
          isRetrying: false,
        });
        return result;
      } catch (error) {
        const err = error instanceof Error ? error : new Error(String(error));
        
        setState((prev) => ({
          ...prev,
          isLoading: false,
          error: err,
          isRetrying: false,
        }));
        
        return null;
      }
    },
    [asyncFn]
  );

  const retry = useCallback(async (): Promise<T | null> => {
    const currentRetryCount = state.retryCount;
    
    if (currentRetryCount >= maxRetries) {
      onMaxRetriesReached?.();
      return null;
    }

    const nextRetryCount = currentRetryCount + 1;
    const delay = retryDelay * Math.pow(backoffMultiplier, currentRetryCount);

    onRetry?.(nextRetryCount);

    setState((prev) => ({
      ...prev,
      retryCount: nextRetryCount,
      isRetrying: true,
    }));

    // Wait before retrying
    return new Promise((resolve) => {
      timeoutRef.current = setTimeout(async () => {
        const result = await execute(...argsRef.current);
        resolve(result);
      }, delay);
    });
  }, [execute, maxRetries, retryDelay, backoffMultiplier, onRetry, onMaxRetriesReached, state.retryCount]);

  const reset = useCallback(() => {
    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current);
      timeoutRef.current = null;
    }
    
    setState({
      data: null,
      isLoading: false,
      error: null,
      retryCount: 0,
      isRetrying: false,
    });
    argsRef.current = [];
  }, []);

  return {
    ...state,
    execute,
    retry,
    reset,
  };
}

// Hook for auto-retry on error
export function useAutoRetry<T>(
  asyncFn: (...args: unknown[]) => Promise<T>,
  options: UseRetryOptions & { autoRetry?: boolean } = {}
): UseRetryReturn<T> {
  const { autoRetry = true, ...retryOptions } = options;
  const retryHook = useRetry(asyncFn, retryOptions);
  const { error, retryCount, execute: _execute } = retryHook;
  const [hasRetried, setHasRetried] = useState(false);

   
  // auto-retry pattern requires setState in effect when error occurs
  useEffect(() => {
    if (error && autoRetry && retryCount < (options.maxRetries || 3) && !hasRetried) {
      setHasRetried(true);
      retryHook.retry();
    }   
    // retryHook.retry() intentionally triggers state changes for auto-retry
  }, [error, autoRetry, retryCount, options.maxRetries, hasRetried, retryHook]);

  // Reset flag when successful
  useEffect(() => {
    if (!error) {
      setHasRetried(false);
    }
  }, [error]);

  return retryHook;
}

// Hook with optimistic updates
export function useOptimisticRetry<T>(
  asyncFn: (...args: unknown[]) => Promise<T>,
  options: UseRetryOptions & {
    optimisticData?: T;
    rollbackOnError?: boolean;
  } = {}
): UseRetryReturn<T> & {
  optimisticData: T | null;
} {
  const { optimisticData, rollbackOnError = true } = options;
  const [optimisticState, setOptimisticState] = useState<T | null>(null);
  const previousDataRef = useRef<T | null>(null);

  const wrappedFn = useCallback(
    async (...args: unknown[]): Promise<T> => {
      // Store previous data for rollback
      previousDataRef.current = optimisticState;
      
      // Set optimistic data
      if (optimisticData !== undefined) {
        setOptimisticState(optimisticData);
      }

      try {
        const result = await asyncFn(...args);
        setOptimisticState(result);
        return result;
      } catch (error) {
        // Rollback on error
        if (rollbackOnError) {
          setOptimisticState(previousDataRef.current);
        }
        throw error;
      }
    },
    [asyncFn, optimisticData, rollbackOnError, optimisticState]
  );

  const retryHook = useRetry(wrappedFn, options);

  return {
    ...retryHook,
    optimisticData: optimisticState,
  };
}

/**
 * useSocket Hook
 * 
 * Hook para conectar al servidor Socket.IO
 */

'use client';

import { useSession } from 'next-auth/react';
import { useEffect, useRef, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';

import type {
  ClientToServerEvents,
  ServerToClientEvents,
} from '@/lib/socket';

type SocketType = Socket<ServerToClientEvents, ClientToServerEvents>;

interface UseSocketOptions {
  autoConnect?: boolean;
  onConnect?: () => void;
  onDisconnect?: (reason: string) => void;
  onError?: (error: Error) => void;
}

export function useSocket(options: UseSocketOptions = {}) {
  const { data: session, status } = useSession();
  const socketRef = useRef<SocketType | null>(null);
  const [socket, setSocket] = useState<SocketType | null>(null);
  const [isConnected, setIsConnected] = useState(false);
  const [transport, setTransport] = useState('N/A');
  const [error, setError] = useState<string | null>(null);
  
  const { autoConnect = true, onConnect, onDisconnect, onError } = options;

  useEffect(() => {
    if (status === 'loading' || !session) return;

    const initSocket = async () => {
      try {
        // Solo inicializar en cliente
        if (typeof window === 'undefined') return;

        // Obtener token de sesión
        const token = session.user?.id; // Simplificado, idealmente usar JWT

        // Crear conexión Socket.IO
        const socket: SocketType = io(process.env.NEXT_PUBLIC_SOCKET_URL || '', {
          path: '/api/socket',
          auth: { token },
          transports: ['websocket', 'polling'],
          reconnection: true,
          reconnectionAttempts: 5,
          reconnectionDelay: 1000,
          reconnectionDelayMax: 5000,
          randomizationFactor: 0.5,
        });

        socketRef.current = socket;
        setSocket(socket); // Update state after socket is initialized

        // Event listeners
        socket.on('connect', () => {
          console.info('[Socket] Connected');
          setIsConnected(true);
          setTransport(socket.io.engine?.transport?.name || 'N/A');
          setError(null);
          onConnect?.();
        });

        socket.on('disconnect', (reason) => {
          console.info('[Socket] Disconnected:', reason);
          setIsConnected(false);
          onDisconnect?.(reason);
        });

        socket.on('connect_error', (err) => {
          console.error('[Socket] Connection error:', err);
          setError(err.message);
          onError?.(err);
        });

    socket.io.engine.on('upgrade', (transport) => {
      const name = typeof transport === 'string' ? transport : transport.name;
      console.info('[Socket] Transport upgraded to:', name);
      setTransport(name);
    });

        // Auto connect
        if (autoConnect) {
          socket.connect();
        }
      } catch (err) {
        console.error('[Socket] Init error:', err);
        setError(err instanceof Error ? err.message : 'Unknown error');
      }
    };

    initSocket();

    // Cleanup
    return () => {
      if (socketRef.current) {
        socketRef.current.disconnect();
        socketRef.current = null;
      }
    };
  }, [session, status, autoConnect, onConnect, onDisconnect, onError]);

  // Métodos expuestos
  const joinRoom = useCallback((room: string) => {
    socketRef.current?.emit('user:join-room', room);
  }, []);

  const leaveRoom = useCallback((room: string) => {
    socketRef.current?.emit('user:leave-room', room);
  }, []);

  const emit = useCallback(<T extends keyof ClientToServerEvents>(
    event: T,
    ...args: Parameters<ClientToServerEvents[T]>
  ) => {
    socketRef.current?.emit(event, ...args);
  }, []);

  const on = useCallback(<T extends keyof ServerToClientEvents>(
    event: T,
    callback: ServerToClientEvents[T]
  ) => {
    (socketRef.current?.on as any)(event, callback);
    return () => {
      (socketRef.current?.off as any)(event, callback);
    };
  }, []);

  return {
    socket,
    isConnected,
    transport,
    error,
    joinRoom,
    leaveRoom,
    emit,
    on,
  };
}

export default useSocket;

import type { Locale } from './locales';
import en from '@/i18n/locales/en.json';
import es from '@/i18n/locales/es.json';

type NestedRecord = { [key: string]: string | NestedRecord };
const messages: Record<Locale, NestedRecord> = { es, en };

function getNestedValue(obj: NestedRecord, path: string): string | undefined {
  const keys = path.split('.');
  let current: any = obj;
  for (const key of keys) {
    if (current == null || typeof current !== 'object') return undefined;
    current = current[key];
  }
  return typeof current === 'string' ? current : undefined;
}

function interpolate(template: string, params?: Record<string, string | number>): string {
  if (!params) return template;
  return template.replace(/\{(\w+)\}/g, (_, key) => {
    return params[key] !== undefined ? String(params[key]) : `{${key}}`;
  });
}

export function getT(locale: Locale) {
  return (key: string, params?: Record<string, string | number>): string => {
    const msg = messages[locale];
    const value = getNestedValue(msg, key);
    if (value === undefined) {
      const esValue = getNestedValue(messages.es, key);
      if (esValue !== undefined && locale !== 'es') {
        return interpolate(esValue, params);
      }
      return key;
    }
    return interpolate(value, params);
  };
}

'use client';

import React, { createContext, useContext, useState, useCallback, useMemo } from 'react';

import type { Locale } from './locales';
import en from '@/i18n/locales/en.json';
import es from '@/i18n/locales/es.json';

export { SUPPORTED_LOCALES, DEFAULT_LOCALE } from './locales';
export type { Locale } from './locales';

type NestedRecord = { [key: string]: string | NestedRecord };

const messages: Record<Locale, NestedRecord> = { es, en };

export type TranslationParams = Record<string, string | number>;

interface I18nContextType {
  locale: Locale;
  setLocale: (locale: Locale) => void;
  t: (key: string, params?: TranslationParams) => string;
}

const I18nContext = createContext<I18nContextType | null>(null);

function getNestedValue(obj: NestedRecord, path: string): string | undefined {
  const keys = path.split('.');
  let current: any = obj;
  for (const key of keys) {
    if (current == null || typeof current !== 'object') return undefined;
    current = current[key];
  }
  return typeof current === 'string' ? current : undefined;
}

function interpolate(template: string, params?: TranslationParams): string {
  if (!params) return template;
  return template.replace(/\{(\w+)\}/g, (_, key) => {
    return params[key] !== undefined ? String(params[key]) : `{${key}}`;
  });
}

function setLocaleCookie(locale: Locale) {
  document.cookie = `inkverse-locale=${locale};path=/;max-age=31536000;SameSite=Lax`;
}

export function I18nProvider({ children, defaultLocale }: { children: React.ReactNode; defaultLocale?: Locale }) {
  const [locale, setLocaleState] = useState<Locale>(() => defaultLocale || 'es');

  const setLocale = useCallback((newLocale: Locale) => {
    setLocaleState(newLocale);
    setLocaleCookie(newLocale);
  }, []);

  const t = useCallback(
    (key: string, params?: TranslationParams): string => {
      const msg = messages[locale];
      const value = getNestedValue(msg, key);
      if (value === undefined) {
        const esValue = getNestedValue(messages.es, key);
        if (esValue !== undefined && locale !== 'es') {
          return interpolate(esValue, params);
        }
        return key;
      }
      return interpolate(value, params);
    },
    [locale]
  );

  const value = useMemo(() => ({ locale, setLocale, t }), [locale, setLocale, t]);

  return <I18nContext.Provider value={value}>{children}</I18nContext.Provider>;
}

export function useI18n(): I18nContextType {
  const context = useContext(I18nContext);
  if (!context) {
    throw new Error('useI18n must be used within an I18nProvider');
  }
  return context;
}

export function useT() {
  return useI18n().t;
}

export function useLocale() {
  const { locale, setLocale } = useI18n();
  return { locale, setLocale };
}

