import { ICommentRepository } from '../../application/use-cases/PostCommentUseCase';
import { CommentModel } from '@/infrastructure/persistence/mongodb/models/Comment';
import dbConnect from '@/lib/mongoose';

export class CommentRepositoryAdapter implements ICommentRepository {
  async create(data: Parameters<ICommentRepository['create']>[0]): Promise<Awaited<ReturnType<ICommentRepository['create']>>> {
    await dbConnect();
    const doc = await CommentModel.create({
      chapterId: data.chapterId,
      userId: data.userId,
      parentId: data.parentId || undefined,
      content: data.content,
      aiAnalysis: (data as any).aiAnalysis,
      isHidden: (data as any).isHidden ?? false,
      hiddenReason: (data as any).hiddenReason,
      moderatedBy: (data as any).moderatedBy,
      requiresReview: (data as any).requiresReview ?? false,
      containsSpoiler: data.containsSpoiler,
      spoilerConfidence: data.spoilerConfidence,
      likes: (data as any).likes ?? 0,
      replies: (data as any).replies ?? 0,
      likedBy: (data as any).likedBy ?? [],
    });
    return {
      id: doc._id.toString(),
      userId: doc.userId,
      chapterId: doc.chapterId,
      content: doc.content,
      parentId: doc.parentId || undefined,
      createdAt: doc.createdAt,
    };
  }

  async incrementReplies(commentId: string): Promise<void> {
    await dbConnect();
    await CommentModel.findByIdAndUpdate(commentId, { $inc: { replies: 1 } });
  }
}

import { DomainEvent as AppDomainEvent } from '../../application/events/DomainEvent';
import { IEventBus } from '../../application/services/IEventBus';
import { getEventBus, DomainEvent as InfraDomainEvent } from '../queue/LocalEventBus';

export class EventBusAdapter implements IEventBus {
  async publish<T extends AppDomainEvent>(event: T): Promise<void> {
    const infraEvent: InfraDomainEvent = {
      id: event.eventId,
      type: event.name,
      payload: event.payload as Record<string, unknown>,
      occurredAt: event.timestamp,
    };
    await getEventBus().publish(infraEvent);
  }

  async publishBatch<T extends AppDomainEvent>(events: T[]): Promise<void> {
    await Promise.all(events.map(e => this.publish(e)));
  }

  subscribe<T extends AppDomainEvent>(
    eventName: string,
    handler: (event: T) => void | Promise<void>
  ): string {
    getEventBus().subscribe(eventName, handler as any);
    return eventName;
  }

  subscribeToMany<T extends AppDomainEvent>(
    eventNames: string[],
    handler: (event: T) => void | Promise<void>
  ): string[] {
    const handlerWrapper = handler as any;
    eventNames.forEach(name => getEventBus().subscribe(name, handlerWrapper));
    return eventNames;
  }

  unsubscribe(_subscriptionId: string): boolean {
    return true;
  }

  unsubscribeAll(_eventName: string): number {
    return 0;
  }

  getSubscriptions() {
    return [];
  }

  getSubscriptionsForEvent(_eventName: string) {
    return [];
  }

  hasSubscribers(_eventName: string): boolean {
    return false;
  }

  async waitForPendingEvents(): Promise<void> {}

  clear(): void {}

  getStats() {
    return {
      totalPublished: 0,
      totalProcessed: 0,
      totalFailed: 0,
      activeSubscriptions: 0,
      eventsByName: {},
    };
  }
}

export const eventBusAdapter = new EventBusAdapter();

import type {
  IReadingAnalyticsRepository,
  ReadingEvent,
  ReadingLogRecord,
  ReadingStats,
  UserReadingHistory,
  CreatorStats,
  ChapterLogsResult,
} from '@/core/services/IReadingAnalyticsRepository';
import { ReadingLogModel, IReadingLog } from '@/infrastructure/persistence/mongodb/models/ReadingLog';
import dbConnect from '@/lib/mongoose';

function toRecord(doc: IReadingLog): ReadingLogRecord {
  return {
    id: doc._id.toString(),
    userId: doc.userId,
    chapterId: doc.chapterId,
    mangaId: doc.mangaId,
    events: doc.events.map((e: any) => ({
      type: e.type as ReadingEvent['type'],
      timestamp: e.timestamp,
      data: e.data ? { pageNumber: e.data.pageNumber, scrollDepth: e.data.scrollDepth, duration: e.data.duration } : undefined,
    })),
    totalTimeSeconds: doc.totalTimeSeconds,
    pagesViewed: doc.pagesViewed,
    completed: doc.completed,
    completedAt: doc.completedAt,
    readingSpeed: doc.readingSpeed,
    createdAt: doc.createdAt,
    updatedAt: doc.updatedAt,
  };
}

export class MongoReadingAnalyticsRepository implements IReadingAnalyticsRepository {
  async logReading(data: {
    userId: string;
    mangaId: string;
    chapterId: string;
    chapterNumber: number;
    pagesRead: number;
    totalPages: number;
    timeSpent: number;
    completed: boolean;
  }): Promise<void> {
    await dbConnect();
    await ReadingLogModel.create({
      userId: data.userId,
      chapterId: data.chapterId,
      mangaId: data.mangaId,
      events: [],
      totalTimeSeconds: data.timeSpent,
      pagesViewed: Array.from({ length: data.pagesRead }, (_, i) => i + 1),
      completed: data.completed,
      completedAt: data.completed ? new Date() : undefined,
      readingSpeed: data.timeSpent > 0 ? Math.round(data.pagesRead / (data.timeSpent / 60)) : 0,
    });
  }

  async getReadingStats(userId: string, mangaId?: string): Promise<{
    totalChaptersRead: number;
    totalPagesRead: number;
    totalTimeSpent: number;
    averageCompletionRate: number;
    readingStreak: number;
    lastReadAt: Date | null;
  }> {
    await dbConnect();
    const match: any = { userId };
    if (mangaId) match.mangaId = mangaId;

    const logs = await ReadingLogModel.find(match).sort({ createdAt: -1 }).lean();
    const totalChaptersRead = logs.length;
    const totalPagesRead = logs.reduce((sum: number, l: any) => sum + (l.pagesViewed?.length || 0), 0);
    const totalTimeSpent = logs.reduce((sum: number, l: any) => sum + (l.totalTimeSeconds || 0), 0);
    const completedLogs = logs.filter((l: any) => l.completed);
    const averageCompletionRate = logs.length > 0 ? Math.round((completedLogs.length / logs.length) * 100) : 0;
    const lastReadAt = logs.length > 0 ? logs[0].createdAt : null;

    const readingStreak = this.calculateStreak(logs.map((l: any) => l.createdAt));

    return { totalChaptersRead, totalPagesRead, totalTimeSpent, averageCompletionRate, readingStreak, lastReadAt };
  }

  async getPopularMangas(limit: number = 10): Promise<Array<{ mangaId: string; totalReaders: number; totalReads: number }>> {
    await dbConnect();
    const results = await ReadingLogModel.aggregate([
      {
        $group: {
          _id: '$mangaId',
          totalReaders: { $addToSet: '$userId' },
          totalReads: { $sum: 1 },
        },
      },
      {
        $project: {
          mangaId: '$_id',
          totalReaders: { $size: '$totalReaders' },
          totalReads: 1,
        },
      },
      { $sort: { totalReads: -1 } },
      { $limit: limit },
    ]);
    return results.map((r: any) => ({ mangaId: r.mangaId, totalReaders: r.totalReaders, totalReads: r.totalReads }));
  }

  async findOrCreateLog(userId: string, chapterId: string, mangaId: string): Promise<ReadingLogRecord> {
    await dbConnect();
    let doc = await ReadingLogModel.findOne({ userId, chapterId, mangaId });
    if (!doc) {
      doc = await ReadingLogModel.create({
        userId,
        chapterId,
        mangaId,
        events: [],
        totalTimeSeconds: 0,
        pagesViewed: [],
        completed: false,
        readingSpeed: 0,
      });
    }
    return toRecord(doc);
  }

  async saveLog(log: ReadingLogRecord): Promise<void> {
    await dbConnect();
    await ReadingLogModel.findByIdAndUpdate(log.id, {
      events: log.events,
      totalTimeSeconds: log.totalTimeSeconds,
      pagesViewed: log.pagesViewed,
      completed: log.completed,
      completedAt: log.completedAt,
      readingSpeed: log.readingSpeed,
    });
  }

  async getChapterStats(chapterId: string): Promise<ReadingStats> {
    await dbConnect();

    const [totalStats, completionStats, timeStats, speedStats, dailyAggregation] = await Promise.all([
      ReadingLogModel.countDocuments({ chapterId }),
      ReadingLogModel.countDocuments({ chapterId, completed: true }),
      ReadingLogModel.aggregate([
        { $match: { chapterId } },
        { $group: { _id: null, avgTime: { $avg: '$totalTimeSeconds' } } },
      ]),
      ReadingLogModel.aggregate([
        { $match: { chapterId, readingSpeed: { $gt: 0 } } },
        { $group: { _id: null, avgSpeed: { $avg: '$readingSpeed' } } },
      ]),
      ReadingLogModel.aggregate([
        { $match: { chapterId } },
        {
          $group: {
            _id: { $dateToString: { format: '%Y-%m-%d', date: '$createdAt' } },
            reads: { $sum: 1 },
            completions: { $sum: { $cond: ['$completed', 1, 0] } },
          },
        },
        { $sort: { _id: 1 } },
        { $limit: 30 },
      ]),
    ]);

    const pageViews = await ReadingLogModel.aggregate([
      { $match: { chapterId } },
      { $unwind: '$pagesViewed' },
      { $group: { _id: '$pagesViewed', views: { $sum: 1 } } },
      { $sort: { views: -1 } },
      { $limit: 5 },
    ]);

    const totalReads = totalStats || 0;
    const totalCompletions = completionStats || 0;
    const completionRate = totalReads > 0 ? Math.round((totalCompletions / totalReads) * 100) : 0;

    return {
      chapterId,
      totalReads,
      totalCompletions,
      completionRate,
      avgTimeSeconds: Math.round(timeStats[0]?.avgTime || 0),
      avgReadingSpeed: Math.round(speedStats[0]?.avgSpeed || 0),
      mostViewedPages: pageViews.map((p: any) => ({ page: p._id, views: p.views })),
      dailyStats: dailyAggregation.map((d: any) => ({ date: d._id, reads: d.reads, completions: d.completions })),
    };
  }

  async getUserHistory(userId: string): Promise<UserReadingHistory> {
    await dbConnect();
    const docs = await ReadingLogModel.find({ userId }).sort({ createdAt: -1 }).limit(50);
    const logs = docs.map(toRecord);

    const totalChaptersRead = logs.length;
    const totalCompletions = logs.filter((l) => l.completed).length;
    const totalTimeSeconds = logs.reduce((sum, l) => sum + l.totalTimeSeconds, 0);

    const recentReads = logs.slice(0, 20).map((log) => ({
      chapterId: log.chapterId,
      mangaId: log.mangaId,
      completed: log.completed,
      completedAt: log.completedAt,
      totalTimeSeconds: log.totalTimeSeconds,
      readingSpeed: log.readingSpeed,
    }));

    const mangaMap = new Map<string, { chaptersRead: number; totalTimeSeconds: number }>();
    logs.forEach((log) => {
      const existing = mangaMap.get(log.mangaId);
      if (existing) {
        existing.chaptersRead += 1;
        existing.totalTimeSeconds += log.totalTimeSeconds;
      } else {
        mangaMap.set(log.mangaId, { chaptersRead: 1, totalTimeSeconds: log.totalTimeSeconds });
      }
    });

    const readingByManga = Array.from(mangaMap.entries()).map(([mangaId, stats]) => ({ mangaId, ...stats }));

    return { userId, totalChaptersRead, totalCompletions, totalTimeSeconds, recentReads, readingByManga };
  }

  async getCreatorStats(mangaIds: string[], dateFrom: Date, dateTo: Date): Promise<CreatorStats> {
    await dbConnect();
    const matchClause: any = {
      mangaId: { $in: mangaIds },
      createdAt: { $gte: dateFrom, $lte: dateTo },
    };

    const stats = await ReadingLogModel.aggregate([
      { $match: matchClause },
      {
        $group: {
          _id: null,
          totalViews: { $sum: 1 },
          totalCompletions: { $sum: { $cond: ['$completed', 1, 0] } },
          avgTime: { $avg: '$totalTimeSeconds' },
        },
      },
    ]);

    const chapterStats = await ReadingLogModel.aggregate([
      { $match: matchClause },
      {
        $group: {
          _id: { chapterId: '$chapterId', mangaId: '$mangaId' },
          reads: { $sum: 1 },
          completions: { $sum: { $cond: ['$completed', 1, 0] } },
        },
      },
      {
        $project: {
          chapterId: '$_id.chapterId',
          mangaId: '$_id.mangaId',
          reads: 1,
          completions: 1,
          completionRate: { $multiply: [{ $divide: ['$completions', '$reads'] }, 100] },
        },
      },
      { $sort: { reads: -1 } },
    ]);

    const result = stats[0] || { totalViews: 0, totalCompletions: 0, avgTime: 0 };
    const totalReads = result.totalViews;
    const totalCompletions = result.totalCompletions;

    return {
      totalViews: totalReads,
      totalReads,
      totalCompletions,
      completionRate: totalReads > 0 ? Math.round((totalCompletions / totalReads) * 100) : 0,
      avgTimeSeconds: Math.round(result.avgTime || 0),
      chapterStats: chapterStats.map((c: any) => ({
        chapterId: c.chapterId,
        mangaId: c.mangaId,
        reads: c.reads,
        completions: c.completions,
        completionRate: Math.round(c.completionRate || 0),
      })),
    };
  }

  async getChapterLogs(chapterId: string, options: { limit?: number; offset?: number } = {}): Promise<ChapterLogsResult> {
    await dbConnect();
    const { limit = 20, offset = 0 } = options;

    const [docs, total] = await Promise.all([
      ReadingLogModel.find({ chapterId }).sort({ createdAt: -1 }).skip(offset).limit(limit).lean(),
      ReadingLogModel.countDocuments({ chapterId }),
    ]);

    return {
      logs: docs.map((d: any) => ({
        id: d._id.toString(),
        userId: d.userId,
        chapterId: d.chapterId,
        mangaId: d.mangaId,
        events: (d.events || []).map((e: any) => ({
          type: e.type as ReadingEvent['type'],
          timestamp: e.timestamp,
          data: e.data ? { pageNumber: e.data.pageNumber, scrollDepth: e.data.scrollDepth, duration: e.data.duration } : undefined,
        })),
        totalTimeSeconds: d.totalTimeSeconds,
        pagesViewed: d.pagesViewed || [],
        completed: d.completed,
        completedAt: d.completedAt,
        readingSpeed: d.readingSpeed,
        createdAt: d.createdAt,
        updatedAt: d.updatedAt,
      })),
      total,
    };
  }

  async hasUserCompleted(userId: string, chapterId: string): Promise<boolean> {
    await dbConnect();
    const doc = await ReadingLogModel.findOne({ userId, chapterId, completed: true });
    return !!doc;
  }

  private calculateStreak(dates: Date[]): number {
    if (dates.length === 0) return 0;
    const uniqueDays = [...new Set(dates.map((d) => d.toISOString().slice(0, 10)))].sort().reverse();
    let streak = 1;
    for (let i = 1; i < uniqueDays.length; i++) {
      const prev = new Date(uniqueDays[i - 1]);
      const curr = new Date(uniqueDays[i]);
      const diffMs = prev.getTime() - curr.getTime();
      const diffDays = Math.round(diffMs / (1000 * 60 * 60 * 24));
      if (diffDays === 1) {
        streak++;
      } else {
        break;
      }
    }
    return streak;
  }
}

import { PrismaClient, Prisma } from '@prisma/client';

import type { IAchievementRepository, Achievement, AchievementCondition, UserStats } from '@/core/services/IAchievementRepository';

export class PrismaAchievementRepository implements IAchievementRepository {
  constructor(private readonly prisma: PrismaClient) {}

  async findAll(): Promise<Achievement[]> {
    const achievements = await this.prisma.achievementDefinition.findMany({
      orderBy: [
        { category: 'asc' },
        { xpReward: 'asc' },
      ],
    });
    return achievements.map(a => this.mapToAchievement(a));
  }

  async findByBadgeId(badgeId: string): Promise<Achievement | null> {
    const achievement = await this.prisma.achievementDefinition.findUnique({
      where: { badgeId },
    });
    if (!achievement) return null;
    return this.mapToAchievement(achievement);
  }

  async isUnlocked(userId: string, achievementId: string): Promise<boolean> {
    const count = await this.prisma.userAchievement.count({
      where: { userId, achievementId },
    });
    return count > 0;
  }

  async createUserAchievement(userId: string, achievementId: string): Promise<void> {
    await this.prisma.userAchievement.create({
      data: {
        userId,
        achievementId,
        unlockedAt: new Date(),
      },
    });
  }

  async getUserStats(userId: string): Promise<UserStats> {
    const [
      chaptersRead,
      commentsPosted,
      correctionsApproved,
      mangasCompleted,
      commentLikesReceived,
      mangasCreated,
      sponsorshipsWon,
      questsCompleted,
      user,
    ] = await Promise.all([
      this.prisma.readingSession.count({ where: { userId } }),
      this.prisma.comment.count({ where: { userId } }),
      this.prisma.chapterCorrection.count({ where: { userId, status: 'APPROVED' } }),
      this.prisma.userManga.count({ where: { userId, status: 'COMPLETED' } }),
      this.prisma.commentLike.count({ where: { comment: { userId } } }),
      this.prisma.mangaSeries.count({ where: { authorId: userId } }),
      this.prisma.sponsorshipBid.count({ where: { userId, isWinning: true } }),
      this.prisma.userQuest.count({ where: { userId, completed: true } }),
      this.prisma.user.findUnique({ where: { id: userId }, select: { level: true, readingStreak: true } }),
    ]);

    return {
      chaptersRead,
      commentsPosted,
      correctionsApproved,
      mangasCompleted,
      commentLikesReceived,
      mangasCreated,
      sponsorshipsWon,
      questsCompleted,
      currentLevel: user?.level || 1,
      readingStreak: user?.readingStreak || 0,
    };
  }

  async getTotalXPEarned(userId: string): Promise<number> {
    const userAchievements = await this.prisma.userAchievement.findMany({
      where: { userId },
      include: { achievement: true },
    });

    return userAchievements.reduce((total, ua) => total + ua.achievement.xpReward, 0);
  }

  async getUserAchievementRecords(userId: string): Promise<Array<{ achievementId: string; unlockedAt: Date }>> {
    const records = await this.prisma.userAchievement.findMany({
      where: { userId },
    });
    return records.map(r => ({ achievementId: r.achievementId, unlockedAt: r.unlockedAt }));
  }

  private mapToAchievement(
    data: Prisma.AchievementDefinitionGetPayload<{}>
  ): Achievement {
    return {
      id: data.id,
      badgeId: data.badgeId,
      name: data.name,
      description: data.description,
      xpReward: data.xpReward,
      iconUrl: data.iconUrl,
      condition: JSON.parse(data.condition) as AchievementCondition,
      category: (data as unknown as { category?: string }).category || 'MILESTONE',
      difficulty: (data as unknown as { difficulty?: string }).difficulty || 'MEDIUM',
      createdAt: data.createdAt,
    };
  }
}

import { PrismaClient } from '@prisma/client';

import type {
  ICollectionRepository,
  CollectionRecord,
  CollectionCreateInput,
  CollectionUpdateInput,
  CollectionWithItems,
  CollectionQuery,
} from '@/core/services/ICollectionRepository';
import { logSecurityEvent, SecurityAction, Severity } from '@/lib/security-audit';

interface PrismaCollectionItem {
  id: string;
  manga: {
    id: string;
    title: string;
    coverUrl: string | null;
    slug: string;
    authorName: string;
  };
}

export class PrismaCollectionRepository implements ICollectionRepository {
  constructor(private readonly prisma: PrismaClient) {}

  async countByUser(userId: string): Promise<number> {
    return this.prisma.collection.count({ where: { userId } });
  }

  async create(data: CollectionCreateInput): Promise<CollectionRecord> {
    const collection = await this.prisma.collection.create({
      data: {
        userId: data.userId,
        title: data.title,
        description: data.description ?? null,
        coverUrl: data.coverUrl ?? null,
        isPublic: data.isPublic,
      },
      include: { items: { select: { id: true } } },
    });
    return this.toRecord(collection);
  }

  async findByUser(collectionId: string, userId: string): Promise<CollectionRecord | null> {
    const collection = await this.prisma.collection.findFirst({
      where: { id: collectionId, userId },
      include: { items: { select: { id: true } } },
    });
    return collection ? this.toRecord(collection) : null;
  }

  async findById(collectionId: string): Promise<CollectionRecord | null> {
    const collection = await this.prisma.collection.findFirst({
      where: { id: collectionId },
      include: { items: { select: { id: true } } },
    });
    return collection ? this.toRecord(collection) : null;
  }

  async update(collectionId: string, data: CollectionUpdateInput): Promise<CollectionRecord> {
    const updateData: Record<string, unknown> = {};
    if (data.title !== undefined) updateData.title = data.title;
    if (data.description !== undefined) updateData.description = data.description;
    if (data.coverUrl !== undefined) updateData.coverUrl = data.coverUrl;
    if (data.isPublic !== undefined) updateData.isPublic = data.isPublic;

    const collection = await this.prisma.collection.update({
      where: { id: collectionId },
      data: updateData,
      include: { items: { select: { id: true } } },
    });
    return this.toRecord(collection);
  }

  async delete(collectionId: string): Promise<void> {
    await this.prisma.collection.delete({ where: { id: collectionId } });
  }

  async findManga(mangaId: string): Promise<{ id: string; coverUrl: string | null } | null> {
    return this.prisma.mangaSeries.findUnique({
      where: { id: mangaId },
      select: { id: true, coverUrl: true },
    });
  }

  async countItems(collectionId: string): Promise<number> {
    return this.prisma.collectionItem.count({ where: { collectionId } });
  }

  async addItem(collectionId: string, mangaId: string): Promise<void> {
    await this.prisma.collectionItem.upsert({
      where: { collectionId_mangaId: { collectionId, mangaId } },
      update: {},
      create: { collectionId, mangaId },
    });
  }

  async removeItem(collectionId: string, mangaId: string): Promise<void> {
    await this.prisma.collectionItem.delete({
      where: { collectionId_mangaId: { collectionId, mangaId } },
    });
  }

  async findMany(query: CollectionQuery): Promise<[CollectionRecord[], number]> {
    const where: Record<string, unknown> = {};
    if (query.userId) {
      where.userId = query.userId;
    } else {
      where.isPublic = query.isPublic ?? true;
    }

    const [collections, total] = await Promise.all([
      this.prisma.collection.findMany({
        where,
        skip: query.skip,
        take: query.limit,
        orderBy: { likesCount: 'desc' },
        include: {
          user: {
            select: { id: true, username: true, displayName: true, avatarUrl: true },
          },
          items: { select: { id: true } },
        },
      }),
      this.prisma.collection.count({ where }),
    ]);

    return [
      collections.map((c: any) => this.toRecord(c)),
      total,
    ];
  }

  async findWithItems(collectionId: string): Promise<CollectionWithItems | null> {
    const collection = await this.prisma.collection.findUnique({
      where: { id: collectionId },
      include: {
        user: {
          select: { id: true, username: true, displayName: true, avatarUrl: true },
        },
        items: {
          include: { manga: true },
        },
      },
    }) as any;

    if (!collection) return null;

    return {
      ...this.toRecord(collection),
      items: collection.items.map((item: PrismaCollectionItem) => ({
        id: item.id,
        mangaId: item.manga.id,
        title: item.manga.title,
        coverUrl: item.manga.coverUrl,
        slug: item.manga.slug,
        authorName: item.manga.authorName,
      })),
    };
  }

  async updateCover(collectionId: string, coverUrl: string): Promise<void> {
    await this.prisma.collection.update({
      where: { id: collectionId },
      data: { coverUrl },
    });
  }

  async getLikesCount(collectionId: string): Promise<number> {
    const collection = await this.prisma.collection.findUnique({
      where: { id: collectionId },
      select: { likesCount: true },
    });
    return collection?.likesCount ?? 0;
  }

  async updateLikesCount(collectionId: string, count: number): Promise<void> {
    await this.prisma.collection.update({
      where: { id: collectionId },
      data: { likesCount: count },
    });
  }

  async findCollaborators(collectionId: string): Promise<Array<{ id: string; userId: string; role: string; addedAt: Date; user: { id: string; username: string; displayName: string | null; avatarUrl: string | null } }>> {
    return this.prisma.collectionCollaborator.findMany({
      where: { collectionId },
      include: {
        user: {
          select: { id: true, username: true, displayName: true, avatarUrl: true },
        },
      },
      orderBy: { addedAt: 'asc' },
    });
  }

  async addCollaborator(collectionId: string, userId: string, role: string, addedById: string): Promise<void> {
    await this.prisma.collectionCollaborator.create({
      data: { collectionId, userId, role, addedById },
    });
  }

  async removeCollaborator(collectionId: string, userId: string): Promise<void> {
    await this.prisma.collectionCollaborator.delete({
      where: { collectionId_userId: { collectionId, userId } },
    });
  }

  async isCollaborator(collectionId: string, userId: string): Promise<boolean> {
    const count = await this.prisma.collectionCollaborator.count({
      where: { collectionId, userId },
    });
    return count > 0;
  }

  async findByCollaborator(collectionId: string, userId: string): Promise<{ id: string; role: string } | null> {
    const collaborator = await this.prisma.collectionCollaborator.findUnique({
      where: { collectionId_userId: { collectionId, userId } },
      select: { id: true, role: true },
    });
    return collaborator;
  }

  async logSecurityEvent(userId: string, action: string, targetId: string, severity: string): Promise<void> {
    await logSecurityEvent({ userId, action: action as SecurityAction, targetId, severity: severity as Severity });
  }

  private toRecord(data: any): CollectionRecord {
    return {
      id: data.id,
      userId: data.userId,
      title: data.title,
      description: data.description,
      coverUrl: data.coverUrl,
      isPublic: data.isPublic,
      likesCount: data.likesCount ?? 0,
      itemCount: data.items?.length ?? 0,
      createdAt: data.createdAt,
      updatedAt: data.updatedAt,
      user: data.user,
    };
  }
}

import type {
  INotificationRepository,
  IRealtimeNotificationService,
  IPushNotificationService,
  NotificationRecord,
  CreateNotificationData,
} from '@/core/services/INotificationRepository';
import { prisma } from '@/lib/prisma';
import { sendPushNotification } from '@/lib/push-notifications';
import { emitNotification } from '@/lib/socket';

export class PrismaNotificationRepository implements INotificationRepository {
  async create(data: CreateNotificationData): Promise<NotificationRecord> {
    const notification = await prisma.notification.create({
      data: {
        userId: data.userId,
        type: data.type,
        title: data.title,
        message: data.message,
        data: data.data ? JSON.stringify(data.data) : null,
        linkUrl: data.linkUrl ?? null,
      },
    });
    return notification as unknown as NotificationRecord;
  }

  async findById(id: string): Promise<NotificationRecord | null> {
    try {
      const notification = await prisma.notification.findUnique({ where: { id } });
      return notification as unknown as NotificationRecord | null;
    } catch {
      return null;
    }
  }

  async findByUserId(
    userId: string,
    options?: { limit?: number; offset?: number }
  ): Promise<NotificationRecord[]> {
    const notifications = await prisma.notification.findMany({
      where: { userId },
      orderBy: { createdAt: 'desc' },
      take: options?.limit ?? 20,
      skip: options?.offset ?? 0,
    });
    return notifications as unknown as NotificationRecord[];
  }

  async findUnreadByUserId(userId: string, limit: number = 50): Promise<NotificationRecord[]> {
    const notifications = await prisma.notification.findMany({
      where: { userId, isRead: false },
      orderBy: { createdAt: 'desc' },
      take: limit,
    });
    return notifications as unknown as NotificationRecord[];
  }

  async getUnreadCount(userId: string): Promise<number> {
    return prisma.notification.count({
      where: { userId, isRead: false },
    });
  }

  async markAsRead(id: string): Promise<NotificationRecord | null> {
    try {
      const notification = await prisma.notification.update({
        where: { id },
        data: { isRead: true },
      });
      return notification as unknown as NotificationRecord;
    } catch (error) {
      console.error('[PrismaNotificationRepository] Error marking as read:', error);
      return null;
    }
  }

  async markAllAsRead(userId: string): Promise<number> {
    const result = await prisma.notification.updateMany({
      where: { userId, isRead: false },
      data: { isRead: true },
    });
    return result.count;
  }

  async delete(id: string, userId?: string): Promise<boolean> {
    try {
      if (userId) {
        const notification = await prisma.notification.findFirst({
          where: { id, userId },
        });
        if (!notification) return false;
      }
      await prisma.notification.delete({ where: { id } });
      return true;
    } catch (error) {
      console.error('[PrismaNotificationRepository] Error deleting notification:', error);
      return false;
    }
  }

  async cleanupOld(days: number = 30): Promise<number> {
    const cutoffDate = new Date();
    cutoffDate.setDate(cutoffDate.getDate() - days);

    const result = await prisma.notification.deleteMany({
      where: {
        createdAt: { lt: cutoffDate },
        isRead: true,
      },
    });

    console.info(`[PrismaNotificationRepository] Cleaned up ${result.count} old notifications`);
    return result.count;
  }

  async getStats(userId: string): Promise<{ total: number; unread: number; byType: Record<string, number> }> {
    const [total, unread, byType] = await Promise.all([
      prisma.notification.count({ where: { userId } }),
      prisma.notification.count({ where: { userId, isRead: false } }),
      prisma.notification.groupBy({
        by: ['type'],
        where: { userId },
        _count: { type: true },
      }),
    ]);

    const byTypeMap = byType.reduce((acc: Record<string, number>, curr: any) => {
      acc[curr.type] = curr._count.type;
      return acc;
    }, {} as Record<string, number>);

    return { total, unread, byType: byTypeMap };
  }

  async createMany(data: CreateNotificationData[]): Promise<NotificationRecord[]> {
    const batchSize = 50;
    const results: NotificationRecord[] = [];

    for (let i = 0; i < data.length; i += batchSize) {
      const batch = data.slice(i, i + batchSize);
      const promises = batch.map(d => this.create(d));
      const batchResults = await Promise.all(promises);
      results.push(...batchResults);
    }

    return results;
  }
}

export class PushNotificationAdapter implements IPushNotificationService {
  private readonly pushEnabled: boolean;

  constructor() {
    this.pushEnabled = process.env.ENABLE_PUSH_NOTIFICATIONS !== 'false';
  }

  async sendToUser(userId: string, data: { title: string; body: string; icon?: string; url?: string; tag?: string }): Promise<void> {
    if (!this.pushEnabled) return;

    await sendPushNotification(userId, {
      title: data.title,
      body: data.body,
      icon: data.icon,
      url: data.url || '/',
      tag: data.tag || 'default',
    }).catch(() => {});
  }
}

export class RealtimeNotificationAdapter implements IRealtimeNotificationService {
  emitToUser(userId: string, notification: Record<string, unknown>): void {
    try {
      emitNotification(userId, notification);
    } catch (error) {
      console.info('[RealtimeNotificationAdapter] Socket emit failed (may be server-side)');
    }
  }
}

