    return user?.inkcoinsBalance || 0;
  }

  async sendTipTransaction(params: SendTipTransactionParams): Promise<{ tip: TipRecord; newSenderBalance: number }> {
    const { chapterId, fromUserId, toUserId, amount, message, authorName, chapterNumber } = params;

    const result = await prisma.$transaction(async (tx) => {
      const senderUpdated = await tx.user.update({
        where: { id: fromUserId },
        data: { inkcoinsBalance: { decrement: amount } },
        select: { inkcoinsBalance: true },
      });

      await tx.user.update({
        where: { id: toUserId },
        data: { inkcoinsBalance: { increment: amount } },
      });

      const tip = await tx.tip.create({
        data: {
          chapterId,
          fromUserId,
          toUserId,
          amount,
          message: message || null,
        },
      });

      await tx.transaction.create({
        data: {
          userId: fromUserId,
          amount: -amount,
          type: 'TIP_SENT',
          referenceId: tip.id,
          description: `Propina enviada a ${authorName}`,
        },
      });

      await tx.transaction.create({
        data: {
          userId: toUserId,
          amount: amount,
          type: 'TIP_RECEIVED',
          referenceId: tip.id,
          description: `Propina recibida de capítulo ${chapterNumber}`,
        },
      });

      return { tip, balance: senderUpdated.inkcoinsBalance };
    });

    return { tip: this.toTipRecord(result.tip), newSenderBalance: result.balance };
  }

  async contributeTransaction(params: ContributeTransactionParams): Promise<{ contribution: CrowdfundingContributionRecord; newCrowdfundingCurrent: number }> {
    const { chapterId, userId, amount, isAnonymous, message, chapterNumber } = params;

    const result = await prisma.$transaction(async (tx) => {
      const existingContribution = await tx.crowdfundingContribution.findUnique({
        where: {
          chapterId_userId: { chapterId, userId },
        },
      });

      let contribution: any;

      if (existingContribution) {
        contribution = await tx.crowdfundingContribution.update({
          where: { id: existingContribution.id },
          data: {
            amount: { increment: amount },
            message: message || existingContribution.message,
            isAnonymous,
          },
        });
      } else {
        contribution = await tx.crowdfundingContribution.create({
          data: {
            chapterId,
            userId,
            amount,
            isAnonymous,
            message: message || null,
          },
        });
      }

      await tx.user.update({
        where: { id: userId },
        data: { inkcoinsBalance: { decrement: amount } },
      });

      const updated = await tx.chapter.update({
        where: { id: chapterId },
        data: { crowdfundingCurrent: { increment: amount } },
      });

      await tx.transaction.create({
        data: {
          userId,
          amount: -amount,
          type: 'CROWDFUNDING_CONTRIBUTION',
          referenceId: chapterId,
          description: `Contribución a crowdfunding - Capítulo ${chapterNumber}`,
        },
      });

      return { contribution, updated };
    });

    return { contribution: this.toCrowdfundingContributionRecord(result.contribution), newCrowdfundingCurrent: result.updated.crowdfundingCurrent };
  }

  async getChapterTips(chapterId: string): Promise<TipWithRelationsRecord[]> {
    const tips = await prisma.tip.findMany({
      where: { chapterId },
      orderBy: { createdAt: 'desc' },
      include: {
        chapter: {
          select: { id: true, chapterNumber: true, title: true },
        },
        fromUser: {
          select: { id: true, username: true, avatarUrl: true },
        },
        toUser: {
          select: { id: true, username: true, avatarUrl: true },
        },
      },
    });

    return tips as unknown as TipWithRelationsRecord[];
  }

  async getUserTipsReceived(userId: string, limit: number): Promise<TipWithRelationsRecord[]> {
    const tips = await prisma.tip.findMany({
      where: { toUserId: userId },
      orderBy: { createdAt: 'desc' },
      take: limit,
      include: {
        chapter: {
          select: { id: true, chapterNumber: true, title: true },
        },
        fromUser: {
          select: { id: true, username: true, avatarUrl: true },
        },
        toUser: {
          select: { id: true, username: true, avatarUrl: true },
        },
      },
    });

    return tips as unknown as TipWithRelationsRecord[];
  }

  async getUserTipsGiven(userId: string, limit: number): Promise<TipWithRelationsRecord[]> {
    const tips = await prisma.tip.findMany({
      where: { fromUserId: userId },
      orderBy: { createdAt: 'desc' },
      take: limit,
      include: {
        chapter: {
          select: { id: true, chapterNumber: true, title: true },
        },
        fromUser: {
          select: { id: true, username: true, avatarUrl: true },
        },
        toUser: {
          select: { id: true, username: true, avatarUrl: true },
        },
      },
    });

    return tips as unknown as TipWithRelationsRecord[];
  }

  async getTotalTipsReceived(userId: string): Promise<number> {
    const result = await prisma.tip.aggregate({
      where: { toUserId: userId },
      _sum: { amount: true },
    });

    return result._sum.amount || 0;
  }

  async getChapterCrowdfunding(chapterId: string): Promise<{ crowdfundingGoal: number | null; crowdfundingCurrent: number } | null> {
    const chapter = await prisma.chapter.findUnique({
      where: { id: chapterId },
      select: {
        crowdfundingGoal: true,
        crowdfundingCurrent: true,
      },
    });

    return chapter;
  }

  async countChapterContributors(chapterId: string): Promise<number> {
    return prisma.crowdfundingContribution.count({
      where: { chapterId },
    });
  }

  async getChapterContributors(chapterId: string): Promise<ContributionWithRelationsRecord[]> {
    const contributions = await prisma.crowdfundingContribution.findMany({
      where: { chapterId },
      orderBy: { amount: 'desc' },
      include: {
        user: {
          select: { id: true, username: true, avatarUrl: true },
        },
      },
    });

    return contributions.map((c: any) => ({
      ...c,
      user: c.isAnonymous ? null : c.user,
    })) as ContributionWithRelationsRecord[];
  }

  async getUserContribution(chapterId: string, userId: string): Promise<CrowdfundingContributionRecord | null> {
    const contribution = await prisma.crowdfundingContribution.findUnique({
      where: {
        chapterId_userId: { chapterId, userId },
      },
    });

    if (!contribution) return null;
    return this.toCrowdfundingContributionRecord(contribution);
  }

  async getUserTipStats(userId: string): Promise<UserTipStats> {
    const [givenStats, receivedStats] = await Promise.all([
      prisma.tip.aggregate({
        where: { fromUserId: userId },
        _sum: { amount: true },
        _count: true,
      }),
      prisma.tip.aggregate({
        where: { toUserId: userId },
        _sum: { amount: true },
        _count: true,
      }),
    ]);

    return {
      totalGiven: givenStats._sum.amount || 0,
      totalReceived: receivedStats._sum.amount || 0,
      countGiven: givenStats._count || 0,
      countReceived: receivedStats._count || 0,
    };
  }

  async getUserCrowdfundingStats(userId: string): Promise<UserCrowdfundingStats> {
    const chapters = await prisma.chapter.findMany({
      where: {
        manga: { authorId: userId },
        crowdfundingGoal: { not: null },
      },
      include: {
        crowdfundingContributions: true,
      },
    });

    let totalRaised = 0;
    let activeCampaigns = 0;
    let completedCampaigns = 0;

    const uniqueContributors = new Set<string>();

    for (const chapter of chapters) {
      totalRaised += chapter.crowdfundingCurrent;

      for (const contribution of chapter.crowdfundingContributions) {
        uniqueContributors.add(contribution.userId);
      }

      if (chapter.crowdfundingCurrent >= (chapter.crowdfundingGoal || 0)) {
        completedCampaigns++;
      } else {
        activeCampaigns++;
      }
    }

    return {
      totalRaised,
      totalContributors: uniqueContributors.size,
      activeCampaigns,
      completedCampaigns,
    };
  }

  private toTipRecord(data: any): TipRecord {
    return {
      id: data.id,
      chapterId: data.chapterId,
      fromUserId: data.fromUserId,
      toUserId: data.toUserId,
      amount: data.amount,
      message: data.message,
      createdAt: data.createdAt,
    };
  }

  private toCrowdfundingContributionRecord(data: any): CrowdfundingContributionRecord {
    return {
      id: data.id,
      chapterId: data.chapterId,
      userId: data.userId,
      amount: data.amount,
      isAnonymous: data.isAnonymous,
      message: data.message,
      createdAt: data.createdAt,
    };
  }
}

/**
 * AlertManager - Sistema de alertas para el servicio de IA
 *
 * Gestiona alertas cuando modelos fallan o se degradan.
 * Usa EventEmitter para notificar cambios de estado.
 */

import { EventEmitter } from 'events';

// =============================================================================
// TYPES & INTERFACES
// =============================================================================

export type AlertType =
  | 'model_degraded'
  | 'model_unhealthy'
  | 'high_error_rate'
  | 'queue_backlog';

export type AlertSeverity = 'warning' | 'critical' | 'info';

export interface Alert {
  id: string;
  type: AlertType;
  severity: AlertSeverity;
  title: string;
  message: string;
  metadata?: Record<string, unknown>;
  createdAt: Date;
  acknowledged: boolean;
  dismissed: boolean;
}

export interface AlertThresholds {
  /** Umbral para marcar un modelo como degradado (fallos consecutivos) */
  degradedThreshold: number;
  /** Umbral para marcar un modelo como no saludable (fallos consecutivos) */
  unhealthyThreshold: number;
  /** Umbral de tasa de error (0-1, ej: 0.05 = 5%) */
  errorRateThreshold: number;
  /** Umbral de profundidad de cola para alerta de backlog */
  queueBacklogThreshold: number;
  /** Tiempo de vida de una alerta antes de auto-limpiarse (ms) */
  alertTTLMs: number;
}

export interface AlertConfig {
  thresholds?: Partial<AlertThresholds>;
  /** Habilitar auto-limpieza de alertas antiguas */
  enableAutoCleanup?: boolean;
  /** Intervalo de limpieza en ms */
  cleanupIntervalMs?: number;
}

export type AlertListener = (alert: Alert) => void;

// =============================================================================
// DEFAULT CONFIGURATION
// =============================================================================

const DEFAULT_THRESHOLDS: AlertThresholds = {
  degradedThreshold: 2,
  unhealthyThreshold: 5,
  errorRateThreshold: 0.05, // 5%
  queueBacklogThreshold: 100,
  alertTTLMs: 3600000, // 1 hora
};

// =============================================================================
// ALERT MANAGER CLASS
// =============================================================================

export class AlertManager extends EventEmitter {
  private alerts: Map<string, Alert> = new Map();
  private thresholds: AlertThresholds;
  private enableAutoCleanup: boolean;
  private cleanupInterval?: NodeJS.Timeout;

  constructor(config: AlertConfig = {}) {
    super();
    this.setMaxListeners(100);

    this.thresholds = {
      ...DEFAULT_THRESHOLDS,
      ...config.thresholds,
    };
    this.enableAutoCleanup = config.enableAutoCleanup ?? true;

    if (this.enableAutoCleanup) {
      this.startCleanupTimer(config.cleanupIntervalMs ?? 60000);
    }
  }

  // ===========================================================================
  // SUBSCRIPTION
  // ===========================================================================

  /**
   * Suscribe a nuevas alertas
   * @param listener Función callback que recibe la alerta
   * @returns Función para desuscribirse
   */
  subscribe(listener: AlertListener): () => void {
    (this as any).on('alert:new', listener);
    return () => {
      (this as any).off('alert:new', listener);
    };
  }

  /**
   * Suscribe a todos los cambios de alertas (nueva, actualizada, eliminada)
   * @param listener Función callback
   * @returns Función para desuscribirse
   */
  subscribeToAll(listener: (event: string, alert: Alert) => void): () => void {
    const newHandler = (alert: Alert) => listener('new', alert);
    const updatedHandler = (alert: Alert) => listener('updated', alert);
    const clearedHandler = (alert: Alert) => listener('cleared', alert);

    (this as any).on('alert:new', newHandler);
    (this as any).on('alert:updated', updatedHandler);
    (this as any).on('alert:cleared', clearedHandler);
    return () => {
      (this as any).off('alert:new', newHandler);
      (this as any).off('alert:updated', updatedHandler);
      (this as any).off('alert:cleared', clearedHandler);
    };
  }

  // ===========================================================================
  // NOTIFICATION
  // ===========================================================================

  /**
   * Crea y emite una nueva alerta
   */
  notify(
    type: AlertType,
    severity: AlertSeverity,
    title: string,
    message: string,
    metadata?: Record<string, unknown>
  ): Alert {
    // Verificar si ya existe una alerta similar activa
    const existingAlert = this.findExistingAlert(type, metadata);

    if (existingAlert) {
      // Actualizar alerta existente
      const updated: Alert = {
        ...existingAlert,
        message,
        metadata: { ...existingAlert.metadata, ...metadata, occurrenceCount: (existingAlert.metadata?.occurrenceCount as number ?? 1) + 1 },
        createdAt: new Date(),
      };
      this.alerts.set(updated.id, updated);
      (this as any).emit('alert:updated', updated);
      return updated;
    }

    // Crear nueva alerta
    const alert: Alert = {
      id: crypto.randomUUID(),
      type,
      severity,
      title,
      message,
      metadata,
      createdAt: new Date(),
      acknowledged: false,
      dismissed: false,
    };

    this.alerts.set(alert.id, alert);
    (this as any).emit('alert:new', alert);

    return alert;
  }

  /**
   * Notifica que un modelo ha sido degradado
   */
  notifyModelDegraded(modelId: string, modelName: string, reason?: string): Alert {
    return this.notify(
      'model_degraded',
      'warning',
      'Modelo Degradado',
      `El modelo "${modelName}" (${modelId}) ha sido marcado como degradado${reason ? `: ${reason}` : ''}`,
      { modelId, modelName, reason }
    );
  }

  /**
   * Notifica que un modelo no está saludable
   */
  notifyModelUnhealthy(modelId: string, modelName: string, consecutiveFailures: number): Alert {
    return this.notify(
      'model_unhealthy',
      'critical',
      'Modelo No Saludable',
      `El modelo "${modelName}" (${modelId}) ha sido marcado como no saludable tras ${consecutiveFailures} fallos consecutivos`,
      { modelId, modelName, consecutiveFailures }
    );
  }

  /**
   * Notifica tasa de error alta
   */
  notifyHighErrorRate(errorRate: number, threshold: number): Alert {
    return this.notify(
      'high_error_rate',
      errorRate > threshold * 2 ? 'critical' : 'warning',
      'Tasa de Error Alta',
      `La tasa de error actual es del ${(errorRate * 100).toFixed(1)}%, superando el umbral del ${(threshold * 100).toFixed(1)}%`,
      { errorRate, threshold, errorPercentage: errorRate * 100 }
    );
  }

  /**
   * Notifica backlog en la cola
   */
  notifyQueueBacklog(queueDepth: number, threshold: number): Alert {
    return this.notify(
      'queue_backlog',
      queueDepth > threshold * 2 ? 'critical' : 'warning',
      'Backlog en Cola',
      `La cola tiene ${queueDepth} trabajos pendientes, superando el umbral de ${threshold}`,
      { queueDepth, threshold }
    );
  }

  // ===========================================================================
  // ALERT MANAGEMENT
  // ===========================================================================

  /**
   * Marca una alerta como reconocida
   */
  acknowledgeAlert(alertId: string): boolean {
    const alert = this.alerts.get(alertId);
    if (!alert) return false;

    alert.acknowledged = true;
    this.alerts.set(alertId, alert);
    (this as any).emit('alert:updated', alert);
    return true;
  }

  /** 
   * Descarta/dismiss una alerta
   */
  dismissAlert(alertId: string): boolean {
    const alert = this.alerts.get(alertId);
    if (!alert) return false;

    alert.dismissed = true;
    this.alerts.set(alertId, alert);
    (this as any).emit('alert:updated', alert);
    return true;
  }

  /**
   * Elimina una alerta permanentemente
   */
  clearAlert(alertId: string): boolean {
    const alert = this.alerts.get(alertId);
    if (!alert) return false;

    this.alerts.delete(alertId);
    (this as any).emit('alert:cleared', alert);
    return true;
  }

  /**
   * Limpia todas las alertas descartadas o antiguas
   */
  clearResolvedAlerts(): number {
    const now = Date.now();
    const toDelete: string[] = [];

    for (const [id, alert] of this.alerts) {
      if (alert.dismissed) {
        toDelete.push(id);
      } else if (now - alert.createdAt.getTime() > this.thresholds.alertTTLMs) {
        toDelete.push(id);
      }
    }

    toDelete.forEach((id) => {
      const alert = this.alerts.get(id);
      if (alert) {
      this.alerts.delete(id);
      (this as any).emit('alert:cleared', alert);
    }
  });

  return toDelete.length;
}

  /**
   * Limpia alertas por tipo
   */
  clearAlertsByType(type: AlertType): number {
    const toDelete: string[] = [];

    for (const [id, alert] of this.alerts) {
      if (alert.type === type) {
        toDelete.push(id);
      }
    }

    toDelete.forEach((id) => {
      const alert = this.alerts.get(id);
      if (alert) {
        this.alerts.delete(id);
        (this as any).emit('alert:cleared', alert);
      }
    });

    return toDelete.length;
  }

  /**
   * Elimina todas las alertas
   */
  clearAllAlerts(): void {
    const allAlerts = Array.from(this.alerts.values());
    this.alerts.clear();
    allAlerts.forEach((alert) => (this as any).emit('alert:cleared', alert));
  }

  // ===========================================================================
  // QUERIES
  // ===========================================================================

  /**
   * Obtiene todas las alertas activas
   */
  getActiveAlerts(): Alert[] {
    return Array.from(this.alerts.values())
      .filter((alert) => !alert.dismissed)
      .sort((a, b) => {
        // Ordenar por severidad (critical primero) y luego por fecha
        const severityOrder = { critical: 0, warning: 1, info: 2 };
        if (severityOrder[a.severity] !== severityOrder[b.severity]) {
          return severityOrder[a.severity] - severityOrder[b.severity];
        }
        return b.createdAt.getTime() - a.createdAt.getTime();
      });
  }

  /**
   * Obtiene alertas por tipo
   */
  getAlertsByType(type: AlertType): Alert[] {
    return this.getActiveAlerts().filter((alert) => alert.type === type);
  }

  /**
   * Obtiene alertas por severidad
   */
  getAlertsBySeverity(severity: AlertSeverity): Alert[] {
    return this.getActiveAlerts().filter((alert) => alert.severity === severity);
  }

  /**
   * Obtiene una alerta por ID
   */
  getAlert(alertId: string): Alert | undefined {
    return this.alerts.get(alertId);
  }

  /**
   * Verifica si hay alertas críticas activas
   */
  hasCriticalAlerts(): boolean {
    return this.getActiveAlerts().some((alert) => alert.severity === 'critical');
  }

  /**
   * Obtiene el número total de alertas activas
   */
  getActiveAlertCount(): number {
    return this.getActiveAlerts().length;
  }

  // ===========================================================================
  // CONFIGURATION
  // ===========================================================================

  /**
   * Actualiza los umbrales de alerta
   */
  updateThresholds(thresholds: Partial<AlertThresholds>): void {
    this.thresholds = { ...this.thresholds, ...thresholds };
    (this as any).emit('config:updated', { thresholds: this.thresholds });
  }

  /**
   * Obtiene los umbrales actuales
   */
  getThresholds(): AlertThresholds {
    return { ...this.thresholds };
  }

  // ===========================================================================
  // PRIVATE METHODS
  // ===========================================================================

  private findExistingAlert(
    type: AlertType,
    metadata?: Record<string, unknown>
  ): Alert | undefined {
    for (const alert of this.alerts.values()) {
      if (alert.type === type && !alert.dismissed) {
        // Para alertas de modelo, verificar si es el mismo modelo
        if (metadata?.modelId && alert.metadata?.modelId === metadata.modelId) {
          return alert;
        }
        // Para alertas de sistema, verificar si ya existe una similar
        if (
          type === 'high_error_rate' ||
          type === 'queue_backlog'
        ) {
          return alert;
        }
      }
    }
    return undefined;
  }

  private startCleanupTimer(intervalMs: number): void {
    this.cleanupInterval = setInterval(() => {
      this.clearResolvedAlerts();
    }, intervalMs);
  }

  // ===========================================================================
  // LIFECYCLE
  // ===========================================================================

  dispose(): void {
    if (this.cleanupInterval) {
      clearInterval(this.cleanupInterval);
    }
    this.removeAllListeners();
    this.alerts.clear();
  }
}

// =============================================================================
// SINGLETON INSTANCE
// =============================================================================

let globalAlertManager: AlertManager | null = null;

export function getAlertManager(config?: AlertConfig): AlertManager {
  if (!globalAlertManager) {
    globalAlertManager = new AlertManager(config);
  }
  return globalAlertManager;
}

export function resetAlertManager(): void {
  globalAlertManager?.dispose();
  globalAlertManager = null;
}

export default AlertManager;

/**
 * ModelRegistry - Sistema de registro y enrutamiento de modelos de IA
 *
 * Este módulo proporciona un registro centralizado para modelos de IA,
 * con capacidades de health checking y estrategias de enrutamiento.
 */

import { EventEmitter } from 'events';

// =============================================================================
// TYPES & INTERFACES
// =============================================================================

/**
 * Capacidades soportadas por los modelos
 */
export type ModelCapability =
  | 'chat'
  | 'embedding'
  | 'classification'
  | 'summarization'
  | 'image-generation';

/**
 * Estado de salud de un modelo
 */
export type ModelHealthStatus = 'healthy' | 'degraded' | 'unhealthy' | 'unknown';

/**
 * Configuración del modelo
 */
export interface ModelConfig {
  /** URL base del endpoint del modelo */
  baseUrl?: string;
  /** API Key (encriptada) */
  apiKey?: string;
  /** Límite de requests por minuto */
  maxRequestsPerMinute?: number;
  /** Máximo de tokens de contexto */
  contextWindow?: number;
  /** Temperatura por defecto */
  defaultTemperature?: number;
  /** Timeout en ms */
  timeoutMs?: number;
  /** Peso para estrategias ponderadas (mayor = más probabilidad de selección) */
  weight?: number;
  /** Metadata adicional */
  metadata?: Record<string, unknown>;
}

/**
 * Modelo registrado en el sistema
 */
export interface RegisteredModel {
  /** ID único del modelo (ej: 'nvidia/llama-3.1-nemotron-70b') */
  id: string;
  /** Nombre legible del modelo */
  name: string;
  /** Proveedor del servicio (ej: 'nvidia', 'openai', 'anthropic') */
  provider: string;
  /** Capacidades que soporta este modelo */
  capabilities: ModelCapability[];
  /** Configuración específica del modelo */
  config: ModelConfig;
  /** Estado actual del modelo */
  status: {
    health: ModelHealthStatus;
    /** Última latencia medida en ms */
    lastLatencyMs?: number;
    /** Timestamp del último health check */
    lastHealthCheck?: Date;
    /** Número de requests fallidos consecutivos */
    consecutiveFailures: number;
    /** Número total de requests exitosos */
    totalSuccessfulRequests: number;
    /** Número total de requests fallidos */
    totalFailedRequests: number;
  };
  /** Timestamp de registro */
  registeredAt: Date;
}

/**
 * Estrategias de enrutamiento disponibles
 */
export type RoutingStrategy =
  | 'round-robin'
  | 'least-latency'
  | 'capability-match'
  | 'fallback-chain'
  | 'weighted-random';

/**
 * Estrategia de enrutamiento de modelos
 */
export interface ModelRoutingStrategy {
  /** Nombre de la estrategia */
  readonly name: RoutingStrategy;
  /** Selecciona un modelo basado en la estrategia */
  select(
    models: RegisteredModel[],
    requirements: ModelCapability[]
  ): RegisteredModel | null;
}

/**
 * Métricas de enrutamiento para un modelo específico
 */
export interface ModelRoutingMetrics {
  modelId: string;
  modelName: string;
  provider: string;
  /** Total de requests procesados */
  totalRequests: number;
  /** Requests exitosos */
  successfulRequests: number;
  /** Requests fallidos */
  failedRequests: number;
  /** Tasa de éxito (0-1) */
  successRate: number;
  /** Latencia promedio en ms */
  averageLatencyMs: number;
  /** Latencia del último request en ms */
  lastLatencyMs?: number;
  /** Estado de salud actual */
  healthStatus: ModelHealthStatus;
}

/**
 * Métricas globales del sistema de enrutamiento
 */
export interface RoutingMetrics {
  /** Métricas por modelo */
  models: ModelRoutingMetrics[];
  /** Total de modelos registrados */
  totalRegisteredModels: number;
  /** Modelos saludables */
  healthyModelsCount: number;
  /** Estrategia de enrutamiento actual */
  currentStrategy: RoutingStrategy;
  /** Timestamp de la última actualización de métricas */
  lastUpdated: Date;
}

// =============================================================================
// IMPLEMENTACIONES DE ESTRATEGIAS
// =============================================================================

class RoundRobinStrategy implements ModelRoutingStrategy {
  readonly name: RoutingStrategy = 'round-robin';
  private currentIndex = 0;

  select(
    models: RegisteredModel[],
    requirements: ModelCapability[]
  ): RegisteredModel | null {
    if (models.length === 0) return null;

    const eligibleModels = this.filterEligible(models, requirements);
    if (eligibleModels.length === 0) return null;

    const selected = eligibleModels[this.currentIndex % eligibleModels.length];
    this.currentIndex = (this.currentIndex + 1) % eligibleModels.length;

    return selected;
  }

  private filterEligible(
    models: RegisteredModel[],
    requirements: ModelCapability[]
  ): RegisteredModel[] {
    return models.filter(
      (m) =>
        m.status.health === 'healthy' &&
        requirements.every((req) => m.capabilities.includes(req))
    );
  }
}

class LeastLatencyStrategy implements ModelRoutingStrategy {
  readonly name: RoutingStrategy = 'least-latency';

  select(
    models: RegisteredModel[],
    requirements: ModelCapability[]
  ): RegisteredModel | null {
    const eligibleModels = models.filter(
      (m) =>
        m.status.health === 'healthy' &&
        requirements.every((req) => m.capabilities.includes(req)) &&
        m.status.lastLatencyMs !== undefined
    );

    if (eligibleModels.length === 0) return null;

    // Ordenar por latencia (menor primero)
    eligibleModels.sort((a, b) => {
      const latencyA = a.status.lastLatencyMs ?? Infinity;
      const latencyB = b.status.lastLatencyMs ?? Infinity;
      return latencyA - latencyB;
    });

    return eligibleModels[0];
  }
}

class CapabilityMatchStrategy implements ModelRoutingStrategy {
  readonly name: RoutingStrategy = 'capability-match';

  select(
    models: RegisteredModel[],
    requirements: ModelCapability[]
  ): RegisteredModel | null {
    if (requirements.length === 0) return null;

    // Buscar modelos que tengan TODAS las capacidades requeridas
    const eligibleModels = models.filter(
      (m) =>
        m.status.health === 'healthy' &&
        requirements.every((req) => m.capabilities.includes(req))
    );

    if (eligibleModels.length === 0) return null;

    // Priorizar modelos con menos capacidades extra (match más específico)
    eligibleModels.sort((a, b) => a.capabilities.length - b.capabilities.length);

    return eligibleModels[0];
  }
}

class FallbackChainStrategy implements ModelRoutingStrategy {
  readonly name: RoutingStrategy = 'fallback-chain';
  /** Lista de modelos en orden de preferencia para fallback */
  fallbackOrder: string[] = [];

  select(
    models: RegisteredModel[],
    requirements: ModelCapability[]
  ): RegisteredModel | null {
    if (this.fallbackOrder.length === 0) {
      // Si no hay orden definido, usar el primero que cumpla
      return (
        models.find(
          (m) =>
            m.status.health === 'healthy' &&
            requirements.every((req) => m.capabilities.includes(req))
        ) || null
      );
    }

    // Buscar en orden de fallback
    for (const modelId of this.fallbackOrder) {
      const model = models.find(
        (m) =>
          m.id === modelId &&
          m.status.health === 'healthy' &&
          requirements.every((req) => m.capabilities.includes(req))
      );
      if (model) return model;
    }

    return null;
  }

  /**
   * Configura el orden de fallback
   */
  setFallbackOrder(order: string[]): void {
    this.fallbackOrder = [...order];
  }
}

class WeightedRandomStrategy implements ModelRoutingStrategy {
  readonly name: RoutingStrategy = 'weighted-random';

  select(
    models: RegisteredModel[],
    requirements: ModelCapability[]
  ): RegisteredModel | null {
    const eligibleModels = models.filter(
      (m) =>
        m.status.health === 'healthy' &&
        requirements.every((req) => m.capabilities.includes(req))
    );

    if (eligibleModels.length === 0) return null;

    // Calcular pesos totales
    const totalWeight = eligibleModels.reduce(
      (sum, m) => sum + (m.config.weight || 1),
      0
    );

    // Selección ponderada aleatoria
    let random = Math.random() * totalWeight;

    for (const model of eligibleModels) {
      random -= model.config.weight || 1;
      if (random <= 0) return model;
    }

    // Fallback al último si hay errores de redondeo
    return eligibleModels[eligibleModels.length - 1];
  }
}

// =============================================================================
// REGISTRY IMPLEMENTATION
// =============================================================================

export class ModelRegistry extends EventEmitter {
  private models: Map<string, RegisteredModel> = new Map();
  private strategies: Map<RoutingStrategy, ModelRoutingStrategy> = new Map();
  private currentStrategy: RoutingStrategy = 'round-robin';

  // Instancias de estrategias
  private roundRobinStrategy = new RoundRobinStrategy();
  private leastLatencyStrategy = new LeastLatencyStrategy();
  private capabilityMatchStrategy = new CapabilityMatchStrategy();
  private fallbackChainStrategy = new FallbackChainStrategy();
  private weightedRandomStrategy = new WeightedRandomStrategy();

  constructor() {
    super();
    this.setMaxListeners(50);

    // Registrar todas las estrategias
    this.strategies.set('round-robin', this.roundRobinStrategy);
    this.strategies.set('least-latency', this.leastLatencyStrategy);
    this.strategies.set('capability-match', this.capabilityMatchStrategy);
    this.strategies.set('fallback-chain', this.fallbackChainStrategy);
    this.strategies.set('weighted-random', this.weightedRandomStrategy);
  }

  // ===========================================================================
  // MÉTODOS DE REGISTRO
  // ===========================================================================

  /**
   * Registra un nuevo modelo en el sistema
   */
  register(model: RegisteredModel): void {
    if (!model.id) {
      throw new Error('Model ID is required');
    }

    if (this.models.has(model.id)) {
      throw new Error(`Model with ID '${model.id}' is already registered`);
    }

    // Validar que tenga al menos una capacidad
    if (!model.capabilities || model.capabilities.length === 0) {
      throw new Error('Model must have at least one capability');
    }

    // Asegurar que el status esté completo
    const modelWithDefaults: RegisteredModel = {
      ...model,
      status: {
        health: model.status?.health ?? 'unknown',
        consecutiveFailures: model.status?.consecutiveFailures ?? 0,
        totalSuccessfulRequests: model.status?.totalSuccessfulRequests ?? 0,
        totalFailedRequests: model.status?.totalFailedRequests ?? 0,
        lastHealthCheck: model.status?.lastHealthCheck,
        lastLatencyMs: model.status?.lastLatencyMs,
      },
      registeredAt: model.registeredAt ?? new Date(),
    };

    this.models.set(model.id, modelWithDefaults);
  }

  /**
   * Desregistra un modelo del sistema
   */
  unregister(modelId: string): void {
    if (!this.models.has(modelId)) {
      throw new Error(`Model with ID '${modelId}' is not registered`);
    }

    this.models.delete(modelId);
  }

  // ===========================================================================
  // MÉTODOS DE CONSULTA
  // ===========================================================================

  /**
   * Obtiene un modelo por su ID
   */
  getModel(modelId: string): RegisteredModel | undefined {
    return this.models.get(modelId);
  }

  /**
   * Obtiene todos los modelos registrados
   */
  getAllModels(): RegisteredModel[] {
    return Array.from(this.models.values());
  }

  /**
   * Busca modelos que tengan todas las capacidades especificadas
   */
  findModels(capabilities: ModelCapability[]): RegisteredModel[] {
    return Array.from(this.models.values()).filter((model) =>
      capabilities.every((cap) => model.capabilities.includes(cap))
    );
  }

  /**
   * Obtiene todos los modelos saludables (health check pasado)
   */
  getHealthyModels(): RegisteredModel[] {
    return Array.from(this.models.values()).filter(
      (model) => model.status.health === 'healthy'
    );
  }

  /**
   * Obtiene modelos por proveedor
   */
  getModelsByProvider(provider: string): RegisteredModel[] {
    return Array.from(this.models.values()).filter(
      (model) => model.provider === provider
    );
  }

  // ===========================================================================
  // HEALTH CHECK & STATUS
  // ===========================================================================

  /**
   * Actualiza el estado de salud de un modelo
   */
  updateHealth(
    modelId: string,
    isHealthy: boolean,
    latencyMs?: number
  ): void {
    const model = this.models.get(modelId);
    if (!model) {
      throw new Error(`Model with ID '${modelId}' is not registered`);
    }

    const previousHealth = model.status.health;
    const now = new Date();

    // Actualizar salud
    model.status.lastHealthCheck = now;

    if (latencyMs !== undefined) {
      model.status.lastLatencyMs = latencyMs;
    }

    if (isHealthy) {
      model.status.health = 'healthy';
      model.status.consecutiveFailures = 0;
      model.status.totalSuccessfulRequests++;
    } else {
      model.status.consecutiveFailures++;
      model.status.totalFailedRequests++;

      // Degradar salud basado en fallos consecutivos
      if (model.status.consecutiveFailures >= 5) {
        model.status.health = 'unhealthy';
      } else if (model.status.consecutiveFailures >= 2) {
        model.status.health = 'degraded';
      }
    }

    // Emitir evento si el estado de salud cambió
    if (previousHealth !== model.status.health) {
      (this as any).emit('model:health-changed', {
        modelId: model.id,
        modelName: model.name,
        previousHealth,
        newHealth: model.status.health,
        consecutiveFailures: model.status.consecutiveFailures,
        timestamp: now,
      });
    }
  }

  /**
   * Marca un modelo como degradado
   */
  markDegraded(modelId: string, reason?: string): void {
    const model = this.models.get(modelId);
    if (!model) {
      throw new Error(`Model with ID '${modelId}' is not registered`);
    }

    model.status.health = 'degraded';
    model.status.lastHealthCheck = new Date();

    if (reason) {
      // Guardar el motivo en metadata si existe
      if (!model.config.metadata) {
        model.config.metadata = {};
      }
      model.config.metadata.lastDegradedReason = reason;
    }
  }

  // ===========================================================================
  // ROUTING
  // ===========================================================================

  /**
   * Selecciona un modelo basado en la estrategia de enrutamiento
   */
  selectModel(
    strategy: RoutingStrategy,
    requirements: ModelCapability[]
  ): RegisteredModel | null {
    const healthyModels = this.getHealthyModels();

    if (healthyModels.length === 0) {
      return null;
    }

    const strategyImpl = this.strategies.get(strategy);
    if (!strategyImpl) {
      throw new Error(`Unknown routing strategy: ${strategy}`);
    }

    this.currentStrategy = strategy;

    return strategyImpl.select(healthyModels, requirements);
  }

  /**
   * Configura el orden de fallback para la estrategia fallback-chain
   */
  setFallbackChain(order: string[]): void {
    this.fallbackChainStrategy.setFallbackOrder(order);
  }

  /**
   * Obtiene la estrategia de enrutamiento actual
   */
  getCurrentStrategy(): RoutingStrategy {
    return this.currentStrategy;
  }

  // ===========================================================================
  // MÉTRICAS
  // ===========================================================================

  /**
   * Obtiene métricas de uso del sistema de enrutamiento
   */
  getRoutingMetrics(): RoutingMetrics {
    const allModels = this.getAllModels();
    const healthyModels = this.getHealthyModels();

    const modelMetrics: ModelRoutingMetrics[] = allModels.map((model) => {
      const totalRequests =
        model.status.totalSuccessfulRequests + model.status.totalFailedRequests;

      const successRate =
        totalRequests > 0
          ? model.status.totalSuccessfulRequests / totalRequests
          : 0;

      // Calcular latencia promedio (simplificado, usaríamos histórico real en producción)
      const averageLatencyMs =
        model.status.lastLatencyMs ??
        (model.status.health === 'healthy' ? 100 : 500);

      return {
        modelId: model.id,
        modelName: model.name,
        provider: model.provider,
        totalRequests,
        successfulRequests: model.status.totalSuccessfulRequests,
        failedRequests: model.status.totalFailedRequests,
        successRate: Math.round(successRate * 100) / 100,
        averageLatencyMs,
        lastLatencyMs: model.status.lastLatencyMs,
        healthStatus: model.status.health,
      };
    });

    // Ordenar por tasa de éxito descendente
    modelMetrics.sort((a, b) => b.successRate - a.successRate);

    return {
      models: modelMetrics,
      totalRegisteredModels: allModels.length,
      healthyModelsCount: healthyModels.length,
      currentStrategy: this.currentStrategy,
      lastUpdated: new Date(),
    };
  }

  /**
   * Obtiene métricas de un modelo específico
   */
  getModelMetrics(modelId: string): ModelRoutingMetrics | null {
    const model = this.models.get(modelId);
    if (!model) return null;

    const totalRequests =
      model.status.totalSuccessfulRequests + model.status.totalFailedRequests;

    const successRate =
      totalRequests > 0
        ? model.status.totalSuccessfulRequests / totalRequests
        : 0;

    return {
      modelId: model.id,
      modelName: model.name,
      provider: model.provider,
      totalRequests,
      successfulRequests: model.status.totalSuccessfulRequests,
      failedRequests: model.status.totalFailedRequests,
      successRate: Math.round(successRate * 100) / 100,
      averageLatencyMs: model.status.lastLatencyMs ?? 0,
      lastLatencyMs: model.status.lastLatencyMs,
      healthStatus: model.status.health,
    };
  }

  /**
   * Reinicia las métricas de un modelo
   */
  resetModelMetrics(modelId: string): void {
    const model = this.models.get(modelId);
    if (!model) {
      throw new Error(`Model with ID '${modelId}' is not registered`);
    }

    model.status.totalSuccessfulRequests = 0;
    model.status.totalFailedRequests = 0;
    model.status.consecutiveFailures = 0;
  }

  // ===========================================================================
  // UTILIDADES
  // ===========================================================================

  /**
   * Limpia todos los modelos registrados (útil para tests)
   */
  clear(): void {
    this.models.clear();
    this.currentStrategy = 'round-robin';
    this.fallbackChainStrategy.setFallbackOrder([]);
  }

  /**
   * Verifica si un modelo existe
   */
  hasModel(modelId: string): boolean {
    return this.models.has(modelId);
  }

  /**
   * Obtiene el número total de modelos registrados
   */
  get size(): number {
    return this.models.size;
  }
}

// =============================================================================
// EXPORT DEFAULT
// =============================================================================

export default ModelRegistry;

import Bottleneck from 'bottleneck';

import {
  IAProvider,
  CommentAnalysis,
  ChapterSummary,
  AIServiceError,
  QualityAssessment,
} from '@/core/services/IAProvider';

interface NVIDIAConfig {
  apiKey: string;
  baseUrl: string;
  maxRequestsPerMinute: number;
}

export class NVIDIAProvider implements IAProvider {
  private readonly limiter: Bottleneck;
  private readonly config: NVIDIAConfig;
  private readonly cache: Map<string, unknown> = new Map();

  constructor(config: Partial<NVIDIAConfig> = {}) {
    this.config = {
      apiKey: config.apiKey || process.env.NVIDIA_API_KEY || '',
      baseUrl: config.baseUrl || 'https://integrate.api.nvidia.com/v1',
      maxRequestsPerMinute: config.maxRequestsPerMinute || 40,
    };

    if (!this.config.apiKey) {
      throw new Error('NVIDIA_API_KEY no está configurada');
    }

    // Rate limiting: 40 requests por minuto
    this.limiter = new Bottleneck({
      reservoir: this.config.maxRequestsPerMinute,
      reservoirRefreshAmount: this.config.maxRequestsPerMinute,
      reservoirRefreshInterval: 60 * 1000, // 1 minuto
      maxConcurrent: 1,
      minTime: 1500, // 1.5s entre requests (conservador)
    });

    // Eventos para monitoreo
    this.limiter.on('failed', (error, jobInfo) => {
      console.error(`Job ${jobInfo.options.id} failed:`, error);
    });
  }

  private async makeRequest<T>(
    endpoint: string,
    payload: unknown,
    cacheKey?: string
  ): Promise<T> {
    // Verificar caché
    if (cacheKey && this.cache.has(cacheKey)) {
      return this.cache.get(cacheKey) as T;
    }

    try {
      const response = await this.limiter.schedule(async () => {
        const res = await fetch(`${this.config.baseUrl}${endpoint}`, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${this.config.apiKey}`,
          },
          body: JSON.stringify(payload),
        });

        if (!res.ok) {
          const errorData = await res.json().catch(() => ({}));
          throw new AIServiceError(
            errorData.error?.message || `HTTP ${res.status}`,
            `NVIDIA_${res.status}`,
            res.status === 429
          );
        }

        return res.json();
      });

      // Guardar en caché
      if (cacheKey) {
        this.cache.set(cacheKey, response);
        // TTL de 1 hora
        setTimeout(() => this.cache.delete(cacheKey), 3600000);
      }

      return response as T;
    } catch (error) {
      if (error instanceof AIServiceError) {
        throw error;
      }
      throw new AIServiceError(
        error instanceof Error ? error.message : 'Error desconocido',
        'NVIDIA_UNKNOWN'
      );
    }
  }

  async analyzeComment(
    content: string,
    context?: string
  ): Promise<CommentAnalysis> {
    const cacheKey = `analyze:${this.hash(content)}`;

    const prompt = `Analiza el siguiente comentario y determina:
1. Probabilidad de spoiler (0-100)
2. Sentimiento (positivo/negativo/neutral)
3. Toxicidad (0-100)
4. Categorías relevantes

Comentario: """${content}"""
${context ? `Contexto del capítulo: """${context}"""` : ''}

Responde en JSON exactamente con este formato:
{
  "spoilerScore": number,
  "sentiment": "positive" | "negative" | "neutral",
  "toxicity": number,
  "categories": string[]
}`;

    try {
      const response = await this.makeRequest<{
        choices: Array<{
          message: { content: string };
        }>;
      }>(
        '/chat/completions',
        {
          model: 'nvidia/llama-3.1-nemotron-70b-instruct',
          messages: [{ role: 'user', content: prompt }],
          temperature: 0.3,
          max_tokens: 256,
          response_format: { type: 'json_object' },
        },
        cacheKey
      );

      const content = response.choices[0]?.message?.content || '{}';
      const parsed = JSON.parse(content);

      return {
        spoilerScore: Math.min(100, Math.max(0, parsed.spoilerScore || 0)),
        sentiment: ['positive', 'negative', 'neutral'].includes(parsed.sentiment)
          ? parsed.sentiment
          : 'neutral',
        toxicity: Math.min(100, Math.max(0, parsed.toxicity || 0)),
        categories: Array.isArray(parsed.categories) ? parsed.categories : [],
      };
    } catch (error) {
      console.error('Error analizando comentario:', error);
      // Fallback: análisis básico
      return this.fallbackCommentAnalysis(content);
    }
  }

  async detectSpoiler(content: string, chapterContext: string): Promise<number> {
    const analysis = await this.analyzeComment(content, chapterContext);
    return analysis.spoilerScore;
  }

  async summarizeChapter(chapterText: string): Promise<ChapterSummary> {
    const cacheKey = `summary:${this.hash(chapterText.substring(0, 500))}`;

    const prompt = `Resume el siguiente capítulo de manga y genera un titular atractivo:

Texto del capítulo: """${chapterText.substring(0, 3000)}"""

Responde en JSON exactamente con este formato:
{
  "title": "Título corto del capítulo",
  "hook": "Titular atractivo para notificación push (máx 60 caracteres)",
  "keyEvents": ["evento 1", "evento 2", "evento 3"],
  "emotionalTone": "descripción del tono emocional"
}`;

    try {
      const response = await this.makeRequest<{
        choices: Array<{
          message: { content: string };
        }>;
      }>(
        '/chat/completions',
        {
          model: 'nvidia/llama-3.1-nemotron-70b-instruct',
          messages: [{ role: 'user', content: prompt }],
          temperature: 0.7,
          max_tokens: 512,
          response_format: { type: 'json_object' },
        },
        cacheKey
      );

      const content = response.choices[0]?.message?.content || '{}';
      const parsed = JSON.parse(content);

      return {
        title: parsed.title || 'Capítulo sin título',
        hook:
          parsed.hook?.substring(0, 60) ||
          '¡Nuevo capítulo disponible!',
        keyEvents: Array.isArray(parsed.keyEvents) ? parsed.keyEvents : [],
        emotionalTone: parsed.emotionalTone || 'neutral',
      };
    } catch (error) {
      console.error('Error generando resumen:', error);
      return {
        title: 'Capítulo',
        hook: '¡Nuevo capítulo disponible!',
        keyEvents: [],
        emotionalTone: 'neutral',
      };
    }
  }

  async generateNotificationHook(chapterSummary: string): Promise<string> {
    const prompt = `Genera un titular atractivo para notificación push basado en este resumen:
"""${chapterSummary}"""

El titular debe:
- Ser emocionante y crear curiosidad
- Máximo 60 caracteres
- Sin spoilers directos
- Incluir emojis relevantes

Responde solo con el titular, sin formato JSON.`;

    try {
      const response = await this.makeRequest<{
        choices: Array<{
          message: { content: string };
        }>;
      }>('/chat/completions', {
        model: 'nvidia/llama-3.1-nemotron-70b-instruct',
        messages: [{ role: 'user', content: prompt }],
        temperature: 0.8,
        max_tokens: 100,
      });

      return (
        response.choices[0]?.message?.content?.trim().substring(0, 60) ||
        '¡Nuevo capítulo disponible!'
      );
    } catch {
      return '¡Nuevo capítulo disponible!';
    }
  }

  async generateEmbedding(text: string): Promise<number[]> {
    const cacheKey = `embedding:${this.hash(text)}`;

    try {
      const response = await this.makeRequest<{
        data: Array<{ embedding: number[] }>;
      }>(
        '/embeddings',
        {
          input: text,
          model: 'nvidia/nv-embedqa-e5-v5',
          encoding_format: 'float',
        },
        cacheKey
      );

      return response.data[0]?.embedding || [];
    } catch (error) {
      console.error('Error generando embedding:', error);
      // Fallback: embedding vacío (busqueda caerá en fallback)
      return new Array(1024).fill(0);
    }
  }

  calculateSimilarity(embedding1: number[], embedding2: number[]): number {
    if (embedding1.length !== embedding2.length) {
      return 0;
    }

    // Similitud de coseno
    let dotProduct = 0;
    let norm1 = 0;
    let norm2 = 0;

    for (let i = 0; i < embedding1.length; i++) {
      dotProduct += embedding1[i] * embedding2[i];
      norm1 += embedding1[i] * embedding1[i];
      norm2 += embedding2[i] * embedding2[i];
    }

    if (norm1 === 0 || norm2 === 0) return 0;

    return dotProduct / (Math.sqrt(norm1) * Math.sqrt(norm2));
  }

  async classifyGenre(prompt: string): Promise<string[]> {
    const genrePrompt = `Clasifica el siguiente prompt de generación de imagen en géneros de manga:

Prompt: """${prompt.substring(0, 1000)}"""

Géneros disponibles: Acción, Aventura, Comedia, Drama, Fantasía, Romance, Ciencia Ficción, Terror, Misterio, Deportes, Slice of Life, Histórico, Mecha, Isekai

Responde en JSON con array de géneros (máximo 3):
{"genres": ["género1", "género2"]}`;

    try {
      const response = await this.makeRequest<{
        choices: Array<{
          message: { content: string };
        }>;
      }>('/chat/completions', {
        model: 'nvidia/llama-3.1-nemotron-70b-instruct',
        messages: [{ role: 'user', content: genrePrompt }],
        temperature: 0.3,
        max_tokens: 128,
        response_format: { type: 'json_object' },
      });

      const content = response.choices[0]?.message?.content || '{}';
      const parsed = JSON.parse(content);

      return Array.isArray(parsed.genres) ? parsed.genres.slice(0, 3) : [];
    } catch {
      return [];
    }
  }

  async classifyQuality(imageUrl: string): Promise<QualityAssessment> {
    // Para imágenes, usamos análisis de prompt
    const prompt = `Analiza la calidad técnica de una imagen de manga generada por IA:

URL: ${imageUrl}

Responde en JSON:
{
  "score": number (0-100),
  "issues": [
    {"type": "typo|artifact|incoherence|anatomy|other", "severity": "low|medium|high|critical", "description": "...", "confidence": number}
  ],
  "overallQuality": "excellent|good|fair|poor"
}`;

    try {
      const response = await this.makeRequest<{
        choices: Array<{
          message: { content: string };
        }>;
      }>('/chat/completions', {
        model: 'nvidia/llama-3.1-nemotron-70b-instruct',
        messages: [{ role: 'user', content: prompt }],
        temperature: 0.3,
        max_tokens: 512,
        response_format: { type: 'json_object' },
      });

      const content = response.choices[0]?.message?.content || '{}';
      const parsed = JSON.parse(content);

      return {
        score: Math.min(100, Math.max(0, parsed.score || 70)),
        issues: Array.isArray(parsed.issues) ? parsed.issues : [],
        overallQuality: ['excellent', 'good', 'fair', 'poor'].includes(
          parsed.overallQuality
        )
          ? parsed.overallQuality
          : 'fair',
      };
    } catch {
      return {
        score: 70,
        issues: [],
        overallQuality: 'fair',
      };
    }
  }

  // Fallback para cuando la IA no está disponible
  private fallbackCommentAnalysis(content: string): CommentAnalysis {
    const lowerContent = content.toLowerCase();

    // Palabras que indican spoiler
    const spoilerWords = [
      'muere',
      'muerte',
      'asesin',
      'mató',
      'mata',
      'revél',
      'secreto',
      'traición',
      'traidor',
      'final',
      'último capítulo',
      'giró',
      'plot twist',
      'spoiler',
    ];

    let spoilerScore = 0;
    for (const word of spoilerWords) {
      if (lowerContent.includes(word)) {
        spoilerScore += 15;
      }
    }

    // Palabras de sentimiento
    const positiveWords = ['bueno', 'excelente', 'increíble', 'me encanta', 'genial'];
    const negativeWords = ['malo', 'horrible', 'odio', 'peor', 'basura'];

    let sentiment: 'positive' | 'negative' | 'neutral' = 'neutral';
    const hasPositive = positiveWords.some((w) => lowerContent.includes(w));
    const hasNegative = negativeWords.some((w) => lowerContent.includes(w));

    if (hasPositive && !hasNegative) sentiment = 'positive';
    else if (hasNegative && !hasPositive) sentiment = 'negative';

    // Toxicidad simple
    const toxicWords = ['tonto', 'idiota', 'estúpido', 'basura', 'mierda'];
    const toxicity = toxicWords.some((w) => lowerContent.includes(w)) ? 50 : 10;

    return {
      spoilerScore: Math.min(100, spoilerScore),
      sentiment,
      toxicity,
      categories: [],
    };
  }

  private hash(str: string): string {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
      const char = str.charCodeAt(i);
      hash = (hash << 5) - hash + char;
      hash = hash & hash;
    }
    return hash.toString(16);
  }

  // Utilidades
  getCacheSize(): number {
    return this.cache.size;
  }

  clearCache(): void {
    this.cache.clear();
  }

  async getRateLimitStats(): Promise<{
    reservoir: number;
    queued: number;
    running: number;
  }> {
    const counts = this.limiter.counts() as any;
    return {
      reservoir: (counts as any).RECEIVED || 0,
      queued: await (this.limiter as any).queued(),
      running: await (this.limiter as any).running(),
    };
  }
}

/**
 * UnifiedAIService - Servicio unificado de IA
 * 
 * Integra todos los componentes del sistema de IA:
 * - InferenceJobQueue: Cola prioritaria de trabajos
 * - ModelWorkerPool: Pool de workers para ejecución
 * - ParallelInferenceEngine: Motor de inferencia paralela
 * - ModelRegistry: Registro y routing de modelos
 * 
 * Esta es la capa de orquestación principal que expone una API simple
 * para el resto de la aplicación.
 */

import { EventEmitter } from 'events';

import { IAProvider, CommentAnalysis, ChapterSummary, QualityAssessment } from '@/core/services/IAProvider';
import { AlertManager, getAlertManager } from '@/infrastructure/ai/AlertManager';
import { InMemoryAIProvider } from '@/infrastructure/ai/InMemoryAIProvider';
import { 
  ModelRegistry, 
  RegisteredModel, 
  RoutingStrategy,
  RoutingMetrics 
} from '@/infrastructure/ai/ModelRegistry';
import { ModelWorkerPool, InferenceJob as WorkerJob, PoolMetrics, PoolEvent } from '@/infrastructure/ai/ModelWorkerPool';
import { NVIDIAProvider } from '@/infrastructure/ai/NVIDIAProvider';
import { 
  ParallelInferenceEngine, 
  InferenceJob as EngineJob, 
  InferenceResult as EngineResult,
  InferenceProvider
} from '@/infrastructure/ai/ParallelInferenceEngine';
import { InferenceJobQueue, JobType, QueueStats } from '@/infrastructure/queue/InferenceJobQueue';

// ============================================================================
// Types & Interfaces
// ============================================================================

export type ServiceJobType = 
  | 'analyze-comment'
  | 'detect-spoiler'
  | 'summarize-chapter'
  | 'generate-notification'
  | 'generate-embedding'
  | 'classify-genre'
  | 'classify-quality'
  | 'batch-inference';

export interface ServiceJob {
  id?: string;
  type: ServiceJobType;
  payload: unknown;
  priority?: number;
  modelId?: string;
  timeout?: number;
  retryable?: boolean;
}

export interface ServiceJobResult<T = unknown> {
  jobId: string;
  success: boolean;
  data?: T;
  error?: {
    message: string;
    code?: string;
    retryable: boolean;
  };
  metadata: {
    latencyMs: number;
    modelId?: string;
    queueTimeMs: number;
    processingTimeMs: number;
  };
}

export interface BatchJobRequest {
  jobs: ServiceJob[];
  strategy?: 'parallel' | 'sequential' | 'race';
  failFast?: boolean;
}

export interface ServiceConfig {
  // Queue config
  maxRetries?: number;
  retryDelayMs?: number;
  enablePersistence?: boolean;
  
  // Pool config
  minWorkers?: number;
  maxWorkers?: number;
  maxJobsPerWorker?: number;
  idleTimeoutMs?: number;
  
  // Engine config
  maxConcurrent?: number;
  defaultTimeout?: number;
  
  // Routing
  defaultStrategy?: RoutingStrategy;
  
  // Providers
  nvidiaApiKey?: string;
  useInMemoryFallback?: boolean;
}

export interface ServiceHealth {
  status: 'healthy' | 'degraded' | 'unhealthy';
  components: {
    queue: 'up' | 'down';
    pool: 'up' | 'down';
    engine: 'up' | 'down';
    registry: 'up' | 'down';
  };
  models: {
    total: number;
    healthy: number;
    degraded: number;
    unhealthy: number;
  };
  performance: {
    throughput: number;
    avgLatency: number;
    queueDepth: number;
  };
}

export interface ServiceMetrics {
  jobs: {
    total: number;
    completed: number;
    failed: number;
    retried: number;
    cancelled: number;
  };
  performance: {
    avgQueueTimeMs: number;
    avgProcessingTimeMs: number;
    throughputPerMinute: number;
    errorRate: number;
  };
  models: RoutingMetrics;
}

// ============================================================================
// Provider Adapter
// ============================================================================

class IAProviderAdapter implements InferenceProvider {
  constructor(_provider?: any) {}

  async infer(modelId: string, input: unknown): Promise<unknown> {
    // Este adapter es un puente genérico - en producción sería más específico
    // por modelo. Por ahora devuelve un resultado simulado.
    return { modelId, input, timestamp: Date.now() };
  }

  async isAvailable(): Promise<boolean> {
    return true;
  }
}

// ============================================================================
// Unified AI Service
// ============================================================================

export class UnifiedAIService extends EventEmitter {
  private queue: InferenceJobQueue;
  private pool: ModelWorkerPool;
  private engine: ParallelInferenceEngine;
  private registry: ModelRegistry;
  private alertManager: AlertManager;

  private providers: Map<string, IAProvider> = new Map();
  private config: Required<ServiceConfig>;
  private isRunning = false;
  private processingInterval?: NodeJS.Timeout;
  private healthCheckInterval?: NodeJS.Timeout;

  // Metrics tracking
  private metrics = {
    totalJobs: 0,
    completedJobs: 0,
    failedJobs: 0,
    retriedJobs: 0,
    cancelledJobs: 0,
    totalQueueTime: 0,
    totalProcessingTime: 0,
  };

  // Last emitted alert states (to avoid duplicate emissions)
  private lastEmittedStates = {
    modelHealth: new Map<string, string>(),
    errorRateHigh: false,
    queueBacklog: false,
  };

  constructor(config: ServiceConfig = {}) {
    super();
    this.setMaxListeners(100);
    
    this.config = {
      maxRetries: config.maxRetries ?? 3,
      retryDelayMs: config.retryDelayMs ?? 5000,
      enablePersistence: config.enablePersistence ?? false,
      minWorkers: config.minWorkers ?? 2,
      maxWorkers: config.maxWorkers ?? 10,
      maxJobsPerWorker: config.maxJobsPerWorker ?? 100,
      idleTimeoutMs: config.idleTimeoutMs ?? 60000,
      maxConcurrent: config.maxConcurrent ?? 5,
      defaultTimeout: config.defaultTimeout ?? 30000,
      defaultStrategy: config.defaultStrategy ?? 'round-robin',
      nvidiaApiKey: config.nvidiaApiKey ?? process.env.NVIDIA_API_KEY ?? '',
      useInMemoryFallback: config.useInMemoryFallback ?? true,
    };

    // Initialize components
    this.queue = new InferenceJobQueue({
      maxRetries: this.config.maxRetries,
      retryDelayMs: this.config.retryDelayMs,
      enablePersistence: this.config.enablePersistence,
    });

    this.pool = new ModelWorkerPool({
      minWorkers: this.config.minWorkers,
      maxWorkers: this.config.maxWorkers,
      idleTimeoutMs: this.config.idleTimeoutMs,
      maxJobsPerWorker: this.config.maxJobsPerWorker,
    });

    this.engine = new ParallelInferenceEngine(
      {
        maxConcurrent: this.config.maxConcurrent,
        defaultTimeout: this.config.defaultTimeout,
      },
      (modelId) => new IAProviderAdapter(this.getProvider(modelId))
    );

    this.registry = new ModelRegistry();
    this.alertManager = getAlertManager();

    this.setupEventListeners();
    this.registerDefaultModels();
    this.setupAlertListeners();
  }

  // ==========================================================================
  // Initialization
  // ==========================================================================

  private setupEventListeners(): void {
    // Queue events
    this.queue.on('job:added', (payload) => {
      (this as any).emit('job:queued', payload);
      this.processQueue();
    });

    this.queue.on('job:started', (payload) => {
      (this as any).emit('job:started', payload);
    });

    this.queue.on('job:completed', (payload) => {
      this.metrics.completedJobs++;
      (this as any).emit('job:completed', payload);
    });

    this.queue.on('job:failed', (payload) => {
      if (payload.deadLettered) {
        this.metrics.failedJobs++;
      } else {
        this.metrics.retriedJobs++;
      }
      (this as any).emit('job:failed', payload);
    });

    // Pool events
    this.pool.onEvent((event: PoolEvent) => {
      (this as any).emit('pool:event', event);
    });
  }

  private registerDefaultModels(): void {
    // Register NVIDIA models
    if (this.config.nvidiaApiKey) {
      this.registry.register({
        id: 'nvidia/llama-3.1-nemotron-70b-instruct',
