          totalFailedRequests: 0,
        },
        registeredAt: new Date(),
      });

      this.registry.register({
        id: 'nvidia/nv-embedqa-e5-v5',
        name: 'NVIDIA E5 Embedding',
        provider: 'nvidia',
        capabilities: ['embedding'],
        config: {
