import mongoose, { Schema } from 'mongoose';

export interface IPromptLibrary {
  authorId: string;
  name: string;
  prompt: string;
  style?: string;
  tags: string[];
  isPublic: boolean;
  likes: number;
  likedBy: string[];
  chapterId?: string;
  mangaId?: string;
  model?: string;
  negativePrompt?: string;
  seed?: number;
  cfgScale?: number;
  views: number;
  forks: number;
  forkedBy: string[];
  createdAt: Date;
  updatedAt: Date;
}

export interface IPromptLibraryDocument extends IPromptLibrary {
  _id: string;
}

const PromptLibrarySchema = new Schema<IPromptLibrary>(
  {
    authorId: { type: String, required: true, index: true },
    name: { type: String, required: true, maxlength: 100 },
    prompt: { type: String, required: true, maxlength: 2000 },
    style: String,
    tags: [{ type: String, index: true }],
    isPublic: { type: Boolean, default: true },
    likes: { type: Number, default: 0 },
    likedBy: [{ type: String }],
    // Referencias opcionales
    chapterId: { type: String, index: true },
    mangaId: { type: String, index: true },
    // Configuración
    model: String,
    negativePrompt: String,
    seed: Number,
    cfgScale: Number,
    // Stats
    views: { type: Number, default: 0 },
    forks: { type: Number, default: 0 },
    forkedBy: [{ type: String }],
  },
  { timestamps: true }
);

// Índices
PromptLibrarySchema.index({ authorId: 1, createdAt: -1 });
PromptLibrarySchema.index({ tags: 1 });
PromptLibrarySchema.index({ isPublic: 1, likes: -1 });
PromptLibrarySchema.index({ isPublic: 1, createdAt: -1 });
PromptLibrarySchema.index({ name: 'text', prompt: 'text' }); // Para búsqueda

// Método para dar/quitar like
PromptLibrarySchema.methods.toggleLike = function(userId: string) {
  const index = this.likedBy.indexOf(userId);
  if (index === -1) {
    this.likedBy.push(userId);
  } else {
    this.likedBy.splice(index, 1);
  }
  this.likes = this.likedBy.length;
};

// Método para incrementar views
PromptLibrarySchema.methods.incrementViews = function() {
  this.views += 1;
};

// Método para fork
PromptLibrarySchema.methods.fork = function(userId: string) {
  if (!this.forkedBy.includes(userId)) {
    this.forkedBy.push(userId);
    this.forks = this.forkedBy.length;
  }
};

export const PromptLibraryModel =
  mongoose.models.PromptLibrary ||
  mongoose.model<IPromptLibrary>('PromptLibrary', PromptLibrarySchema) as mongoose.Model<IPromptLibrary, {}, {}, {}>;

import { PrismaClient } from '@prisma/client';
import bcrypt from 'bcryptjs';

import { User, UserProps } from '@/core/entities/User';
import { UserRepository } from '@/core/repositories/UserRepository';
import { Email } from '@/core/value-objects/Email';
import { Password } from '@/core/value-objects/Password';
import { prisma as defaultPrisma } from '@/lib/prisma';

export class PrismaUserRepository implements UserRepository {
  private prisma: PrismaClient;

  constructor(prismaClient?: PrismaClient) {
    this.prisma = prismaClient || defaultPrisma;
  }

  async findById(id: string): Promise<User | null> {
    const dbUser = await this.prisma.user.findUnique({
      where: { id },
    });

    if (!dbUser) return null;

    return this.mapToDomain(dbUser);
  }

  async findByEmail(email: string): Promise<User | null> {
    const dbUser = await this.prisma.user.findUnique({
      where: { email: email.toLowerCase() },
    });

    if (!dbUser) return null;

    return this.mapToDomain(dbUser);
  }

  async findByUsername(username: string): Promise<User | null> {
    const dbUser = await this.prisma.user.findUnique({
      where: { username: username.toLowerCase() },
    });

    if (!dbUser) return null;

    return this.mapToDomain(dbUser);
  }

  async save(user: User): Promise<void> {
    const json = user.toJSON();

    await this.prisma.user.upsert({
      where: { id: user.id },
      update: {
        email: json.email as string,
        username: json.username as string,
        displayName: json.displayName as string | undefined,
        avatarUrl: json.avatarUrl as string | undefined,
        xpPoints: json.xpPoints as number,
        inkcoinsBalance: json.inkcoinsBalance as number,
        level: json.level as number,
        readingStreak: json.readingStreak as number,
        lastReadAt: json.lastReadAt ? new Date(json.lastReadAt as string) : undefined,
        updatedAt: new Date(),
      },
      create: {
        id: user.id,
        email: json.email as string,
        username: json.username as string,
        displayName: json.displayName as string | undefined,
        avatarUrl: json.avatarUrl as string | undefined,
        passwordHash: user.passwordHash,
        emailVerified: json.emailVerified
          ? new Date(json.emailVerified as string)
          : undefined,
        role: json.role as string,
        xpPoints: json.xpPoints as number,
        inkcoinsBalance: json.inkcoinsBalance as number,
        level: json.level as number,
        readingStreak: json.readingStreak as number,
        lastReadAt: json.lastReadAt ? new Date(json.lastReadAt as string) : undefined,
        createdAt: new Date(json.createdAt as string),
        updatedAt: new Date(json.updatedAt as string),
      },
    });
  }

  async createWithPassword(
    email: Email,
    username: string,
    password: string
  ): Promise<User> {
    const passwordObj = Password.createFromPlain(password);
    const { user } = User.registerWithEmail(
      email,
      username,
      passwordObj
    );

    // Hashear contraseña
    const hashedPassword = await bcrypt.hash(password, 12);

    // Guardar en DB
    await this.prisma.user.create({
      data: {
        id: user.id,
        email: user.email.value,
        username: user.username,
        passwordHash: hashedPassword,
        xpPoints: 0,
        inkcoinsBalance: 50, // Bonus de registro
        level: 1,
        readingStreak: 0,
      },
    });

    return user;
  }

  async updatePassword(userId: string, newPassword: string): Promise<void> {
    const hashedPassword = await bcrypt.hash(newPassword, 12);

    await this.prisma.user.update({
      where: { id: userId },
      data: { passwordHash: hashedPassword },
    });
  }

  async updateXP(userId: string, xpPoints: number): Promise<void> {
    const level = Math.floor(xpPoints / 1000) + 1;

    await this.prisma.user.update({
      where: { id: userId },
      data: { xpPoints, level },
    });
  }

  async updateInkCoins(userId: string, balance: number): Promise<void> {
    await this.prisma.user.update({
      where: { id: userId },
      data: { inkcoinsBalance: balance },
    });
  }

  async existsByEmail(email: string): Promise<boolean> {
    const count = await this.prisma.user.count({
      where: { email: email.toLowerCase() },
    });
    return count > 0;
  }

  async existsByUsername(username: string): Promise<boolean> {
    const count = await this.prisma.user.count({
      where: { username: username.toLowerCase() },
    });
    return count > 0;
  }

  async getLeaderboard(limit: number = 10): Promise<User[]> {
    const dbUsers = await this.prisma.user.findMany({
      orderBy: { xpPoints: 'desc' },
      take: limit,
    });

    return dbUsers.map((u: any) => this.mapToDomain(u));
  }

  async findByIds(ids: string[]): Promise<User[]> {
    const dbUsers = await this.prisma.user.findMany({
      where: { id: { in: ids } },
    });

    return dbUsers.map((u: any) => this.mapToDomain(u));
  }

  async count(): Promise<number> {
    return this.prisma.user.count();
  }

  // Método auxiliar para mapear de Prisma a Domain
  private mapToDomain(dbUser: {
    id: string;
    email: string;
    username: string;
    displayName: string | null;
    avatarUrl: string | null;
    passwordHash: string | null;
    emailVerified: Date | null;
    role: string;
    xpPoints: number;
    inkcoinsBalance: number;
    level: number;
    readingStreak: number;
    lastReadAt: Date | null;
    createdAt: Date;
    updatedAt: Date;
  }): User {
    return User.create({
      id: dbUser.id,
      email: Email.create(dbUser.email),
      username: dbUser.username,
      displayName: dbUser.displayName || undefined,
      avatarUrl: dbUser.avatarUrl || undefined,
      passwordHash: dbUser.passwordHash || undefined,
      emailVerified: dbUser.emailVerified || undefined,
      role: dbUser.role as UserProps['role'],
      xpPoints: dbUser.xpPoints,
      inkcoinsBalance: dbUser.inkcoinsBalance,
      readingStreak: dbUser.readingStreak,
      lastReadAt: dbUser.lastReadAt || undefined,
      createdAt: dbUser.createdAt,
      updatedAt: dbUser.updatedAt,
    });
  }
}

/**
 * Email Worker para InkVerse
 * Procesa jobs de la cola de emails usando BullMQ
 * @packageDocumentation
 */

import { Worker, Job } from 'bullmq';
import type { Redis } from 'ioredis';

import { emailService } from '@/infrastructure/adapters/emailService';
import type {
  EmailJobData,
  WelcomeEmailData,
  PasswordResetData,
  NewChapterData,
  AchievementData,
  TipReceivedData,
  CrowdfundingGoalData,
  CommentReplyData,
} from '@/infrastructure/queue/EmailQueue';
import { baseEmailTemplate } from '@/lib/email-templates';
import { redis, isMockRedis } from '@/lib/redis';

// ============================================================================
// Mock Worker for Development (when Redis is not available)
// ============================================================================

class MockEmailWorker {
  async close(): Promise<void> {
    if (process.env.DEBUG_EMAIL) {
      console.log('[EmailWorker] Mock worker stopped');
    }
  }

  on(_event: string, _listener: (...args: unknown[]) => void): void {
    // No-op
  }
}

// ============================================================================
// Email Worker
// ============================================================================

export class EmailWorker {
  private worker: Worker | MockEmailWorker | null = null;
  private useMock: boolean;

  constructor() {
    this.useMock = isMockRedis();

    if (this.useMock) {
      this.initializeMockWorker();
    } else {
      this.initializeRealWorker();
    }
  }

  /**
   * Inicializa un worker mock para desarrollo sin Redis
   */
  private initializeMockWorker(): void {
    this.worker = new MockEmailWorker();

    // Log once that we're using mock mode
    if (process.env.DEBUG_EMAIL) {
      console.log('[EmailWorker] Running in mock mode (Redis not available)');
      console.log('[EmailWorker] Emails will be logged but not actually sent');
    }
  }

  /**
   * Inicializa el worker de emails real con BullMQ
   */
  private initializeRealWorker(): void {
    if (isMockRedis()) {
      this.useMock = true;
      this.initializeMockWorker();
      return;
    }
    try {
      this.worker = new Worker(
        'emails',
        async (job: Job<EmailJobData>) => {
          await this.processJob(job);
        },
        {
          connection: redis as Redis,
          concurrency: 5,
          limiter: {
            max: 10,
            duration: 1000,
          },
          stalledInterval: 30000,
          maxStalledCount: 3,
        }
      );

      this.setupEventHandlers();
    } catch (error) {
      console.error('[EmailWorker] Failed to initialize worker:', error);
      // Fallback to mock mode on error
      this.useMock = true;
      this.initializeMockWorker();
    }
  }

  /**
   * Configura los event handlers del worker
   */
  private setupEventHandlers(): void {
    if (!this.worker || this.useMock) return;

    const bullWorker = this.worker as Worker;

    bullWorker.on('completed', (job: any) => {
      console.info(`[EmailWorker] Job ${job.id} completed: ${job.data.type}`);
    });

    bullWorker.on('failed', (job: any, err: any) => {
      console.error(`[EmailWorker] Job ${job?.id} failed:`, err.message);
    });

    bullWorker.on('error', (error: any) => {
      // Only log errors in production or with DEBUG_EMAIL flag
      if (process.env.NODE_ENV === 'production' || process.env.DEBUG_EMAIL) {
        console.error('[EmailWorker] Worker error:', error);
      }
    });
  }

  /**
   * Procesa un job segun su tipo
   */
  private async processJob(job: Job<EmailJobData>): Promise<void> {
    const { data } = job;
    console.info(`[EmailWorker] Processing job ${job.id}: ${data.type}`);

    try {
      // In mock mode, just log the email instead of sending
      if (this.useMock) {
        this.logMockEmail(data);
        return;
      }

      switch (data.type) {
        case 'welcome':
          await this.processWelcomeEmail(job as Job<WelcomeEmailData>);
          break;
        case 'password-reset':
          await this.processPasswordResetEmail(job as Job<PasswordResetData>);
          break;
        case 'new-chapter':
          await this.processNewChapterEmail(job as Job<NewChapterData>);
          break;
        case 'achievement':
          await this.processAchievementEmail(job as Job<AchievementData>);
          break;
        case 'tip-received':
          await this.processTipReceivedEmail(job as Job<TipReceivedData>);
          break;
        case 'crowdfunding-goal-reached':
          await this.processCrowdfundingGoalEmail(job as Job<CrowdfundingGoalData>);
          break;
        case 'comment-reply':
          await this.processCommentReplyEmail(job as Job<CommentReplyData>);
          break;
        case 'custom':
          await this.processCustomEmail(job);
          break;
        case 'marketing':
          await this.processMarketingEmail(job);
          break;
        default:
          throw new Error(`Unknown job type: ${(data as EmailJobData).type}`);
      }
    } catch (error) {
      console.error(`[EmailWorker] Error processing job ${job.id}:`, error);
      throw error;
    }
  }

  /**
   * Log mock email for development
   */
  private logMockEmail(data: EmailJobData): void {
    if (!process.env.DEBUG_EMAIL) return;

    const { type, to, userId, username } = data;
    console.log('[EmailWorker] MOCK EMAIL:', {
      type,
      to,
      userId,
      username,
      timestamp: new Date().toISOString(),
    });
  }

  private async processWelcomeEmail(job: Job<WelcomeEmailData>): Promise<void> {
    const { to, userId, username, displayName } = job.data;
    await emailService.sendWelcomeEmail({
      id: userId,
      email: to,
      username,
      displayName,
    });
  }

  private async processPasswordResetEmail(job: Job<PasswordResetData>): Promise<void> {
    const { to, userId, username, resetToken } = job.data;
    await emailService.sendPasswordResetEmail(
      { id: userId, email: to, username },
      resetToken
    );
  }

  private async processNewChapterEmail(job: Job<NewChapterData>): Promise<void> {
    const { to, userId, username, mangaTitle, chapterTitle, mangaCoverUrl } = job.data;
    const mangaSlug = job.data.mangaSlug;
    const chapterNumber = job.data.chapterNumber;

    await emailService.sendNewChapterNotification(
      { id: userId, email: to, username },
      { id: job.data.mangaId, title: mangaTitle, slug: mangaSlug, coverUrl: mangaCoverUrl, authorName: '' },
      { id: job.data.chapterId, chapterNumber, title: chapterTitle }
    );
  }

