/**
 * Image Optimizer Service
 * 
 * Optimiza imágenes de capítulos usando Sharp.
 */

import { existsSync } from 'fs';
import { writeFile, readFile, mkdir } from 'fs/promises';
import path from 'path';
import sharp from 'sharp';

import { generateCacheKey, getCached, setCache } from './cache';

const IMAGE_CACHE_TTL = 7 * 24 * 60 * 60; // 7 days

interface OptimizationOptions {
  width?: number;
  quality?: number;
  format?: 'jpeg' | 'webp' | 'png';
  progressive?: boolean;
}

interface OptimizedImage {
  buffer: Buffer;
  format: string;
  width: number;
  height: number;
  size: number;
}

/**
 * Optimize an image buffer
 */
export async function optimizeImageBuffer(
  buffer: Buffer,
  options: OptimizationOptions = {}
): Promise<OptimizedImage> {
  const {
    width = 1200,
    quality = 85,
    format = 'webp',
    progressive = true,
  } = options;

  try {
    let pipeline = sharp(buffer);

    // Get metadata
    const metadata = await pipeline.metadata();
    const originalWidth = metadata.width || width;
    const originalHeight = metadata.height || width;

    // Resize maintaining aspect ratio
    if (originalWidth > width) {
      pipeline = pipeline.resize(width, null, {
        withoutEnlargement: true,
        fit: 'inside',
      });
    }

    // Convert format
    switch (format) {
      case 'webp':
        pipeline = pipeline.webp({ 
          quality, 
          effort: 4,
          smartSubsample: true,
        });
        break;
      case 'jpeg':
        pipeline = pipeline.jpeg({ 
          quality, 
          progressive,
          mozjpeg: true,
        });
        break;
      case 'png':
        pipeline = pipeline.png({ 
          quality,
          progressive,
          compressionLevel: 9,
        });
        break;
    }

    const optimizedBuffer = await pipeline.toBuffer();
    const info = await sharp(optimizedBuffer).metadata();

    return {
      buffer: optimizedBuffer,
      format,
      width: info.width || width,
      height: info.height || Math.round(width * (originalHeight / originalWidth)),
      size: optimizedBuffer.length,
    };
  } catch (error) {
    console.error('Error optimizing image:', error);
    throw new Error('Failed to optimize image');
  }
}

/**
 * Generate responsive image variants
 */
export async function generateResponsiveImages(
  buffer: Buffer,
  baseOptions: OptimizationOptions = {}
): Promise<{ [key: string]: OptimizedImage }> {
  const sizes = {
    thumbnail: 150,
    small: 400,
    medium: 800,
    large: 1200,
    original: 0, // No resize
  };

  const results: { [key: string]: OptimizedImage } = {};

  await Promise.all(
    Object.entries(sizes).map(async ([name, width]) => {
      if (width === 0) {
        // Original size, just convert format
        results[name] = await optimizeImageBuffer(buffer, {
          ...baseOptions,
          width: undefined,
        });
      } else {
        results[name] = await optimizeImageBuffer(buffer, {
          ...baseOptions,
          width,
        });
      }
    })
  );

  return results;
}

/**
 * Get optimized image with caching
 */
export async function getOptimizedImage(
  imagePath: string,
  options: OptimizationOptions = {}
): Promise<Buffer> {
  const cacheKey = generateCacheKey('image', `${imagePath}:${JSON.stringify(options)}`);
  
  // Try cache
  const cached = await getCached<Buffer>(cacheKey);
  if (cached) {
    return Buffer.from(cached);
  }

  // Read and optimize
  const buffer = await readFile(imagePath);
  const optimized = await optimizeImageBuffer(buffer, options);

  // Cache result
  await setCache(cacheKey, optimized.buffer, IMAGE_CACHE_TTL);

  return optimized.buffer;
}

/**
 * Process chapter images
 */
export async function processChapterImages(
  files: File[],
  chapterId: string
): Promise<{ urls: string[]; totalSize: number }> {
  const uploadDir = path.join(process.cwd(), 'public', 'uploads', 'chapters', chapterId);
  
  if (!existsSync(uploadDir)) {
    await mkdir(uploadDir, { recursive: true });
  }

  const urls: string[] = [];
  let totalSize = 0;

  await Promise.all(
    files.map(async (file, index) => {
      const arrayBuffer = await file.arrayBuffer();
      const buffer = Buffer.from(arrayBuffer);
      
      // Generate optimized variants
      const optimized = await generateResponsiveImages(buffer, {
        quality: 85,
        format: 'webp',
      });

      // Save medium quality (default view)
      const fileName = `${(index + 1).toString().padStart(3, '0')}.webp`;
      const filePath = path.join(uploadDir, fileName);
      
      await writeFile(filePath, optimized.medium.buffer);
      totalSize += optimized.medium.size;

      // Also save thumbnail
      const thumbName = `${(index + 1).toString().padStart(3, '0')}_thumb.webp`;
      const thumbPath = path.join(uploadDir, thumbName);
      await writeFile(thumbPath, optimized.thumbnail.buffer);

      urls.push(`/uploads/chapters/${chapterId}/${fileName}`);
    })
  );

  return { urls, totalSize };
}

/**
 * Optimize manga cover
 */
export async function optimizeCover(
  buffer: Buffer,
  mangaId: string
): Promise<string> {
  const uploadDir = path.join(process.cwd(), 'public', 'uploads', 'covers');
  
  if (!existsSync(uploadDir)) {
    await mkdir(uploadDir, { recursive: true });
  }

  // Generate responsive cover
  const optimized = await generateResponsiveImages(buffer, {
    width: 800,
    quality: 90,
    format: 'webp',
  });

  const fileName = `${mangaId}.webp`;
  const filePath = path.join(uploadDir, fileName);
  
  await writeFile(filePath, optimized.large.buffer);

  // Save thumbnail
  const thumbName = `${mangaId}_thumb.webp`;
  const thumbPath = path.join(uploadDir, thumbName);
  await writeFile(thumbPath, optimized.thumbnail.buffer);

  return `/uploads/covers/${fileName}`;
}

/**
 * Get image dimensions without loading full image
 */
export async function getImageDimensions(buffer: Buffer): Promise<{ width: number; height: number }> {
  const metadata = await sharp(buffer).metadata();
  return {
    width: metadata.width || 0,
    height: metadata.height || 0,
  };
}

/**
 * Validate image file
 */
export function validateImageFile(file: File): { valid: boolean; error?: string } {
  const allowedTypes = ['image/jpeg', 'image/png', 'image/webp', 'image/gif'];
  const maxSize = 10 * 1024 * 1024; // 10MB

  if (!allowedTypes.includes(file.type)) {
    return { valid: false, error: 'Invalid file type. Only JPEG, PNG, WebP, and GIF are allowed.' };
  }

  if (file.size > maxSize) {
    return { valid: false, error: 'File too large. Maximum size is 10MB.' };
  }

  return { valid: true };
}

export default {
  optimizeImageBuffer,
  generateResponsiveImages,
  getOptimizedImage,
  processChapterImages,
  optimizeCover,
  getImageDimensions,
  validateImageFile,
};

'use server';

/**
 * Push Notifications Service
 * 
 * Gestiona suscripciones Web Push y envío de notificaciones.
 * Usa web-push para enviar notificaciones push a los navegadores.
 */

import webpush from 'web-push';

import { prisma } from '@/lib/prisma';
import type { WebPushSubscription, PushNotificationPayload } from '@/types/push';

// Configurar VAPID
const vapidPublicKey = process.env.NEXT_PUBLIC_VAPID_PUBLIC_KEY;
const vapidPrivateKey = process.env.VAPID_PRIVATE_KEY;
const vapidSubject = process.env.VAPID_SUBJECT || 'mailto:noreply@inkverse.app';

if (vapidPublicKey && vapidPrivateKey) {
  webpush.setVapidDetails(
    vapidSubject,
    vapidPublicKey,
    vapidPrivateKey
  );
}

/**
 * Guardar o actualizar suscripción de push
 */
export async function savePushSubscription(
  userId: string,
  subscription: WebPushSubscription
): Promise<void> {
  await prisma.pushSubscription.upsert({
    where: { endpoint: subscription.endpoint },
    update: {
      userId,
      p256dh: subscription.keys.p256dh,
      auth: subscription.keys.auth,
      updatedAt: new Date(),
    },
    create: {
      userId,
      endpoint: subscription.endpoint,
      p256dh: subscription.keys.p256dh,
      auth: subscription.keys.auth,
    },
  });
}

/**
 * Eliminar suscripción de push
 */
export async function deletePushSubscription(endpoint: string): Promise<void> {
  await prisma.pushSubscription.deleteMany({
    where: { endpoint },
  });
}

/**
 * Enviar notificación push a un usuario
 */
export async function sendPushNotification(
  userId: string,
  payload: PushNotificationPayload
): Promise<{ success: boolean; error?: string }> {
  // Buscar suscripciones del usuario
  const subscriptions = await prisma.pushSubscription.findMany({
    where: { userId },
  });

  if (subscriptions.length === 0) {
    return { success: false, error: 'No push subscriptions found' };
  }

  const notificationPayload = JSON.stringify({
    title: payload.title,
    body: payload.body,
    icon: payload.icon || '/icon-192x192.png',
    badge: payload.badge || '/badge-72x72.png',
    tag: payload.tag || 'default',
    url: payload.url || '/',
    requireInteraction: payload.requireInteraction || false,
    actions: payload.actions || [],
  });

  // Enviar a todas las suscripciones del usuario
  const results = await Promise.allSettled(
    subscriptions.map(async (sub: any) => {
      const subscription = {
        endpoint: sub.endpoint,
        keys: {
          p256dh: sub.p256dh,
          auth: sub.auth,
        },
      };

      try {
        await webpush.sendNotification(subscription, notificationPayload);
      } catch (error: any) {
        // Si falla, eliminar suscripción inválida
        if (error.statusCode === 404 || error.statusCode === 410) {
          await deletePushSubscription(sub.endpoint);
        }
        throw error;
      }
    })
  );

  const failed = results.filter((r: any) => r.status === 'rejected');
  return {
    success: failed.length === 0,
    error: failed.length > 0 ? `${failed.length} de ${results.length} fallaron` : undefined,
  };
}

/**
 * Enviar notificación push a múltiples usuarios
 */
export async function sendBulkPushNotifications(
  userIds: string[],
  payload: PushNotificationPayload
): Promise<{ sent: number; failed: number }> {
  const results = await Promise.allSettled(
    userIds.map(userId => sendPushNotification(userId, payload))
  );

  const sent = results.filter(
    r => r.status === 'fulfilled' && r.value.success
  ).length;
  const failed = results.length - sent;

  return { sent, failed };
}

/**
 * Obtener suscripciones de un usuario
 */
export async function getUserPushSubscriptions(userId: string): Promise<WebPushSubscription[]> {
  const subscriptions = await prisma.pushSubscription.findMany({
    where: { userId },
  });

  return subscriptions.map((sub: any) => ({
    endpoint: sub.endpoint,
    keys: {
      p256dh: sub.p256dh,
      auth: sub.auth,
    },
  }));
}

/**
 * Verificar si un usuario tiene suscripciones push
 */
export async function hasPushSubscriptions(userId: string): Promise<boolean> {
  const count = await prisma.pushSubscription.count({
    where: { userId },
  });
  return count > 0;
}

import { Redis } from 'ioredis';

// ============================================================================
// Redis Configuration with Graceful Fallback
// ============================================================================

const REDIS_URL = process.env.REDIS_URL;
const isDevelopment = process.env.NODE_ENV !== 'production';
// Suppress ioredis unhandled error warnings globally in development
// Guard: only run in Node.js runtime (not Edge or browser)
if (isDevelopment && typeof globalThis.process !== 'undefined' && typeof (globalThis.process as any).emit === 'function') {
  try {
    const nodeProcess = globalThis.process as any;
    const originalEmit = nodeProcess.emit;
    nodeProcess.emit = function (event: string | symbol, ...args: unknown[]): boolean {
      if (event === 'warning' && args[0] instanceof Error) {
        const warning = args[0] as Error;
        if (warning.message?.includes('ioredis') || warning.message?.includes('Unhandled error event')) {
          return false;
        }
      }
      return originalEmit.call(this, event, ...args);
    };
  } catch {
    // Silently fail if process.emit manipulation is not allowed
  }
}

// Track if Redis is available
let redisAvailable = false;
let redisInstance: Redis | null = null;
let mockRedisInstance: MockRedis | null = null;

// Global reference for hot reload (defined early for use in getRedisInstance)
const globalForRedis = global as unknown as {
  redis?: Redis;
  mockRedis?: MockRedis;
};

// ============================================================================
// Mock Redis Implementation (for development without Redis)
// ============================================================================

class MockRedis {
  private store = new Map<string, { value: string; expiry?: number }>();
  private sortedSets = new Map<string, { score: number; member: string }[]>();

  async get(key: string): Promise<string | null> {
    const item = this.store.get(key);
    if (!item) return null;
    if (item.expiry && item.expiry < Date.now()) {
      this.store.delete(key);
      return null;
    }
    return item.value;
  }

  async setex(key: string, seconds: number, value: string): Promise<void> {
    this.store.set(key, {
      value,
      expiry: Date.now() + seconds * 1000,
    });
  }

  async set(key: string, value: string): Promise<void> {
    this.store.set(key, { value });
  }

  async del(...keys: string[]): Promise<number> {
    let deleted = 0;
    for (const key of keys) {
      if (this.store.delete(key)) deleted++;
    }
    return deleted;
  }

  async keys(pattern: string): Promise<string[]> {
    const regex = new RegExp(pattern.replace(/\*/g, '.*'));
    return Array.from(this.store.keys()).filter(key => regex.test(key));
  }

  async zadd(key: string, score: number, member: string): Promise<number> {
    if (!this.sortedSets.has(key)) {
      this.sortedSets.set(key, []);
    }
    const set = this.sortedSets.get(key)!;
    const existing = set.findIndex(item => item.member === member);
    if (existing >= 0) {
      set[existing].score = score;
      return 0;
    }
    set.push({ score, member });
    return 1;
  }

  async zremrangebyscore(key: string, min: number, max: number): Promise<number> {
    const set = this.sortedSets.get(key);
    if (!set) return 0;
    const before = set.length;
    const filtered = set.filter(item => item.score < min || item.score > max);
    this.sortedSets.set(key, filtered);
    return before - filtered.length;
  }

  async zcard(key: string): Promise<number> {
    return this.sortedSets.get(key)?.length ?? 0;
  }

  async scard(key: string): Promise<number> {
    const set = this.sortedSets.get(key);
    if (set) return set.length;
    const item = this.store.get(key);
    if (!item) return 0;
    try {
      const arr = JSON.parse(item.value);
      return Array.isArray(arr) ? arr.length : 0;
    } catch {
      return 0;
    }
  }

  async zrange(key: string, start: number, stop: number, withScores?: string): Promise<string[]> {
    const set = this.sortedSets.get(key);
    if (!set) return [];
    const sorted = [...set].sort((a, b) => a.score - b.score);
    const end = stop < 0 ? sorted.length + stop + 1 : stop + 1;
    const slice = sorted.slice(start, end);
    if (withScores === 'WITHSCORES') {
      const result: string[] = [];
      for (const item of slice) {
        result.push(item.member);
        result.push(String(item.score));
      }
      return result;
    }
    return slice.map(item => item.member);
  }

  async expire(key: string, seconds: number): Promise<number> {
    if (this.sortedSets.has(key)) {
      setTimeout(() => { this.sortedSets.delete(key); }, seconds * 1000);
      return 1;
    }
    const item = this.store.get(key);
    if (item) {
      item.expiry = Date.now() + seconds * 1000;
      return 1;
    }
    return 0;
  }

  async incr(key: string): Promise<number> {
    const item = this.store.get(key);
    if (!item || (item.expiry && item.expiry < Date.now())) {
      this.store.delete(key);
      this.store.set(key, { value: '1' });
      return 1;
    }
    const current = parseInt(item.value, 10) || 0;
    const next = current + 1;
    item.value = String(next);
    return next;
  }

  async ttl(key: string): Promise<number> {
    const item = this.store.get(key);
    if (!item) return -2;
    if (!item.expiry) return -1;
    const remaining = Math.max(0, Math.floor((item.expiry - Date.now()) / 1000));
    return remaining;
  }

  async quit(): Promise<void> {
    this.store.clear();
  }

  // Event emitter compatible methods (no-op)
  on(_event: string, _listener: (...args: unknown[]) => void): this {
    return this;
  }

  once(_event: string, _listener: (...args: unknown[]) => void): this {
    return this;
  }

  off(_event: string, _listener: (...args: unknown[]) => void): this {
    return this;
  }

  emit(_event: string, ..._args: unknown[]): boolean {
    return true;
  }
}

// ============================================================================
// Redis Connection Factory
// ============================================================================

function createRealRedis(): Redis {
  const client = new Redis(REDIS_URL || 'redis://localhost:6379', {
    retryStrategy: (times) => {
      const delay = Math.min(times * 50, 2000);
      return delay;
    },
    maxRetriesPerRequest: 3,
    lazyConnect: true, // Don't connect immediately
    enableOfflineQueue: false, // Don't queue commands when offline
    // Suppress connection errors in development
    showFriendlyErrorStack: isDevelopment,
  });

  // Suppress all error output in development
  const silentError = () => {};

  // Handle connection events silently in dev, with logging in production
  client.on('connect', () => {
    redisAvailable = true;
    if (!isDevelopment) {
      console.log('[Redis] Connected successfully');
    }
  });

  client.on('ready', () => {
    redisAvailable = true;
  });

  // Primary error handler - silently swallow errors in development
  client.on('error', (error: Error & { code?: string }) => {
    redisAvailable = false;
    // Completely suppress connection errors in development
    if (isDevelopment) {
      return;
    }
    // Only log in production if DEBUG_REDIS is set
    if (process.env.DEBUG_REDIS) {
      console.error('[Redis] Connection error:', error.message);
    }
  });

  // Additional error event handlers to prevent unhandled warnings
  client.on('close', () => {
    redisAvailable = false;
    if (!isDevelopment && process.env.DEBUG_REDIS) {
      console.log('[Redis] Connection closed');
    }
  });

  client.on('reconnecting', () => {
    if (!isDevelopment && process.env.DEBUG_REDIS) {
      console.log('[Redis] Reconnecting...');
    }
  });

  client.on('end', silentError);
  client.on('wait', silentError);

  // Catch-all for any other events that might emit errors
  client.on('node error', silentError);

  return client;
}

function getRedisInstance(): Redis | MockRedis {
  // Clear any cached real Redis instance in development without REDIS_URL
  if (isDevelopment && !process.env.REDIS_URL && redisInstance) {
    redisInstance.disconnect?.();
    redisInstance = null;
    globalForRedis.redis = undefined;
  }

  if (mockRedisInstance) return mockRedisInstance;
  if (redisInstance) return redisInstance;

  // In development, default to mock Redis unless explicitly configured
  if (isDevelopment && !process.env.REDIS_URL) {
    mockRedisInstance = new MockRedis();
    if (process.env.DEBUG_REDIS) {
      console.log('[Redis] Using MockRedis for development');
    }
    return mockRedisInstance;
  }

  // Try to create real Redis connection
  try {
    redisInstance = createRealRedis();
    return redisInstance;
  } catch (error) {
    // Fallback to mock if creation fails
    mockRedisInstance = new MockRedis();
    if (!isDevelopment) {
      console.warn('[Redis] Failed to create Redis client, using mock fallback');
    }
    return mockRedisInstance;
  }
}

// ============================================================================
// Exported Redis Client (singleton)
// ============================================================================

export const redis =
  globalForRedis.redis ||
  globalForRedis.mockRedis ||
  getRedisInstance();

// Store in global for hot reload in development
if (isDevelopment) {
  if (redis instanceof Redis) {
    globalForRedis.redis = redis as Redis;
  } else {
    globalForRedis.mockRedis = redis as MockRedis;
  }
}

// ============================================================================
// Utility Functions
// ============================================================================

/**
 * Check if Redis is available and connected
 */
export function isRedisConnected(): boolean {
  return redisAvailable;
}

/**
 * Check if using mock Redis (development fallback)
 */
export function isMockRedis(): boolean {
  return redis instanceof MockRedis;
}

/**
 * Get Redis connection status for health checks
 */
export async function getRedisStatus(): Promise<{
  connected: boolean;
  isMock: boolean;
  mode: string;
}> {
  return {
    connected: redisAvailable,
    isMock: isMockRedis(),
    mode: isMockRedis() ? 'mock' : redisAvailable ? 'connected' : 'disconnected',
  };
}

// ============================================================================
// Cleanup Function for Graceful Shutdown
// ============================================================================

export async function closeRedisConnection(): Promise<void> {
  if (redisInstance) {
    await redisInstance.quit();
    redisInstance = null;
  }
  if (mockRedisInstance) {
    await mockRedisInstance.quit();
    mockRedisInstance = null;
  }
  redisAvailable = false;
}

/**
 * Socket.IO Redis Adapter
 *
 * Adaptador Redis para Socket.IO que permite escalar horizontalmente
 * múltiples instancias del servidor WebSocket.
 */

import { createAdapter } from '@socket.io/redis-adapter';
import { Redis } from 'ioredis';
import type { Server as SocketIOServer } from 'socket.io';

import { redis, isMockRedis } from '@/lib/redis';

export async function createRedisAdapter(io: SocketIOServer): Promise<boolean> {
  if (isMockRedis()) {
    console.info('[Socket] Using in-memory adapter (Redis not available)');
    return false;
  }

  const realRedis = redis as Redis;

  // Ensure the main Redis client is connected before duplicating
  try {
    if (realRedis.status === 'wait') {
      await realRedis.connect();
    }
  } catch (connErr) {
    console.warn('[Socket] Redis not reachable, using in-memory adapter');
    return false;
  }

  try {
    const pubClient = realRedis.duplicate();
    const subClient = realRedis.duplicate();

    // Suppress errors on duplicated clients to prevent crashes
    const onError = (role: string) => (err: Error) => {
      console.warn(`[Socket] Redis ${role} error:`, err.message);
    };
    pubClient.on('error', onError('pubClient'));
    subClient.on('error', onError('subClient'));

    // Connect duplicated clients before passing to adapter
    await Promise.all([pubClient.connect(), subClient.connect()]);

    io.adapter(createAdapter(pubClient, subClient));
    console.info('[Socket] Redis adapter enabled for multi-server scaling');
    return true;
  } catch (error) {
    console.warn('[Socket] Failed to create Redis adapter, using in-memory fallback:', error instanceof Error ? error.message : error);
    return false;
  }
}

export async function getOnlineClientsCount(): Promise<number> {
  if (isMockRedis()) return 0;

  try {
    const keys = await redis.keys('socket.io#*');
    let total = 0;

    for (const key of keys) {
      if (key.includes('#/#')) {
        const count = await redis.scard(key);
        total += count;
      }
    }

    return total;
  } catch {
    return 0;
  }
}

export async function getRoomClientsCount(room: string): Promise<number> {
  if (isMockRedis()) return 0;

  try {
    const keys = await redis.keys('socket.io#*#' + room + '#');
    let total = 0;

    for (const key of keys) {
      const count = await redis.scard(key);
      total += count;
    }

    return total;
  } catch {
    return 0;
  }
}

export { createAdapter };

/**
 * Socket.IO Server Configuration
 *
 * WebSocket para notificaciones en tiempo real y Party Reading.
 */

import { getToken } from '@auth/core/jwt';
import { Server as NetServer } from 'http';
import { Server as SocketIOServer } from 'socket.io';

import { partyService } from '@/core/services/PartyService';
import { setRealtimeAnalytics } from '@/lib/analytics-store';
import { sanitizeText } from '@/lib/sanitize';
import { createRedisAdapter } from '@/lib/socket-redis-adapter';
import type {
  ServerToClientEvents,
  ClientToServerEvents,
  InterServerEvents,
  SocketData,
  JoinPartyUser,
  Notification,
  RealtimeAnalytics,
} from '@/types/socket';

// Re-exportar tipos para compatibilidad
export * from '@/types/socket';

// Singleton para el servidor Socket.IO
export type IOServer = SocketIOServer<
  ClientToServerEvents,
  ServerToClientEvents,
  InterServerEvents,
  SocketData
>;

let io: IOServer | null = null;

export const getIO = (): IOServer | null => io;

export const initIO = (httpServer: NetServer): IOServer => {
  if (io) {
    return io;
  }

  io = new SocketIOServer(httpServer, {
    path: '/api/socket',
    addTrailingSlash: false,
    cors: {
      origin: process.env.NEXTAUTH_URL || 'http://localhost:3000',
      methods: ['GET', 'POST'],
      credentials: true,
    },
    transports: ['websocket', 'polling'],
  });

  // Inicializar adaptador Redis para escalabilidad multi-servidor
  createRedisAdapter(io).then((enabled) => {
    if (enabled) {
      console.info('[Socket] Redis adapter initialized');
    }
  }).catch((error) => {
    console.warn('[Socket] Redis adapter init failed (non-blocking):', error.message);
  });

  // Mapa de sesiones activas para analiticas en tiempo real
  const activeSessions = new Map<string, {
    userId: string;
    username: string;
    avatarUrl: string | null;
    mangaId?: string;
    chapterId?: string;
    page?: number;
    chapterNumber?: number;
    mangaTitle?: string;
    slug?: string;
    coverUrl?: string | null;
    startedAt: Date;
    lastHeartbeat: Date;
  }>();

  // Middleware de autenticacion
  io.use(async (socket, next) => {
    try {
      const token = socket.handshake.auth.token;

      if (!token) {
        return next(new Error('Authentication required'));
      }

      // Verificar token con next-auth
      const decoded = await getToken({
        req: { headers: { cookie: `next-auth.session-token=${token}` } },
        secret: process.env.NEXTAUTH_SECRET,
      });

      if (!decoded?.sub) {
        return next(new Error('Invalid token'));
      }

      socket.data.userId = decoded.sub;
      socket.data.username = decoded.name as string;
      socket.data.avatarUrl = decoded.image as string | undefined;

      next();
    } catch (error) {
      next(new Error('Authentication failed'));
    }
  });

  // Eventos de conexion
  io.on('connection', (socket) => {
    const userId = socket.data.userId;
    const username = socket.data.username;
    const avatarUrl = socket.data.avatarUrl;

    if (!userId) {
      socket.disconnect();
      return;
    }

    console.info(`[Socket] User ${userId} connected`);

    // Unirse a room personal
    socket.join(`user:${userId}`);

    // =============== PARTY EVENTS ===============

    // Unirse a party
    socket.on('party:join', ({ partyId, user }) => {
      const userData: JoinPartyUser = user || {
        userId,
        username: username || 'Anonymous',
        avatarUrl,
      };

      const result = partyService.joinParty(partyId, userData, socket.id);

      if (!result.success || !result.member) {
        socket.emit('party:error', { message: result.error || 'Failed to join party' });
        return;
      }

      const party = partyService.getParty(partyId);
      if (!party) {
        socket.emit('party:error', { message: 'Party not found' });
        return;
      }

      // Unirse al room del party
      socket.join(`party:${partyId}`);

      // Notificar al usuario que se unio
      socket.emit('party:joined', { party, member: result.member });

      // Notificar a otros miembros
      socket.to(`party:${partyId}`).emit('party:member-joined', { member: result.member });

      // Enviar estado actual del party
      socket.emit('party:state', party);

      // Mensaje de sistema
      const systemMessage = partyService.addMessage(
        partyId,
        'system',
        'System',
        `${userData.username} joined the party`,
        'system'
      );

      if (systemMessage) {
        io?.to(`party:${partyId}`).emit('party:message-received', systemMessage);
      }

      console.info(`[Socket] User ${userId} joined party ${partyId}`);
    });

    // Salir del party
    socket.on('party:leave', ({ partyId }) => {
      const result = partyService.leaveParty(partyId, userId);

      if (result.success) {
        socket.leave(`party:${partyId}`);

        // Notificar a otros miembros
        socket.to(`party:${partyId}`).emit('party:member-left', { userId });

        // Mensaje de sistema
        const systemMessage = partyService.addMessage(
          partyId,
          'system',
          'System',
          `${username || 'A user'} left the party`,
          'system'
        );

        if (systemMessage) {
          io?.to(`party:${partyId}`).emit('party:message-received', systemMessage);
        }

        // Si era host, notificar cambio de host
        if (result.wasHost) {
          const party = partyService.getParty(partyId);
          if (party) {
            const newHost = party.members.find((m) => m.isHost);
            if (newHost) {
              io?.to(`party:${partyId}`).emit('party:host-changed', {
                newHostId: newHost.userId,
                newHostName: newHost.username,
              });
            }
          }
        }
      }

      console.info(`[Socket] User ${userId} left party ${partyId}`);
    });

    // Cambiar pagina (solo host)
    socket.on('party:page-change', ({ partyId, page }) => {
      const result = partyService.updatePage(partyId, userId, page);

      if (result.success) {
        // Notificar a todos los miembros
        io?.to(`party:${partyId}`).emit('party:page-sync', {
          page,
          hostId: userId,
        });

        // Mensaje de sistema
        const systemMessage = partyService.addMessage(
          partyId,
          'system',
          'System',
          `${username || 'Host'} changed to page ${page}`,
          'system'
        );

        if (systemMessage) {
          io?.to(`party:${partyId}`).emit('party:message-received', systemMessage);
        }
      } else {
        socket.emit('party:error', { message: result.error || 'Failed to change page' });
      }
    });

    // Movimiento del cursor
    socket.on('party:cursor-move', ({ partyId, position }) => {
      const party = partyService.getParty(partyId);
      if (!party) return;

      // Broadcast a otros miembros
      socket.to(`party:${partyId}`).emit('party:cursor-update', {
        userId,
        position: {
          ...position,
          userId,
          username: username || 'Anonymous',
        },
      });
    });

    // Enviar reaccion
    socket.on('party:reaction', ({ partyId, reaction, page }) => {
      const party = partyService.getParty(partyId);
      if (!party) return;

      const reactionData = {
        id: `reaction_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
        userId,
        username: username || 'Anonymous',
        reaction,
        page,
        createdAt: new Date(),
      };

      // Broadcast a todos los miembros
      io?.to(`party:${partyId}`).emit('party:reaction-received', reactionData);

      // Mensaje de sistema para reaccion
      const systemMessage = partyService.addMessage(
        partyId,
        'system',
        'System',
        `${username || 'Someone'} reacted with ${reaction}`,
        'system'
      );

      if (systemMessage) {
        io?.to(`party:${partyId}`).emit('party:message-received', systemMessage);
      }
    });

    // Enviar mensaje de chat
    socket.on('party:message', ({ partyId, content }) => {
      if (!content.trim()) return;

      const sanitized = sanitizeText(content);
      if (!sanitized) return;

      const message = partyService.addMessage(
        partyId,
        userId,
        username || 'Anonymous',
        sanitized,
        'chat',
        avatarUrl
      );

      if (message) {
        io?.to(`party:${partyId}`).emit('party:message-received', message);
      }
    });

    // Indicador de escritura
    socket.on('party:typing', ({ partyId, isTyping }) => {
      socket.to(`party:${partyId}`).emit('party:typing-update', {
        userId,
        username: username || 'Anonymous',
        isTyping,
      });
    });

    // Ser anfitrion
    socket.on('party:become-host', ({ partyId }) => {
      const party = partyService.getParty(partyId);
      if (!party) return;

      // Solo el host actual puede transferir, o si no hay host
      if (party.hostId && party.hostId !== userId) {
        // Verificar si el host esta activo
        const currentHost = party.members.find((m) => m.isHost);
        if (currentHost?.isOnline) {
          socket.emit('party:error', { message: 'Current host is still active' });
          return;
        }
      }

      const success = partyService.transferHost(partyId, party.hostId, userId);

      if (success) {
        io?.to(`party:${partyId}`).emit('party:host-changed', {
          newHostId: userId,
          newHostName: username || 'Anonymous',
        });

        // Mensaje de sistema
        const systemMessage = partyService.addMessage(
          partyId,
          'system',
          'System',
          `${username || 'A user'} is now the host`,
          'system'
        );

        if (systemMessage) {
          io?.to(`party:${partyId}`).emit('party:message-received', systemMessage);
        }
      }
    });

      // =============== NOTIFICATION EVENTS ===============

    // Unirse a rooms de mangas seguidos
    socket.on('user:join-room', (room) => {
      socket.join(room);
      console.info(`[Socket] User ${userId} joined room ${room}`);
    });

    // Salir de rooms
    socket.on('user:leave-room', (room) => {
      socket.leave(room);
      console.info(`[Socket] User ${userId} left room ${room}`);
    });

    // Marcar notificacion como leida
    socket.on('notification:mark-read', (notificationId) => {
      io?.to(`user:${userId}`).emit('notification:read', notificationId);
    });

    // Marcar todas como leidas
    socket.on('notification:mark-all-read', () => {
      io?.to(`user:${userId}`).emit('notification:count', 0);
    });

    // Ping-pong para mantener conexion
  socket.on('ping', () => {
    socket.emit('notification:new', { notification: null } as any);
  });

    // =============== ANALYTICS EVENTS ===============

    socket.on('analytics:heartbeat', (data) => {
      const existing = activeSessions.get(userId);
      if (existing) {
        existing.lastHeartbeat = new Date();
        if (data.mangaId) existing.mangaId = data.mangaId;
        if (data.chapterId) existing.chapterId = data.chapterId;
        if (data.page !== undefined) existing.page = data.page;
      } else {
        activeSessions.set(userId, {
          userId,
          username: username || 'Anonymous',
          avatarUrl: avatarUrl || null,
          mangaId: data.mangaId,
          chapterId: data.chapterId,
          page: data.page,
          startedAt: new Date(),
          lastHeartbeat: new Date(),
        });
      }
    });

    socket.on('analytics:subscribe', () => {
      socket.join('admin:analytics');
    });

    socket.on('analytics:unsubscribe', () => {
      socket.leave('admin:analytics');
    });

    // Desconexion
    (socket.on as (event: string, handler: (...args: any[]) => void) => void)('disconnect', () => {
      console.info(`[Socket] User ${userId} disconnected`);

      activeSessions.delete(userId);

      // Desconectar de todos los parties
      const userParty = partyService.getUserParty(userId);
      if (userParty) {
        partyService.disconnectUser(userParty.partyId, userId);

        // Notificar a otros miembros
        socket.to(`party:${userParty.partyId}`).emit('party:member-updated', {
          member: {
            ...userParty.members.find((m) => m.userId === userId)!,
            isOnline: false,
          },
        });
      }
    });
  });

  // =============== ANALYTICS BROADCAST INTERVAL ===============

  let peakToday = 0;
  let peakTime = '';
  let lastMinuteReads = 0;
  let lastMinuteCount = 0;
  const ANALYTICS_INTERVAL = 5000;

  const analyticsInterval = setInterval(() => {
    const now = Date.now();
    const activeThreshold = 60_000;
    const staleThreshold = 120_000;

    let activeCount = 0;
    const sessionsList: RealtimeAnalytics['activeSessions'] = [];
    const mangaReaders = new Map<string, { title: string; coverUrl: string | null; slug: string; readers: number }>();

    for (const [sid, session] of activeSessions) {
      const elapsed = now - session.lastHeartbeat.getTime();

      if (elapsed > staleThreshold) {
        activeSessions.delete(sid);
        continue;
      }

      if (elapsed <= activeThreshold) {
        activeCount++;
        sessionsList.push({
          userId: session.userId,
          username: session.username,
          avatarUrl: session.avatarUrl,
          mangaId: session.mangaId,
          mangaTitle: session.mangaTitle,
          chapterNumber: session.chapterNumber,
          currentPage: session.page,
          startedAt: session.startedAt,
          lastHeartbeat: session.lastHeartbeat,
        });

        if (session.mangaId && session.mangaTitle) {
          const existing = mangaReaders.get(session.mangaId);
          if (existing) {
            existing.readers++;
          } else {
            mangaReaders.set(session.mangaId, {
              title: session.mangaTitle,
              coverUrl: session.coverUrl || null,
              slug: session.slug || '',
              readers: 1,
            });
          }
        }
      }
    }

    lastMinuteCount++;
    if (lastMinuteCount >= 12) {
      lastMinuteReads = activeCount;
      lastMinuteCount = 0;
    }

    if (activeCount > peakToday) {
      peakToday = activeCount;
      peakTime = new Date().toLocaleTimeString();
    }

    const readersPerMinute = lastMinuteReads;

    const popularNow = Array.from(mangaReaders.entries())
      .map(([mangaId, data]) => ({ mangaId, ...data }))
      .sort((a, b) => b.readers - a.readers)
      .slice(0, 10);

    const stats: RealtimeAnalytics = {
      activeReaders: activeCount,
      activeReadersChange: 0,
      activeSessions: sessionsList,
      popularNow,
      readersPerMinute,
      peakToday,
      peakTime,
    };

    setRealtimeAnalytics(stats);
    io?.to('admin:analytics').emit('analytics:stats', stats);
  }, ANALYTICS_INTERVAL);

  // Limpiar intervalo al apagar
  (io as any).on('close', () => {
    clearInterval(analyticsInterval);
  });

  return io;
};

// Helper para emitir notificaciones
export const emitNotification = (
  userId: string,
  notification: unknown
) => {
  const io = getIO();
  if (io) {
    io.to(`user:${userId}`).emit('notification:new', notification as Notification);
  }
};

// Helper para emitir a múltiples usuarios
export const emitToRoom = (
  room: string,
  event: keyof ServerToClientEvents & string,
  data: any
) => {
  const io = getIO();
  if (io) {
    io.to(room).emit(event, data);
  }
};

// Helper para broadcast
export const broadcastNotification = (
  event: keyof ServerToClientEvents & string,
  data: any
) => {
  const io = getIO();
  if (io) {
    io.emit(event, data);
  }
};
